        //double ut_L = ux_L/(Um+1e-100);
        //double  f1_p =   0.25*rhon_Lx[i][j]*sqrt(8.0*Boltz*Tn/(M_PI*massi))*(exp(-ut_L*ut_L) + sqrt(M_PI)*ut_L*(erf(ut_L) + 1.0)); //置き換え
