            fnr1[i][j] = -fn_In;
            fnr2[i][j] = 0.0; //rL/rR*fnr2[i][j-1]; //Maxwellian
            fnr3[i][j] = 0.0; //rL/rR*fnr3[i][j-1]; //Maxwellian
