//*****************************************************************
//**                                                             **
//**           void update_Ui                                    **
//**                                                             **
//*****************************************************************
void update_Ui_constTe(){


    double ratio = 1.0;
    double Te_rep = 0.1*e0/Boltz; //代表温度は3eVに固定
    double nu_star = 0.1/rmax*sqrt(Boltz*Te_rep/massi); //代表衝突周波数

    //time step for ion
    //------------------------------------
    double dt_i = dt*double(ndt_i);
    //------------------------------------
    
    //update Uix
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                //diffusion coefficient (numerical param.)
                //------------------------------------
                double Te_rep = Te_rep_eV*e0/Boltz;
                double nu_star = 1.0/rmax*sqrt(Boltz*Te_rep/massi);
                double nui_m_tmp = (nui_m[i][j]+nui_m[i-1][j])/2.0;
                double Te_tmp = Te_rep;
                double D_tmp = Boltz*(Ti + Te_tmp)/(massi*(nui_m_tmp+nu_star)+1e-100);
                //----------------------------------------------------
                
                //density at cell (Uix control volume) center
                //----------------------------------------------------
                double rhoi_tmp = (rhoi[i][j]+rhoi[i-1][j])/2.0;
                //----------------------------------------------------

                //density gradient at cell (Uix control volume) center
                //------------------------------------
                double dndx_old = (rhoi_old[i][j] - rhoi_old[i-1][j])/dx; //density gradient calculation
                double dndx = (rhoi[i][j] - rhoi[i-1][j])/dx;
                //------------------------------------

                //temporary flux
                //------------------------------------
                double rhoUix_tmp =  rhoi[i-1][j]*(Uix[i][j] + fabs(Uix[i][j]))/2.0
                    + rhoi[i][j]*(Uix[i][j] - fabs(Uix[i][j]))/2.0;
                //------------------------------------

                //Update Uix
                //----------------------------------------------------
                rhoUix[i][j] = rhoUix_tmp - D_tmp*(dndx - dndx_old);
                Uix[i][j] = Uix[i][j] - D_tmp/(rhoi_tmp+1e-100)*(dndx - dndx_old);
                //----------------------------------------------------
            }
        }
    }
    //=================================================================================

    //update Uir
    //=================================================================================
    for (int iblock=0;iblock<n_bl-2;iblock++){
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1] + int(iblock == 4);j++){
                //diffusion coefficient (numerical param.)
                //------------------------------------
                double Te_rep = Te_rep_eV*e0/Boltz;
                double nu_star = 1.0/rmax*sqrt(Boltz*Te_rep/massi);
                double r_tmp = (r[j]+r[j-1])/2.0;
                double nui_m_tmp = (nui_m[i][j] + nui_m[i][j-1])/2.0;
                double Te_tmp = Te_rep;
                double D_tmp = Boltz*(Ti + Te_tmp)/(massi*(nui_m_tmp+nu_star)+1e-100);
                //----------------------------------------------------
                
                //density at cell (Uir control volume) center
                //----------------------------------------------------
                double rhoi_tmp = (rhoi[i][j] + rhoi[i][j-1])/2.0;
                //----------------------------------------------------

                //density gradient at cell (Uir control volume) center
                //------------------------------------
                double dndr_old = (rhoi_old[i][j] - rhoi_old[i][j-1])/dr;
                double dndr     = (rhoi[i][j]     - rhoi[i][j-1]    )/dr;
                //------------------------------------

                //temporary flux
                //------------------------------------
                double rhoUir_tmp =  rhoi[i][j-1]*(Uir[i][j] + fabs(Uir[i][j]))/2.0
                    + rhoi[i][j]*(Uir[i][j] - fabs(Uir[i][j]))/2.0;
                //------------------------------------

                //Update Uir
                //----------------------------------------------------
                rhoUir[i][j] = rhoUir_tmp - D_tmp*(dndr - dndr_old);
                Uir[i][j] = Uir[i][j] - D_tmp/(rhoi_tmp+1e-100)*(dndr - dndr_old);
                //----------------------------------------------------
            }
        }
    }
    //=================================================================================

    //update Uip
    //=================================================================================
    // No process due to absense of density gradient in azimuthal direction
    //=================================================================================

    //calculation of particle balance
    //------------------------------------
    if(itime%ndiv_fout == 0 || itime == ntime){
        
        //volume integrated values
        //------------------------------------
        double dNidt_sum         = 0.0;
        double nabla_rhoUi_sum   = 0.0;
        double rate_d_ionz_sum   = 0.0;
        double rate_s_ionz_sum   = 0.0;
        //------------------------------------
    
        //calculate volume integrated of each term
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //BC - set flag for adjacent to the wall, open, or central axis (adjacent = 0, others = 1)
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //w/o x5
                    double bRr = bRr_wall;
                    //------------------------------------

                    double nabla_rhoUi = (rhoUix[i+1][j]*bRx_wall - rhoUix[i][j]*bLx_wall)/dx 
                                       + (qR*rhoUir[i][j+1]*bRr_wall -qL*rhoUir[i][j]*bLr_wall)/dr
                                       + (rhoUix_wall[i+1][j] - rhoUix_wall[i][j])/dx 
                                       + (qR*rhoUir_wall[i][j+1] - qL*rhoUir_wall[i][j])/dr;
                    
                    double volume = 2.0*M_PI*r[j]*dr*dx;
                    
                    dNidt_sum         = dNidt_sum         + volume*(rhoi[i][j] - rhoi_old[i][j])/dt;
                    nabla_rhoUi_sum   = nabla_rhoUi_sum   + volume*nabla_rhoUi;
                    rate_d_ionz_sum   = rate_d_ionz_sum   + volume*rhoe[i][j]*nu_ionz[i][j];
                    rate_s_ionz_sum   = rate_s_ionz_sum   + volume*rhoe[i][j]*nu_ionzStep[i][j];
                }
            }
        }

        //output particle balance for ion
        //------------------------------------
        std::string char1="results/particle_balance_ion";
        std::string char2=std::to_string(nOut);
        std::string char_csv=".csv";
        std::ofstream outputfile9(char1+char2+char_csv);
        outputfile9 << std::setprecision(std::numeric_limits<double>::max_digits10) << std::scientific;
        outputfile9<< "dN/dt (pcl/s), loss_to_bnd (pcl/s), direct-iz (pcl/s), sw-iz (pcl/s), sum (pcl/s)"<< std::endl;
        double sum = -dNidt_sum + (-nabla_rhoUi_sum + rate_d_ionz_sum + rate_s_ionz_sum);
        outputfile9<< dNidt_sum << "," << -nabla_rhoUi_sum << "," << rate_d_ionz_sum << ","<< rate_s_ionz_sum 
            << "," << -dNidt_sum + (-nabla_rhoUi_sum + rate_d_ionz_sum + rate_s_ionz_sum)<< std::endl;
        outputfile9.close();
        //------------------------------------
    }
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //ion density
    //------------------------------------
    error_rhoi = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoi[i][j] - rhoi_old[i][j])/(rhoi[i][j] + rhoi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoi){
                        error_rhoi = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoi += pow(rhoi[i][j]-rhoi_old[i][j],2)/(pow(rhoi_old[i][j],2)+1e10)/CFL;
                    ncount++;
                }
            }
        }
        error_rhoi = sqrt(error_rhoi/double(ncount));
    }
    //------------------------------------
    
    //x-directional ion bulk velocity
    //------------------------------------
    error_Uix = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1] + 1;i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((Uix[i][j] - Uix_old[i][j])/(Uix[i][j] + Uix_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Uix){
                        error_Uix = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1] + 1;i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_Uix += pow(Uix[i][j]-Uix_old[i][j],2)/(pow(Uix_old[i][j],2)+1e-6)/CFL;
                    ncount++;
                }
            }
        }
        error_Uix = sqrt(error_Uix/double(ncount));
    }
    //------------------------------------

    //r-directional ion bulk velocity
    //------------------------------------
    error_Uir = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0]+1;j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((Uir[i][j] - Uir_old[i][j])/(Uir[i][j] + Uir_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Uir){
                        error_Uir = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0]+1;j<=j_flr_bl[iblock][1];j++){
                    error_Uir += pow(Uir[i][j]-Uir_old[i][j],2)/(pow(Uir_old[i][j],2)+1e-6)/CFL;
                    ncount++;
                }
            }
        }
        error_Uir = sqrt(error_Uir/double(ncount));
    }
    //------------------------------------

    //p-directional ion bulk velocity
    //------------------------------------
    error_Uip = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Uip[i][j] - Uip_old[i][j])/(Uip[i][j] + Uip_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Uip){
                        error_Uip = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Uip += pow(Uip[i][j]-Uip_old[i][j],2)/(pow(Uip_old[i][j],2)+1e-6)/CFL;
                    ncount++;
                }
            }
        }
        error_Uip = sqrt(error_Uip/double(ncount));
    }
    //------------------------------------
    //=====================================================================================
}

//*****************************************************************
//**                                                             **
//**           void update_Ui                                    **
//**                                                             **
//*****************************************************************
void update_Ui_my(){

    //update Uix
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                //diffusion coefficient (numerical param.)
                //------------------------------------
                double rhoi_old_tmp = (rhoi_old[i][j] + rhoi_old[i-1][j])/2.0;
                double rate_ionize_tmp = (rate_ionize[i][j] + rate_ionize[i-1][j])/2.0;
                double nui_m_tmp = (nui_m[i][j]+nui_m[i-1][j])/2.0;
                double D_tmp = Boltz*Ti/(massi*(rate_ionize_tmp/(rhoi_old_tmp + 1e-100) + nui_m_tmp)+1e-100);
                //----------------------------------------------------
                
                //density at cell (Uix control volume) center
                //----------------------------------------------------
                double rhoi_tmp = (rhoi[i][j]+rhoi[i-1][j])/2.0;
                //----------------------------------------------------

                //density gradient at cell (Uix control volume) center
                //------------------------------------
                double dndx_old = (rhoi_old[i][j] - rhoi_old[i-1][j])/dx; //density gradient calculation
                double dndx = (rhoi[i][j] - rhoi[i-1][j])/dx;
                //------------------------------------

                //Update Uix
                //----------------------------------------------------
                Uix[i][j] = Uix[i][j] - D_tmp/(rhoi_tmp+1e-100)*(dndx - dndx_old);
                //----------------------------------------------------
            }
        }
    }
    //=================================================================================

    //update Uir
    //=================================================================================
    for (int iblock=0;iblock<n_bl-2;iblock++){
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1] + int(iblock == 4);j++){
                //diffusion coefficient (numerical param.)
                //------------------------------------
                double rhoi_old_tmp = (rhoi_old[i][j] + rhoi_old[i][j-1])/2.0;
                double rate_ionize_tmp = (rate_ionize[i][j] + rate_ionize[i][j-1])/2.0;
                double r_tmp = (r[j]+r[j-1])/2.0;
                double nui_m_tmp = (nui_m[i][j] + nui_m[i][j-1])/2.0;
                double D_tmp = Boltz*Ti/(massi*(rate_ionize_tmp/(rhoi_old_tmp + 1e-100) + nui_m_tmp)+1e-100);
                //----------------------------------------------------
                
                //density at cell (Uir control volume) center
                //----------------------------------------------------
                double rhoi_tmp = (rhoi[i][j] + rhoi[i][j-1])/2.0;
                //----------------------------------------------------

                //density gradient at cell (Uir control volume) center
                //------------------------------------
                double dndr_old = (rhoi_old[i][j] - rhoi_old[i][j-1])/dr;
                double dndr     = (rhoi[i][j]     - rhoi[i][j-1]    )/dr;
                //------------------------------------

                //Update Uir
                //----------------------------------------------------
                Uir[i][j] = Uir[i][j] - D_tmp/(rhoi_tmp+1e-100)*(dndr - dndr_old);
                //----------------------------------------------------
            }
        }
    }
    //=================================================================================

    //update Uip
    //=================================================================================
    // No process due to absense of density gradient in azimuthal direction
    //=================================================================================


    //Caluculate residuals
    //=====================================================================================
    //ion density
    //------------------------------------
    error_rhoi = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoi[i][j] - rhoi_old[i][j])/(rhoi[i][j] + rhoi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoi){
                        error_rhoi = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoi += pow(rhoi[i][j]-rhoi_old[i][j],2)/(pow(rhoi_old[i][j],2)+1e10)/CFL;
                    ncount++;
                }
            }
        }
        error_rhoi = sqrt(error_rhoi/double(ncount));
    }
    //------------------------------------
    
    //x-directional ion bulk velocity
    //------------------------------------
    error_Uix = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1] + 1;i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((Uix[i][j] - Uix_old[i][j])/(Uix[i][j] + Uix_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Uix){
                        error_Uix = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1] + 1;i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_Uix += pow(Uix[i][j]-Uix_old[i][j],2)/(pow(Uix_old[i][j],2)+1e-6)/CFL;
                    ncount++;
                }
            }
        }
        error_Uix = sqrt(error_Uix/double(ncount));
    }
    //------------------------------------

    //r-directional ion bulk velocity
    //------------------------------------
    error_Uir = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0]+1;j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((Uir[i][j] - Uir_old[i][j])/(Uir[i][j] + Uir_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Uir){
                        error_Uir = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0]+1;j<=j_flr_bl[iblock][1];j++){
                    error_Uir += pow(Uir[i][j]-Uir_old[i][j],2)/(pow(Uir_old[i][j],2)+1e-6)/CFL;
                    ncount++;
                }
            }
        }
        error_Uir = sqrt(error_Uir/double(ncount));
    }
    //------------------------------------

    //p-directional ion bulk velocity
    //------------------------------------
    error_Uip = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Uip[i][j] - Uip_old[i][j])/(Uip[i][j] + Uip_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Uip){
                        error_Uip = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Uip += pow(Uip[i][j]-Uip_old[i][j],2)/(pow(Uip_old[i][j],2)+1e-6)/CFL;
                    ncount++;
                }
            }
        }
        error_Uip = sqrt(error_Uip/double(ncount));
    }
    //------------------------------------
    //=====================================================================================
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    
    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            phi_old[i][j] = phi[i][j];
        }
    }
    //------------------------------------

    //Make coefficient for poission equation 
    // (coupled with electron continuity) for 9 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qL = rL/r[j];
                double qR = rR/r[j];
                //------------------------------------

                //electron density at cell interface
                //------------------------------------
                double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;
                double mu_Lx = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                double mu_Rx = (mu_para[i][j] + mu_para[i+1][j])/2.0;
                double mu_Lr = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                double mu_Rr = (mu_para[i][j] + mu_para[i][j+1])/2.0;
                //------------------------------------

                //div. of drift-flux
                //------------------------------------
                double divDflux = ((rhoe_Rx*mu_Rx)*phi[i+1][j] 
                    - ((rhoe_Rx*mu_Rx) + (rhoe_Lx*mu_Lx))*phi[i][j] 
                    + (rhoe_Lx*mu_Lx)*phi[i-1][j])/(dx*dx) 
                    + ((qR*rhoe_Rr*mu_Rr)*phi[i][j+1]
                    -  ((qR*rhoe_Rr*mu_Rr) + (qL*rhoe_Lr*mu_Lr))*phi[i][j]
                    +  (qL*rhoe_Lr*mu_Lr)*phi[i][j-1])/(dr*dr);
                //------------------------------------

                //coefficient for ion momentum conservation for 5 point stencil
                //*****************************************************
                //vertical and horizental 5 stencil
                //------------------------------------
                aP[i][j] = ((eps0 + e0*dt*rhoe_Rx*mu_Rx) + (eps0 + e0*dt*rhoe_Lx*mu_Lx))*dr*dr 
                    + (qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr) + qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr))*dx*dx;
                aE[i][j] = (eps0 + e0*dt*rhoe_Rx*mu_Rx)*dr*dr;
                aW[i][j] = (eps0 + e0*dt*rhoe_Lx*mu_Lx)*dr*dr;
                aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr)*dx*dx;
                aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr)*dx*dx;
                //------------------------------------

                //RHS
                //------------------------------------
                b[i][j] = (e0*rhoi[i][j] - e0*(2.0*rhoe[i][j] - rhoe_old[i][j]) - e0*dt*divDflux)*dx*dx*dr*dr;
                //------------------------------------
                //*****************************************************
            }
        }   
    }

    //left-wall-BC (z0) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        //modify coefficient
        //------------------------------------
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
        //------------------------------------
    }
    //------------------------------------

    //left-wall-BC (z1) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }
   //------------------------------------

    //left-wall-BC (z2) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (z4) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }
    //------------------------------------

    //right-wall-BC (z3) continuity potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        aP[i][j] = aP[i][j] + aE[i][j];
        aE[i][j] = 0.0;
    }
    //------------------------------------

    //right-wall-BC (z5) continuity potential = V_bias
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        aP[i][j] = aP[i][j] + aE[i][j];
        b[i][j] = b[i][j] + 2.0*aE[i][j]*V_bias;
        aE[i][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (x0) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        aP[i][j] = aP[i][j] + aS[i][j];
        aS[i][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (x2) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        aP[i][j] = aP[i][j] + aS[i][j];
        aS[i][j] = 0.0;
    }
    //------------------------------------

    //upper-wall-BC (x1) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        aP[i][j] = aP[i][j] + aN[i][j];
        aN[i][j] = 0.0;
    }
    //------------------------------------

    //upper-wall-BC (x4) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        aP[i][j] = aP[i][j] + aN[i][j];
        aN[i][j] = 0.0;
    }
    //------------------------------------

    //upper-open-BC (x5) grad(phi) = 0
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        aP[i][j] = aP[i][j] - aN[i][j];
        aN[i][j] = 0.0;
    }
    //------------------------------------

    //Solver
    //=====================================================================
    if(icon_iter_phi==0){
        //SOR
        //------------------------------------
        double alpha = 0.8;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
        //------------------------------------
    }else{
        //Semi-coarse Multi-Grid by Hypre
        //------------------------------------
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
        //------------------------------------
    }
    //=====================================================================

    //Update Ex
    //------------------------------------
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }
    //------------------------------------

    //Reflect BCs for ghost cell and Update Electric field
    //=====================================================================
    //left-wall-BC (z0) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //left-wall-BC (z1) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //left-wall-BC (z2) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //left-wall-BC (z4) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //right-wall-BC (z3) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
        Ex[i+1][j] =  - (phi[i+1][j]-phi[i][j])/dx;
    }
    //------------------------------------
    
    //right-wall-BC (z5) potential = V_bias
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        phi[i+1][j] = 2.0*V_bias - phi[i][j];
        Ex[i+1][j] =  - (phi[i+1][j]-phi[i][j])/dx;
    }
    //------------------------------------

    //Update Er
    //------------------------------------
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
    //------------------------------------

    //lower-wall-BC (x0) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        phi[i][j-1] = - phi[i][j];
        Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
    }
    //------------------------------------

    //lower-wall-BC (x2) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        phi[i][j-1] = - phi[i][j];
        Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
    }
    //------------------------------------

    //upper-wall-BC (x1) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        phi[i][j+1] = - phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //------------------------------------

    //upper-wall-BC (x4) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        phi[i][j+1] = - phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //------------------------------------

    //upper-wall-BC (x5) grad(phi) = 0
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        phi[i][j+1] = phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //phi
    //------------------------------------
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j],2)+1e-12)/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }
    //------------------------------------
    //=====================================================================================
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_PC_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j]-phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i-1][j]*Te[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        //nUex[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                        nUex[i][j] = nUex_old[i+1][j];
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        //nUex[i][j] =  0.0; //rhoi[i-1][j]*Uix[i][j];
                        nUex[i][j] = nUex_old[i-1][j];
                    }
                }
            }     
        }

        //nUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i][j-1]*Te[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double rL = (r[j]+r[j-1])/2.0;
                        double rR = (r[j]+r[j+1])/2.0;
                        
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        nUer[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                        nUer[i][j] = rR/rL*nUer_old[i][j+1];
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        double rL = (r[j]+r[j-1])/2.0;
                        double rR = (r[j]+r[j+1])/2.0;

                        nUer[i][j] =  0.0; //rhoi[i][j-1]*Uir[i][j];
                        nUer[i][j] = rL/rR*nUer_old[i][j-1];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,dphi);
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            dphi[i+1][j] = -dphi[i][j];
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
            dphi[i][j-1] = - dphi[i][j];
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            dphi[i][j+1] = - dphi[i][j];
        }

        /********************* 更新 *******************/
        //dnUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //dnUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }

        //電位更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    phi[i][j] = phi[i][j] + dphi[i][j];
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //左壁境界1 (値0)
     for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
}


//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_PC_old2(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j]-phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i-1][j]*Te[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    //if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                    //    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    //nUex[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    nUex[i][j] = nUex_old[i+1][j];
                    //}
                    ////右はイオンフラックスと同じ
                    //if(i==i_flc_bl[1][1]+1){
                    //    //nUex[i][j] =  0.0; //rhoi[i-1][j]*Uix[i][j];
                    //    nUex[i][j] = nUex_old[i-1][j];
                    //}
                }
            }     
        }

        //左 壁1
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            nUex[i][j] = nUex[i+1][j];
        }
    
        //左 壁2
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            nUex[i][j] = nUex[i+1][j];
        }

        //右 壁
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            //nUex[i+1][j] = nUex[i][j];
            nUex[i+1][j] =  rhoi[i][j]*Uix[i+1][j];
        }

        //nUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i][j-1]*Te[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    //if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    
                    //    //double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    //nUer[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    nUer[i][j] = rR/rL*nUer_old[i][j+1];
                    //}
                    ////上はイオンフラックスと同じ
                    //if(j==j_flc_bl[1][1]+1){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    //nUer[i][j] =  0.0; //rhoi[i][j-1]*Uir[i][j];
                    //    nUer[i][j] = rL/rR*nUer_old[i][j-1];
                    //}
                }
            }
        }

        //下 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;

            nUer[i][j] = rR/rL*nUer[i][j+1];
        }

        //上 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[0][1];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;

            //nUer[i][j+1] = rL/rR*nUer[i][j-1];
            nUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,dphi);
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            dphi[i+1][j] = -dphi[i][j];
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
            dphi[i][j-1] = - dphi[i][j];
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            dphi[i][j+1] = - dphi[i][j];
        }

        /********************* 更新 *******************/
        //dnUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //dnUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }

        //電位更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    phi[i][j] = phi[i][j] + dphi[i][j];
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //左壁境界1 (値0)
     for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_PC_old3(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j]-phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i-1][j]*Te[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    //if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                    //    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    //nUex[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    nUex[i][j] = nUex_old[i+1][j];
                    //}
                    ////右はイオンフラックスと同じ
                    //if(i==i_flc_bl[1][1]+1){
                    //    //nUex[i][j] =  0.0; //rhoi[i-1][j]*Uix[i][j];
                    //    nUex[i][j] = nUex_old[i-1][j];
                    //}
                }
            }     
        }

        //左 壁1
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            nUex[i][j] = nUex[i+1][j];
        }
    
        //左 壁2
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            nUex[i][j] = nUex[i+1][j];
        }

        //右 壁
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            //nUex[i+1][j] = nUex[i][j];
            nUex[i+1][j] =  rhoi[i][j]*Uix[i+1][j];
        }

        //nUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i][j-1]*Te[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    //if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    
                    //    //double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    //nUer[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    nUer[i][j] = rR/rL*nUer_old[i][j+1];
                    //}
                    ////上はイオンフラックスと同じ
                    //if(j==j_flc_bl[1][1]+1){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    //nUer[i][j] =  0.0; //rhoi[i][j-1]*Uir[i][j];
                    //    nUer[i][j] = rL/rR*nUer_old[i][j-1];
                    //}
                }
            }
        }

        //下 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;

            nUer[i][j] = rR/rL*nUer[i][j+1];
        }

        //上 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[0][1];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;

            //nUer[i][j+1] = rL/rR*nUer[i][j-1];
            nUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double mu_min_Lx = (mu_perp[i][j]*(1.0 + nbLx) + mu_perp[i-1][j]*bLx)/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]*(1.0 + nbRx) + mu_perp[i+1][j]*bRx)/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]*(1.0 + nbLr) + mu_perp[i][j-1]*bLr)/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]*(1.0 + nbRr) + mu_perp[i][j+1]*bRr)/2.0*ratioY;

                    double Te_Lx = (Te[i][j]*(1.0 + nbLx) + Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]*(1.0 + nbRx) + Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]*(1.0 + nbLr) + Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]*(1.0 + nbRr) + Te[i][j+1])/2.0;

                    double rhoe_Lx = (rhoe[i][j]*(1.0 + nbLx) + rhoe[i-1][j]*bLx)/2.0;
                    double rhoe_Rx = (rhoe[i][j]*(1.0 + nbRx) + rhoe[i+1][j]*bRx)/2.0;
                    double rhoe_Lr = (rhoe[i][j]*(1.0 + nbLr) + rhoe[i][j-1]*bLr)/2.0;
                    double rhoe_Rr = (rhoe[i][j]*(1.0 + nbRr) + rhoe[i][j+1]*bRr)/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }

        //solve
        if(icon_iter_phi == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            dphi[i+1][j] = -dphi[i][j];
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
            dphi[i][j-1] = - dphi[i][j];
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            dphi[i][j+1] = - dphi[i][j];
        }

        /********************* 更新 *******************/
        //dnUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //dnUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }

        //電位更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    phi[i][j] = phi[i][j] + dphi[i][j];
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //左壁境界1 (値0)
     for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_PC_old4(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j]-phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*Te_tmp*(rhoe[i][j] - rhoe[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    //if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                    //    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    //nUex[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    nUex[i][j] = nUex_old[i+1][j];
                    //}
                    ////右はイオンフラックスと同じ
                    //if(i==i_flc_bl[1][1]+1){
                    //    //nUex[i][j] =  0.0; //rhoi[i-1][j]*Uix[i][j];
                    //    nUex[i][j] = nUex_old[i-1][j];
                    //}
                }
            }     
        }

        //左 壁1
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            nUex[i][j] = nUex[i+1][j];
        }
    
        //左 壁2
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            nUex[i][j] = nUex[i+1][j];
        }

        //右 壁
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            //nUex[i+1][j] = nUex[i][j];
            nUex[i+1][j] =  rhoi[i][j]*Uix[i+1][j];
        }

        //nUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*Te_tmp*(rhoe[i][j] - rhoe[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    //if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    
                    //    //double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    //nUer[i][j] = 0.0; //-0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    nUer[i][j] = rR/rL*nUer_old[i][j+1];
                    //}
                    ////上はイオンフラックスと同じ
                    //if(j==j_flc_bl[1][1]+1){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    //nUer[i][j] =  0.0; //rhoi[i][j-1]*Uir[i][j];
                    //    nUer[i][j] = rL/rR*nUer_old[i][j-1];
                    //}
                }
            }
        }

        //下 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;

            nUer[i][j] = rR/rL*nUer[i][j+1];
        }

        //上 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[0][1];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;

            //nUer[i][j+1] = rL/rR*nUer[i][j-1];
            nUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double mu_min_Lx = (mu_perp[i][j]*(1.0 + nbLx) + mu_perp[i-1][j]*bLx)/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]*(1.0 + nbRx) + mu_perp[i+1][j]*bRx)/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]*(1.0 + nbLr) + mu_perp[i][j-1]*bLr)/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]*(1.0 + nbRr) + mu_perp[i][j+1]*bRr)/2.0*ratioY;

                    double Te_Lx = (Te[i][j]*(1.0 + nbLx) + Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]*(1.0 + nbRx) + Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]*(1.0 + nbLr) + Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]*(1.0 + nbRr) + Te[i][j+1])/2.0;

                    double rhoe_Lx = (rhoe[i][j]*(1.0 + nbLx) + rhoe[i-1][j]*bLx)/2.0;
                    double rhoe_Rx = (rhoe[i][j]*(1.0 + nbRx) + rhoe[i+1][j]*bRx)/2.0;
                    double rhoe_Lr = (rhoe[i][j]*(1.0 + nbLr) + rhoe[i][j-1]*bLr)/2.0;
                    double rhoe_Rr = (rhoe[i][j]*(1.0 + nbRr) + rhoe[i][j+1]*bRr)/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }

        //solve
        if(icon_iter_phi == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            dphi[i+1][j] = -dphi[i][j];
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
            dphi[i][j-1] = - dphi[i][j];
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            dphi[i][j+1] = - dphi[i][j];
        }

        /********************* 更新 *******************/
        //dnUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //dnUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }

        //電位更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    phi[i][j] = phi[i][j] + dphi[i][j];
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //左壁境界1 (値0)
     for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j]-phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*Te_tmp*(rhoe[i][j] - rhoe[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                        //nUex[i][j] = nUex_old[i+1][j];
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        nUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                        //nUex[i][j] = nUex_old[i-1][j];
                    }
                }
            }     
        }

        //左 壁1
        //for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        //    int i = i_flc_bl[0][0];
        //    nUex[i][j] = nUex[i+1][j];
        //}
        ////左 壁2
        //for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        //    int i = i_flc_bl[1][0];
        //    nUex[i][j] = nUex[i+1][j];
        //}
        ////右 壁
        //for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        //    int i = i_flc_bl[1][1];
        //    //nUex[i+1][j] = nUex[i][j];
        //    nUex[i+1][j] =  rhoi[i][j]*Uix[i+1][j];
        //}

        //nUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*Te_tmp*(rhoe[i][j] - rhoe[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double rL = (r[j]+r[j-1])/2.0;
                        double rR = (r[j]+r[j+1])/2.0;
                        
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                        //nUer[i][j] = rR/rL*nUer_old[i][j+1];
                    }
                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        double rL = (r[j]+r[j-1])/2.0;
                        double rR = (r[j]+r[j+1])/2.0;
                        nUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                        //nUer[i][j] = rL/rR*nUer_old[i][j-1];
                    }
                }
            }
        }

        //下 壁
        //for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        //    int j = j_flc_bl[0][0];
        //    double rL = (r[j]+r[j-1])/2.0;
        //    double rR = (r[j]+r[j+1])/2.0;
        //    nUer[i][j] = rR/rL*nUer[i][j+1];
        //}
        ////上 壁
        //for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        //    int j = j_flc_bl[0][1];
        //    double rL = (r[j]+r[j-1])/2.0;
        //    double rR = (r[j]+r[j+1])/2.0;
        //    //nUer[i][j+1] = rL/rR*nUer[i][j-1];
        //    nUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
        //}

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double mu_min_Lx = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j] + mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j] + mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j] + Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j] + Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j] + Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j] + Te[i][j+1])/2.0;

                    double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }

        //solve
        if(icon_iter_phi == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            dphi[i+1][j] = -dphi[i][j];
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
            dphi[i][j-1] = - dphi[i][j];
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            dphi[i][j+1] = - dphi[i][j];
        }

        /********************* 更新 *******************/
        //dnUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //dnUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }

        //電位更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    phi[i][j] = phi[i][j] + dphi[i][j];
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //左壁境界1 (値0)
     for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_wdTe_PC_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j]-phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    //左 壁 z0 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }
    //左 壁 z1 (値0)
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        phi[i-1][j] = - phi[i][j];
    }
    //左 壁 z2 (値0)
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        phi[i-1][j] = - phi[i][j];
    }
    //左 壁 z4 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        phi[i-1][j] = - phi[i][j];
    }
    //右 壁 z3 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }
    //右 壁 z5 (値V_bias)
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        phi[i+1][j] = 2.0*V_bias - phi[i][j];
    }

    //下 壁 x0 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        phi[i][j-1] = - phi[i][j];
    }
    //下 壁 x2 (値0)
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        phi[i][j-1] = - phi[i][j];
    }

    //上 壁 x1 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        phi[i][j+1] = - phi[i][j];
    }
    //上 壁 x4 (値0)
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        phi[i][j+1] = - phi[i][j];
    }
    //上 開放 x5 (値0)
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        phi[i][j+1] = phi[i][j];
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2


                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    //double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    //double nbRr1  = 1.0 - bRr1; //x5だけ
                    //bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    //bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr_Lx + rL*nUer_old_tmp[i-1][j]*bLr_Lx)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    //double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_min_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_min_tmp);

                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i-1][j]*Te[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                }
            }     
        }

        //左 壁 z0
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = rhoUex[i][j];
        }
        //左 壁 z1
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = rhoUex[i][j];
        }
        //左 壁 z2
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = rhoUex[i][j];
        }
        //左 壁 z4
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = rhoUex[i][j];
        }
        //右 壁 z3
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i+1][j] =  rhoUex[i+1][j];
        }
        //右 壁 z5
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i+1][j] =  rhoUex[i+1][j];
        }

        //nUer更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx_Lr + r[j-1]*nUex_old_tmp[i][j-1]*bLx_Lr)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    //double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i][j-1]*Te[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                }
            }
        }

        //下 壁 x0
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j] = rhoUer[i][j];
        }
        //下 壁 x2
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j] = rhoUer[i][j];
        }

        //上 壁 x1
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j+1] = rhoUer[i][j+1];
        }
        //上 壁 x4
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j+1] = rhoUer[i][j+1];
        }
        //上 開放 x5
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            nUer[i][j+1] =  rhoUer[i][j+1];
        }

        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                    double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                    bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                    double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                    bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                    
                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    double nbRr1  = 1.0 - bRr1; //x5だけ
                    
                    bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double bRr_Rx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Rx = bRr_Rx*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                    bRr_Rx = bRr_Rx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double mu_min_Lx = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_min[i][j] + mu_min[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_min[i][j] + mu_min[i][j+1])/2.0*ratioY;

                    double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //境界条件
        //左 壁 z0 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //左 壁 z1 (値0)
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //左 壁 z2 (値0)
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //左 壁 z4 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //右 壁 z3 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //右 壁 z5 (値V_bias)
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //下 壁 x0 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //下 壁 x2 (値0)
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //上 壁 x1 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //上 壁 x4 (値0)
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //上 開放 x5 (値0)
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            aP[i][j] = aP[i][j] - aN[i][j];
            aN[i][j] = 0.0;
        }

        //solve
        if(icon_iter_phi == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }

        /********************* 更新 *******************/
         //左 壁 z0 (値0)
         for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z1 (値0)
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z2 (値0)
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z4 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //右 壁 z3 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //右 壁 z5 (値V_bias)
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //下 壁 x0 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //下 壁 x2 (値0)
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //上 壁 x1 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //上 壁 x4 (値0)
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //上 開放 x5 (値0)
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            dphi[i][j+1] = dphi[i][j];
        }

        //dnUexを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //左 壁 z0 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z1 (値0)
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z2 (値0)
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z4 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //右 壁 z3 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //右 壁 z5 (値V_bias)
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //下 壁 x0 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //下 壁 x2 (値0)
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //上 壁 x1 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //上 壁 x4 (値0)
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //上 開放 x5 (値0)
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            dphi[i][j+1] = dphi[i][j];
        }

        //dnUerを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //電場更新
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //左 壁 z0 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //左 壁 z1 (値0)
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //左 壁 z2 (値0)
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //左 壁 z4 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //右 壁 z3 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
        Ex[i+1][j] =  - (phi[i+1][j]-phi[i][j])/dx;
    }
    //右 壁 z5 (値V_bias)
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        phi[i+1][j] = 2.0*V_bias - phi[i][j];
        Ex[i+1][j] =  - (phi[i+1][j]-phi[i][j])/dx;
    }

    //電場更新
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }

    //下 壁 x0 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        phi[i][j-1] = - phi[i][j];
        Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
    }
    //下 壁 x2 (値0)
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        phi[i][j-1] = - phi[i][j];
        Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
    }

    //上 壁 x1 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        phi[i][j+1] = - phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //上 壁 x4 (値0)
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        phi[i][j+1] = - phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //上 開放 x5 (値0)
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        phi[i][j+1] = phi[i][j];
        Er[i][j+1] = 0.0; //- (phi[i][j+1]-phi[i][j])/dr;
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_wdTe_wSEE_PC_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------

    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];

            //nUex_old[i][j] = rhoUex_old[i][j];
            //nUer_old[i][j] = rhoUer_old[i][j];
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            dphi[i][j] = phi[i][j]-phi_old[i][j];
        }
    }
    //------------------------------------

    //set BCs for PC method
    //=====================================================================
    //left-wall-BC (z0) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //left-wall-BC (z1) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //left-wall-BC (z2) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //left-wall-BC (z4) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //right-wall-BC (z3) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }
    //------------------------------------
    
    //right-wall-BC (z5) potential = V_bias
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        phi[i+1][j] = 2.0*V_bias - phi[i][j];
    }
    //------------------------------------


    //lower-wall-BC (x0) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        phi[i][j-1] = - phi[i][j];
    }
    //------------------------------------

    //lower-wall-BC (x2) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        phi[i][j-1] = - phi[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x1) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        phi[i][j+1] = - phi[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x4) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        phi[i][j+1] = - phi[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x5) grad(phi) = 0
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        phi[i][j+1] = phi[i][j];
    }
    //------------------------------------
    //=====================================================================

    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }
        //------------------------------------

        //Predict flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_rr_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_inv_xx_tmp = mu_rr_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface
                    //------------------------------------
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i-1][j]*Te[i-1][j])/dx;
                    //------------------------------------
                
                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRrD + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_star_tmp 
                        + mu_star_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            nUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            nUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //=====================================================================================

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_xx_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    
                    double mu_inv_rr_tmp = mu_xx_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface
                    //------------------------------------
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i][j-1]*Te[i][j-1])/dr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRxD + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_star_tmp 
                        + mu_star_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                    //------------------------------------
  
                }
            }
        }
        //------------------------------------

        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            nUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            nUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            nUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            nUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            nUer[i][j+1] =  Gamma_open_Rr;
        }
        //------------------------------------

        //Make coefficient for Poisson equation for 5 point stencil
        //==============================================
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j] + mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j] + mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron density at cell interface
                    //------------------------------------
                    double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall, open, or central axis BC
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------
                    //==============================================

                    //coefficient for Poisson equation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_star_Rx*bRx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_star_Lx*bLx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_star_Rr*bRr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_star_Lr*bLr)
                                )*dx*dx;

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_star_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_star_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_star_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_star_Lr*bLr)*dx*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    double lapPhi =  (   phi_old_tmp[i+1][j] -       2.0*phi_old_tmp[i][j] +    phi_old_tmp[i-1][j])/(dx*dx) 
                                   + (qR*phi_old_tmp[i][j+1] - (qR + qL)*phi_old_tmp[i][j] + qL*phi_old_tmp[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                    //------------------------------------
                }
            }
        }
        //==============================================

        //Set boundary condition
        //==============================================
        //left-wall-BC (z0) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            //modify coefficient
            //------------------------------------
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //left-wall-BC (z1) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //------------------------------------

        //left-wall-BC (z2) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //------------------------------------

        //left-wall-BC (z4) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //------------------------------------

        //right-wall-BC (z3) continuity potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //------------------------------------

        //right-wall-BC (z5) continuity potential = V_bias
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //------------------------------------

        //lower-wall-BC (x0) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //------------------------------------

        //lower-wall-BC (x2) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //------------------------------------

        //upper-wall-BC (x1) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //------------------------------------

        //upper-wall-BC (x4) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //------------------------------------

        //upper-open-BC (x5) grad(phi) = 0
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            aP[i][j] = aP[i][j] - aN[i][j];
            aN[i][j] = 0.0;
        }
        //------------------------------------
        //==============================================

        //Solver
        //------------------------------------
        if(icon_iter_phi == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
            //------------------------------------
        }
        //------------------------------------

        //Reflect BCs for ghost cell
        //==============================================
        
        //set BCs for PC method
        //=====================================================================
        //left-wall-BC (z0) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //------------------------------------

        //left-wall-BC (z1) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //------------------------------------

        //left-wall-BC (z2) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //------------------------------------

        //left-wall-BC (z4) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //------------------------------------

        //right-wall-BC (z3) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //------------------------------------

        //right-wall-BC (z5) potential = V_bias
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //------------------------------------


        //lower-wall-BC (x0) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //------------------------------------

        //lower-wall-BC (x2) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //------------------------------------

        //upper-wall-BC (x1) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //------------------------------------

        //upper-wall-BC (x4) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //------------------------------------

        //upper-wall-BC (x5) grad(phi) = 0
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            dphi[i][j+1] = dphi[i][j];
        }
        //------------------------------------
        //=====================================================================

        //Correction
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    //------------------------------------
                    
                    //calculate flux correction
                    //------------------------------------
                    dnUex[i][j] = mu_star_tmp*rhoe_tmp*ddphidx;
                    //------------------------------------

                    //Update
                    //------------------------------------
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    dnUer[i][j] =  mu_star_tmp*rhoe_tmp*ddphidr;
                    //------------------------------------

                    //Update
                    //------------------------------------
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                    //------------------------------------
                }
            }
        }
        //------------------------------------
        
        //for phi
        //------------------------------------
        for(int i=0;i<=ni+1;i++){
            for(int j=0;j<=nj+1;j++){
                phi[i][j] = phi[i][j] + dphi[i][j];
            }
        }
        //------------------------------------
        //==============================================
        
        //Caluculate residuals
        //=====================================================================================
        //phi
        //------------------------------------
        double error_phi2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_phi = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_nUex2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_nUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }
        //------------------------------------

        //r-directional flux
        //------------------------------------
        double error_nUer2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_nUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        //------------------------------------
        //=====================================================================================
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //std::cout << "ncount_phi = "<<ncount<<std::endl;
    

    //Update Ex
    //------------------------------------
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }
    //------------------------------------

    
    //Reflect BCs for ghost cell and Update Electric field
    //=====================================================================
    //left-wall-BC (z0) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //left-wall-BC (z1) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //left-wall-BC (z2) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //left-wall-BC (z4) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        phi[i-1][j] = - phi[i][j];
        Ex[i][j] =  - (phi[i][j]-phi[i-1][j])/dx;
    }
    //------------------------------------

    //right-wall-BC (z3) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
        Ex[i+1][j] =  - (phi[i+1][j]-phi[i][j])/dx;
    }
    //------------------------------------
    
    //right-wall-BC (z5) potential = V_bias
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        phi[i+1][j] = 2.0*V_bias - phi[i][j];
        Ex[i+1][j] =  - (phi[i+1][j]-phi[i][j])/dx;
    }
    //------------------------------------

    //Update Er
    //------------------------------------
    for (int iblock=0;iblock<n_bl-1;iblock++){
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
    //------------------------------------

    //lower-wall-BC (x0) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        phi[i][j-1] = - phi[i][j];
        Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
    }
    //------------------------------------

    //lower-wall-BC (x2) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        phi[i][j-1] = - phi[i][j];
        Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
    }
    //------------------------------------

    //upper-wall-BC (x1) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        phi[i][j+1] = - phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //------------------------------------

    //upper-wall-BC (x4) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        phi[i][j+1] = - phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //------------------------------------

    //upper-open-BC (x5) grad(phi) = 0
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        phi[i][j+1] = phi[i][j];
        Er[i][j+1] = - (phi[i][j+1]-phi[i][j])/dr;
    }
    //------------------------------------
    
    //Caluculate residuals
    //=====================================================================================
    //phi
    //------------------------------------
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j],2)+1e-12)/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }


}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_wdTe_wSEE_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    std::vector<std::vector<double> > Ex_old(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Er_old(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------

    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            phi_old[i][j] = phi[i][j];
            Ex_old[i][j] = Ex[i][j];
            Er_old[i][j] = Er[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];

            //nUex_old[i][j] = rhoUex_old[i][j];
            //nUer_old[i][j] = rhoUer_old[i][j];
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            dphi[i][j] = phi[i][j]-phi_old[i][j];
        }
    }
    //------------------------------------

    //set BCs for PC method
    //=====================================================================
    //left-wall-BC (z0) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //left-wall-BC (z1) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //left-wall-BC (z2) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //left-wall-BC (z4) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        phi[i-1][j] = - phi[i][j];
    }
    //------------------------------------

    //right-wall-BC (z3) potential = 0
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }
    //------------------------------------
    
    //right-wall-BC (z5) potential = V_bias
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        phi[i+1][j] = 2.0*V_bias - phi[i][j];
    }
    //------------------------------------


    //lower-wall-BC (x0) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        phi[i][j-1] = - phi[i][j];
    }
    //------------------------------------

    //lower-wall-BC (x2) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        phi[i][j-1] = - phi[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x1) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        phi[i][j+1] = - phi[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x4) potential = 0
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        phi[i][j+1] = - phi[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x5) grad(phi) = 0
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        phi[i][j+1] = phi[i][j];
    }
    //------------------------------------
    //=====================================================================

    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }
        //------------------------------------

        //Predict flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_rr_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_inv_xx_tmp = mu_rr_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface
                    //------------------------------------
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dpedx = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i-1][j]*Te[i-1][j])/dx;
                    //------------------------------------
                
                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRrD + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_star_tmp 
                        + mu_star_tmp*(rhoe_tmp*dphidx - dpedx/e0);
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex_old[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex_old[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex_old[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex_old[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            nUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex_old[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            nUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex_old[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            nUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //=====================================================================================

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_xx_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    
                    double mu_inv_rr_tmp = mu_xx_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface
                    //------------------------------------
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dpedr = Boltz*(rhoe[i][j]*Te[i][j] - rhoe[i][j-1]*Te[i][j-1])/dr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRxD + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_star_tmp 
                        + mu_star_tmp*(rhoe_tmp*dphidr - dpedr/e0);
                    //------------------------------------
  
                }
            }
        }
        //------------------------------------

        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er_old[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            nUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er_old[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            nUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er_old[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            nUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er_old[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            nUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            nUer[i][j+1] =  Gamma_open_Rr;
        }
        //------------------------------------

        //Make coefficient for Poisson equation for 5 point stencil
        //==============================================
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j] + mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j] + mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron density at cell interface
                    //------------------------------------
                    double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall, open, or central axis BC
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------
                    //==============================================

                    //coefficient for Poisson equation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_star_Rx*bRx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_star_Lx*bLx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_star_Rr*bRr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_star_Lr*bLr)
                                )*dx*dx;

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_star_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_star_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_star_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_star_Lr*bLr)*dx*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    double lapPhi =  -(Ex[i+1][j] - Ex[i][j])/dx - (qR*Er[i][j+1] - qL*Er[i][j])/dr;
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                    //------------------------------------
                }
            }
        }
        //==============================================

        //Set boundary condition
        //==============================================
        //left-wall-BC (z0) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            //modify coefficient
            //------------------------------------
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //left-wall-BC (z1) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //------------------------------------

        //left-wall-BC (z2) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //------------------------------------

        //left-wall-BC (z4) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //------------------------------------

        //right-wall-BC (z3) continuity potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //------------------------------------

        //right-wall-BC (z5) continuity potential = V_bias
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //------------------------------------

        //lower-wall-BC (x0) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //------------------------------------

        //lower-wall-BC (x2) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //------------------------------------

        //upper-wall-BC (x1) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //------------------------------------

        //upper-wall-BC (x4) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //------------------------------------

        //upper-open-BC (x5) grad(phi) = 0
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            aP[i][j] = aP[i][j] - aN[i][j];
            aN[i][j] = 0.0;
        }
        //------------------------------------
        //==============================================

        //Solver
        //------------------------------------
        if(icon_iter_phi == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
            //------------------------------------
        }
        //------------------------------------

        //Reflect BCs for ghost cell
        //==============================================
        
        //set BCs for PC method
        //=====================================================================
        //left-wall-BC (z0) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
            Ex[i][j] = Ex[i][j] - (dphi[i][j]-dphi[i-1][j])/dx;
        }
        //------------------------------------

        //left-wall-BC (z1) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            dphi[i-1][j] = - dphi[i][j];
            Ex[i][j] = Ex[i][j] - (dphi[i][j]-dphi[i-1][j])/dx;
        }
        //------------------------------------

        //left-wall-BC (z2) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            dphi[i-1][j] = - dphi[i][j];
            Ex[i][j] = Ex[i][j] - (dphi[i][j]-dphi[i-1][j])/dx;
        }
        //------------------------------------

        //left-wall-BC (z4) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            dphi[i-1][j] = - dphi[i][j];
            Ex[i][j] = Ex[i][j] - (dphi[i][j]-dphi[i-1][j])/dx;
        }
        //------------------------------------

        //right-wall-BC (z3) potential = 0
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            dphi[i+1][j] = - dphi[i][j];
            Ex[i+1][j] = Ex[i+1][j] - (dphi[i+1][j]-dphi[i][j])/dx;
        }
        //------------------------------------

        //right-wall-BC (z5) potential = V_bias
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            dphi[i+1][j] = - dphi[i][j];
            Ex[i+1][j] = Ex[i+1][j] - (dphi[i+1][j]-dphi[i][j])/dx;
        }
        //------------------------------------


        //lower-wall-BC (x0) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            dphi[i][j-1] = - dphi[i][j];
            Er[i][j] = Er[i][j] - (dphi[i][j]-dphi[i][j-1])/dr;
        }
        //------------------------------------

        //lower-wall-BC (x2) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            dphi[i][j-1] = - dphi[i][j];
            Er[i][j] = Er[i][j] - (dphi[i][j]-dphi[i][j-1])/dr;
        }
        //------------------------------------

        //upper-wall-BC (x1) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            dphi[i][j+1] = - dphi[i][j];
            Er[i][j+1] = Er[i][j+1] - (dphi[i][j+1]-dphi[i][j])/dr;
        }
        //------------------------------------

        //upper-wall-BC (x4) potential = 0
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            dphi[i][j+1] = - dphi[i][j];
            Er[i][j+1] = Er[i][j+1] - (dphi[i][j+1]-dphi[i][j])/dr;
        }
        //------------------------------------

        //upper-open-BC (x5) grad(phi) = 0
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            dphi[i][j+1] = dphi[i][j];
            Er[i][j+1] = 0.0;
        }
        //------------------------------------
        //=====================================================================

        //Correction
        //==============================================
        //for phi
        //------------------------------------
        for(int i=0;i<=ni+1;i++){
            for(int j=0;j<=nj+1;j++){
                phi[i][j] = phi[i][j] + dphi[i][j];
            }
        }
        //------------------------------------

        //Update Ex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
                }
            }
        }
        //------------------------------------

        //Update Er
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
                }
            }
        }
        //------------------------------------

        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    //------------------------------------
                    
                    //calculate flux correction
                    //------------------------------------
                    dnUex[i][j] = mu_star_tmp*rhoe_tmp*ddphidx;
                    //------------------------------------

                    //Update
                    //------------------------------------
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double rhoe_tmp = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    dnUer[i][j] =  mu_star_tmp*rhoe_tmp*ddphidr;
                    //------------------------------------

                    //Update
                    //------------------------------------
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                    //------------------------------------
                }
            }
        }
        //------------------------------------
        
        
        //==============================================
        
        //Caluculate residuals
        //=====================================================================================
        //phi
        //------------------------------------
        double error_phi2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_phi = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_nUex2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_nUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }
        //------------------------------------

        //r-directional flux
        //------------------------------------
        double error_nUer2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_nUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        //------------------------------------
        //=====================================================================================
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //std::cout << "ncount_phi = "<<ncount<<std::endl;
    
    //Caluculate residuals
    //=====================================================================================
    //phi
    //------------------------------------
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j],2)+1e-12)/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }


}


//*****************************************************************
//**                                                             **
//**           double func_g1                                    **
//**                                                             **
//*****************************************************************
double func_g1(double z,double lim_exp){
    double deno = pow(exp(fmin(z,lim_exp)) - 1.0,2);
    double nume = (1.0 - z)*exp(fmin(z,lim_exp)) - 1.0;

    return nume/deno;
}

//*****************************************************************
//**                                                             **
//**           double func_g2                                    **
//**                                                             **
//*****************************************************************
double func_g2(double z,double lim_exp){
    double deno = pow(exp(fmin(z,lim_exp)) - 1.0,2);
    double nume = exp(fmin(z,lim_exp))*(exp(fmin(z,lim_exp)) - (1.0 + z));

    return nume/deno;
}

//*****************************************************************
//**                                                             **
//**           double func_h                                     **
//**                                                             **
//*****************************************************************
double func_h(double z,double lim_exp){
    double deno = pow(exp(fmin(z,lim_exp)) - 1.0,2);
    double nume = z*z*exp(fmin(z,lim_exp));

    return nume/deno;
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_SG_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j] - phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    //左 壁 z0 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }
    //左 壁 z1 (値0)
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        phi[i-1][j] = - phi[i][j];
    }
    //左 壁 z2 (値0)
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        phi[i-1][j] = - phi[i][j];
    }
    //左 壁 z4 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        phi[i-1][j] = - phi[i][j];
    }
    //右 壁 z3 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }
    //右 壁 z5 (値V_bias)
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        phi[i+1][j] = 2.0*V_bias - phi[i][j];
    }

    //下 壁 x0 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        phi[i][j-1] = - phi[i][j];
    }
    //下 壁 x2 (値0)
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        phi[i][j-1] = - phi[i][j];
    }

    //上 壁 x1 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        phi[i][j+1] = - phi[i][j];
    }
    //上 壁 x4 (値0)
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        phi[i][j+1] = - phi[i][j];
    }
    //上 開放 x5 (値0)
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        phi[i][j+1] = phi[i][j];
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2


                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    //double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    //double nbRr1  = 1.0 - bRr1; //x5だけ
                    //bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    //bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr_Lx + rL*nUer_old_tmp[i-1][j]*bLr_Lx)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Ex[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;

                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_min_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_min_tmp);

                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i-1][j];
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dndx = (rhoe[i][j] - rhoe[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx 
                                - Boltz*Te_tmp/e0*func_h(z_tmp,lim_exp)*dndx);
                }
            }     
        }

        //nUer更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5


                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx_Lr + r[j-1]*nUex_old_tmp[i][j-1]*bLx_Lr)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Er[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;
                    
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_min_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_min_tmp);
                    
                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i][j-1];
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dndr = (rhoe[i][j] - rhoe[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr 
                            - Boltz*Te_tmp/e0*func_h(z_tmp,lim_exp)*dndr);
                }
            }
        }

        //左 壁 z0
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //左 壁 z1
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //左 壁 z2
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //左 壁 z4
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //右 壁 z3
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //右 壁 z5
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }

        //下 壁 x0
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //下 壁 x2
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }

        //上 壁 x1
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //上 壁 x4
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //nUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            nUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //上 開放 x5
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            nUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
        }

        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                    double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                    bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                    double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                    bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                    
                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    double nbRr1  = 1.0 - bRr1; //x5だけ
                    
                    bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double bRr_Rx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Rx = bRr_Rx*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                    bRr_Rx = bRr_Rx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double mu_min_Lx = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_min[i][j] + mu_min[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_min[i][j] + mu_min[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j] + Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j] + Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j] + Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j] + Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx  = vd_Lx*dx/D_Lx;
                    double z_Rx  = vd_Rx*dx/D_Rx;
                    double z_Lr  = vd_Lr*dr/D_Lr;
                    double z_Rr  = vd_Rr*dr/D_Rr;

                    double rhoe_Lx = func_g1(z_Lx,lim_exp)*rhoe[i  ][j  ] - func_g2(z_Lx,lim_exp)*rhoe[i-1][j  ];
                    double rhoe_Rx = func_g1(z_Rx,lim_exp)*rhoe[i+1][j  ] - func_g2(z_Rx,lim_exp)*rhoe[i  ][j  ];
                    double rhoe_Lr = func_g1(z_Lr,lim_exp)*rhoe[i  ][j  ] - func_g2(z_Lr,lim_exp)*rhoe[i  ][j-1];
                    double rhoe_Rr = func_g1(z_Rr,lim_exp)*rhoe[i  ][j+1] - func_g2(z_Rr,lim_exp)*rhoe[i  ][j  ];

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //境界条件
        //左 壁 z0 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //左 壁 z1 (値0)
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //左 壁 z2 (値0)
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //左 壁 z4 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }
        //右 壁 z3 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //右 壁 z5 (値V_bias)
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }
        //下 壁 x0 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //下 壁 x2 (値0)
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }
        //上 壁 x1 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //上 壁 x4 (値0)
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }
        //上 開放 x5 (値0)
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            aP[i][j] = aP[i][j] - aN[i][j];
            aN[i][j] = 0.0;
        }

        //solve
        if(icon_iter_phi == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }

        //左 壁 z0 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z1 (値0)
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z2 (値0)
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //左 壁 z4 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            dphi[i-1][j] = - dphi[i][j];
        }
        //右 壁 z3 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //右 壁 z5 (値V_bias)
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            dphi[i+1][j] = - dphi[i][j];
        }
        //下 壁 x0 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //下 壁 x2 (値0)
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            dphi[i][j-1] = - dphi[i][j];
        }
        //上 壁 x1 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //上 壁 x4 (値0)
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            dphi[i][j+1] = - dphi[i][j];
        }
        //上 開放 x5 (値0)
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            dphi[i][j+1] = dphi[i][j];
        }

        /********************* 更新 *******************/
        //dnUexを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Ex[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;
                    
                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i-1][j];
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //dnUerを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Er[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;
                    
                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i][j-1];
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }

        //電位更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    phi[i][j] = phi[i][j] + dphi[i][j];
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //左壁境界1 (値0)
     for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
}


//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_SG_PC_new(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUex(ni+2,std::vector<double>(nj+2,0.0));
    //std::vector<std::vector<double> > nUer(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > nUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dphi(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dnUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 1;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            dphi[i][j] = phi[i][j] - phi_old[i][j];
            
            //SGフラックスから予測
            //nUex[i][j] = rhoUex[i][j];
            //nUer[i][j] = rhoUer[i][j];

            phi_old[i][j] = phi[i][j];
            nUex_old[i][j] = nUex[i][j];
            nUer_old[i][j] = nUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                phi_old_tmp[i][j] = phi[i][j];
                nUex_old_tmp[i][j] = nUex[i][j];
                nUer_old_tmp[i][j] = nUer[i][j];
            }
        }

        //nUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //nUerの補間 (壁上のフラックスはゼロ)
                    double nUer_tmp = (rR*nUer_old_tmp[i][j+1]*bRr + rL*nUer_old_tmp[i][j]*bLr
                        + rR*nUer_old_tmp[i-1][j+1]*bRr + rL*nUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Ex[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;

                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i-1][j];
                    double dphidx = (phi[i][j] - phi[i-1][j])/dx;
                    double dndx = (rhoe[i][j] - rhoe[i-1][j])/dx;

                    nUex[i][j] = nUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*nUex_old_tmp[i][j] + mu_inv_xr_tmp*nUer_tmp)*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidx 
                                - Boltz*Te_tmp/e0*func_h(z_tmp,lim_exp)*dndx);
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    //if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                    //    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    nUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi_old[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    //nUex[i][j] = nUex_old[i+1][j];
                    //}
                    ////右はイオンフラックスと同じ
                    //if(i==i_flc_bl[1][1]+1){
                    //    nUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    //    //nUex[i][j] = nUex_old[i-1][j];
                    //}
                }
            }     
        }

        //左 壁1
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            nUex[i][j] = nUex[i+1][j];
        }
        //左 壁2
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            nUex[i][j] = nUex[i+1][j];
        }
        //右 壁
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            //nUex[i+1][j] = nUex[i][j];
            nUex[i+1][j] =  rhoi[i][j]*Uix[i+1][j];
        }

        //nUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //nUexの補間 (壁上のフラックスはゼロ)
                    double nUex_tmp = (r[j]*nUex_old_tmp[i+1][j]*bRx + r[j]*nUex_old_tmp[i][j]*bLx 
                        + r[j-1]*nUex_old_tmp[i+1][j-1]*bRx + r[j-1]*nUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Er[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;
                    
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
                    
                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i][j-1];
                    double dphidr = (phi[i][j] - phi[i][j-1])/dr;
                    double dndr = (rhoe[i][j] - rhoe[i][j-1])/dr;

                    nUer[i][j] =  nUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*nUex_tmp + mu_inv_rr_tmp*nUer_old_tmp[i][j])*mu_min_tmp 
                        + mu_min_tmp*(rhoe_tmp*dphidr 
                            - Boltz*Te_tmp/e0*func_h(z_tmp,lim_exp)*dndr);
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    //if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    
                    //    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    //    nUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi_old[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    //    //nUer[i][j] = rR/rL*nUer_old[i][j+1];
                    //}
                    ////上はイオンフラックスと同じ
                    //if(j==j_flc_bl[1][1]+1){
                    //    double rL = (r[j]+r[j-1])/2.0;
                    //    double rR = (r[j]+r[j+1])/2.0;
                    //    nUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    //    //nUer[i][j] = rL/rR*nUer_old[i][j-1];
                    //}
                }
            }
        }

        //下 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;
            nUer[i][j] = rR/rL*nUer[i][j+1];
        }
        //上 壁
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[0][1];
            double rL = (r[j]+r[j-1])/2.0;
            double rR = (r[j]+r[j+1])/2.0;
            //nUer[i][j+1] = rL/rR*nUer[i][j-1];
            nUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double mu_min_Lx = (mu_perp[i][j]*(1.0 + nbLx) + mu_perp[i-1][j]*bLx)/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]*(1.0 + nbRx) + mu_perp[i+1][j]*bRx)/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]*(1.0 + nbLr) + mu_perp[i][j-1]*bLr)/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]*(1.0 + nbRr) + mu_perp[i][j+1]*bRr)/2.0*ratioY;

                    double Te_Lx = (Te[i][j]*(1.0 + nbLx) + Te[i-1][j]*bLx)/2.0;
                    double Te_Rx = (Te[i][j]*(1.0 + nbRx) + Te[i+1][j]*bRx)/2.0;
                    double Te_Lr = (Te[i][j]*(1.0 + nbLr) + Te[i][j-1]*bLr)/2.0;
                    double Te_Rr = (Te[i][j]*(1.0 + nbRr) + Te[i][j+1]*bRr)/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx  = vd_Lx*dx/D_Lx;
                    double z_Rx  = vd_Rx*dx/D_Rx;
                    double z_Lr  = vd_Lr*dr/D_Lr;
                    double z_Rr  = vd_Rr*dr/D_Rr;

                    double rhoe_Lx = func_g1(z_Lx,lim_exp)*rhoe[i  ][j  ]*(1.0 + nbLx) - func_g2(z_Lx,lim_exp)*rhoe[i-1][j  ]*bLx;
                    double rhoe_Rx = func_g1(z_Rx,lim_exp)*rhoe[i+1][j  ]*bRx          - func_g2(z_Rx,lim_exp)*rhoe[i  ][j  ]*(1.0 + nbRx);
                    double rhoe_Lr = func_g1(z_Lr,lim_exp)*rhoe[i  ][j  ]*(1.0 + nbLr) - func_g2(z_Lr,lim_exp)*rhoe[i  ][j-1]*bLr;
                    double rhoe_Rr = func_g1(z_Rr,lim_exp)*rhoe[i  ][j+1]*bRr          - func_g2(z_Rr,lim_exp)*rhoe[i  ][j  ]*(1.0 + nbRr);

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =  (    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx) 
                                 +   (eps0 + e0*dt*rhoe_Lx*mu_min_Lx)
                                )*dr*dr 
                              + ( qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr) 
                                + qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr)
                                )*dx*dx
                              + dx*dx*dr*dr/dtau*double(icon_dtau); //擬似時間項

                    aE[i][j] =    (eps0 + e0*dt*rhoe_Rx*mu_min_Rx*bRx)*dr*dr;
                    aW[i][j] =    (eps0 + e0*dt*rhoe_Lx*mu_min_Lx*bLx)*dr*dr;
                    aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_min_Rr*bRr)*dx*dx;
                    aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_min_Lr*bLr)*dx*dx;

                    //double nabla_nUe_tmp = (nUex[i+1][j]*bRx - nUex[i][j]*bLx)/dx + (qR*nUer[i][j+1]*bRr - qL*nUer[i][j]*bLr)/dr;
                    double nabla_nUe_tmp = (nUex[i+1][j]-nUex[i][j])/dx + (qR*nUer[i][j+1]-qL*nUer[i][j])/dr;
                    //double lapPhi =  (   phi[i+1][j]*bRx -       (bRx + bLx)*phi[i][j] +    phi[i-1][j]*bLx)/(dx*dx) 
                    //               + (qR*phi[i][j+1]*bRr - (qR*bRr + qL*bLr)*phi[i][j] + qL*phi[i][j-1]*bLr)/(dr*dr);
                    double lapPhi =  (   phi[i+1][j] -       2.0*phi[i][j] +    phi[i-1][j])/(dx*dx) 
                                   + (qR*phi[i][j+1] - (qR + qL)*phi[i][j] + qL*phi[i][j-1])/(dr*dr);
                    
                    b[i][j] = (  e0*rhoi[i][j] - e0*rhoe[i][j] //rhoeはまだ更新されていないのでrhoe_oldでなくrhoeを使う
                               - e0*dt*rate_ionize[i][j] 
                               + eps0*lapPhi + e0*dt*nabla_nUe_tmp
                              )*dx*dx*dr*dr;
                }
            }
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            aP[i][j] = aP[i][j] + aW[i][j];
            aW[i][j] = 0.0;
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aE[i][j];
            aE[i][j] = 0.0;
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            aP[i][j] = aP[i][j] + aS[i][j];
            aS[i][j] = 0.0;
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            aP[i][j] = aP[i][j] + aN[i][j];
            aN[i][j] = 0.0;
        }

        //solve
        if(icon_iter_phi == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,dphi);
        }

        //左壁境界1 (値0)
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i = i_flc_bl[0][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //左壁境界2 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
            int i = i_flc_bl[1][0];
            dphi[i-1][j] = - dphi[i][j];
        }

        //右開放境界 (値0)
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i = i_flc_bl[1][1];
            dphi[i+1][j] = -dphi[i][j];
        }

        //下壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
            int j = j_flc_bl[0][0];
            //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
            dphi[i][j-1] = - dphi[i][j];
        }

        //上壁境界 (値0)
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
            int j = j_flc_bl[1][1];
            dphi[i][j+1] = - dphi[i][j];
        }

        /********************* 更新 *******************/
        //dnUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Ex[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;
                    
                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i-1][j];
                    double ddphidx = (dphi[i][j] - dphi[i-1][j])/dx;
                    
                    dnUex[i][j] = mu_min_tmp*rhoe_tmp*ddphidx;
                }
            }
        }

        //dnUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp  = Boltz*Te_tmp/e0*mu_min_tmp;
                    double vd_tmp  = mu_min_tmp* (-Er[i  ][j  ]) + EPS;
                    double z_tmp  = vd_tmp*dx/D_tmp;
                    
                    double rhoe_tmp = func_g1(z_tmp,lim_exp)*rhoe[i][j] - func_g2(z_tmp,lim_exp)*rhoe[i][j-1];
                    double ddphidr = (dphi[i][j] - dphi[i][j-1])/dr;

                    dnUer[i][j] =  mu_min_tmp*rhoe_tmp*ddphidr;
                }
            }
        }

        //電位更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    phi[i][j] = phi[i][j] + dphi[i][j];
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    nUex[i][j] = nUex[i][j] + dnUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    nUer[i][j] = nUer[i][j] + dnUer[i][j];
                }
            }
        }

        //エラー計算
        double error_phi2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((phi[i][j]-phi_old_tmp[i][j])/(phi[i][j]+phi_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_phi2){
                            error_phi2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_phi = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_phi2 += pow(phi[i][j]-phi_old_tmp[i][j],2)/(pow(phi_old_tmp[i][j]+1e-6,2));
                        ncount_phi++;
                    }
                }
            }
            error_phi2 = sqrt(error_phi2/double(ncount_phi));
        }

        double error_nUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_nUex_tmp = fabs((nUex[i][j]-nUex_old_tmp[i][j])/(nUex[i][j]+nUex_old_tmp[i][j]+1e-100));
                        if(error_nUex_tmp > error_nUex2){
                            error_nUex2 = error_nUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_nUex2 += pow(nUex[i][j]-nUex_old_tmp[i][j],2)/(pow(nUex_old_tmp[i][j]+1e16,2));
                        ncount_nUex++;
                    }
                }
            }
            error_nUex2 = sqrt(error_nUex2/double(ncount_nUex));
        }

        double error_nUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_nUer_tmp = fabs((nUer[i][j]-nUer_old_tmp[i][j])/(nUer[i][j]+nUer_old_tmp[i][j]+1e-100));
                        if(error_nUer_tmp > error_nUer2){
                            error_nUer2 = error_nUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_nUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_nUer2 += pow(nUer[i][j]-nUer_old_tmp[i][j],2)/(pow(nUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_nUer++;
                    }
                }
            }
            error_nUer2 = sqrt(error_nUer2/double(ncount_nUer));
        }
        
        double error_global = fmax(fmax(error_phi2,error_nUex2),error_nUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_phi = " << error_phi2
                <<  " error_nUex = " << error_nUex2
                <<  " error_nUer= " << error_nUer2
                <<  " error_max = " << fmax(fmax(error_phi2,error_nUex2),error_nUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_phi || ncount >= maxITR_HES_phi){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_phi = "<<ncount<<std::endl;

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }

    //********** 境界条件回復 + 電場計算 ***************
    //左壁境界1 (値0)
     for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_directional(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    
    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            phi_old[i][j] = phi[i][j];
        }
    }

    double ratio = 1.0;
    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;
                double Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                double Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                double Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                double Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;

                double mu_Lx = Cx_Lx*(mu_para[i][j] + mu_para[i-1][j])/2.0*ratio;
                double mu_Rx = Cx_Rx*(mu_para[i][j] + mu_para[i+1][j])/2.0*ratio;
                double mu_Lr = Cr_Lr*(mu_para[i][j] + mu_para[i][j-1])/2.0*ratio;
                double mu_Rr = Cr_Rr*(mu_para[i][j] + mu_para[i][j+1])/2.0*ratio;

                aP[i][j] = ((eps0 + e0*dt*rhoe_Rx*mu_Rx) + (eps0 + e0*dt*rhoe_Lx*mu_Lx))*dr*dr 
                    + (qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr) + qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr))*dx*dx;
                aE[i][j] = (eps0 + e0*dt*rhoe_Rx*mu_Rx)*dr*dr;
                aW[i][j] = (eps0 + e0*dt*rhoe_Lx*mu_Lx)*dr*dr;
                aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr)*dx*dx;
                aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr)*dx*dx;

                double lapPhi = ((rhoe_Rx*mu_Rx)*phi[i+1][j] 
                    - ((rhoe_Rx*mu_Rx) + (rhoe_Lx*mu_Lx))*phi[i][j] 
                    + (rhoe_Lx*mu_Lx)*phi[i-1][j])/(dx*dx) 
                    + ((qR*rhoe_Rr*mu_Rr)*phi[i][j+1]
                    -  ((qR*rhoe_Rr*mu_Rr) + (qL*rhoe_Lr*mu_Lr))*phi[i][j]
                    +  (qL*rhoe_Lr*mu_Lr)*phi[i][j-1])/(dr*dr);

                b[i][j] = (e0*rhoi[i][j] - e0*(2.0*rhoe[i][j] - rhoe_old[i][j]) - e0*dt*lapPhi)*dx*dx*dr*dr;
            }
        }   
    }

    //左壁境界1 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        aP[i][j] = aP[i][j] + aE[i][j];
        aE[i][j] = 0.0;
    }
    
    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        aP[i][j] = aP[i][j] + aS[i][j];
        aS[i][j] = 0.0;
    }

    //下中心境界
    //　処理なし

    //上開放境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        aP[i][j] = aP[i][j] + aN[i][j];
        aN[i][j] = 0.0;
    }

    if(icon_iter_phi==0){
        double alpha = 0.8;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
    }

    //double alpha = 0.01;
    //for (int iblock=0;iblock<2;iblock++){ 
    //    for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
    //        for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
    //            phi[i][j] = alpha*phi_new[i][j] + (1.0 - alpha)*phi_old[i][j];
    //        }
    //    }
    //}
    
    //左壁境界1 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j],2)+1e-12)/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_dieleOpen(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    
    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            phi_old[i][j] = phi[i][j];
        }
    }

    double ratio = 1.0;

    
    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;
                double mu_Lx = (mu_para[i][j] + mu_para[i-1][j])/2.0*ratio;
                double mu_Rx = (mu_para[i][j] + mu_para[i+1][j])/2.0*ratio;
                double mu_Lr = (mu_para[i][j] + mu_para[i][j-1])/2.0*ratio;
                double mu_Rr = (mu_para[i][j] + mu_para[i][j+1])/2.0*ratio;

                aP[i][j] = ((eps0 + e0*dt*rhoe_Rx*mu_Rx) + (eps0 + e0*dt*rhoe_Lx*mu_Lx))*dr*dr 
                    + (qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr) + qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr))*dx*dx;
                aE[i][j] = (eps0 + e0*dt*rhoe_Rx*mu_Rx)*dr*dr;
                aW[i][j] = (eps0 + e0*dt*rhoe_Lx*mu_Lx)*dr*dr;
                aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr)*dx*dx;
                aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr)*dx*dx;

                double lapPhi = ((rhoe_Rx*mu_Rx)*phi[i+1][j] 
                    - ((rhoe_Rx*mu_Rx) + (rhoe_Lx*mu_Lx))*phi[i][j] 
                    + (rhoe_Lx*mu_Lx)*phi[i-1][j])/(dx*dx) 
                    + ((qR*rhoe_Rr*mu_Rr)*phi[i][j+1]
                    -  ((qR*rhoe_Rr*mu_Rr) + (qL*rhoe_Lr*mu_Lr))*phi[i][j]
                    +  (qL*rhoe_Lr*mu_Lr)*phi[i][j-1])/(dr*dr);
                
                //表面電荷の電荷密度換算量
                double rhoq_sc = (scx[i][j]*2.0*M_PI*r[j]*dr + scr[i][j]*2.0*M_PI*rR*dx)/(2.0*M_PI*r[j]*dx*dr); 

                b[i][j] = (e0*rhoi[i][j] - e0*(2.0*rhoe[i][j] - rhoe_old[i][j]) + rhoq_sc - e0*dt*lapPhi)*dx*dx*dr*dr;
            }
        }   
    }

    //左壁境界1 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        aP[i][j] = aP[i][j] + aE[i][j];
        aE[i][j] = 0.0;
    }
    
    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        aP[i][j] = aP[i][j] + aS[i][j];
        aS[i][j] = 0.0;
    }

    //下中心境界
    //　処理なし

    //上開放境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        aP[i][j] = aP[i][j] + aN[i][j];
        aN[i][j] = 0.0;
    }

    if(icon_iter_phi==0){
        double alpha = 0.8;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
    }

    //double alpha = 0.01;
    //for (int iblock=0;iblock<2;iblock++){ 
    //    for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
    //        for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
    //            phi[i][j] = alpha*phi_new[i][j] + (1.0 - alpha)*phi_old[i][j];
    //        }
    //    }
    //}
    
    //左壁境界1 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j],2)+1e-12)/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_phi_couple_simple                         **
//**                                                             **
//*****************************************************************
void solve_phi_couple_direc(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > phi_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    
    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            phi_old[i][j] = phi[i][j];
        }
    }

    double ratio = 1.0;
    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                
                
                double rhoe_Lx = (rhoe[i][j] + rhoe[i-1][j])/2.0;
                double rhoe_Rx = (rhoe[i][j] + rhoe[i+1][j])/2.0;
                double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1])/2.0;
                double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1])/2.0;
                double mu_Lx = (mu_para[i][j] + mu_para[i-1][j])/2.0*ratio;
                double mu_Rx = (mu_para[i][j] + mu_para[i+1][j])/2.0*ratio;
                double mu_Lr = (mu_para[i][j] + mu_para[i][j-1])/2.0*ratio;
                double mu_Rr = (mu_para[i][j] + mu_para[i][j+1])/2.0*ratio;

                aP[i][j] = (eps0 + e0*dt*(Cx_Rx*rhoe_Rx + Cc_Rx*qR*rhoe_Rr - Cc_Rx*qL*rhoe_Lr))*dr*dr 
                    + (eps0 + e0*dt*(Cx_Lx*rhoe_Lx - Cc_Lx*qR*rhoe_Rr + Cc_Lx*qL*rhoe_Lr))*dr*dr
                    + qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr)*dx*dx 
                    + qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr)*dx*dx;

                aE[i][j] = (eps0 + e0*dt*rhoe_Rx*mu_Rx)*dr*dr;
                aW[i][j] = (eps0 + e0*dt*rhoe_Lx*mu_Lx)*dr*dr;
                aN[i][j] = qR*(eps0 + e0*dt*rhoe_Rr*mu_Rr)*dx*dx;
                aS[i][j] = qL*(eps0 + e0*dt*rhoe_Lr*mu_Lr)*dx*dx;

                double lapPhi = ((rhoe_Rx*mu_Rx)*phi[i+1][j] 
                    - ((rhoe_Rx*mu_Rx) + (rhoe_Lx*mu_Lx))*phi[i][j] 
                    + (rhoe_Lx*mu_Lx)*phi[i-1][j])/(dx*dx) 
                    + ((qR*rhoe_Rr*mu_Rr)*phi[i][j+1]
                    -  ((qR*rhoe_Rr*mu_Rr) + (qL*rhoe_Lr*mu_Lr))*phi[i][j]
                    +  (qL*rhoe_Lr*mu_Lr)*phi[i][j-1])/(dr*dr);

                b[i][j] = (e0*rhoi[i][j] - e0*(2.0*rhoe[i][j] - rhoe_old[i][j]) - e0*dt*lapPhi)*dx*dx*dr*dr;
            }
        }   
    }

    //左壁境界1 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        aP[i][j] = aP[i][j] + aW[i][j];
        aW[i][j] = 0.0;
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        aP[i][j] = aP[i][j] + aE[i][j];
        aE[i][j] = 0.0;
    }
    
    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        aP[i][j] = aP[i][j] + aS[i][j];
        aS[i][j] = 0.0;
    }

    //下中心境界
    //　処理なし

    //上開放境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        aP[i][j] = aP[i][j] + aN[i][j];
        aN[i][j] = 0.0;
    }

    if(icon_iter_phi==0){
        double alpha = 0.8;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,phi);
    }

    //double alpha = 0.01;
    //for (int iblock=0;iblock<2;iblock++){ 
    //    for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
    //        for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
    //            phi[i][j] = alpha*phi_new[i][j] + (1.0 - alpha)*phi_old[i][j];
    //        }
    //    }
    //}
    
    //左壁境界1 (値0)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        phi[i-1][j] = - phi[i][j];
    }

    //左壁境界2 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        phi[i-1][j] = - phi[i][j];
    }

    //右開放境界 (値0)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        phi[i+1][j] = -phi[i][j];
    }

    //電場更新 ※ 角の問題があるので早めに更新しておく．
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Ex[i][j] = - (phi[i][j]-phi[i-1][j])/dx;
            }
        }
    }

    //下壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        //phi[i][j-1] = - phi[i][j]*r[j]/r[j-1];
        phi[i][j-1] = - phi[i][j];
    }

    //下中心境界
    // 処理なし

    //上壁境界 (値0)
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[1][1];
        phi[i][j+1] = - phi[i][j];
    }

    //電場更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                Er[i][j] = - (phi[i][j]-phi[i][j-1])/dr;
            }
        }
    }

    //誤差を計算
    error_phi = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((phi[i][j] - phi_old[i][j])/(phi[i][j] + phi_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_phi){
                        error_phi = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_phi += pow(phi[i][j]-phi_old[i][j],2)/(pow(phi_old[i][j],2)+1e-12)/CFL;
                    ncount++;
                }
            }
        }
        error_phi = sqrt(error_phi/double(ncount));
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_direct(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new (ni+2,std::vector<double>(nj+2,0.0));
    

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字

    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                
                double Te_Lx  = (Te[i][j]   + Te[i-1][j]  )/2.0;
                double Te_LxU = (Te[i][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]   + Te[i+1][j]  )/2.0;
                double Te_RxU = (Te[i][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]   + Te[i][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j] + Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ]) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1]) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1]) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ]) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1]) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1]) + EPS;
                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ]) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ]) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ]) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1]) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1]) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1]) + EPS;

                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;

                double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                double bRx  = double(i!=i_flc_bl[1][1]);
                double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                double bRr  = double(j!=j_flc_bl[1][1]);

                //壁の接線方向の処理
                if(bLxD == 0 || bRx == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx == 0 || bRx == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLrD == 0 || bRr == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr == 0 || bRr == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }

                double nbLx  = 1.0 - bLx;
                double nbLr  = 1.0 - bLr;
                double nbRx  = 1.0 - bRx;
                double nbRr  = 1.0 - bRr;

                double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                aP[i][j] =      (    Cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   + Cc_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                   + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*Cr_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   + Cc_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - Cc_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                    + Cc_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - Cc_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                         + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                         + dx*dr/dt; //時間項
                aE[i][j] =   (Cx_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - Cc_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + Cc_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                             )*dr*bRx
                           + (Cc_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                           - (Cc_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (Cc_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (Cc_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] = (qR*Cr_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                           )*dx*bRr
                         + (qR*Cc_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                         - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] = (qL*Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                           )*dx*bLr
                    -  (qL*Cc_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                    +  (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                aEN[i][j] =   (Cc_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                            + (Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] = - (Cc_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                            - (Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] = - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                            - (Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] =   (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                            + (Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;

                b[i][j] = (
                    + rate_ionize[i][j] //陽的ソース項
                    + rhoe_old[i][j]/dt)*dx*dr
                    + (0.0
                          //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                      )*dr
                    - (
                        rhoi[i][j]*Uix[i+1][j]*nbRx //右壁境界
                      )*dr
                    + qL*(0.0
                          //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                      )*dx
                    - qR*(
                        rhoi[i][j]*Uir[i][j+1]*nbRr //上壁境界
                      )*dx;
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoe);
    }
    
    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }

    //電位境界用に入れておく
    //左 壁1
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }

    //左 壁2
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        rhoe[i-1][j] = 0.0;
    }

    //下 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }

    //右 壁
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoe[i+1][j] = rhoe[i][j];
    }

    //上 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoe[i][j+1] = rhoe[i][j];
    }

    //フラックス計算
    //rhoUexを計算
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){

                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;

                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;; //中心軸特別;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;; //中心軸特別;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_Lr  = (Te[i][j]  + Te[i][j-1]  )/2.0;
                double Te_LrD = (Te[i-1][j]+ Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]  + Te[i][j+1]  )/2.0;
                double Te_RrD = (Te[i-1][j]+ Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ]) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ]) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ]) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1]) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1]) + EPS;
                
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                
                //フラックス
                double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                double bRr  = double(j!=j_flc_bl[1][1]);
                
                //壁の接線方向の処理
                if(bLrD == 0 || bRr == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }

                rhoUex[i][j] 
                    = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                        - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoe[i-1][j]
                    - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoe[i][j+1]
                    + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1]
                    - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoe[i-1][j+1]
                    + (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoe[i-1][j-1];

                if(i==i_flc_bl[0][0]){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                }

                //左側の壁
                if(i==i_flc_bl[1][0] && j<=j_flc_bl[0][0]-1){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                }
                //右側の開放境界
                if(i==i_flc_bl[1][1]+1){
                    rhoUex[i][j] =  rhoi[i-1][j]*Uir[i][j];
                }
            }
        }
    }

    //rhoUerを計算
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){

                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_LxD = (Te[i][j-1]+Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]+Te[i+1][j])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ]) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1]) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ]) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1]) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ]) + EPS;

                double z_Lx = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr = vd_Lr*dr/D_Lr;

                double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                double bRx  = double(i!=i_flc_bl[1][1]);
                
                //壁の接線方向の処理
                if(bLxD == 0 || bRx == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }

                rhoUer[i][j] 
                    = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + Cc_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                       - Cc_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                       - Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoe[i][j-1]
                    - (Cc_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoe[i+1][j]
                    + (Cc_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j]
                    - (Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoe[i+1][j-1]
                    + (Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoe[i-1][j-1];

                //下側の壁
                if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                }

                //上側の開放境界
                if(j==j_flc_bl[1][1]+1){
                    rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                }
            }
        }
    }

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_direct_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new (ni+2,std::vector<double>(nj+2,0.0));
    

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字

    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                
                double Te_Lx  = (Te[i][j]   + Te[i-1][j]  )/2.0;
                double Te_LxU = (Te[i][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]   + Te[i+1][j]  )/2.0;
                double Te_RxU = (Te[i][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]   + Te[i][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j] + Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxU = (Te[i  ][j+1] - Te[i-1][j+1])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxU = (Te[i+1][j+1] - Te[i  ][j+1])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrU = (Te[i+1][j  ] - Te[i+1][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrU = (Te[i+1][j+1] - Te[i+1][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;

                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr*bRr1; //全部含む

                double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bRr_Rx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Rx = bRr_Rx*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                bRr_Rx = bRr_Rx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx_Rr == 0 || bRx_Rr == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLr_Lx == 0 || bRr_Lx == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr_Rx == 0 || bRr_Rx == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }

                /*
                //壁の接線方向の処理
                if(bLx == 0 || bRxD == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx == 0 || bRx == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLrD == 0 || bRrD == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr == 0 || bRr == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }
                */

                //if(nbRr1 == 1) test1[i][j] = 1.0;
                //if(nbRr == 1) test2[i][j] = 1.0;
                
                double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                aP[i][j] =      (    Cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   + Cc_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                   + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*Cr_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   + Cc_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - Cc_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                    + Cc_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - Cc_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         +    0.25*vth*exp(fmin(-e0*(-Ex[i  ][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                         +    0.25*vth*exp(fmin(-e0*( Ex[i+1][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx //陰的指定
                         + qL*0.25*vth*exp(fmin(-e0*(-Er[i  ][j  ]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                         + qR*0.25*vth*exp(fmin(-e0*( Er[i  ][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr //陰的指定
                         //+    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx
                         //+    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx
                         //+ qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr
                         //+ qR*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr
                         + dx*dr/dt; //時間項
                aE[i][j] =   (Cx_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - Cc_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + Cc_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                             )*dr*bRx
                           + (Cc_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                           - (Cc_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (Cc_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (Cc_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] = (qR*Cr_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                           )*dx*bRr
                         + (qR*Cc_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                         - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] = (qL*Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                           )*dx*bLr
                         - (qL*Cc_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                         + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                aEN[i][j] =   (Cc_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                            + (Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] = - (Cc_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                            - (Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] = - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                            - (Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] =   (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                            + (Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;

                b[i][j] = (
                    + rate_ionize[i][j] //陽的ソース項
                    + rhoe_old[i][j]/dt)*dx*dr
                    + (0.0
                          //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                      )*dr
                    - (0.0
                        //rhoi[i][j]*Uix[i+1][j]*nbRx //右壁境界
                      )*dr
                    + qL*(0.0
                          //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                      )*dx
                    - qR*(
                        rhoi[i][j]*Uir[i][j+1]*nbRr1 //上壁境界
                      )*dx;
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoe);
    }
    
    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }

    //フラックス計算
    //rhoUexを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;

                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_Lr  = (Te[i][j]  + Te[i][j-1]  )/2.0;
                double Te_LrD = (Te[i-1][j]+ Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]  + Te[i][j+1]  )/2.0;
                double Te_RrD = (Te[i-1][j]+ Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                
                //フラックス
                //double bLrD  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                //bLrD = bLrD*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //壁の接線方向の処理
                if(bLr_Lx == 0 || bRr_Lx == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }

                
                rhoUex[i][j] 
                    = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                        - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoe[i-1][j]
                    - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoe[i][j+1]
                    + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1]
                    - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoe[i-1][j+1]
                    + (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoe[i-1][j-1];
            }
        }
    }

    //rhoUerを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;;
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_LxD = (Te[i][j-1]+Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]+Te[i+1][j])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;

                double z_Lx = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr = vd_Lr*dr/D_Lr;

                //double bLxD  = double(i!=i_flc_bl[0][0]); //z0
                //bLxD = bLxD*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                //bLxD = bLxD*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                //bLxD = bLxD*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                //double bRxD  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                //bRxD = bRxD*double(i!=i_flc_bl[4][1]); //z5

                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                
                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }

                rhoUer[i][j] 
                    = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + Cc_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                       - Cc_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                       - Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoe[i][j-1]
                    - (Cc_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoe[i+1][j]
                    + (Cc_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j]
                    - (Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoe[i+1][j-1]
                    + (Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoe[i-1][j-1];
            }
        }
    }


    //電位境界用に入れておく
    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoe[i+1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoe[i+1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }

    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoe[i][j-1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoe[i][j+1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoe[i][j+1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        rhoe[i][j+1] = rhoe[i][j];
        rhoUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
    }


    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
}
//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_direct_old2(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new (ni+2,std::vector<double>(nj+2,0.0));
    

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字

    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                
                double Te_Lx  = (Te[i][j]   + Te[i-1][j]  )/2.0;
                double Te_LxU = (Te[i][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]   + Te[i+1][j]  )/2.0;
                double Te_RxU = (Te[i][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]   + Te[i][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j] + Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxU = (Te[i  ][j+1] - Te[i-1][j+1])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxU = (Te[i+1][j+1] - Te[i  ][j+1])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrU = (Te[i+1][j  ] - Te[i+1][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrU = (Te[i+1][j+1] - Te[i+1][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;

                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr*bRr1; //全部含む

                double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bRr_Rx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Rx = bRr_Rx*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                bRr_Rx = bRr_Rx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx_Rr == 0 || bRx_Rr == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLr_Lx == 0 || bRr_Lx == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr_Rx == 0 || bRr_Rx == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }

                /*
                //壁の接線方向の処理
                if(bLx == 0 || bRxD == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx == 0 || bRx == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLrD == 0 || bRrD == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr == 0 || bRr == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }
                */

                //if(nbRr1 == 1) test1[i][j] = 1.0;
                //if(nbRr == 1) test2[i][j] = 1.0;
                
                double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                aP[i][j] =      (    Cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   + Cc_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                   + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*Cr_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   + Cc_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - Cc_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                    + Cc_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - Cc_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         +    0.25*vth*exp(fmin(-e0*(-Ex[i  ][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                         +    0.25*vth*exp(fmin(-e0*( Ex[i+1][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx //陰的指定
                         + qL*0.25*vth*exp(fmin(-e0*(-Er[i  ][j  ]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                         + qR*0.25*vth*exp(fmin(-e0*( Er[i  ][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr //陰的指定
                         //+    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx
                         //+    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx
                         //+ qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr
                         //+ qR*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr
                         + dx*dr/dt; //時間項
                aE[i][j] =   (Cx_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - Cc_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + Cc_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                             )*dr*bRx
                           + (Cc_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                           - (Cc_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (Cc_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (Cc_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] = (qR*Cr_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                           )*dx*bRr
                         + (qR*Cc_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                         - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] = (qL*Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                           )*dx*bLr
                         - (qL*Cc_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                         + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                aEN[i][j] =   (Cc_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                            + (Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] = - (Cc_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                            - (Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] = - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                            - (Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] =   (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                            + (Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;

                b[i][j] = (
                    + rate_ionize[i][j] //陽的ソース項
                    + rhoe_old[i][j]/dt)*dx*dr
                    + (0.0
                          //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                      )*dr
                    - (0.0
                        //rhoi[i][j]*Uix[i+1][j]*nbRx //右壁境界
                      )*dr
                    + qL*(0.0
                          //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                      )*dx
                    - qR*(
                        rhoi[i][j]*Uir[i][j+1]*nbRr1 //上壁境界
                      )*dx;
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoe);
    }
    
    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }

    //フラックス計算
    //rhoUexを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;

                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_Lr  = (Te[i][j]  + Te[i][j-1]  )/2.0;
                double Te_LrD = (Te[i-1][j]+ Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]  + Te[i][j+1]  )/2.0;
                double Te_RrD = (Te[i-1][j]+ Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                
                //フラックス
                //double bLrD  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                //bLrD = bLrD*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //壁の接線方向の処理
                if(bLr_Lx == 0 || bRr_Lx == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }

                
                rhoUex[i][j] 
                    = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                        - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoe[i-1][j]
                    - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoe[i][j+1]
                    + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1]
                    - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoe[i-1][j+1]
                    + (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoe[i-1][j-1];
            }
        }
    }

    //rhoUerを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;;
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_LxD = (Te[i][j-1]+Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]+Te[i+1][j])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;

                double z_Lx = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr = vd_Lr*dr/D_Lr;

                //double bLxD  = double(i!=i_flc_bl[0][0]); //z0
                //bLxD = bLxD*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                //bLxD = bLxD*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                //bLxD = bLxD*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                //double bRxD  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                //bRxD = bRxD*double(i!=i_flc_bl[4][1]); //z5

                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                
                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }

                rhoUer[i][j] 
                    = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + Cc_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                       - Cc_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                       - Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoe[i][j-1]
                    - (Cc_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoe[i+1][j]
                    + (Cc_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j]
                    - (Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoe[i+1][j-1]
                    + (Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoe[i-1][j-1];
            }
        }
    }


    //電位境界用に入れておく
    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoe[i+1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoe[i+1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }

    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoe[i][j-1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoe[i][j+1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoe[i][j+1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        rhoe[i][j+1] = rhoe[i][j];
        rhoUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
    }


    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_direct_old3(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new (ni+2,std::vector<double>(nj+2,0.0));
    

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字

    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                
                double Te_Lx  = (Te[i][j]   + Te[i-1][j]  )/2.0;
                double Te_LxU = (Te[i][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]   + Te[i+1][j]  )/2.0;
                double Te_RxU = (Te[i][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]   + Te[i][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j] + Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxU = (Te[i  ][j+1] - Te[i-1][j+1])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxU = (Te[i+1][j+1] - Te[i  ][j+1])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrU = (Te[i+1][j  ] - Te[i+1][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrU = (Te[i+1][j+1] - Te[i+1][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;

                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr*bRr1; //全部含む

                double bRr_Lx0  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx0 = bRr_Lx0*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double bRr_Lx1 = double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bRr_Rx0  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Rx0 = bRr_Rx0*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                double bRr_Rx1 = double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx_Rr == 0 || bRx_Rr == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLr_Lx == 0 || bRr_Lx0 == 0 || bRr_Lx1 == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr_Rx == 0 || bRr_Rx0 == 0 || bRr_Rx1 == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0; //(mu_xr[i+1][j]/mu_rr[i+1][j] + mu_xr[i][j]/mu_rr[i][j])/2.0;
                }

                /*
                //壁の接線方向の処理
                if(bLx == 0 || bRxD == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx == 0 || bRx == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLrD == 0 || bRrD == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr == 0 || bRr == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }
                */

                //if(nbRr1 == 1) test1[i][j] = 1.0;
                //if(nbRr == 1) test2[i][j] = 1.0;
                
                double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                aP[i][j] =      (    Cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   + Cc_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                   + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*Cr_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   + Cc_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - Cc_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                   + Cc_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - Cc_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         +    0.25*vth*exp(fmin(-e0*(-Ex[i  ][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                         +    0.25*vth*exp(fmin(-e0*( Ex[i+1][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx //陰的指定
                         + qL*0.25*vth*exp(fmin(-e0*(-Er[i  ][j  ]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                         + qR*0.25*vth*exp(fmin(-e0*( Er[i  ][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr //陰的指定
                         //+    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx
                         //+    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx
                         //+ qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr
                         //+ qR*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr
                         + dx*dr/dt; //時間項
                aE[i][j] =   (Cx_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - Cc_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + Cc_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                             )*dr*bRx
                           + (Cc_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                           - (Cc_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (Cc_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (Cc_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] = (qR*Cr_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                           )*dx*bRr
                         + (qR*Cc_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                         - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] = (qL*Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                           )*dx*bLr
                         - (qL*Cc_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                         + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                aEN[i][j] =   (Cc_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                            + (Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] = - (Cc_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                            - (Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] = - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                            - (Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] =   (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                            + (Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;

                b[i][j] = (
                    + rate_ionize[i][j] //陽的ソース項
                    + rhoe_old[i][j]/dt)*dx*dr
                    + (
                        (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0
                        *(rhoi[i][j]*Uir[i][j+1] + rhoi[i-1][j]*Uir[i-1][j+1])/2.0*(1.0 - bRr_Lx1)*bLx //上側境界の接線方向 (左) フラックス第2項
                      )*dr
                    - (
                        (mu_xr[i+1][j]/mu_rr[i+1][j] + mu_xr[i][j]/mu_rr[i][j])/2.0
                        *(rhoi[i][j]*Uir[i][j+1] + rhoi[i+1][j]*Uir[i+1][j+1])/2.0*(1.0 - bRr_Rx1)*bRx //上側境界の接線方向 (右) フラックス第2項
                      )*dr
                    + qL*(0.0
                          //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                      )*dx
                    - qR*(
                        rhoi[i][j]*Uir[i][j+1]*nbRr1 //上壁境界
                      )*dx;
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoe);
    }
    
    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }

    //フラックス計算
    //rhoUexを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;

                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_Lr  = (Te[i][j]  + Te[i][j-1]  )/2.0;
                double Te_LrD = (Te[i-1][j]+ Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]  + Te[i][j+1]  )/2.0;
                double Te_RrD = (Te[i-1][j]+ Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                
                //フラックス
                //double bLrD  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                //bLrD = bLrD*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bRr_Lx0  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx0 = bRr_Lx0*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double bRr_Lx1 = double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //壁の接線方向の処理
                if(bLr_Lx == 0 || bRr_Lx0 == 0 || bRr_Lx1 == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }

                
                rhoUex[i][j] 
                    = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                        - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoe[i-1][j]
                    - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoe[i][j+1]
                    + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1]
                    - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoe[i-1][j+1]
                    + (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoe[i-1][j-1]
                    + (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0
                     *(rhoi[i][j]*Uir[i][j+1] + rhoi[i-1][j]*Uir[i-1][j+1])/2.0*(1.0 - bRr_Lx1);
            }
        }
    }

    //rhoUerを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;;
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_LxD = (Te[i][j-1]+Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]+Te[i+1][j])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;

                double z_Lx = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr = vd_Lr*dr/D_Lr;

                //double bLxD  = double(i!=i_flc_bl[0][0]); //z0
                //bLxD = bLxD*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                //bLxD = bLxD*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                //bLxD = bLxD*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                //double bRxD  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                //bRxD = bRxD*double(i!=i_flc_bl[4][1]); //z5

                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                
                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }

                rhoUer[i][j] 
                    = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + Cc_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                       - Cc_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                       - Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoe[i][j-1]
                    - (Cc_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoe[i+1][j]
                    + (Cc_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j]
                    - (Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoe[i+1][j-1]
                    + (Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoe[i-1][j-1];
            }
        }
    }


    //電位境界用に入れておく
    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoe[i-1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoe[i+1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoe[i+1][j] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }

    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoe[i][j-1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoe[i][j+1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoe[i][j+1] = 0.0;
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        rhoe[i][j+1] = rhoe[i][j];
        rhoUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
    }


    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_direct(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new (ni+2,std::vector<double>(nj+2,0.0));
    

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //limit the arguments of exponential functions not to overflow.
    double EPS = 1.0e-3; //small values to avoid zero division in SG scheme
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Make coefficient for electron continuity equation for 9 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xx_hat_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_rr_hat_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xr_hat_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_xr_hat_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                //------------------------------------
                
                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;

                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                //------------------------------------
                
                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te[i][j]   + Te[i-1][j]  )/2.0;
                double Te_LxU = (Te[i][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]   + Te[i+1][j]  )/2.0;
                double Te_RxU = (Te[i][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]   + Te[i][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j] + Te[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxU = (Te[i  ][j+1] - Te[i-1][j+1])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxU = (Te[i+1][j+1] - Te[i  ][j+1])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrU = (Te[i+1][j  ] - Te[i+1][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrU = (Te[i+1][j+1] - Te[i+1][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;

                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;

                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "cell" to the wall, open, or central axis BC
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;

                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;

                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_open;
                //------------------------------------

                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                double btLxU_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                double btRxU_wall  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                btRxU_wall = btRxU_wall*double(i!=i_flr_bl[4][1]); //z5

                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                double btLrU_wall  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                btLrU_wall = btLrU_wall*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                double btRrU_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrU_wall = btRrU_wall*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                double btRrU_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //------------------------------------
                //*****************************************************

                //BC - normal flux component to the wall or open boundaries
                //*****************************************************
                //wall-flux divide by density (for implicit method)
                //------------------------------------
                double GammaPerN_wall_Lx = 0.0;
                double GammaPerN_wall_Rx = 0.0;
                double GammaPerN_wall_Lr = 0.0;
                double GammaPerN_wall_Rr = 0.0;
                if(bLx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                if(bRx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                if(bLr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                if(bRr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                //------------------------------------

                //open-flux (equal to ion)
                //------------------------------------
                double Gamma_open_Rr = 0.0;
                if(bRr_open == 0){
                    double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
                    Gamma_open_Rr = rhoUir_Rr;
                }
                //------------------------------------
                //*****************************************************

                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                double Gamma_trans_x_term2_Rx = 0.0;

                double Gamma_trans_r_term2_Lr = 0.0;
                double Gamma_trans_r_term2_Rr = 0.0;
                //------------------------------------
                
                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                if(btLxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    double mu_hat_trans_r_term2_Rr = (mu_xr[i][j]/mu_xx[i][j] + mu_xr[i][j+1]/mu_xx[i][j+1])/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double rhoUex_out_Rr =  0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*rhoUex_out_Rr;
                }
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btLrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    double mu_hat_trans_x_term2_Rx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i+1][j]/mu_rr[i+1][j])/2.0;

                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;

                    double rhoUer_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*rhoUer_out_Rx;
                }
                //------------------------------------

                //r-directional flux adjacent to right-wall boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                if(btRxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]  /mu_xx[i][j]  )/2.0;
                    double mu_hat_trans_r_term2_Rr = (  mu_xr[i][j+1]/mu_xx[i][j+1] +   mu_xr[i][j]  /mu_xx[i][j]  )/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double rhoUex_out_Rr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*rhoUex_out_Rr;
                }
                //------------------------------------
                
                //x-directional flux adjacent to upper-wall & -open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUir_out_Lx = (rhoi[i][j]*Uir[i][j+1] + rhoi[i-1][j]*Uir[i-1][j+1])/2.0; //outflow flux of ion
                    double rhoUer_out_Lx = rhoUir_out_Lx; //outflow flux of electron (equal to ion)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btRrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double rhoUer_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*rhoUer_out_Rx;
                }
                if(btRrU_open == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double rhoUir_out_Rx = (rhoi[i][j]*Uir[i][j+1] + rhoi[i+1][j]*Uir[i+1][j+1])/2.0; //outflow flux of ion
                    double rhoUer_out_Rx = rhoUir_out_Rx; //outflow flux of electron (equal to ion)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*rhoUer_out_Rx;
                }
                //------------------------------------
                //*****************************************************

                //*****************************************************
                //coefficient for electron continuity equation for 9 point stencil
                //*****************************************************
                //vertical and horizental 5 stencil
                //------------------------------------
                aP[i][j] =      (    mu_xx_hat_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   + mu_xr_hat_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - mu_xr_hat_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                   + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*mu_rr_hat_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   + mu_xr_hat_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - mu_xr_hat_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                   + mu_xr_hat_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - mu_xr_hat_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         -    GammaPerN_wall_Lx*dr //wall-flux boundary at left  wall (implicit)
                         +    GammaPerN_wall_Rx*dr //wall-flux boundary at right wall (implicit)
                         - qL*GammaPerN_wall_Lr*dx //wall-flux boundary at lower wall (implicit)
                         + qR*GammaPerN_wall_Rr*dx //wall-flux boundary at upper wall (implicit)
                         + dx*dr/dt; //time term
                aE[i][j] =   (mu_xx_hat_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + mu_xr_hat_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                             )*dr*bRx
                           + (mu_xr_hat_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                           - (mu_xr_hat_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (mu_xr_hat_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (mu_xr_hat_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] = (qR*mu_rr_hat_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                           )*dx*bRr
                         + (qR*mu_xr_hat_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                         - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] = (qL*mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                           )*dx*bLr
                         - (qL*mu_xr_hat_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                         + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                //------------------------------------

                //oblique 4 stencil
                //------------------------------------
                aEN[i][j] =   (mu_xr_hat_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                            + (mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] = - (mu_xr_hat_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                            - (mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] = - (mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                            - (mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] =   (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                            + (mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;
                //------------------------------------

                //RHS
                //------------------------------------
                b[i][j] = (
                    + rate_ionize[i][j]  //source term
                    + rhoe_old[i][j]/dt)*dx*dr; //time term
                //------------------------------------
                    
                //flux boundaries
                //------------------------------------
                b[i][j] = b[i][j] 
                    //left-BC
                    + (
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Lx*bLx //at upper and lower (left interface)
                      )*dr
                    //right-BC
                    - (
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Rx*bRx //at upper and lower (right interface)
                      )*dr
                    //lower-BC
                    + qL*(0.0
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Lr*bLr //at left and right (lower interface)
                      )*dx
                    //upper-BC
                    - qR*(
                        //normal (r) boundary flux
                        + Gamma_open_Rr //Open-BC
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Rr*bRr //at left and right (upper interface)
                      )*dx;
            }
        }
    }

    //Solver
    //=====================================================================
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        //GMRES
        //------------------------------------
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        //------------------------------------
    }else{
        //LU-decimposition
        //------------------------------------
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoe);
        //------------------------------------
    }
    
    //Don’t update unless the value is positive.
    //------------------------------------
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }
    //------------------------------------

    //set values of ghost cells for ES-potential calculation
    //=====================================================================================
    
    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoe[i+1][j] = 0.0;
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoe[i+1][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoe[i][j-1] = 0.0;
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoe[i][j+1] = 0.0;
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoe[i][j+1] = 0.0;
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        rhoe[i][j+1] = rhoe[i][j];
    }
    //------------------------------------
    //=====================================================================================

    //Update flux
    //=====================================================================================
    //for rhoUex
    //*****************************************************************
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;

                double Te_Lr  = (Te[i][j]  + Te[i][j-1]  )/2.0;
                double Te_LrD = (Te[i-1][j]+ Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]  + Te[i][j+1]  )/2.0;
                double Te_RrD = (Te[i-1][j]+ Te[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;

                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //------------------------------------
                //*****************************************************

 
                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                //------------------------------------

                //x-directional flux adjacent to upper-wall & -open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUir_out_Lx = (rhoi[i][j]*Uir[i][j+1] + rhoi[i-1][j]*Uir[i-1][j+1])/2.0; //outflow flux of ion
                    double rhoUer_out_Lx = rhoUir_out_Lx; //outflow flux of electron (equal to ion)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                //------------------------------------
                //*****************************************************

                //update rhoUex
                //------------------------------------
                rhoUex[i][j] 
                    = (-mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                        - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                    + (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoe[i-1][j]
                    - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoe[i][j+1]
                    + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1]
                    - (mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoe[i-1][j+1]
                    + (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoe[i-1][j-1]
                    + Gamma_trans_x_term2_Lx;
                //------------------------------------
            }
        }
    }

    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx;
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx;
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx;
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx;
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx;
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx;
    }
    //=====================================================================================

    //rhoUerを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                //radial position at upper and lower cell interface
                //------------------------------------
                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //radial position at upper and lower cell interface
                //------------------------------------
                //double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_LxD = (Te[i][j-1]+Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]+Te[i+1][j])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                //------------------------------------
                //*****************************************************

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                //------------------------------------
                //*****************************************************
                
                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_r_term2_Lr = 0.0;
                //------------------------------------

                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                //------------------------------------
                
                //r-directional flux adjacent to right-open boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                //------------------------------------
                //*****************************************************

                //update rhoUer
                //------------------------------------
                rhoUer[i][j] 
                    = (- mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                       - mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                    + (mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                       - mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoe[i][j-1]
                    - (mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoe[i+1][j]
                    + (mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j]
                    - (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoe[i+1][j-1]
                    + (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoe[i-1][j-1]
                    + Gamma_trans_r_term2_Lr;
                //------------------------------------
            }
        }
    }
    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr;
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr;
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr;
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
        rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr;
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
        double Gamma_open_Rr = rhoUir_Rr;
        rhoUer[i][j+1] =  Gamma_open_Rr;
    }
    //------------------------------------
    //=====================================================================================

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoe = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_rhoUex = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_rhoUer = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
    //------------------------------------
    //=====================================================================================
}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_wSEE_direct(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new (ni+2,std::vector<double>(nj+2,0.0));
    

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //limit the arguments of exponential functions not to overflow.
    double EPS = 1.0e-3; //small values to avoid zero division in SG scheme
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Make coefficient for electron continuity equation for 9 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xx_hat_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_rr_hat_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xr_hat_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_xr_hat_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                //------------------------------------
                
                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;

                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                //------------------------------------
                
                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te[i][j]   + Te[i-1][j]  )/2.0;
                double Te_LxU = (Te[i][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]   + Te[i+1][j]  )/2.0;
                double Te_RxU = (Te[i][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]   + Te[i][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j] + Te[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxU = (Te[i  ][j+1] - Te[i-1][j+1])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxU = (Te[i+1][j+1] - Te[i  ][j+1])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrU = (Te[i+1][j  ] - Te[i+1][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrU = (Te[i+1][j+1] - Te[i+1][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;

                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;

                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "cell" to the wall, open, or central axis BC
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;

                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;

                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_open;
                //------------------------------------

                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                double btLxU_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                double btRxU_wall  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                btRxU_wall = btRxU_wall*double(i!=i_flr_bl[4][1]); //z5

                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                double btLrU_wall  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                btLrU_wall = btLrU_wall*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                double btRrU_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrU_wall = btRrU_wall*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                double btRrU_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //------------------------------------
                //*****************************************************

                //BC - normal flux component to the wall or open boundaries
                //*****************************************************
                //wall-flux divide by density (for implicit method)
                //------------------------------------
                double GammaPerN_wall_Lx = 0.0;
                double GammaPerN_wall_Rx = 0.0;
                double GammaPerN_wall_Lr = 0.0;
                double GammaPerN_wall_Rr = 0.0;
                if(bLx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                if(bRx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                if(bLr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                if(bRr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
                }
                //------------------------------------

                //open-flux (equal to ion)
                //------------------------------------
                double Gamma_open_Rr = 0.0;
                if(bRr_open == 0){
                    double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
                    Gamma_open_Rr = rhoUir_Rr;
                }
                //------------------------------------

                //wallSEE-flux
                //------------------------------------
                double Gamma_wallSEE_Lx = 0.0;
                double Gamma_wallSEE_Rx = 0.0;
                double Gamma_wallSEE_Lr = 0.0;
                double Gamma_wallSEE_Rr = 0.0;
                if(bLx_wall == 0){

                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

                    Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        -coefMISEE_ts*rhoUmx[i][j]; //MISEE
                }
                if(bRx_wall == 0){

                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

                    Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                        -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
                }
                if(bLr_wall == 0){

                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

                    Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                        -coefMISEE_ts*rhoUmr[i][j]; //MISEE
                }
                if(bRr_wall == 0){

                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

                    Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                        -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
                }
                //------------------------------------

                //*****************************************************

                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                double Gamma_trans_x_term2_Rx = 0.0;

                double Gamma_trans_r_term2_Lr = 0.0;
                double Gamma_trans_r_term2_Rr = 0.0;
                //------------------------------------
                
                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                if(btLxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    double mu_hat_trans_r_term2_Rr = (mu_xr[i][j]/mu_xx[i][j] + mu_xr[i][j+1]/mu_xx[i][j+1])/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double rhoUex_out_Rr =  0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*rhoUex_out_Rr;
                }
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btLrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    double mu_hat_trans_x_term2_Rx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i+1][j]/mu_rr[i+1][j])/2.0;

                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;

                    double rhoUer_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*rhoUer_out_Rx;
                }
                //------------------------------------

                //r-directional flux adjacent to right-wall boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                if(btRxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]  /mu_xx[i][j]  )/2.0;
                    double mu_hat_trans_r_term2_Rr = (  mu_xr[i][j+1]/mu_xx[i][j+1] +   mu_xr[i][j]  /mu_xx[i][j]  )/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double rhoUex_out_Rr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*rhoUex_out_Rr;
                }
                //------------------------------------
                
                //x-directional flux adjacent to upper-wall & -open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUir_out_Lx = (rhoi[i][j]*Uir[i][j+1] + rhoi[i-1][j]*Uir[i-1][j+1])/2.0; //outflow flux of ion
                    double rhoUer_out_Lx = rhoUir_out_Lx; //outflow flux of electron (equal to ion)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btRrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double rhoUer_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*rhoUer_out_Rx;
                }
                if(btRrU_open == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double rhoUir_out_Rx = (rhoi[i][j]*Uir[i][j+1] + rhoi[i+1][j]*Uir[i+1][j+1])/2.0; //outflow flux of ion
                    double rhoUer_out_Rx = rhoUir_out_Rx; //outflow flux of electron (equal to ion)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*rhoUer_out_Rx;
                }
                //------------------------------------
                //*****************************************************

                //*****************************************************
                //coefficient for electron continuity equation for 9 point stencil
                //*****************************************************
                //vertical and horizental 5 stencil
                //------------------------------------
                aP[i][j] =      (    mu_xx_hat_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   + mu_xr_hat_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - mu_xr_hat_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                   + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*mu_rr_hat_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                   + mu_xr_hat_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - mu_xr_hat_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                   + mu_xr_hat_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                   - mu_xr_hat_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         -    GammaPerN_wall_Lx*dr //wall-flux boundary at left  wall (implicit)
                         +    GammaPerN_wall_Rx*dr //wall-flux boundary at right wall (implicit)
                         - qL*GammaPerN_wall_Lr*dx //wall-flux boundary at lower wall (implicit)
                         + qR*GammaPerN_wall_Rr*dx //wall-flux boundary at upper wall (implicit)
                         + dx*dr/dt; //time term
                aE[i][j] =   (mu_xx_hat_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + mu_xr_hat_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                             )*dr*bRx
                           + (mu_xr_hat_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                           - (mu_xr_hat_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (mu_xr_hat_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (mu_xr_hat_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] = (qR*mu_rr_hat_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                           )*dx*bRr
                         + (qR*mu_xr_hat_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                         - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] = (qL*mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                           )*dx*bLr
                         - (qL*mu_xr_hat_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                         + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                //------------------------------------

                //oblique 4 stencil
                //------------------------------------
                aEN[i][j] =   (mu_xr_hat_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                            + (mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] = - (mu_xr_hat_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                            - (mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] = - (mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                            - (mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] =   (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                            + (mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;
                //------------------------------------

                //RHS
                //------------------------------------
                b[i][j] = (
                    + rate_ionize[i][j]  //source term
                    + rhoe_old[i][j]/dt)*dx*dr; //time term
                //------------------------------------
                    
                //flux boundaries
                //------------------------------------
                b[i][j] = b[i][j] 
                    //left-BC
                    + (
                        //normal (x) wall-SEE flux
                        + Gamma_wallSEE_Lx //wall-SEE
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Lx*bLx //at upper and lower (left interface)
                      )*dr
                    //right-BC
                    - (
                        //normal (x) wall-SEE flux
                        + Gamma_wallSEE_Rx //wall-SEE
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Rx*bRx //at upper and lower (right interface)
                      )*dr
                    //lower-BC
                    + qL*(
                        //normal (r) wall-SEE flux
                        + Gamma_wallSEE_Lr //wall-SEE
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Lr*bLr //at left and right (lower interface)
                      )*dx
                    //upper-BC
                    - qR*(
                        //normal (r) boundary flux
                        + Gamma_open_Rr //Open-BC
                        //normal (r) wall-SEE flux
                        + Gamma_wallSEE_Rr //wall-SEE
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Rr*bRr //at left and right (upper interface)
                      )*dx;
            }
        }
    }

    //Solver
    //=====================================================================
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        //GMRES
        //------------------------------------
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        //------------------------------------
    }else{
        //LU-decimposition
        //------------------------------------
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoe);
        //------------------------------------
    }
    
    //Don’t update unless the value is positive.
    //------------------------------------
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }
    //------------------------------------

    //set values of ghost cells for ES-potential calculation
    //=====================================================================================
    
    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoe[i+1][j] = 0.0;
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoe[i+1][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoe[i][j-1] = 0.0;
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoe[i][j+1] = 0.0;
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoe[i][j+1] = 0.0;
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        rhoe[i][j+1] = rhoe[i][j];
    }
    //------------------------------------
    //=====================================================================================

    //Update flux
    //=====================================================================================
    //for rhoUex
    //*****************************************************************
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;

                double Te_Lr  = (Te[i][j]  + Te[i][j-1]  )/2.0;
                double Te_LrD = (Te[i-1][j]+ Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]  + Te[i][j+1]  )/2.0;
                double Te_RrD = (Te[i-1][j]+ Te[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;

                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //------------------------------------
                //*****************************************************

 
                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                //------------------------------------

                //x-directional flux adjacent to upper-wall & -open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUer_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double rhoUir_out_Lx = (rhoi[i][j]*Uir[i][j+1] + rhoi[i-1][j]*Uir[i-1][j+1])/2.0; //outflow flux of ion
                    double rhoUer_out_Lx = rhoUir_out_Lx; //outflow flux of electron (equal to ion)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*rhoUer_out_Lx;
                }
                //------------------------------------
                //*****************************************************

                //update rhoUex
                //------------------------------------
                rhoUex[i][j] 
                    = (-mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                        - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                    + (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoe[i-1][j]
                    - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoe[i][j+1]
                    + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1]
                    - (mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoe[i-1][j+1]
                    + (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoe[i-1][j-1]
                    + Gamma_trans_x_term2_Lx;
                //------------------------------------
            }
        }
    }

    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        -coefMISEE_ts*rhoUmx[i][j]; //MISEE
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        -coefMISEE_ts*rhoUmx[i][j]; //MISEE
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        -coefMISEE_ts*rhoUmx[i][j]; //MISEE
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        -coefMISEE_ts*rhoUmx[i][j]; //MISEE
        rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                        -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
        rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                        -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
        rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
    }
    //=====================================================================================

    //rhoUerを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                //radial position at upper and lower cell interface
                //------------------------------------
                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //radial position at upper and lower cell interface
                //------------------------------------
                //double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_LxD = (Te[i][j-1]+Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]+Te[i+1][j])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                //------------------------------------
                //*****************************************************

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                //------------------------------------
                //*****************************************************
                
                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_r_term2_Lr = 0.0;
                //------------------------------------

                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                //------------------------------------
                
                //r-directional flux adjacent to right-open boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double rhoUex_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*rhoUex_out_Lr;
                }
                //------------------------------------
                //*****************************************************

                //update rhoUer
                //------------------------------------
                rhoUer[i][j] 
                    = (- mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                       - mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                    + (mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                       - mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoe[i][j-1]
                    - (mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoe[i+1][j]
                    + (mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j]
                    - (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoe[i+1][j-1]
                    + (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoe[i-1][j-1]
                    + Gamma_trans_r_term2_Lr;
                //------------------------------------
            }
        }
    }
    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                        -coefMISEE_ts*rhoUmr[i][j]; //MISEE
        rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                        -coefMISEE_ts*rhoUmr[i][j]; //MISEE
        rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);
        
        double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                        -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
        rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                        -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                        -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
        rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
        double Gamma_open_Rr = rhoUir_Rr;
        rhoUer[i][j+1] =  Gamma_open_Rr;
    }
    //------------------------------------
    //=====================================================================================

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoe = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_rhoUex = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_rhoUer = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
    //------------------------------------
    //=====================================================================================
}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_direct_dieleOpen(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new (ni+2,std::vector<double>(nj+2,0.0));
    

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字

    //過去の値を保持
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
            scx_old[i][j] = scx[i][j];
            scr_old[i][j] = scr[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[1][0]);
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                
                double Te_Lx  = (Te[i][j]   + Te[i-1][j]  )/2.0;
                double Te_LxU = (Te[i][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]   + Te[i+1][j]  )/2.0;
                double Te_RxU = (Te[i][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]   + Te[i][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j] + Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ]) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1]) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1]) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ]) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1]) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1]) + EPS;
                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ]) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ]) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ]) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1]) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1]) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1]) + EPS;

                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;

                double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                double bRx  = double(i!=i_flc_bl[1][1]);
                double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                double bRr  = double(j!=j_flc_bl[1][1]);

                //壁の接線方向の処理
                if(bLxD == 0 || bRx == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx == 0 || bRx == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLrD == 0 || bRr == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr == 0 || bRr == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }

                double nbLx  = 1.0 - bLx;
                double nbLr  = 1.0 - bLr;
                double nbRx  = 1.0 - bRx;
                double nbRr  = 1.0 - bRr;

                double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                aP[i][j] =       (    Cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) + Cc_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) - Cc_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*dr*bRx*bRr
                         -       (   -Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*dr*bLx*bRx*bRr
                         +       ( qR*Cr_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) + Cc_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) - Cc_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*dx*bRr*bRx
                         -       (-qL*Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) + Cc_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) - Cc_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*dx*bLr*bRx*bRr
                         +    0.25*vth*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                         + qL*0.25*vth*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                         + dx*dr/dt; //時間項
                aE[i][j] =   (Cx_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) - Cc_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) + Cc_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0))*dr*bRx*bRr
                    +    (Cc_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr*bRx
                    -    (Cc_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr*bRx*bRr;
                aW[i][j] =   (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*dr*bLx*bRx*bRr
                    -    (Cc_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr*bRx
                    +    (Cc_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr*bRx*bRr;
                aN[i][j] = (qR*Cr_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) - Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) + Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0))*dx*bRr*bRx
                    +  (qR*Cc_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx*bRr
                    -  (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx*bRx*bRr;
                aS[i][j] = (qL*Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) + Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) - Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*dx*bLr*bRx*bRr
                    -  (qL*Cc_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx*bRr
                    +  (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx*bRx*bRr;
                aEN[i][j] =  (Cc_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx*bRr
                    + (Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr*bRx;
                aES[i][j] = -(Cc_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx*bRr
                    - (Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr*bRx*bRr;
                aWN[i][j] = -(Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx*bRx*bRr
                    - (Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr*bRx;
                aWS[i][j] =  (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx*bRx*bRr
                    + (Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr*bRx*bRr;

                double rhoi_Lx = (rhoi[i][j] + rhoi[i-1][j])/2.0;
                double rhoi_Rx = rhoi[i][j];
                double rhoi_Lr = (rhoi[i][j] + rhoi[i][j-1])/2.0;
                double rhoi_Rr = rhoi[i][j];
                double nabla_rhoUi = (rhoi_Rx*Uix[i+1][j]-rhoi_Lx*Uix[i][j])/dx + (qR*rhoi_Rr*Uir[i][j+1]-qL*rhoi_Lr*Uir[i][j])/dr;

                b[i][j] = (
                    + rate_ionize[i][j] //陽的ソース項
                    + rhoe_old[i][j]/dt*bRx*bRr //時間項
                    + (rhoi_old[i][j]/dt - nabla_rhoUi)*fmin(1.0,nbRx + nbRr) //開放境界でイオンの発散に置き換え
                    )*dx*dr;
                
                //std::cout << i << " , "<< j << " , "<<bRx*bRr << " , "<<+ fmin(1.0,nbRx + nbRr) << std::endl;
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoe);
    }
    
    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }

    //電位境界用に入れておく
    //左 壁1
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }

    //左 壁2
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        rhoe[i-1][j] = 0.0;
    }

    //下 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }

    //右 壁
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoe[i+1][j] = rhoe[i][j];
    }

    //上 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoe[i][j+1] = rhoe[i][j];
    }

    //フラックス計算
    //rhoUexを計算
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){

                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;

                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;; //中心軸特別;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;; //中心軸特別;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_Lr  = (Te[i][j]  + Te[i][j-1]  )/2.0;
                double Te_LrD = (Te[i-1][j]+ Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i][j]  + Te[i][j+1]  )/2.0;
                double Te_RrD = (Te[i-1][j]+ Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ]) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ]) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ]) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1]) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1]) + EPS;
                
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                
                //フラックス
                double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                double bRr  = double(j!=j_flc_bl[1][1]);
                
                //壁の接線方向の処理
                if(bLrD == 0 || bRr == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }

                rhoUex[i][j] 
                    = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                        - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoe[i-1][j]
                    - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoe[i][j+1]
                    + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1]
                    - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoe[i-1][j+1]
                    + (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoe[i-1][j-1];

                if(i==i_flc_bl[0][0]){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                }

                //左側の壁
                if(i==i_flc_bl[1][0] && j<=j_flc_bl[0][0]-1){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                }
            }
        }
    }

    //rhoUerを計算
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1];j++){

                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;

                double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                double Te_LxD = (Te[i][j-1]+Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i][j]+Te[i+1][j])/2.0;
                double Te_RxD = (Te[i][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i][j]   + Te[i][j-1]  )/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ]) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1]) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ]) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1]) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ]) + EPS;

                double z_Lx = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr = vd_Lr*dr/D_Lr;

                double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                double bRx  = double(i!=i_flc_bl[1][1]);
                
                //壁の接線方向の処理
                if(bLxD == 0 || bRx == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }

                rhoUer[i][j] 
                    = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + Cc_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                       - Cc_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                    + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                       - Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoe[i][j-1]
                    - (Cc_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoe[i+1][j]
                    + (Cc_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j]
                    - (Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoe[i+1][j-1]
                    + (Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoe[i-1][j-1];

                //下側の壁
                if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                }
            }
        }
    }

    //右 壁
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1]-1;j++){
        int i = i_flc_bl[1][1];
        
        double rR = (r[j]+r[j+1])/2.0;
        double rL = (r[j]+r[j-1])/2.0;
        double qR = (r[j]+r[j+1])/2.0/r[j];
        double qL = (r[j]+r[j-1])/2.0/r[j];

        double nabla_rhoUe = (0.0*rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
        double rhoi_Lx = (rhoi[i][j] + rhoi[i-1][j])/2.0;
        double rhoi_Rx = rhoi[i][j];
        double rhoi_Lr = (rhoi[i][j] + rhoi[i][j-1])/2.0;
        double rhoi_Rr = rhoi[i][j];
        double nabla_rhoUi = (rhoi_Rx*Uix[i+1][j]-rhoi_Lx*Uix[i][j])/dx + (qR*rhoi_Rr*Uir[i][j+1]-qL*rhoi_Lr*Uir[i][j])/dr;

        rhoUex[i+1][j] =  (nabla_rhoUi - nabla_rhoUe - (rhoi_old[i][j] - rhoe_old[i][j])/dt)*dx;

        //表面電荷更新
        scx[i][j] = scx_old[i][j] + dt*e0*(rhoi_Rx*Uix[i+1][j] - rhoUex[i+1][j]);
    }

    //上 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1]-1;i++){ 
        int j = j_flc_bl[0][1];
        double rR = (r[j]+r[j+1])/2.0;
        double rL = (r[j]+r[j-1])/2.0;
        double qR = (r[j]+r[j+1])/2.0/r[j];
        double qL = (r[j]+r[j-1])/2.0/r[j];

        double nabla_rhoUe = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (0.0*qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
        double rhoi_Lx = (rhoi[i][j] + rhoi[i-1][j])/2.0;
        double rhoi_Rx = rhoi[i][j];
        double rhoi_Lr = (rhoi[i][j] + rhoi[i][j-1])/2.0;
        double rhoi_Rr = rhoi[i][j];
        double nabla_rhoUi = (rhoi_Rx*Uix[i+1][j]-rhoi_Lx*Uix[i][j])/dx + (qR*rhoi_Rr*Uir[i][j+1]-qL*rhoi_Lr*Uir[i][j])/dr;

        rhoUer[i][j+1] =  (nabla_rhoUi - nabla_rhoUe - (rhoi_old[i][j] - rhoe_old[i][j])/dt)*dr/qR;

        //表面電荷更新
        scr[i][j] = scr_old[i][j] + dt*e0*(rhoi_Rr*Uir[i][j+1] - rhoUer[i][j+1]);
    }

    //角
    {
        int i = i_flc_bl[1][1];
        int j = j_flc_bl[1][1];
        double rR = (r[j]+r[j+1])/2.0;
        double rL = (r[j]+r[j-1])/2.0;
        double qR = (r[j]+r[j+1])/2.0/r[j];
        double qL = (r[j]+r[j-1])/2.0/r[j];

        double nabla_rhoUe = (0.0*rhoUex[i+1][j]-rhoUex[i][j])/dx + (0.0*qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
        double rhoi_Lx = (rhoi[i][j] + rhoi[i-1][j])/2.0;
        double rhoi_Rx = rhoi[i][j];
        double rhoi_Lr = (rhoi[i][j] + rhoi[i][j-1])/2.0;
        double rhoi_Rr = rhoi[i][j];
        double nabla_rhoUi = (rhoi_Rx*Uix[i+1][j]-rhoi_Lx*Uix[i][j])/dx + (qR*rhoi_Rr*Uir[i][j+1]-qL*rhoi_Lr*Uir[i][j])/dr;

        double tmp = (nabla_rhoUi - nabla_rhoUe - (rhoi_old[i][j] - rhoe_old[i][j])/dt)/2.0;
        rhoUex[i+1][j] =  tmp*dx;
        rhoUer[i][j+1] =  tmp*dr/qR;

        scx[i][j] = scx_old[i][j] + dt*e0*(rhoi_Rx*Uix[i+1][j] - rhoUex[i+1][j]);
        scr[i][j] = scr_old[i][j] + dt*e0*(rhoi_Rr*Uir[i][j+1] - rhoUer[i][j+1]);
    }

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_PC_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];

            //drhoeを予想
            drhoe[i][j] = rhoe[i][j]-rhoe_old[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j] 
                        + rR*rhoUer_old_tmp[i-1][j+1] + rL*rhoUer_old_tmp[i-1][j])/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    rhoUex[i][j] = rhoUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //壁の接線方向処理
                    if(bLrD == 0 || bRr == 0){
                        double Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                        double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                        double vd_Lx  = mu_para_Lx*(-Ex[i][j]) + EPS;
                        double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                        double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                        double z_Lx = vd_Lx*dx/D_Lx;
    
                        rhoUex[i][j] 
                            = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                            + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j];
                    }
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_tmp + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j] 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1] + r[j-1]*rhoUex_old_tmp[i][j-1])/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    rhoUer[i][j] =  rhoUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                        
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //壁の接線方向処理
                    if(bLxD == 0 || bRx == 0){
                        double Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                        double mu_para_Lr  = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                        double vd_Lr  = mu_para_Lr*(-Er[i][j]) + EPS;
                        double Te_Lr  = (Te[i][j] + Te[i][j-1])/2.0;
                        double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                        double z_Lr = vd_Lr*dr/D_Lr;
    
                        rhoUer[i][j] 
                            = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                            + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1];
                    }

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                        + dx*dr/dt + dx*dr/dtau*double(icon_dtau); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        - (rhoe[i][j] - rhoe_old[i][j])/dt )*dx*dr;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }

        /********************* 更新 *******************/
        //drhoUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    drhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //drhoUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    drhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //密度更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new; //正の密度だった時だけ更新
                    }
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_PC_old2(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 10000000.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];

            //drhoeを予想
            drhoe[i][j] = rhoe[i][j]-rhoe_old[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j] 
                        + rR*rhoUer_old_tmp[i-1][j+1] + rL*rhoUer_old_tmp[i-1][j])/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    rhoUex[i][j] = rhoUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //壁の接線方向処理
                    if(bLrD == 0 || bRr == 0){
                        double Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                        double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                        double vd_Lx  = mu_para_Lx*(-Ex[i][j]) + EPS;
                        double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                        double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                        double z_Lx = vd_Lx*dx/D_Lx;
    
                        rhoUex[i][j] 
                            = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                            + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j];
                    }
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_tmp + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j] 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1] + r[j-1]*rhoUex_old_tmp[i][j-1])/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    rhoUer[i][j] =  rhoUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //壁の接線方向処理
                    if(bLxD == 0 || bRx == 0){
                        double Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                        double mu_para_Lr  = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                        double vd_Lr  = mu_para_Lr*(-Er[i][j]) + EPS;
                        double Te_Lr  = (Te[i][j] + Te[i][j-1])/2.0;
                        double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                        double z_Lr = vd_Lr*dr/D_Lr;
    
                        rhoUer[i][j] 
                            = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                            + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1];
                    }

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                        +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                        + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                        + dx*dr/dt + dx*dr/dtau*double(icon_dtau); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        - (rhoe[i][j] - rhoe_old[i][j])/dt )*dx*dr;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }

        /********************* 更新 *******************/
        //drhoUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    drhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //drhoUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    drhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //密度更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new; //正の密度だった時だけ更新
                    }
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            drhoe[i][j] = rhoe[i][j] - rhoe_old[i][j];

            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRr + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;                   

                    rhoUex[i][j] = rhoUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRx + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    rhoUer[i][j] =  rhoUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                        +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                        + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                        + dx*dr/dt + dx*dr/dtau*double(icon_dtau); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        - (rhoe[i][j] - rhoe_old[i][j])/dt )*dx*dr;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }

        /********************* 更新 *******************/
        //drhoUexを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    drhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //drhoUerを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    drhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //密度更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new; //正の密度だった時だけ更新
                    }
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //輸送係数用に入れておく
    //左 壁1
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }

    //左 壁2
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        rhoe[i-1][j] = 0.0;
    }

    //下 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }

    //右 ノイマン
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoe[i+1][j]  =  rhoe[i][j];
    }

    //上 ノイマン
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoe[i][j+1] =  rhoe[i][j];
    }

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 0.9; //1.9
    double ratioY = 0.9; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            drhoe[i][j] = rhoe[i][j] - rhoe_old[i][j];

            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2


                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    //double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    //double nbRr1  = 1.0 - bRr1; //x5だけ
                    //bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    //bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
   
                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRr_Lx + rL*rhoUer_old_tmp[i-1][j]*bLr_Lx)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_min_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_min_tmp);

                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_min_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;                   

                    rhoUex[i][j] = rhoUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRx_Lr + r[j-1]*rhoUex_old_tmp[i][j-1]*bLx_Lr)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_min_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_min_tmp);
    
                    double dTedr_tmp = (Te[i][j] - Te[i][j-1])/dr;
                    double vd_tmp = mu_min_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    rhoUer[i][j] =  rhoUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                }
            }
        }

        
        //左 壁 z0
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            rhoe[i-1][j] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //左 壁 z1
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            rhoe[i-1][j] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //左 壁 z2
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            rhoe[i-1][j] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //左 壁 z4
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            rhoe[i-1][j] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //右 壁 z3
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            rhoe[i+1][j] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //右 壁 z5
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            rhoe[i+1][j] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUex[i+1][j] =  0.25*rhoe[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }

        //下 壁 x0
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            rhoe[i][j-1] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //下 壁 x2
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            rhoe[i][j-1] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }

        //上 壁 x1
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            rhoe[i][j+1] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //上 壁 x4
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            rhoe[i][j+1] = 0.0;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            //rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
            rhoUer[i][j+1] = 0.25*rhoe[i][j]*exp(fmin(-e0*( Er[i][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
        }
        //上 開放 x5
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            rhoe[i][j+1] = rhoe[i][j];
            rhoUer[i][j+1] =  rhoi[i][j]*Uir[i][j+1];
        }


        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_min[i][j]+mu_min[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_min[i][j]+mu_min[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_min[i][j]+mu_min[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_min[i][j]+mu_min[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double dTedx_Lx = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                    double dTedx_Rx = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                    double dTedr_Lr = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double dTedr_Rr = (Te[i  ][j+1] - Te[i  ][j  ])/dr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                    double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                    bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                    double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                    bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                    
                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    double nbRr1  = 1.0 - bRr1; //x5だけ
                    
                    bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double bRr_Rx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Rx = bRr_Rx*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                    bRr_Rx = bRr_Rx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                        +    0.25*vth*exp(fmin(-e0*(-Ex[i  ][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                        +    0.25*vth*exp(fmin(-e0*( Ex[i+1][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx //陰的指定
                        + qL*0.25*vth*exp(fmin(-e0*(-Er[i  ][j  ]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                        + qR*0.25*vth*exp(fmin(-e0*( Er[i  ][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr //陰的指定
                        + dx*dr/dt + dx*dr/dtau*double(icon_dtau); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        - (rhoe[i][j] - rhoe_old[i][j])/dt )*dx*dr;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }

        /********************* 更新 *******************/
        //drhoUexを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;

                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_min_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    drhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //drhoUerを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;

                    double dTedr_tmp = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double vd_tmp = mu_min_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    drhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //密度更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new; //正の密度だった時だけ更新
                    }
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0] + 1 - iblock;i<=i_flx_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0] + 1 - iblock;i<=i_flx_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0] + 1;j<=j_flr_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0] + 1;j<=j_flr_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}


//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_wSEE_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------


    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------
    
    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            drhoe[i][j] = rhoe[i][j] - rhoe_old[i][j];
        }
    }
    //------------------------------------

    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }
        //------------------------------------

        //Predict flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_rr_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_inv_xx_tmp = mu_rr_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0; //electron temperature
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dx/D_tmp; //Peclet number
                    //------------------------------------
                    
                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRrD + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    rhoUex[i][j] =
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j] 
                        + rhoUex_old_tmp[i][j] 
                        - mu_star_tmp*(mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp);
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
            rhoUex_wall[i][j] = rhoUex[i][j];
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
            rhoUex_wall[i][j] = rhoUex[i][j];
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
            rhoUex_wall[i][j] = rhoUex[i][j];
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
            rhoUex_wall[i][j] = rhoUex[i][j];
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
            rhoUex_wall[i+1][j] = rhoUex[i+1][j];
        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
            rhoUex_wall[i+1][j] = rhoUex[i+1][j];
        }
        //=====================================================================================

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_xx_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    
                    double mu_inv_rr_tmp = mu_xx_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0; //electron temperature
                    double dTedr_tmp = (Te[i][j] - Te[i][j-1])/dr; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dr/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRxD + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    rhoUer[i][j] =  
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + rhoUer_old_tmp[i][j]
                        - mu_star_tmp*(mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j]);
                    //------------------------------------
                }
            }
        }

        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
            rhoUer_wall[i][j] = rhoUer[i][j];
        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
            
            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
            rhoUer_wall[i][j] = rhoUer[i][j];
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
            rhoUer_wall[i][j+1] = rhoUer[i][j+1];
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
            rhoUer_wall[i][j+1] = rhoUer[i][j+1];
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            rhoUer[i][j+1] =  Gamma_open_Rr;
            rhoUer_wall[i][j+1] = 0.0;
        }
        //------------------------------------

        //Make coefficient for electron continuity equation for 5 point stencil
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------
                    
                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron temperature at cell interface
                    //------------------------------------
                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;
                    //------------------------------------

                    //electron diffusion coefficient at cell interface
                    //------------------------------------
                    double D_Lx = Boltz*Te_Lx/e0*mu_star_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_star_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_star_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_star_Rr;
                    //------------------------------------

                    //electron temperature gradient at cell interface
                    //------------------------------------
                    double dTedx_Lx = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                    double dTedx_Rx = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                    double dTedr_Lr = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double dTedr_Rr = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                    //------------------------------------

                    //electron drift velocity at cell interface
                    //------------------------------------
                    double vd_Lx = mu_star_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_star_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_star_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_star_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;
                    //------------------------------------

                    //Peclet number at cell interface
                    //------------------------------------
                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    //coefficient for electron continuity equation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        + dx*dr/dt; //time-term
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j]
                        - (rhoe[i][j] - rhoe_old[i][j])/dt)*dx*dr; //time-term
                    //------------------------------------
                    //==============================================

                }
            }
        }
        //------------------------------------

        //Solver
        //------------------------------------
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }
        //------------------------------------

        //Correction
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUex = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double dTedr_tmp = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUer =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoe
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new;
                    }
                }
            }
        }
        //------------------------------------
        //==============================================

        //Caluculate residuals
        //=====================================================================================
        //rhoe
        //------------------------------------
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }
        //------------------------------------

        //r-directional flux
        //------------------------------------
        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        //------------------------------------
        //=====================================================================================
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    
    //calculation of particle balance
    //------------------------------------
    if(itime%ndiv_fout == 0 || itime == ntime){
        
        //volume integrated values
        //------------------------------------
        double dNedt_sum         = 0.0;
        double nabla_rhoUe_sum   = 0.0;
        double rate_d_ionz_sum   = 0.0;
        double rate_s_ionz_sum   = 0.0;
        //------------------------------------
    
        //calculate volume integrated of each term
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    double nabla_rhoUe = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    
                    double volume = 2.0*M_PI*r[j]*dr*dx;
                    
                    dNedt_sum         = dNedt_sum         + volume*(rhoe[i][j] - rhoe_old[i][j])/dt;
                    nabla_rhoUe_sum   = nabla_rhoUe_sum   + volume*nabla_rhoUe;
                    rate_d_ionz_sum   = rate_d_ionz_sum   + volume*rhoe_old[i][j]*nu_ionz[i][j];
                    rate_s_ionz_sum   = rate_s_ionz_sum   + volume*rhoe_old[i][j]*nu_ionzStep[i][j];
                }
            }
        }

        //output particle balance for electron
        //------------------------------------
        std::string char1="results/particle_balance_electron";
        std::string char2=std::to_string(nOut);
        std::string char_csv=".csv";
        std::ofstream outputfile8(char1+char2+char_csv);
        outputfile8 << std::setprecision(std::numeric_limits<double>::max_digits10) << std::scientific;
        outputfile8<< "dN/dt (pcl/s), loss_to_bnd (pcl/s), direct-iz (pcl/s), sw-iz (pcl/s), sum (pcl/s)"<< std::endl;
        outputfile8<< dNedt_sum << "," << -nabla_rhoUe_sum << "," << rate_d_ionz_sum << ","<< rate_s_ionz_sum 
            << ","<< -dNedt_sum + (-nabla_rhoUe_sum + rate_d_ionz_sum + rate_s_ionz_sum)<< std::endl;
        outputfile8.close();
        //------------------------------------
    }
    //------------------------------------

    //set values of ghost cells for ES-potential calculation
    //=====================================================================================
    
    //left-wall-BC (chamber)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (magnet)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (antenna)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }

    //right-open-BC
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoe[i+1][j] = rhoe[i][j];
    }
    //------------------------------------

    //upper-open-BC
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoe[i][j+1] = rhoe[i][j];
    }
    //------------------------------------
    //=====================================================================================

    /*
    //Caluculate Current
    //------------------------------------
    Ii_Anode = 0.0;
    Ie_Anode = 0.0;
    I_Anode = 0.0;

    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Ti/(M_PI*massi));
        double um = sqrt(2.0*Boltz*Ti/massi);
        double utx_R = Uix[i+1][j]/(um + 1e-100);

        double rhoUix_tmp = rhoi[i][j]*0.25*vth*(exp(-utx_R*utx_R) + utx_R*sqrt(M_PI)*(erf(utx_R) + 1.0));
        
        double delta_Ii = rhoUix_tmp  *2.0*M_PI*r[j]*dr*( e0);
        double delta_Ie = rhoUex[i][j]*2.0*M_PI*r[j]*dr*(-e0);

        Ii_Anode = Ii_Anode + delta_Ii;
        Ie_Anode = Ie_Anode + delta_Ie;
        I_Anode =  I_Anode + delta_Ii + delta_Ie;
    }
    //------------------------------------
    */

    //Caluculate Current
    //------------------------------------
    Ii_Anode = 0.0;
    Ie_Anode = 0.0;
    I_Anode = 0.0;

    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        double vth = sqrt(8.0*Boltz*Ti/(M_PI*massi));
        double um = sqrt(2.0*Boltz*Ti/massi);
        double utx_R = Uix[i+1][j]/(um + 1e-100);

        double rhoUix_tmp = rhoi[i][j]*0.25*vth*(exp(-utx_R*utx_R) + utx_R*sqrt(M_PI)*(erf(utx_R) + 1.0));
        
        double delta_Ii = rhoUix_tmp  *2.0*M_PI*r[j]*dr*( e0);
        double delta_Ie = rhoUex[i+1][j]*2.0*M_PI*r[j]*dr*(-e0);

        Ii_Anode = Ii_Anode + delta_Ii;
        Ie_Anode = Ie_Anode + delta_Ie;
        I_Anode =  I_Anode + delta_Ii + delta_Ie;
    }
    //------------------------------------

    /*
    //Caluculate Current
    //------------------------------------
    Ii_Nozzle = 0.0;
    Ie_Nozzle = 0.0;
    I_Nozzle = 0.0;

    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Ti/(M_PI*massi));
        double um = sqrt(2.0*Boltz*Ti/massi);
        double utx_R = Uix[i+1][j]/(um + 1e-100);
        

        double rhoUix_tmp = rhoi[i][j]*0.25*vth*(exp(-utx_R*utx_R) + utx_R*sqrt(M_PI)*(erf(utx_R) + 1.0));
        
        double delta_Ii = rhoUix_tmp  *2.0*M_PI*r[j]*dr*( e0);
        double delta_Ie = rhoUex[i][j]*2.0*M_PI*r[j]*dr*(-e0);

        Ii_Anode = Ii_Anode + delta_Ii;
        Ie_Anode = Ie_Anode + delta_Ie;
        I_Anode =  I_Anode + delta_Ii + delta_Ie;
    }
        */
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoe = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_rhoUex = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_rhoUer = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_wSEE_wInertia_PC_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------


    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------
    
    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            drhoe[i][j] = rhoe[i][j] - rhoe_old[i][j];
        }
    }
    //------------------------------------

    //calculate maximum electron density to avoid zero-division in Te calc.
    //------------------------------------
    double rhoe_max = 0.0;
    double ratio_rhoe = 0.001;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }
    //------------------------------------

    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }
        //------------------------------------

        //Calculate temppolary flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qL = rL/r[j];
                    double qR = rR/r[j];
                    //------------------------------------

                    //values for upwind discretization
                    //==============================================
                    //flux at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = (rhoUex_old_tmp[i][j]   + rhoUex_old_tmp[i-1][j]  )/2.0;
                    double rhoUex_Rx = (rhoUex_old_tmp[i][j]   + rhoUex_old_tmp[i+1][j]  )/2.0;
                    double rhoUer_Lr = (rhoUer_old_tmp[i][j]   + rhoUer_old_tmp[i-1][j]  )/2.0;
                    double rhoUer_Rr = (rhoUer_old_tmp[i][j+1] + rhoUer_old_tmp[i-1][j+1])/2.0;
                    //------------------------------------

                    //density at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoe_Lx = rhoe[i-1][j];
                    double rhoe_Rx = rhoe[i][j];
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1] + rhoe[i-1][j] + rhoe[i-1][j+1])/4.0;
                    //------------------------------------

                    //velocity at cell (rhoUex control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------


                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_rr_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_inv_xx_tmp = mu_rr_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0; //electron temperature
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dx/D_tmp; //Peclet number
                    //------------------------------------
                    
                    //BC - set adjacent flag for rhoUer (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRrD + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //BC - set adjacent flag for 5 point (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLxI_wall  = double(i!=i_flx_bl[0][0] || iblock != 0); //z0
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[2][0] || j>j_flx_bl[0][0]-1); //z1
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[3][0] || j>j_flx_bl[2][0]-1); //z2
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[4][0] || j<j_flx_bl[1][0]); //z4
                    double bLxI  = bLxI_wall;
                    
                    //right
                    double bRxI_wall  = double(i!=i_flx_bl[1][1] || j<j_flx_bl[1][0]); //z3
                    bRxI_wall = bRxI_wall*double(i!=i_flx_bl[4][1]); //z5
                    double bRxI  = bRxI_wall;
                
                    //lower
                    double bLrI_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLrI_wall = bLrI_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                    double bLrI_cen = double(j!=j_flx_bl[3][0]); //x6
                    double bLrI  = bLrI_wall*bLrI_cen;

                    //upper
                    double bRrI_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                    bRrI_wall = bRrI_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    double bRrI_open  = (j!=j_flx_bl[4][1] || iblock != 4); //x5
                    double bRrI = bRrI_wall;
                    //------------------------------------

                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] = 1.0 + masse/e0*mu_star_tmp*(
                        +    (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)*bRxI
                        -    (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)*bLxI
                        + qR*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)*bRrI
                        - qL*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)*bLrI
                    );

                    aE[i][j] =    -mu_star_tmp*masse/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx)*bRxI;
                    aW[i][j] =     mu_star_tmp*masse/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx)*bLxI;
                    aN[i][j] = -qR*mu_star_tmp*masse/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr)*bRrI;
                    aS[i][j] =  qL*mu_star_tmp*masse/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr)*bLrI;
                    //------------------------------------
                    
                    //RHS
                    //------------------------------------
                    b[i][j] =
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j] 
                        + rhoUex_old_tmp[i][j] 
                        - mu_star_tmp*(mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)
                        + mu_star_tmp/dt*masse/e0*(rhoUex_old[i][j] - rhoUex_old_tmp[i][j]);;
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flx_bl[0][0];j<=j_flx_bl[0][1];j++){
            int i=i_flx_bl[0][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            b[i+1][j] = b[i+1][j] + aW[i+1][j]*rhoUex_wall;
            aW[i+1][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flx_bl[2][0];j<=j_flx_bl[0][0]-1;j++){
            int i=i_flx_bl[2][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aW[i][j]*rhoUex_wall;
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flx_bl[3][0];j<=j_flx_bl[2][0]-1;j++){
            int i=i_flx_bl[3][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aW[i][j]*rhoUex_wall;
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flx_bl[1][0];j<=j_flx_bl[4][1];j++){
            int i=i_flx_bl[4][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aW[i][j]*rhoUex_wall;
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flx_bl[1][0];j<=j_flx_bl[1][1];j++){
            int i=i_flx_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            double rhoUex_wall =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aE[i][j]*rhoUex_wall;
            aE[i][j] = 0.0;
            //------------------------------------

        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flx_bl[4][0];j<=j_flx_bl[4][1];j++){
            int i=i_flx_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            double rhoUex_wall =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aE[i][j]*rhoUex_wall;
            aE[i][j] = 0.0;
            //------------------------------------
        }
        //=====================================================================================

        //Solver
        //=====================================================================
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flx_bl,j_flx_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUex);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flx_bl,j_flx_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUex);
            //------------------------------------
        }
        //=====================================================================

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //=====================================================================================


        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double rL = (r[j-1]+r[j-2])/2.0;
                    double rR = (r[j+1]+r[j])/2.0;
                    //------------------------------------

                    //values for upwind discretization
                    //*****************************************************
                    //flux at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = ( r[j]*rhoUex_old_tmp[i][j]   + r[j-1]*rhoUex_old_tmp[i][j-1]  )/(2.0*r_tmp);
                    double rhoUex_Rx = ( r[j]*rhoUex_old_tmp[i+1][j] + r[j-1]*rhoUex_old_tmp[i+1][j-1])/(2.0*r_tmp);
                    double rhoUer_Lr = (r_tmp*rhoUer_old_tmp[i][j]   +     rL*rhoUer_old_tmp[i][j-1]  )/(2.0*r[j-1]);
                    double rhoUer_Rr = (r_tmp*rhoUer_old_tmp[i][j]   +     rR*rhoUer_old_tmp[i][j+1]  )/(2.0*r[j]);
                    //------------------------------------

                    //density at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoe_Lx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i+1][j] + rhoe[i+1][j-1])/4.0;
                    double rhoe_Lr = rhoe[i][j-1];
                    double rhoe_Rr = rhoe[i][j];
                    //------------------------------------

                    //velocity at cell (rhoUer control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_xx_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    
                    double mu_inv_rr_tmp = mu_xx_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0; //electron temperature
                    double dTedr_tmp = (Te[i][j] - Te[i][j-1])/dr; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dr/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag for rhoUex (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRxD + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //BC - set adjacent flag for 5 point (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLxI_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                    double bLxI  = bLxI_wall;
                    
                    //right
                    double bRxI_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRxI_wall = bRxI_wall*double(i!=i_flr_bl[4][1]); //z5
                    double bRxI  = bRxI_wall;
                
                    //lower
                    double bLrI_wall  = double(j!=j_flr_bl[0][0] || i>i_flr_bl[0][1]); //x0
                    bLrI_wall = bLrI_wall*double(j!=j_flr_bl[2][0] || i>i_flr_bl[2][1]); //x2
                    double bLrI_cen = double(j!=j_flr_bl[3][0]); //x6
                    double bLrI  = bLrI_wall*bLrI_cen;

                    //upper
                    double bRrI_wall  = double(j!=j_flr_bl[0][1] || iblock > 2); //x1
                    bRrI_wall = bRrI_wall*double(j!=j_flr_bl[3][1] || i<i_flr_bl[1][1]+1 || i>i_flr_bl[3][1]); //x4
                    double bRrI_open  = (j!=j_flr_bl[4][1] || iblock != 4); //x5
                    double bRrI = bRrI_wall;
                    //------------------------------------


                    //coefficient for ion momentum conservation for 5 point stencil
                    //*****************************************************
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] = 1.0 + masse/e0*mu_star_tmp*(
                        +              (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)*bRxI
                        -              (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)*bLxI
                        +   r[j]/r_tmp*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)*bRrI
                        - r[j-1]/r_tmp*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)*bLrI
                    );

                    aE[i][j] =              -mu_star_tmp*masse/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx)*bRxI;
                    aW[i][j] =               mu_star_tmp*masse/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx)*bLxI;
                    aN[i][j] = -r[j]  /r_tmp*mu_star_tmp*masse/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr)*bRrI;
                    aS[i][j] =  r[j-1]/r_tmp*mu_star_tmp*masse/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr)*bLrI;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    b[i][j] =  
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + rhoUer_old_tmp[i][j]
                        - mu_star_tmp*(mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])
                        + mu_star_tmp/dt*masse/e0*(rhoUer_old[i][j] - rhoUer_old_tmp[i][j]);
                    //------------------------------------
                }
            }
        }

        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flr_bl[0][0];i<=i_flr_bl[0][1];i++){
            int j=j_flr_bl[0][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;

            //modify coefficient
            //------------------------------------
            b[i][j+1] = b[i][j+1] + aS[i][j+1]*rhoUer_wall;
            aS[i][j+1] = 0.0;
            //------------------------------------

        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flr_bl[2][0];i<=i_flr_bl[2][1];i++){
            int j=j_flr_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
            
            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;

            //modify coefficient
            //------------------------------------
            b[i][j+1] = b[i][j+1] + aS[i][j+1]*rhoUer_wall;
            aS[i][j+1] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flr_bl[0][0];i<=i_flr_bl[1][1];i++){
            int j=j_flr_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aN[i][j]*rhoUer_wall;
            aN[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flr_bl[1][1]+1;i<=i_flr_bl[3][1];i++){
            int j=j_flr_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aN[i][j]*rhoUer_wall;
            aN[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flr_bl[4][0];i<=i_flr_bl[4][1];i++){
            int j=j_flr_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            double rhoUer_open =  Gamma_open_Rr;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aN[i][j]*rhoUer_open;
            aN[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //Solver
        //=====================================================================
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9; //acceleration factor
            solver_SOR(aP,aE,aW,aN,aS,b,i_flr_bl,j_flr_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUer);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flr_bl,j_flr_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUer);
            //------------------------------------
        }
        //=====================================================================

        
        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
            
            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            rhoUer[i][j+1] =  Gamma_open_Rr;
        }
        //------------------------------------


        //Make coefficient for electron continuity equation for 5 point stencil
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------
                    
                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron temperature at cell interface
                    //------------------------------------
                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;
                    //------------------------------------

                    //electron diffusion coefficient at cell interface
                    //------------------------------------
                    double D_Lx = Boltz*Te_Lx/e0*mu_star_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_star_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_star_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_star_Rr;
                    //------------------------------------

                    //electron temperature gradient at cell interface
                    //------------------------------------
                    double dTedx_Lx = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                    double dTedx_Rx = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                    double dTedr_Lr = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double dTedr_Rr = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                    //------------------------------------

                    //electron drift velocity at cell interface
                    //------------------------------------
                    double vd_Lx = mu_star_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_star_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_star_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_star_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;
                    //------------------------------------

                    //Peclet number at cell interface
                    //------------------------------------
                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    //coefficient for electron continuity equation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        + dx*dr/dt; //time-term
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j]
                        - (rhoe[i][j] - rhoe_old[i][j])/dt)*dx*dr; //time-term
                    //------------------------------------
                    //==============================================

                }
            }
        }
        //------------------------------------

        //Solver
        //------------------------------------
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }
        //------------------------------------

        //Correction
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUex = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double dTedr_tmp = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUer =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoe
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new;
                    }
                }
            }
        }
        //------------------------------------
        //==============================================

        //Caluculate residuals
        //=====================================================================================
        //rhoe
        //------------------------------------
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }
        //------------------------------------

        //r-directional flux
        //------------------------------------
        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        //------------------------------------
        //=====================================================================================
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //set values of ghost cells for ES-potential calculation
    //=====================================================================================
    
    //left-wall-BC (chamber)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (magnet)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (antenna)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }

    //right-open-BC
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoe[i+1][j] = rhoe[i][j];
    }
    //------------------------------------

    //upper-open-BC
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoe[i][j+1] = rhoe[i][j];
    }
    //------------------------------------
    //=====================================================================================


    //Caluculate Current
    //------------------------------------
    Ii_Anode = 0.0;
    Ie_Anode = 0.0;
    I_Anode = 0.0;

    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Ti/(M_PI*massi));
        double um = sqrt(2.0*Boltz*Ti/massi);
        double utx_R = Uix[i+1][j]/(um + 1e-100);

        double rhoUix_tmp = rhoi[i][j]*0.25*vth*(exp(-utx_R*utx_R) + utx_R*sqrt(M_PI)*(erf(utx_R) + 1.0));
        
        double delta_Ii = rhoUix_tmp  *2.0*M_PI*r[j]*dr*( e0);
        double delta_Ie = rhoUex[i][j]*2.0*M_PI*r[j]*dr*(-e0);

        Ii_Anode = Ii_Anode + delta_Ii;
        Ie_Anode = Ie_Anode + delta_Ie;
        I_Anode =  I_Anode + delta_Ii + delta_Ie;
    }
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoe = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_rhoUex = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_rhoUer = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_wSEE_wInertia_PC_old2(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------


    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------
    
    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            drhoe[i][j] = rhoe[i][j] - rhoe_old[i][j];
        }
    }
    //------------------------------------

    //calculate maximum electron density to avoid zero-division in Te calc.
    //------------------------------------
    double rhoe_max = 0.0;
    double ratio_rhoe = 0.001;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }
    //------------------------------------

    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }
        //------------------------------------

        //Calculate temppolary flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qL = rL/r[j];
                    double qR = rR/r[j];
                    //------------------------------------

                    //values for upwind discretization
                    //==============================================
                    //flux at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = (rhoUex_old_tmp[i][j]   + rhoUex_old_tmp[i-1][j]  )/2.0;
                    double rhoUex_Rx = (rhoUex_old_tmp[i][j]   + rhoUex_old_tmp[i+1][j]  )/2.0;
                    double rhoUer_Lr = (rhoUer_old_tmp[i][j]   + rhoUer_old_tmp[i-1][j]  )/2.0;
                    double rhoUer_Rr = (rhoUer_old_tmp[i][j+1] + rhoUer_old_tmp[i-1][j+1])/2.0;
                    //------------------------------------

                    //density at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoe_Lx = rhoe[i-1][j];
                    double rhoe_Rx = rhoe[i][j];
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1] + rhoe[i-1][j] + rhoe[i-1][j+1])/4.0;
                    //------------------------------------

                    //velocity at cell (rhoUex control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------


                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_rr_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_inv_xx_tmp = mu_rr_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0; //electron temperature
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dx/D_tmp; //Peclet number
                    //------------------------------------
                    
                    //BC - set adjacent flag for rhoUer (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRrD + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //BC - set adjacent flag for 5 point (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLxI_wall  = double(i!=i_flx_bl[0][0] || iblock != 0); //z0
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[2][0] || j>j_flx_bl[0][0]-1); //z1
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[3][0] || j>j_flx_bl[2][0]-1); //z2
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[4][0] || j<j_flx_bl[1][0]); //z4
                    double bLxI  = bLxI_wall;
                    
                    //right
                    double bRxI_wall  = double(i!=i_flx_bl[1][1] || j<j_flx_bl[1][0]); //z3
                    bRxI_wall = bRxI_wall*double(i!=i_flx_bl[4][1]); //z5
                    double bRxI  = bRxI_wall;
                
                    //lower
                    double bLrI_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLrI_wall = bLrI_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                    double bLrI_cen = double(j!=j_flx_bl[3][0]); //x6
                    double bLrI  = bLrI_wall*bLrI_cen;

                    //upper
                    double bRrI_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                    bRrI_wall = bRrI_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    double bRrI_open  = (j!=j_flx_bl[4][1] || iblock != 4); //x5
                    double bRrI = bRrI_wall;
                    //------------------------------------

                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] = 1.0 + masse/e0*mu_star_tmp*(
                        +    (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)*bRxI
                        -    (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)*bLxI
                        + qR*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)*bRrI
                        - qL*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)*bLrI
                    );

                    aE[i][j] =    -mu_star_tmp*masse/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx)*bRxI;
                    aW[i][j] =     mu_star_tmp*masse/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx)*bLxI;
                    aN[i][j] = -qR*mu_star_tmp*masse/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr)*bRrI;
                    aS[i][j] =  qL*mu_star_tmp*masse/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr)*bLrI;
                    //------------------------------------
                    
                    //RHS
                    //------------------------------------
                    b[i][j] =
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j] 
                        + rhoUex_old_tmp[i][j] 
                        - mu_star_tmp*(mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)
                        + mu_star_tmp/dt*masse/e0*(rhoUex_old[i][j] - rhoUex_old_tmp[i][j]);;
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        //Solver
        //=====================================================================
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flx_bl,j_flx_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUex);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flx_bl,j_flx_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUex);
            //------------------------------------
        }
        //=====================================================================

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //=====================================================================================


        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double rL = (r[j-1]+r[j-2])/2.0;
                    double rR = (r[j+1]+r[j])/2.0;
                    //------------------------------------

                    //values for upwind discretization
                    //*****************************************************
                    //flux at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = ( r[j]*rhoUex_old_tmp[i][j]   + r[j-1]*rhoUex_old_tmp[i][j-1]  )/(2.0*r_tmp);
                    double rhoUex_Rx = ( r[j]*rhoUex_old_tmp[i+1][j] + r[j-1]*rhoUex_old_tmp[i+1][j-1])/(2.0*r_tmp);
                    double rhoUer_Lr = (r_tmp*rhoUer_old_tmp[i][j]   +     rL*rhoUer_old_tmp[i][j-1]  )/(2.0*r[j-1]);
                    double rhoUer_Rr = (r_tmp*rhoUer_old_tmp[i][j]   +     rR*rhoUer_old_tmp[i][j+1]  )/(2.0*r[j]);
                    //------------------------------------

                    //density at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoe_Lx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i+1][j] + rhoe[i+1][j-1])/4.0;
                    double rhoe_Lr = rhoe[i][j-1];
                    double rhoe_Rr = rhoe[i][j];
                    //------------------------------------

                    //velocity at cell (rhoUer control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_xx_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    
                    double mu_inv_rr_tmp = mu_xx_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0; //electron temperature
                    double dTedr_tmp = (Te[i][j] - Te[i][j-1])/dr; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dr/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag for rhoUex (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRxD + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //BC - set adjacent flag for 5 point (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLxI_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                    double bLxI  = bLxI_wall;
                    
                    //right
                    double bRxI_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRxI_wall = bRxI_wall*double(i!=i_flr_bl[4][1]); //z5
                    double bRxI  = bRxI_wall;
                
                    //lower
                    double bLrI_wall  = double(j!=j_flr_bl[0][0] || i>i_flr_bl[0][1]); //x0
                    bLrI_wall = bLrI_wall*double(j!=j_flr_bl[2][0] || i>i_flr_bl[2][1]); //x2
                    double bLrI_cen = double(j!=j_flr_bl[3][0]); //x6
                    double bLrI  = bLrI_wall*bLrI_cen;

                    //upper
                    double bRrI_wall  = double(j!=j_flr_bl[0][1] || iblock > 2); //x1
                    bRrI_wall = bRrI_wall*double(j!=j_flr_bl[3][1] || i<i_flr_bl[1][1]+1 || i>i_flr_bl[3][1]); //x4
                    double bRrI_open  = (j!=j_flr_bl[4][1] || iblock != 4); //x5
                    double bRrI = bRrI_wall;
                    //------------------------------------


                    //coefficient for ion momentum conservation for 5 point stencil
                    //*****************************************************
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] = 1.0 + masse/e0*mu_star_tmp*(
                        +              (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)*bRxI
                        -              (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)*bLxI
                        +   r[j]/r_tmp*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)*bRrI
                        - r[j-1]/r_tmp*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)*bLrI
                    );

                    aE[i][j] =              -mu_star_tmp*masse/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx)*bRxI;
                    aW[i][j] =               mu_star_tmp*masse/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx)*bLxI;
                    aN[i][j] = -r[j]  /r_tmp*mu_star_tmp*masse/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr)*bRrI;
                    aS[i][j] =  r[j-1]/r_tmp*mu_star_tmp*masse/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr)*bLrI;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    b[i][j] =  
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + rhoUer_old_tmp[i][j]
                        - mu_star_tmp*(mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])
                        + mu_star_tmp/dt*masse/e0*(rhoUer_old[i][j] - rhoUer_old_tmp[i][j]);
                    //------------------------------------
                }
            }
        }

        //Solver
        //=====================================================================
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9; //acceleration factor
            solver_SOR(aP,aE,aW,aN,aS,b,i_flr_bl,j_flr_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUer);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flr_bl,j_flr_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUer);
            //------------------------------------
        }
        //=====================================================================

        
        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
            
            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            rhoUer[i][j+1] =  Gamma_open_Rr;
        }
        //------------------------------------

        //Make coefficient for electron continuity equation for 5 point stencil
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------
                    
                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron temperature at cell interface
                    //------------------------------------
                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;
                    //------------------------------------

                    //electron diffusion coefficient at cell interface
                    //------------------------------------
                    double D_Lx = Boltz*Te_Lx/e0*mu_star_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_star_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_star_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_star_Rr;
                    //------------------------------------

                    //electron temperature gradient at cell interface
                    //------------------------------------
                    double dTedx_Lx = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                    double dTedx_Rx = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                    double dTedr_Lr = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double dTedr_Rr = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                    //------------------------------------

                    //electron drift velocity at cell interface
                    //------------------------------------
                    double vd_Lx = mu_star_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_star_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_star_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_star_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;
                    //------------------------------------

                    //Peclet number at cell interface
                    //------------------------------------
                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    //coefficient for electron continuity equation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        + dx*dr/dt; //time-term
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j]
                        - (rhoe[i][j] - rhoe_old[i][j])/dt)*dx*dr; //time-term
                    //------------------------------------
                    //==============================================

                }
            }
        }
        //------------------------------------

        //Solver
        //------------------------------------
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }
        //------------------------------------

        //Correction
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUex = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double dTedr_tmp = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUer =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoe
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new;
                    }
                }
            }
        }
        //------------------------------------
        //==============================================

        //Caluculate residuals
        //=====================================================================================
        //rhoe
        //------------------------------------
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }
        //------------------------------------

        //r-directional flux
        //------------------------------------
        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        //------------------------------------
        //=====================================================================================
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //set values of ghost cells for ES-potential calculation
    //=====================================================================================
    
    //left-wall-BC (chamber)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (magnet)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (antenna)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }

    //right-open-BC
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoe[i+1][j] = rhoe[i][j];
    }
    //------------------------------------

    //upper-open-BC
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoe[i][j+1] = rhoe[i][j];
    }
    //------------------------------------
    //=====================================================================================


    //Caluculate Current
    //------------------------------------
    Ii_Anode = 0.0;
    Ie_Anode = 0.0;
    I_Anode = 0.0;

    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Ti/(M_PI*massi));
        double um = sqrt(2.0*Boltz*Ti/massi);
        double utx_R = Uix[i+1][j]/(um + 1e-100);

        double rhoUix_tmp = rhoi[i][j]*0.25*vth*(exp(-utx_R*utx_R) + utx_R*sqrt(M_PI)*(erf(utx_R) + 1.0));
        
        double delta_Ii = rhoUix_tmp  *2.0*M_PI*r[j]*dr*( e0);
        double delta_Ie = rhoUex[i][j]*2.0*M_PI*r[j]*dr*(-e0);

        Ii_Anode = Ii_Anode + delta_Ii;
        Ie_Anode = Ie_Anode + delta_Ie;
        I_Anode =  I_Anode + delta_Ii + delta_Ie;
    }
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoe = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_rhoUex = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_rhoUer = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_wdTe_wSEE_wInertia_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------


    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------
    
    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            drhoe[i][j] = rhoe[i][j] - rhoe_old[i][j];
        }
    }
    //------------------------------------

    //calculate maximum electron density to avoid zero-division in Te calc.
    //------------------------------------
    double rhoe_max = 0.0;
    double ratio_rhoe = 0.001;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }
    //------------------------------------

    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }
        //------------------------------------

        //Calculate temppolary flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qL = rL/r[j];
                    double qR = rR/r[j];
                    //------------------------------------

                    //values for upwind discretization
                    //==============================================
                    //flux at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = (rhoUex_old_tmp[i][j]   + rhoUex_old_tmp[i-1][j]  )/2.0;
                    double rhoUex_Rx = (rhoUex_old_tmp[i][j]   + rhoUex_old_tmp[i+1][j]  )/2.0;
                    double rhoUer_Lr = (rhoUer_old_tmp[i][j]   + rhoUer_old_tmp[i-1][j]  )/2.0;
                    double rhoUer_Rr = (rhoUer_old_tmp[i][j+1] + rhoUer_old_tmp[i-1][j+1])/2.0;
                    //------------------------------------

                    //density at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoe_Lx = rhoe[i-1][j];
                    double rhoe_Rx = rhoe[i][j];
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1] + rhoe[i-1][j] + rhoe[i-1][j+1])/4.0;
                    //------------------------------------

                    //velocity at cell (rhoUex control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------


                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_rr_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_inv_xx_tmp = mu_rr_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0; //electron temperature
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dx/D_tmp; //Peclet number
                    //------------------------------------
                    
                    //BC - set adjacent flag for rhoUer (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRrD + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //BC - set adjacent flag for 5 point (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //lower
                    double bLrI_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLrI_wall = bLrI_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                    double bLrI_cen = double(j!=j_flx_bl[3][0]); //x6
                    double bLrI  = bLrI_wall*bLrI_cen;

                    //upper
                    double bRrI_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                    bRrI_wall = bRrI_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    double bRrI_open  = (j!=j_flx_bl[4][1] || iblock != 4); //x5
                    double bRrI = bRrI_wall;
                    //------------------------------------

                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] = 1.0 + masse*scale_inertia/e0*mu_star_tmp*(
                        +    (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)
                        -    (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)
                        + qR*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)*bRrI
                        - qL*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)*bLrI
                    );

                    aE[i][j] =    -mu_star_tmp*masse*scale_inertia/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx);
                    aW[i][j] =     mu_star_tmp*masse*scale_inertia/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx);
                    aN[i][j] = -qR*mu_star_tmp*masse*scale_inertia/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr)*bRrI;
                    aS[i][j] =  qL*mu_star_tmp*masse*scale_inertia/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr)*bLrI;
                    //------------------------------------
                    
                    //RHS
                    //------------------------------------
                    b[i][j] =
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j] 
                        + rhoUex_old_tmp[i][j] 
                        - mu_star_tmp*(mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)
                        + mu_star_tmp/dt*masse*scale_inertia/e0*(rhoUex_old[i][j] - rhoUex_old_tmp[i][j]);;
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flx_bl[0][0];j<=j_flx_bl[0][1];j++){
            int i=i_flx_bl[0][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            //b[i+1][j] = b[i+1][j] + aW[i+1][j]*rhoUex_wall;
            aW[i+1][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flx_bl[2][0];j<=j_flx_bl[0][0]-1;j++){
            int i=i_flx_bl[2][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            //b[i][j] = b[i][j] + aW[i][j]*rhoUex_wall;
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flx_bl[3][0];j<=j_flx_bl[2][0]-1;j++){
            int i=i_flx_bl[3][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            //b[i][j] = b[i][j] + aW[i][j]*rhoUex_wall;
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flx_bl[1][0];j<=j_flx_bl[4][1];j++){
            int i=i_flx_bl[4][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            double rhoUex_wall = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;

            //modify coefficient
            //------------------------------------
            //b[i][j] = b[i][j] + aW[i][j]*rhoUex_wall;
            aW[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flx_bl[1][0];j<=j_flx_bl[1][1];j++){
            int i=i_flx_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            double rhoUex_wall =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;

            //modify coefficient
            //------------------------------------
            //b[i][j] = b[i][j] + aE[i][j]*rhoUex_wall;
            aE[i][j] = 0.0;
            //------------------------------------

        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flx_bl[4][0];j<=j_flx_bl[4][1];j++){
            int i=i_flx_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            double rhoUex_wall =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;

            //modify coefficient
            //------------------------------------
            //b[i][j] = b[i][j] + aE[i][j]*rhoUex_wall;
            aE[i][j] = 0.0;
            //------------------------------------
        }
        //=====================================================================================

        //Solver
        //=====================================================================
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flx_bl,j_flx_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUex);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flx_bl,j_flx_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUex);
            //------------------------------------
        }
        //=====================================================================

        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = -coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            -coefMISEE_ts*rhoUmx[i][j]; //MISEE
            rhoUex[i][j] = rhoe[i][j]*GammaPerN_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------
    
        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //------------------------------------
    
        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = -coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                            -coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
            rhoUex[i+1][j] =  rhoe[i][j]*GammaPerN_wall_Rx + Gamma_wallSEE_Rx;
        }
        //=====================================================================================


        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){

                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double rL = (r[j-1]+r[j-2])/2.0;
                    double rR = (r[j+1]+r[j])/2.0;
                    //------------------------------------

                    //values for upwind discretization
                    //*****************************************************
                    //flux at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = ( r[j]*rhoUex_old_tmp[i][j]   + r[j-1]*rhoUex_old_tmp[i][j-1]  )/(2.0*r_tmp);
                    double rhoUex_Rx = ( r[j]*rhoUex_old_tmp[i+1][j] + r[j-1]*rhoUex_old_tmp[i+1][j-1])/(2.0*r_tmp);
                    double rhoUer_Lr = (r_tmp*rhoUer_old_tmp[i][j]   +     rL*rhoUer_old_tmp[i][j-1]  )/(2.0*r[j-1]);
                    double rhoUer_Rr = (r_tmp*rhoUer_old_tmp[i][j]   +     rR*rhoUer_old_tmp[i][j+1]  )/(2.0*r[j]);
                    //------------------------------------

                    //density at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoe_Lx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i+1][j] + rhoe[i+1][j-1])/4.0;
                    double rhoe_Lr = rhoe[i][j-1];
                    double rhoe_Rr = rhoe[i][j];
                    //------------------------------------

                    //velocity at cell (rhoUer control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_xx_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_xr_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    
                    double mu_inv_rr_tmp = mu_xx_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_xr_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0; //electron temperature
                    double dTedr_tmp = (Te[i][j] - Te[i][j-1])/dr; //electron temperature gradient
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dr/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag for rhoUex (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRxD + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //BC - set adjacent flag for 5 point (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLxI_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                    double bLxI  = bLxI_wall;
                    
                    //right
                    double bRxI_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRxI_wall = bRxI_wall*double(i!=i_flr_bl[4][1]); //z5
                    double bRxI  = bRxI_wall;
                    //------------------------------------


                    //coefficient for ion momentum conservation for 5 point stencil
                    //*****************************************************
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] = 1.0 + masse*scale_inertia/e0*mu_star_tmp*(
                        +              (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)*bRxI
                        -              (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)*bLxI
                        +   r[j]/r_tmp*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)
                        - r[j-1]/r_tmp*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)
                    );

                    aE[i][j] =              -mu_star_tmp*masse*scale_inertia/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx)*bRxI;
                    aW[i][j] =               mu_star_tmp*masse*scale_inertia/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx)*bLxI;
                    aN[i][j] = -r[j]  /r_tmp*mu_star_tmp*masse*scale_inertia/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr);
                    aS[i][j] =  r[j-1]/r_tmp*mu_star_tmp*masse*scale_inertia/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr);
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    b[i][j] =  
                          vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + rhoUer_old_tmp[i][j]
                        - mu_star_tmp*(mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])
                        + mu_star_tmp/dt*masse*scale_inertia/e0*(rhoUer_old[i][j] - rhoUer_old_tmp[i][j]);
                    //------------------------------------
                }
            }
        }

        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flr_bl[0][0];i<=i_flr_bl[0][1];i++){
            int j=j_flr_bl[0][0]-1;
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;

            //modify coefficient
            //------------------------------------
            //b[i][j+1] = b[i][j+1] + aS[i][j+1]*rhoUer_wall;
            aS[i][j+1] = 0.0;
            //------------------------------------

        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flr_bl[2][0];i<=i_flr_bl[2][1];i++){
            int j=j_flr_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
            
            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;

            //modify coefficient
            //------------------------------------
            //b[i][j+1] = b[i][j+1] + aS[i][j+1]*rhoUer_wall;
            aS[i][j+1] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flr_bl[0][0];i<=i_flr_bl[1][1];i++){
            int j=j_flr_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;

            //modify coefficient
            //------------------------------------
            //b[i][j] = b[i][j] + aN[i][j]*rhoUer_wall;
            aN[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flr_bl[1][1]+1;i<=i_flr_bl[3][1];i++){
            int j=j_flr_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            double rhoUer_wall = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;

            //modify coefficient
            //------------------------------------
            //b[i][j] = b[i][j] + aN[i][j]*rhoUer_wall;
            aN[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flr_bl[4][0];i<=i_flr_bl[4][1];i++){
            int j=j_flr_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            double rhoUer_open =  Gamma_open_Rr;

            //modify coefficient
            //------------------------------------
            b[i][j] = b[i][j] + aN[i][j]*rhoUer_open;
            aN[i][j] = 0.0;
            //------------------------------------
        }
        //------------------------------------

        //Solver
        //=====================================================================
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9; //acceleration factor
            solver_SOR(aP,aE,aW,aN,aS,b,i_flr_bl,j_flr_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUer);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flr_bl,j_flr_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoUer);
            //------------------------------------
        }
        //=====================================================================

        
        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));
            
            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j]; //MISEE
            rhoUer[i][j] = rhoe[i][j]*GammaPerN_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------

        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = -coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                            -(coefEISEE_eb + coefEISEE_rd + coefEISEE_ts)*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                            -coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
            rhoUer[i][j+1] = rhoe[i][j]*GammaPerN_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------

        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double rhoUir_Rr = rhoi[i][j]*Uir[i][j+1];
            double Gamma_open_Rr = rhoUir_Rr;
            rhoUer[i][j+1] =  Gamma_open_Rr;
        }
        //------------------------------------


        //Make coefficient for electron continuity equation for 5 point stencil
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------
                    
                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron temperature at cell interface
                    //------------------------------------
                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;
                    //------------------------------------

                    //electron diffusion coefficient at cell interface
                    //------------------------------------
                    double D_Lx = Boltz*Te_Lx/e0*mu_star_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_star_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_star_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_star_Rr;
                    //------------------------------------

                    //electron temperature gradient at cell interface
                    //------------------------------------
                    double dTedx_Lx = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                    double dTedx_Rx = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                    double dTedr_Lr = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double dTedr_Rr = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                    //------------------------------------

                    //electron drift velocity at cell interface
                    //------------------------------------
                    double vd_Lx = mu_star_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_star_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_star_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_star_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;
                    //------------------------------------

                    //Peclet number at cell interface
                    //------------------------------------
                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    //coefficient for electron continuity equation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        + dx*dr/dt; //time-term
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j]
                        - (rhoe[i][j] - rhoe_old[i][j])/dt)*dx*dr; //time-term
                    //------------------------------------
                    //==============================================

                }
            }
        }
        //------------------------------------

        //Solver
        //------------------------------------
        if(icon_iter_rhoe == 0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }else{
            //Semi-coarse Multi-Grid by Hypre
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
            //------------------------------------
        }
        //------------------------------------

        //Correction
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUex = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double dTedr_tmp = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double drhoUer =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //for rhoe
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new;
                    }
                }
            }
        }
        //------------------------------------
        //==============================================

        //Caluculate residuals
        //=====================================================================================
        //rhoe
        //------------------------------------
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }
        //------------------------------------

        //r-directional flux
        //------------------------------------
        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        //------------------------------------
        //=====================================================================================
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //set values of ghost cells for ES-potential calculation
    //=====================================================================================
    
    //left-wall-BC (chamber)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //left-wall-BC (magnet)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        rhoe[i-1][j] = 0.0;
    }
    //------------------------------------

    //lower-wall-BC (antenna)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        rhoe[i][j-1] = 0.0;
    }

    //right-open-BC
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoe[i+1][j] = rhoe[i][j];
    }
    //------------------------------------

    //upper-open-BC
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoe[i][j+1] = rhoe[i][j];
    }
    //------------------------------------
    //=====================================================================================


    //Caluculate Current
    //------------------------------------
    Ii_Anode = 0.0;
    Ie_Anode = 0.0;
    I_Anode = 0.0;

    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Ti/(M_PI*massi));
        double um = sqrt(2.0*Boltz*Ti/massi);
        double utx_R = Uix[i+1][j]/(um + 1e-100);

        double rhoUix_tmp = rhoi[i][j]*0.25*vth*(exp(-utx_R*utx_R) + utx_R*sqrt(M_PI)*(erf(utx_R) + 1.0));
        
        double delta_Ii = rhoUix_tmp  *2.0*M_PI*r[j]*dr*( e0);
        double delta_Ie = rhoUex[i][j]*2.0*M_PI*r[j]*dr*(-e0);

        Ii_Anode = Ii_Anode + delta_Ii;
        Ie_Anode = Ie_Anode + delta_Ie;
        I_Anode =  I_Anode + delta_Ii + delta_Ie;
    }
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoe = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_rhoUex = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_rhoUer = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_Te_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUer(ni+2,std::vector<double>(nj+2,0.0));

    std::vector<std::vector<double> > rhoeps_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gx_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gr_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoeps(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGx(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGr(ni+2,std::vector<double>(nj+2,0.0));


    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            drhoe[i][j] = rhoe[i][j] - rhoe_old[i][j];
            drhoeps[i][j] = rhoeps[i][j] - rhoeps_old[i][j];

            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];

            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRr + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;                   

                    rhoUex[i][j] = rhoUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRx + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    rhoUer[i][j] =  rhoUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j] + mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j] + mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                    double Te_Rx = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                    double Te_Lr = (Te_old[i][j]+Te_old[i][j-1])/2.0;
                    double Te_Rr = (Te_old[i][j]+Te_old[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                        +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                        + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                        + dx*dr/dt + dx*dr/dtau*double(icon_dtau); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        - (rhoe[i][j] - rhoe_old[i][j])/dt )*dx*dr;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }

        /********************* 更新 *******************/
        //drhoUexを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    drhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //drhoUerを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    drhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //密度更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new; //正の密度だった時だけ更新
                    }
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer[i][j];
                }
            }
        }



        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoeps_old_tmp[i][j] = rhoeps[i][j];
                Gx_old_tmp[i][j] = Gx[i][j];
                Gr_old_tmp[i][j] = Gr[i][j];
            }
        }

        //Gx更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //前ステップから
                    double Gr_tmp = (rR*Gr_old_tmp[i][j+1]*bRr + rL*Gr_old_tmp[i][j]*bLr 
                        + rR*Gr_old_tmp[i-1][j+1]*bRr + rL*Gr_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //前ステップから
                    Gx[i][j] = Gx_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*Gx_old_tmp[i][j] + mu_inv_xr_tmp*Gr_tmp)*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;
                    
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                        Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                    }
                    //右は電子フラックス x 5/2kTe
                    if(i == i_flc_bl[1][1]+1){
                        Gx[i][j] = 5.0/2.0*Boltz*Te_old[i-1][j]*rhoUex[i][j];
                    }
                }
            }     
        }

        //Gr更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //前のステップから
                    double Gx_tmp = (r[j]*Gx_old_tmp[i+1][j]*bRx + r[j]*Gx_old_tmp[i][j]*bLx
                        + r[j-1]*Gx_old_tmp[i+1][j-1]*bRx + r[j-1]*Gx_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    Gr[i][j] = Gr_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*Gx_tmp + mu_inv_rr_tmp*Gr_old_tmp[i][j])*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;

                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
                    
                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                        Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                    }    

                    //上はイオンフラックスと同じ
                    if(j == j_flc_bl[1][1]+1){
                        Gr[i][j] = 5.0/2.0*Boltz*Te_old[i][j-1]*rhoUer[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j]*double(j!=j_flc_bl[1][0]);

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                    double Te_Rx = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                    double Te_Lr = (Te_old[i][j]+Te_old[i][j-1])/2.0;
                    double Te_Rr = (Te_old[i][j]+Te_old[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx ;
                    double nbLr  = 1.0 - bLr ;

                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr 
                             +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                             + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                             + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                             +    0.2*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                             + qL*0.2*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                             + 3.0/5.0*delossdeps[i][j]*dx*dr //陰的ソース項予測
                             + 3.0/5.0*(dx*dr/dt + dx*dr/dtau*double(icon_dtau)); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;

                    double nabla_G = (Gx[i+1][j]-Gx[i][j])/dx + (qR*Gr[i][j+1]-qL*Gr[i][j])/dr;
                    double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                    double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                    double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                    double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                    double RHS1 = (-rhoeps[i][j] + rhoeps_old[i][j])/dt;
                    double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                    double RHS3 = Pabs[i][j] 
                        - rhoe[i][j]*rate_eloss[i][j] 
                        - delossdeps[i][j]*rhoeps[i][j]
                        + rhoe[i][j]*(1.5*Boltz*Te[i][j])*delossdeps[i][j]; //陰的ソース項予測
                        
                    double RHS4 = -nabla_G;

                    b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3 + RHS4)*dx*dr;
                }
            }
        }

        //solve
        double alpha_SOR = 1.0;
        int icon_iter = 1;

        if(icon_iter_rhoeps==0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }

        /********************* 更新 *******************/
        //dGxを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //フラックス
                    dGx[i][j] = (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }   
        }
        //dGrを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    dGr[i][j] =  (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }
        }
        
        //更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //rhoeps[i][j] = fmax(rhoeps[i][j] + drhoeps[i][j],1e-6);
                    double rhoeps_new = rhoeps[i][j] + drhoeps[i][j];
                    if(rhoeps_new > 0.0){
                        rhoeps[i][j] = rhoeps_new;
                    }
                }
            }
        }
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    Gx[i][j] = Gx[i][j] + dGx[i][j];
                }
            }
        }
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    Gr[i][j] = Gr[i][j] + dGr[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoeps2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoeps_tmp = fabs((rhoeps[i][j]-rhoeps_old_tmp[i][j])/(rhoeps[i][j]+rhoeps_old_tmp[i][j]+1e-100));
                        if(error_rhoeps_tmp > error_rhoeps2){
                            error_rhoeps2 = error_rhoeps_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoeps = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoeps2 += pow(rhoeps[i][j]-rhoeps_old_tmp[i][j],2)/(pow(rhoeps_old_tmp[i][j]+1e10,2));
                        ncount_rhoeps++;
                    }
                }
            }
            error_rhoeps2 = sqrt(error_rhoeps2/double(ncount_rhoeps));
        }

        double error_Gx2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_Gx_tmp = fabs((Gx[i][j]-Gx_old_tmp[i][j])/(Gx[i][j]+Gx_old_tmp[i][j]+1e-100));
                        if(error_Gx_tmp > error_Gx2){
                            error_Gx2 = error_Gx_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gx = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_Gx2 += pow(Gx[i][j]-Gx_old_tmp[i][j],2)/(pow(Gx_old_tmp[i][j]+1e16,2));
                        ncount_Gx++;
                    }
                }
            }
            error_Gx2 = sqrt(error_Gx2/double(ncount_Gx));
        }

        double error_Gr2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_Gr_tmp = fabs((Gr[i][j]-Gr_old_tmp[i][j])/(Gr[i][j]+Gr_old_tmp[i][j]+1e-100));
                        if(error_Gr_tmp > error_Gr2){
                            error_Gr2 = error_Gr_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gr = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_Gr2 += pow(Gr[i][j]-Gr_old_tmp[i][j],2)/(pow(Gr_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_Gr++;
                    }
                }
            }
            error_Gr2 = sqrt(error_Gr2/double(ncount_Gr));
        }

        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        error_global = fmax(fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2),error_global);

        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_rhoeps = " << error_rhoeps2
                <<  " error_Gx = " << error_Gx2
                <<  " error_Gr= " << error_Gr2
                <<  " error_max = " << error_global
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_rhoe_Te = "<< ncount <<std::endl;

    //電子密度の最大値を計算しておく
    double rhoe_max = 0.0;
    double ratio = 0.1;
    double Te_max = 20.0*e0/Boltz;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }

    //温度を更新
    //double alpha = 1.0;
    ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    ncount ++;
                    //rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                    rhoeps[i][j] = fmax(rhoeps[i][j],0.0);
                }
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100)*(1.0 + ratio),Te_max);
            }
        }
    }

    //輸送係数用に入れておく
    //左 壁1
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
        rhoe[i-1][j] = 0.0;
    }

    //左 壁2
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        Te[i-1][j] = Te[i][j];
        rhoe[i-1][j] = 0.0;
    }

    //下 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
        rhoe[i][j-1] = 0.0;
    }

    //右 ノイマン
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        Te[i+1][j]  =  Te[i][j];
        rhoe[i+1][j]  =  rhoe[i][j];
    }

    //上 ノイマン
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        Te[i][j+1] =  Te[i][j];
        rhoe[i][j+1] =  rhoe[i][j];
    }

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}



//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_TV_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            //std::cout << "Block = "  << iblock  << std::endl;
            //std::cout << " i = "  << i_flc_bl[iblock][0]  << " ~ "<<i_flc_bl[iblock][1] + iblock << std::endl;
            //std::cout << " j = "  << j_flc_bl[iblock][0] << " ~ "<< j_flc_bl[iblock][1] << std::endl;
            //std::cout <<  std::endl;
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    //前ステップから
                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j] 
                        + rR*rhoUer_old_tmp[i-1][j+1] + rL*rhoUer_old_tmp[i-1][j])/(4.0*r[j]);

                    //double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    //double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    //double mu_min_tmp = mu_perp_tmp*ratioX;
                    //double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    //double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double cx_tmp = (cx[i][j] + cx[i-1][j])/2.0;
                    double sx_tmp = (sx[i][j] + sx[i-1][j])/2.0;

                    double vd_tmp = cx_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cx_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    
                    //壁の接線方向処理
                    if(bLrD == 0 || bRr == 0){
                        sx_tmp = 0.0;
                    }

                    //前ステップから
                    rhoUex[i][j] = 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sx_tmp*rhoUer_tmp;
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_tmp + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        //    int i=i_flc_bl[1][1];
        //    rhoUex[i+1][j] = rhoUex[i][j];
        //}

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            //std::cout << "Block = "  << iblock  << std::endl;
            //std::cout << " i = "  << i_flc_bl[iblock][0]  << " ~ "<< i_flc_bl[iblock][1] << std::endl;
            //std::cout << " j = "  << j_flc_bl[iblock][0] + iblock << " ~ "<< j_flc_bl[iblock][1]+1 << std::endl;
            //std::cout <<  std::endl;
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    //前のステップから
                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j] 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1] + r[j-1]*rhoUex_old_tmp[i][j-1])/(4.0*r_tmp);
                    
                    double sr_tmp = (sr[i][j] + r[j-1])/2.0;
                    double cr_tmp = (cr[i][j] + r[j-1])/2.0;
    
                    double vd_tmp = cr_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cr_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //壁の接線方向処理
                    if(bLxD == 0 || bRx == 0){
                        sr_tmp = 0.0;
                    }

                    //前のステップから
                    rhoUer[i][j] =  
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sr_tmp*rhoUex_tmp;

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double cx_Lx = (cx[i][j] + cx[i-1][j])/2.0;
                    double cx_Rx = (cx[i][j] + cx[i+1][j])/2.0;
                    double cr_Lr = (cr[i][j] + cr[i][j-1])/2.0;
                    double cr_Rr = (cr[i][j] + cr[i][j+1])/2.0;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*cx_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*cx_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*cr_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*cr_Rr;

                    double vd_Lx = cx_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = cx_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = cr_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = cr_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double sx_Lx = (sx[i][j] + sx[i-1][j])/2.0;
                    double sx_Rx = (sx[i][j] + sx[i+1][j])/2.0;
                    double sr_Lr = (sr[i][j] + sr[i][j-1])/2.0;
                    double sr_Rr = (sr[i][j] + sr[i][j+1])/2.0;

                    double rhoUer_Lx = (rR*rhoUer[i][j+1]   + rL*rhoUer[i][j]   
                                + rR*rhoUer[i-1][j+1] + rL*rhoUer[i-1][j])/(4.0*r[j]);
                    double rhoUer_Rx = (rR*rhoUer[i+1][j+1] + rL*rhoUer[i+1][j] 
                            + rR*rhoUer[i][j+1]   + rL*rhoUer[i][j]  )/(4.0*r[j]);
                    double rhoUex_Lr =(r[j]*rhoUex[i+1][j]   + r[j]*rhoUex[i][j]   
                            + r[j-1]*rhoUex[i+1][j-1] + r[j-1]*rhoUex[i][j-1])/(4.0*rL+1e-100);
                    double rhoUex_Rr = (r[j+1]*rhoUex[i+1][j+1] + r[j+1]*rhoUex[i][j+1] 
                        + r[j]*rhoUex[i+1][j]   + r[j]*rhoUex[i][j]  )/(4.0*rR);

                    //double nu_ionz_tmp = nu_ionz[i][j] + nu_ionzStep[i][j];
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    //double bLxU = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j+1>=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    //double bRxU = double(i!=i_flc_bl[1][1]);
                    //double bRxD = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    //double bLrU = double(j!=j_flc_bl[0][0] || i+1>=i_flc_bl[1][0]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //壁の接線方向の処理
                    if(bLxD == 0 || bRx == 0){
                        sr_Lr = 0.0;
                    }
                    if(bLx == 0 || bRx == 0){
                        sr_Rr = 0.0;
                    }
                    if(bLrD == 0 || bRr == 0){
                        sx_Lx = 0.0;
                    }
                    if(bLr == 0 || bRr == 0){
                        sx_Rx = 0.0;
                    }

                    //フラックス第2項
                    double Fx_Lx = sx_Lx*rhoUer_Lx;
                    double Fx_Rx = sx_Rx*rhoUer_Rx;
                    double Fr_Lr = sr_Lr*rhoUex_Lr;
                    double Fr_Rr = sr_Rr*rhoUex_Rr;

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    double rhoi_Rx  = (rhoi[i][j]+rhoi[i+1][j])/2.0;
                    double rhoi_Rr  = (rhoi[i][j]+rhoi[i][j+1])/2.0;

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        +    0.25*vth*exp(fmin(-z_Lx/2.0,lim_exp))*dr*nbLx //陰的指定
                        + qL*0.25*vth*exp(fmin(-z_Lr/2.0,lim_exp))*dx*nbLr //陰的指定
                        + dx*dr/dt; //時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double nabla_rhoUe_tmp = (Fx_Rx - Fx_Lx)/dx + (qR*Fr_Rr - qL*Fr_Lr)/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        + (-rhoe[i][j] + rhoe_old[i][j])/dt )*dx*dr
                        + (0.0
                            //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                        )*dr
                      - (
                          rhoi_Rx*Uix[i+1][j]*nbRx //右壁境界
                        )*dr
                      + qL*(0.0
                            //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                            //-0.25*delta_n_Lr*vth*nbLr
                        )*dx
                      - qR*(
                          rhoi_Rr*Uir[i][j+1]*nbRr //上壁境界
                        )*dx;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }

        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                //std::cout << "Block = "  << iblock  << std::endl;
                //std::cout << " i = "  << i_flc_bl[iblock][0] + 1 - iblock << " ~ "<<i_flc_bl[iblock][1] + iblock << std::endl;
                //std::cout << " j = "  << j_flc_bl[iblock][0] << " ~ "<< j_flc_bl[iblock][1] << std::endl;
                //std::cout <<  std::endl;
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                //std::cout << "Block = "  << iblock  << std::endl;
                //std::cout << " i = "  << i_flc_bl[iblock][0] + 1 - iblock << " ~ "<<i_flc_bl[iblock][1] + iblock << std::endl;
                //std::cout << " j = "  << j_flc_bl[iblock][0] << " ~ "<< j_flc_bl[iblock][1] << std::endl;
                //std::cout <<  std::endl;
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                //std::cout << "Block = "  << iblock  << std::endl;
                //std::cout << " i = "  << i_flc_bl[iblock][0]  << " ~ "<< i_flc_bl[iblock][1] << std::endl;
                //std::cout << " j = "  << j_flc_bl[iblock][0] + iblock << " ~ "<< j_flc_bl[iblock][1]+1 << std::endl;
                //std::cout <<  std::endl;
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                //std::cout << "Block = "  << iblock  << std::endl;
                //std::cout << " i = "  << i_flc_bl[iblock][0]  << " ~ "<< i_flc_bl[iblock][1] << std::endl;
                //std::cout << " j = "  << j_flc_bl[iblock][0] + iblock << " ~ "<< j_flc_bl[iblock][1]+1 << std::endl;
                //std::cout <<  std::endl;
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);


    //ゴーストセル以外で負になっているところがあれば戻す
    ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhoe[i][j]<< std::endl; 
                    ncount ++;
                    //rhoe[i][j] = fmax(rhoe_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhoe count = " << ncount << std::endl;
    }

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_TV_old2(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 1;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRr + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double cx_tmp = (cx[i][j]/mu_para[i][j] + cx[i-1][j]/mu_para[i-1][j])/2.0;
                    double sx_tmp = (sx[i][j] + sx[i-1][j])/2.0;
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double vd_tmp = mu_para_tmp*(-Ex[i][j]) + EPS;

                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_para_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;                   

                    rhoUex[i][j] = cx_tmp*vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - cx_tmp*vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sx_tmp*rhoUer_tmp;
                    
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRx + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double cr_tmp = (cr[i][j]/mu_para[i][j] + cr[i][j-1]/mu_para[i][j-1])/2.0;
                    double sr_tmp = (sr[i][j] + sr[i][j-1])/2.0;

                    double vd_tmp = mu_para_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_para_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    rhoUer[i][j] =  cr_tmp*vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - cr_tmp*vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sr_tmp*rhoUex_tmp;

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_para_Lx = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                    double mu_para_Rx = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                    double mu_para_Lr = (mu_para[i][j]+mu_para[i][j-1])/2.0;
                    double mu_para_Rr = (mu_para[i][j]+mu_para[i][j+1])/2.0;

                    double cx_Lx = (cx[i][j]/mu_para[i][j] + cx[i-1][j]/mu_para[i-1][j])/2.0;
                    double cx_Rx = (cx[i][j]/mu_para[i][j] + cx[i+1][j]/mu_para[i+1][j])/2.0;
                    double cr_Lr = (cr[i][j]/mu_para[i][j] + cr[i][j-1]/mu_para[i][j-1])/2.0;
                    double cr_Rr = (cr[i][j]/mu_para[i][j] + cr[i][j+1]/mu_para[i][j+1])/2.0;

                    double sx_Lx = (sx[i][j]+sx[i-1][j])/2.0;
                    double sx_Rx = (sx[i][j]+sx[i+1][j])/2.0;
                    double sr_Lr = (sr[i][j]+sr[i][j-1])/2.0;
                    double sr_Rr = (sr[i][j]+sr[i][j+1])/2.0;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_para_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_para_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_para_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_para_Rr;

                    double vd_Lx = mu_para_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_para_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_para_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_para_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLrU = double(j!=j_flc_bl[0][0] || i+1>=i_flc_bl[1][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bLxU = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j+1>=j_flc_bl[0][0]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double rhoi_Rx  = (rhoi[i][j]+rhoi[i+1][j])/2.0;
                    double rhoi_Rr  = (rhoi[i][j]+rhoi[i][j+1])/2.0;

                    aP[i][j] = cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                          +    cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                          + cr_Rr*qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                          + cr_Lr*qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                          //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                          +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                          + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                          + dx*dr/dt; //時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double Fx_Lx = sx_Lx*(rR*rhoUer[i][j+1]*bRr + rL*rhoUer[i][j]*bLr
                        + rR*rhoUer[i-1][j+1]*bRr + rL*rhoUer[i-1][j]*bLrD)/(4.0*r[j]);

                    double Fx_Rx = sx_Rx*(rR*rhoUer[i+1][j+1]*bRr + rL*rhoUer[i+1][j]*bLrU
                        + rR*rhoUer[i][j+1]*bRr + rL*rhoUer[i][j]*bLr)/(4.0*r[j]);

                    double Fr_Lr = sr_Lr*(r[j]*rhoUex[i+1][j]*bRx + r[j]*rhoUex[i][j]*bLx 
                            + r[j-1]*rhoUex[i+1][j-1]*bRx + r[j-1]*rhoUex[i][j-1]*bLxD)/(4.0*rL);
                    
                    double Fr_Rr = sr_Rr*(r[j+1]*rhoUex[i+1][j+1]*bRx + r[j+1]*rhoUex[i][j+1]*bLxU 
                        + r[j]*rhoUex[i+1][j]*bRx + r[j]*rhoUex[i][j]*bLx)/(4.0*rR);
                    
                    double nabla_rhoUe_tmp = (Fx_Rx - Fx_Lx)/dx + (qR*Fr_Rr - qL*Fr_Rr)/dr;
                    //std::cout << nabla_rhoUe_tmp << std::endl;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        - (rhoe[i][j] - rhoe_old[i][j])/dt )*dx*dr
                        + (0.0
                            //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                        )*dr
                      - (
                          rhoi_Rx*Uix[i+1][j]*nbRx //右壁境界
                        )*dr
                      + qL*(0.0
                            //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                            //-0.25*delta_n_Lr*vth*nbLr
                        )*dx
                      - qR*(
                          rhoi_Rr*Uir[i][j+1]*nbRr //上壁境界
                        )*dx;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe_new);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe_new);
        }

        //密度更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    if(rhoe_new[i][j] > 0.0){
                        rhoe[i][j] = rhoe_new[i][j]; //正の密度だった時だけ更新
                    }
                }
            }
        }
        
        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_TV_old3(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 1;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1]*bRr + rL*rhoUer_old_tmp[i][j]*bLr
                        + rR*rhoUer_old_tmp[i-1][j+1]*bRr + rL*rhoUer_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double cx_tmp = (cx[i][j] + cx[i-1][j])/2.0;
                    double sx_tmp = (sx[i][j] + sx[i-1][j])/2.0;
                    
                    //double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double vd_tmp = cx_tmp*(-Ex[i][j]) + EPS;

                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cx_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;                   

                    rhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sx_tmp*rhoUer_tmp;
                    
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j]*bRx + r[j]*rhoUex_old_tmp[i][j]*bLx 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1]*bRx + r[j-1]*rhoUex_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    
                    //double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double cr_tmp = (cr[i][j] + cr[i][j-1])/2.0;
                    double sr_tmp = (sr[i][j] + sr[i][j-1])/2.0;

                    double vd_tmp = cr_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cr_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    rhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sr_tmp*rhoUex_tmp;

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    //double mu_para_Lx = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                    //double mu_para_Rx = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                    //double mu_para_Lr = (mu_para[i][j]+mu_para[i][j-1])/2.0;
                    //double mu_para_Rr = (mu_para[i][j]+mu_para[i][j+1])/2.0;

                    double cx_Lx = (cx[i][j] + cx[i-1][j])/2.0;
                    double cx_Rx = (cx[i][j] + cx[i+1][j])/2.0;
                    double cr_Lr = (cr[i][j] + cr[i][j-1])/2.0;
                    double cr_Rr = (cr[i][j] + cr[i][j+1])/2.0;

                    double sx_Lx = (sx[i][j]+sx[i-1][j])/2.0;
                    double sx_Rx = (sx[i][j]+sx[i+1][j])/2.0;
                    double sr_Lr = (sr[i][j]+sr[i][j-1])/2.0;
                    double sr_Rr = (sr[i][j]+sr[i][j+1])/2.0;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*cx_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*cx_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*cr_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*cr_Rr;

                    double vd_Lx = cx_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = cx_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = cr_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = cr_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLrU = double(j!=j_flc_bl[0][0] || i+1>=i_flc_bl[1][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bLxU = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j+1>=j_flc_bl[0][0]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double rhoi_Rx  = (rhoi[i][j]+rhoi[i+1][j])/2.0;
                    double rhoi_Rr  = (rhoi[i][j]+rhoi[i][j+1])/2.0;

                    aP[i][j] = vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                          +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                          + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                          + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                          //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                          +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                          + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                          + dx*dr/dt; //時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double Fx_Lx = sx_Lx*(rR*rhoUer[i][j+1]*bRr + rL*rhoUer[i][j]*bLr
                        + rR*rhoUer[i-1][j+1]*bRr + rL*rhoUer[i-1][j]*bLrD)/(4.0*r[j]);

                    double Fx_Rx = sx_Rx*(rR*rhoUer[i+1][j+1]*bRr + rL*rhoUer[i+1][j]*bLrU
                        + rR*rhoUer[i][j+1]*bRr + rL*rhoUer[i][j]*bLr)/(4.0*r[j]);

                    double Fr_Lr = sr_Lr*(r[j]*rhoUex[i+1][j]*bRx + r[j]*rhoUex[i][j]*bLx 
                            + r[j-1]*rhoUex[i+1][j-1]*bRx + r[j-1]*rhoUex[i][j-1]*bLxD)/(4.0*rL);
                    
                    double Fr_Rr = sr_Rr*(r[j+1]*rhoUex[i+1][j+1]*bRx + r[j+1]*rhoUex[i][j+1]*bLxU 
                        + r[j]*rhoUex[i+1][j]*bRx + r[j]*rhoUex[i][j]*bLx)/(4.0*rR);
                    
                    double nabla_rhoUe_tmp = (Fx_Rx - Fx_Lx)/dx + (qR*Fr_Rr - qL*Fr_Rr)/dr;
                    //std::cout << nabla_rhoUe_tmp << std::endl;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        + rhoe_old[i][j]/dt )*dx*dr
                        + (0.0
                            //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                        )*dr
                      - (
                          rhoi_Rx*Uix[i+1][j]*nbRx //右壁境界
                        )*dr
                      + qL*(0.0
                            //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                            //-0.25*delta_n_Lr*vth*nbLr
                        )*dx
                      - qR*(
                          rhoi_Rr*Uir[i][j+1]*nbRr //上壁境界
                        )*dx;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }

        //密度チェック
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    if(rhoe[i][j] < 0.0){
                        rhoe[i][j] = rhoe_old[i][j]; //負の密度だった時は戻す
                    }
                }
            }
        }
        
        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_TV_old4(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 1;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j]
                        + rR*rhoUer_old_tmp[i-1][j+1] + rL*rhoUer_old_tmp[i-1][j])/(4.0*r[j]);

                    double cx_tmp = (cx[i][j] + cx[i-1][j])/2.0;
                    double sx_tmp = (sx[i][j] + sx[i-1][j])/2.0;
                    if(bLrD == 0 || bRr == 0){
                        sx_tmp = 0.0;
                    }
                    
                    //double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double vd_tmp = cx_tmp*(-Ex[i][j]) + EPS;

                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cx_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;                   

                    rhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sx_tmp*rhoUer_tmp;
                    
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j] 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1] + r[j-1]*rhoUex_old_tmp[i][j-1])/(4.0*r_tmp);
                    
                    //double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double cr_tmp = (cr[i][j] + cr[i][j-1])/2.0;
                    double sr_tmp = (sr[i][j] + sr[i][j-1])/2.0;

                    if(bLxD == 0 || bRx == 0){
                        sr_tmp = 0.0;
                    }

                    double vd_tmp = cr_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cr_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    rhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sr_tmp*rhoUex_tmp;

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    //double mu_para_Lx = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                    //double mu_para_Rx = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                    //double mu_para_Lr = (mu_para[i][j]+mu_para[i][j-1])/2.0;
                    //double mu_para_Rr = (mu_para[i][j]+mu_para[i][j+1])/2.0;

                    double cx_Lx = (cx[i][j] + cx[i-1][j])/2.0;
                    double cx_Rx = (cx[i][j] + cx[i+1][j])/2.0;
                    double cr_Lr = (cr[i][j] + cr[i][j-1])/2.0;
                    double cr_Rr = (cr[i][j] + cr[i][j+1])/2.0;

                    double sx_Lx = (sx[i][j]+sx[i-1][j])/2.0;
                    double sx_Rx = (sx[i][j]+sx[i+1][j])/2.0;
                    double sr_Lr = (sr[i][j]+sr[i][j-1])/2.0;
                    double sr_Rr = (sr[i][j]+sr[i][j+1])/2.0;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*cx_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*cx_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*cr_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*cr_Rr;

                    double vd_Lx = cx_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = cx_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = cr_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = cr_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLrU = double(j!=j_flc_bl[0][0] || i+1>=i_flc_bl[1][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bLxU = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j+1>=j_flc_bl[0][0]);

                    //壁の接線方向の処理
                    if(bLxD == 0 || bRx == 0){
                        sr_Lr = 0.0;
                    }
                    if(bLx == 0 || bRx == 0){
                        sr_Rr = 0.0;
                    }
                    if(bLrD == 0 || bRr == 0){
                        sx_Lx = 0.0;
                    }
                    if(bLr == 0 || bRr == 0){
                        sx_Rx = 0.0;
                    }

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double rhoi_Rx  = (rhoi[i][j]+rhoi[i+1][j])/2.0;
                    double rhoi_Rr  = (rhoi[i][j]+rhoi[i][j+1])/2.0;

                    aP[i][j] = vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                          +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                          + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                          + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                          //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                          +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                          + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                          + dx*dr/dt; //時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double Fx_Lx = sx_Lx*(rR*rhoUer[i][j+1] + rL*rhoUer[i][j]
                        + rR*rhoUer[i-1][j+1] + rL*rhoUer[i-1][j])/(4.0*r[j]);

                    double Fx_Rx = sx_Rx*(rR*rhoUer[i+1][j+1] + rL*rhoUer[i+1][j]
                        + rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(4.0*r[j]);

                    double Fr_Lr = sr_Lr*(r[j]*rhoUex[i+1][j] + r[j]*rhoUex[i][j]
                            + r[j-1]*rhoUex[i+1][j-1] + r[j-1]*rhoUex[i][j-1])/(4.0*rL);
                    
                    double Fr_Rr = sr_Rr*(r[j+1]*rhoUex[i+1][j+1] + r[j+1]*rhoUex[i][j+1] 
                        + r[j]*rhoUex[i+1][j] + r[j]*rhoUex[i][j])/(4.0*rR);
                    
                    double nabla_rhoUe_tmp = (Fx_Rx - Fx_Lx)/dx + (qR*Fr_Rr - qL*Fr_Lr)/dr;
                    //std::cout << nabla_rhoUe_tmp << std::endl;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        + rhoe_old[i][j]/dt )*dx*dr
                        + (0.0
                            //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                        )*dr
                      - (
                          rhoi_Rx*Uix[i+1][j]*nbRx //右壁境界
                        )*dr
                      + qL*(0.0
                            //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                            //-0.25*delta_n_Lr*vth*nbLr
                        )*dx
                      - qR*(
                          rhoi_Rr*Uir[i][j+1]*nbRr //上壁境界
                        )*dx;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }

        //密度チェック
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    if(rhoe[i][j] < 0.0){
                        rhoe[i][j] = rhoe_old[i][j]; //負の密度だった時は戻す
                    }
                }
            }
        }
        
        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_TV(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        
        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_para_Lx = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                    double mu_para_Rx = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                    double mu_para_Lr = (mu_para[i][j]+mu_para[i][j-1])/2.0;
                    double mu_para_Rr = (mu_para[i][j]+mu_para[i][j+1])/2.0;

                    double cx_Lx = (cx[i][j] + cx[i-1][j])/2.0;
                    double cx_Rx = (cx[i][j] + cx[i+1][j])/2.0;
                    double cr_Lr = (cr[i][j] + cr[i][j-1])/2.0;
                    double cr_Rr = (cr[i][j] + cr[i][j+1])/2.0;

                    double sx_Lx = (sx[i][j]+sx[i-1][j])/2.0;
                    double sx_Rx = (sx[i][j]+sx[i+1][j])/2.0;
                    double sr_Lr = (sr[i][j]+sr[i][j-1])/2.0;
                    double sr_Rr = (sr[i][j]+sr[i][j+1])/2.0;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*cx_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*cx_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*cr_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*cr_Rr;

                    double vd_Lx = cx_Lx*(-Ex[i  ][j  ]) + EPS*cx_Lx/mu_para_Lx;
                    double vd_Rx = cx_Rx*(-Ex[i+1][j  ]) + EPS*cx_Rx/mu_para_Lx;
                    double vd_Lr = cr_Lr*(-Er[i  ][j  ]) + EPS*cr_Lr/mu_para_Lx;
                    double vd_Rr = cr_Rr*(-Er[i  ][j+1]) + EPS*cr_Rr/mu_para_Lx;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLrU = double(j!=j_flc_bl[0][0] || i+1>=i_flc_bl[1][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bLxU = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j+1>=j_flc_bl[0][0]);

                    //壁の接線方向の処理
                    if(bLxD == 0 || bRx == 0){
                        sr_Lr = 0.0;
                    }
                    if(bLx == 0 || bRx == 0){
                        sr_Rr = 0.0;
                    }
                    if(bLrD == 0 || bRr == 0){
                        sx_Lx = 0.0;
                    }
                    if(bLr == 0 || bRr == 0){
                        sx_Rx = 0.0;
                    }

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                    double rhoi_Rx  = (rhoi[i][j] + rhoi[i+1][j])/2.0;
                    double rhoi_Rr  = (rhoi[i][j] + rhoi[i][j+1])/2.0;

                    aP[i][j] = vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                          +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                          + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                          + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                          //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                          +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                          + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                          + dx*dr/dt; //時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double Fx_Lx = sx_Lx*(rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j]
                        + rR*rhoUer_old_tmp[i-1][j+1] + rL*rhoUer_old_tmp[i-1][j])/(4.0*r[j]);

                    double Fx_Rx = sx_Rx*(rR*rhoUer_old_tmp[i+1][j+1] + rL*rhoUer_old_tmp[i+1][j]
                        + rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j])/(4.0*r[j]);

                    double Fr_Lr = sr_Lr*(r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j]
                            + r[j-1]*rhoUex_old_tmp[i+1][j-1] + r[j-1]*rhoUex_old_tmp[i][j-1])/(4.0*rL+1e-100);
                    
                    double Fr_Rr = sr_Rr*(r[j+1]*rhoUex_old_tmp[i+1][j+1] + r[j+1]*rhoUex_old_tmp[i][j+1] 
                        + r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j])/(4.0*rR);
                    
                    double nabla_rhoUe_tmp = (Fx_Rx*bRx - Fx_Lx*bLx)/dx + (qR*Fr_Rr*bRr - qL*Fr_Lr*bLr)/dr;
                    //std::cout << i << "," << j << ","<<nabla_rhoUe_tmp <<","<<Fx_Rx<<","<<Fx_Lx<<","<<Fr_Rr <<","<<Fr_Lr<< std::endl;
                    //double nabla_rhoUe_tmp = (Fx_Rx*bLr - Fx_Lx*bLrD)/dx + (qR*Fr_Rr - qL*Fr_Lr)/dr;
                    b[i][j] = (-nabla_rhoUe_tmp 
                        + rate_ionize[i][j] //陽的ソース項
                        + rhoe_old[i][j]/dt )*dx*dr
                        + (0.0
                            //-0.25*rhoe[i][j]*vth*nbLx //左壁境界1,2 //陽的指定
                        )*dr
                      - (
                          rhoi_Rx*Uix[i+1][j]*nbRx //右壁境界
                        )*dr
                      + qL*(0.0
                            //-0.25*rhoe[i][j]*vth*nbLr //下壁境界　 //陽的指定
                            //-0.25*delta_n_Lr*vth*nbLr
                        )*dx
                      - qR*(
                          rhoi_Rr*Uir[i][j+1]*nbRr //上壁境界
                        )*dx;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,rhoe);
        }


        //密度チェック
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    if(rhoe[i][j] < 0.0){
                        rhoe[i][j] = rhoe_old_tmp[i][j]; //負の密度だった時は戻す
                    }
                }
            }
        }

        
        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j]
                        + rR*rhoUer_old_tmp[i-1][j+1] + rL*rhoUer_old_tmp[i-1][j])/(4.0*r[j]);

                    double cx_tmp = (cx[i][j] + cx[i-1][j])/2.0;
                    double sx_tmp = (sx[i][j] + sx[i-1][j])/2.0;
                    if(bLrD == 0 || bRr == 0){
                        sx_tmp = 0.0;
                    }

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double vd_tmp = cx_tmp*(-Ex[i][j]) + EPS*cx_tmp/mu_para_tmp;

                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cx_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;                   

                    rhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sx_tmp*rhoUer_tmp;
                    
                    //左壁は電子フラックス指定
                    if((i==i_flc_bl[0][0]) || (i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j] 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1] + r[j-1]*rhoUex_old_tmp[i][j-1])/(4.0*r_tmp);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double cr_tmp = (cr[i][j] + cr[i][j-1])/2.0;
                    double sr_tmp = (sr[i][j] + sr[i][j-1])/2.0;

                    if(bLxD == 0 || bRx == 0){
                        sr_tmp = 0.0;
                    }

                    double vd_tmp = cr_tmp*(-Er[i][j]) + EPS*cr_tmp/mu_para_tmp;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*cr_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    rhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j]
                        + sr_tmp*rhoUex_tmp;

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }
        
        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    std::cout << "ncount_rhoe = "<<ncount<<std::endl;

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_rhoe_PC_pDif(){ //擬似拡散項を追加

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_new(ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoe_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUex_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > rhoUer_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoe(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUex(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoUer(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //1.9
    double ratioY = 1.0; //1.9
    double ratio = 1000.0; //1.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    
    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhoe_old[i][j] = rhoe[i][j];
            rhoUex_old[i][j] = rhoUex[i][j];
            rhoUer_old[i][j] = rhoUer[i][j];

            //drhoeを予想
            drhoe[i][j] = rhoe[i][j]-rhoe_old[i][j];
        }
    }

    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoe_old_tmp[i][j] = rhoe[i][j];
                rhoUex_old_tmp[i][j] = rhoUex[i][j];
                rhoUer_old_tmp[i][j] = rhoUer[i][j];
            }
        }

        //rhoUex更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double rhoUer_tmp = (rR*rhoUer_old_tmp[i][j+1] + rL*rhoUer_old_tmp[i][j] 
                        + rR*rhoUer_old_tmp[i-1][j+1] + rL*rhoUer_old_tmp[i-1][j])/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    rhoUex[i][j] = rhoUex_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*rhoUex_old_tmp[i][j] + mu_inv_xr_tmp*rhoUer_tmp)*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                    
                    //タイムステップが負にならないように確認
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //壁の接線方向処理
                    if(bLrD == 0 || bRr == 0){
                        double Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                        double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                        double vd_Lx  = mu_para_Lx*(-Ex[i][j]) + EPS;
                        double Te_Lx  = (Te[i][j]+Te[i-1][j])/2.0;
                        double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                        double z_Lx = vd_Lx*dx/D_Lx;
    
                        rhoUex[i][j] 
                            = (-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoe[i][j]
                            + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoe[i-1][j];
                    }
  
                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUex[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_tmp + 1e-100),lim_exp))*vth;
                    }
                    //右はイオンフラックスと同じ
                    if(i==i_flc_bl[1][1]+1){
                        rhoUex[i][j] =  rhoi[i-1][j]*Uix[i][j];
                    }
                }
            }     
        }

        //rhoUer更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double rhoUex_tmp = (r[j]*rhoUex_old_tmp[i+1][j] + r[j]*rhoUex_old_tmp[i][j] 
                        + r[j-1]*rhoUex_old_tmp[i+1][j-1] + r[j-1]*rhoUex_old_tmp[i][j-1])/(4.0*r_tmp);
                    
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    rhoUer[i][j] =  rhoUer_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*rhoUex_tmp + mu_inv_rr_tmp*rhoUer_old_tmp[i][j])*mu_min_tmp 
                        + vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoe[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoe[i][j];
                        
                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //壁の接線方向処理
                    if(bLxD == 0 || bRx == 0){
                        double Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                        double mu_para_Lr  = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                        double vd_Lr  = mu_para_Lr*(-Er[i][j]) + EPS;
                        double Te_Lr  = (Te[i][j] + Te[i][j-1])/2.0;
                        double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                        double z_Lr = vd_Lr*dr/D_Lr;
    
                        rhoUer[i][j] 
                            = (- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoe[i][j]
                            + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoe[i][j-1];
                    }

                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                        rhoUer[i][j] = -0.25*rhoe[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*vth;
                    }

                    //上はイオンフラックスと同じ
                    if(j==j_flc_bl[1][1]+1){
                        rhoUer[i][j] =  rhoi[i][j-1]*Uir[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double mu_para_Lx = (mu_para[i][j]+mu_para[i-1][j])/2.0*ratio;
                    double mu_para_Rx = (mu_para[i][j]+mu_para[i+1][j])/2.0*ratio;
                    double mu_para_Lr = (mu_para[i][j]+mu_para[i][j-1])/2.0*ratio;
                    double mu_para_Rr = (mu_para[i][j]+mu_para[i][j+1])/2.0*ratio;

                    double Te_Lx = (Te[i][j]+Te[i-1][j])/2.0;
                    double Te_Rx = (Te[i][j]+Te[i+1][j])/2.0;
                    double Te_Lr = (Te[i][j]+Te[i][j-1])/2.0;
                    double Te_Rr = (Te[i][j]+Te[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*(mu_min_Lx + mu_para_Lx);
                    double D_Rx = Boltz*Te_Rx/e0*(mu_min_Rx + mu_para_Rx);
                    double D_Lr = Boltz*Te_Lr/e0*(mu_min_Lr + mu_para_Lr);
                    double D_Rr = Boltz*Te_Rr/e0*(mu_min_Rr + mu_para_Rr);

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx;
                    double nbLr  = 1.0 - bLr;
                    double nbRx  = 1.0 - bRx;
                    double nbRr  = 1.0 - bRr;

                    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr
                        +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                        + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                        + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                        //- dx*dr*nu_ionz_tmp //陰的ソース項の時だけ使う
                        +    0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                        + qL*0.25*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                        + dx*dr/dt + dx*dr/dtau*double(icon_dtau); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    
                    double nabla_rhoUe_tmp = (rhoUex[i+1][j]-rhoUex[i][j])/dx + (qR*rhoUer[i][j+1]-qL*rhoUer[i][j])/dr;
                    
                    double rhoP_tmp = rhoe_old_tmp[i][j] - rhoe_old[i][j];
                    double rhoE_tmp = rhoe_old_tmp[i+1][j] - rhoe_old[i+1][j];
                    double rhoW_tmp = rhoe_old_tmp[i-1][j] - rhoe_old[i-1][j];
                    double rhoN_tmp = rhoe_old_tmp[i][j+1] - rhoe_old[i][j+1];
                    double rhoS_tmp = rhoe_old_tmp[i][j-1] - rhoe_old[i][j-1];

                    double D_tmp_Lx = Boltz*Te_Lx/e0*mu_para_Lx;
                    double D_tmp_Rx = Boltz*Te_Rx/e0*mu_para_Rx;
                    double D_tmp_Lr = Boltz*Te_Lr/e0*mu_para_Lr;
                    double D_tmp_Rr = Boltz*Te_Rr/e0*mu_para_Rr;

                    double rhoUex_Rx_Dif = -D_tmp_Rx*(rhoE_tmp - rhoP_tmp)/dx;
                    double rhoUex_Lx_Dif = -D_tmp_Lx*(rhoP_tmp - rhoW_tmp)/dx;
                    double rhoUer_Rr_Dif = -D_tmp_Rr*(rhoN_tmp - rhoP_tmp)/dr;
                    double rhoUer_Lr_Dif = -D_tmp_Lr*(rhoP_tmp - rhoS_tmp)/dr;
                    
                    double pDif = (rhoUex_Rx_Dif*bRx - rhoUex_Lx_Dif*bLx)/dx 
                        + (qR*rhoUer_Rr_Dif*bRr - qL*rhoUer_Lr_Dif*bLr)/dr;

                    b[i][j] = (-nabla_rhoUe_tmp - pDif
                        + rate_ionize[i][j] //陽的ソース項
                        - (rhoe[i][j] - rhoe_old[i][j])/dt )*dx*dr;
                }
            }
        }

        //solve
        if(icon_iter_rhoe == 0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoe,error_cnv_SOR_rhoe,0,drhoe);
        }

        /********************* 更新 *******************/
        //drhoUexを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    drhoUex[i][j] = vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i-1][j]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //drhoUerを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    drhoUer[i][j] =  vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoe[i][j-1]
                     - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoe[i][j];
                }
            }
        }

        //密度更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rhoe_new = rhoe[i][j] + drhoe[i][j];
                    if(rhoe_new > 0.0){
                        rhoe[i][j] = rhoe_new; //正の密度だった時だけ更新
                    }
                }
            }
        }
        
        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    rhoUex[i][j] = rhoUex[i][j] + drhoUex[i][j];
                }
            }
        }

        //フラックス更新
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    rhoUer[i][j] = rhoUer[i][j] + drhoUer[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoe2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoe_tmp = fabs((rhoe[i][j]-rhoe_old_tmp[i][j])/(rhoe[i][j]+rhoe_old_tmp[i][j]+1e-100));
                        if(error_rhoe_tmp > error_rhoe2){
                            error_rhoe2 = error_rhoe_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoe = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoe2 += pow(rhoe[i][j]-rhoe_old_tmp[i][j],2)/(pow(rhoe_old_tmp[i][j]+1e10,2));
                        ncount_rhoe++;
                    }
                }
            }
            error_rhoe2 = sqrt(error_rhoe2/double(ncount_rhoe));
        }

        double error_rhoUex2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUex_tmp = fabs((rhoUex[i][j]-rhoUex_old_tmp[i][j])/(rhoUex[i][j]+rhoUex_old_tmp[i][j]+1e-100));
                        if(error_rhoUex_tmp > error_rhoUex2){
                            error_rhoUex2 = error_rhoUex_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUex = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoUex2 += pow(rhoUex[i][j]-rhoUex_old_tmp[i][j],2)/(pow(rhoUex_old_tmp[i][j]+1e16,2));
                        ncount_rhoUex++;
                    }
                }
            }
            error_rhoUex2 = sqrt(error_rhoUex2/double(ncount_rhoUex));
        }

        double error_rhoUer2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_rhoUer_tmp = fabs((rhoUer[i][j]-rhoUer_old_tmp[i][j])/(rhoUer[i][j]+rhoUer_old_tmp[i][j]+1e-100));
                        if(error_rhoUer_tmp > error_rhoUer2){
                            error_rhoUer2 = error_rhoUer_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoUer = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_rhoUer2 += pow(rhoUer[i][j]-rhoUer_old_tmp[i][j],2)/(pow(rhoUer_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_rhoUer++;
                    }
                }
            }
            error_rhoUer2 = sqrt(error_rhoUer2/double(ncount_rhoUer));
        }
        
        double error_global = fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoe = " << error_rhoe2
                <<  " error_rhoUex = " << error_rhoUex2
                <<  " error_rhoUer= " << error_rhoUer2
                <<  " error_max = " << fmax(fmax(error_rhoe2,error_rhoUex2),error_rhoUer2)
                << std::endl;
        }

        if(error_global < error_cnv_HES_rhoe || ncount >= maxITR_HES_rhoe){
            icon_end = 1;
        }

    } while (icon_end == 0);

    //誤差を計算
    error_rhoe = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoe[i][j] - rhoe_old[i][j])/(rhoe[i][j] + rhoe_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoe){
                        error_rhoe = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoe += pow(rhoe[i][j]-rhoe_old[i][j],2)/(pow(rhoe_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoe = sqrt(error_rhoe/double(ncount));
    }

    error_rhoUex = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUex[i][j] - rhoUex_old[i][j])/(rhoUex[i][j] + rhoUex_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUex){
                        error_rhoUex = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUex += pow(rhoUex[i][j]-rhoUex_old[i][j],2)/(pow(rhoUex_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUex = sqrt(error_rhoUex/double(ncount));
    }

    error_rhoUer = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoUer[i][j] - rhoUer_old[i][j])/(rhoUer[i][j] + rhoUer_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoUer){
                        error_rhoUer = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoUer += pow(rhoUer[i][j]-rhoUer_old[i][j],2)/(pow(rhoUer_old[i][j]+1e16,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoUer = sqrt(error_rhoUer/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_direct(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_new(ni+2,std::vector<double>(nj+2,0.0));

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    
    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j  ]/mu_para[i-1][j  ])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j  ]/mu_para[i+1][j  ])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i  ][j-1]/mu_para[i  ][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i  ][j+1]/mu_para[i  ][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j  ]/mu_para[i-1][j  ])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j  ]/mu_para[i+1][j  ])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i  ][j-1]/mu_para[i  ][j-1])/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i  ][j+1]/mu_para[i  ][j+1])/2.0;

                double mu_para_Lx  = (mu_para[i  ][j  ] + mu_para[i-1][j  ])/2.0;
                double mu_para_LxU = (mu_para[i  ][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i  ][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i  ][j  ] + mu_para[i+1][j  ])/2.0;
                double mu_para_RxU = (mu_para[i  ][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i  ][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i  ][j  ] + mu_para[i  ][j-1])/2.0;
                double mu_para_LrU = (mu_para[i+1][j  ] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j  ] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i  ][j  ] + mu_para[i  ][j+1])/2.0;
                double mu_para_RrU = (mu_para[i+1][j  ] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j  ] + mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te[i  ][j  ] + Te[i-1][j  ])/2.0;
                double Te_LxU = (Te[i  ][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i  ][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i  ][j  ] + Te[i+1][j  ])/2.0;
                double Te_RxU = (Te[i  ][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i  ][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i  ][j  ] + Te[i  ][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j  ] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j  ] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i  ][j  ] + Te[i  ][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j  ] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j  ] + Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ]) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1]) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1]) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ]) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1]) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1]) + EPS;
                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ]) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ]) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ]) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1]) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1]) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1]) + EPS;

                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;

                double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                double bRx  = double(i!=i_flc_bl[1][1]);
                double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                double bRr  = double(j!=j_flc_bl[1][1]);

                //壁の接線方向の処理
                if(bLxD == 0 || bRx == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx == 0 || bRx == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLrD == 0 || bRr == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr == 0 || bRr == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }

                double nbLx  = 1.0 - bLx;
                double nbLr  = 1.0 - bLr;
                double nbRx  = 1.0 - bRx;
                double nbRr  = 1.0 - bRr;

                double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));

                aP[i][j] =      (    Cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    + Cc_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - Cc_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                    + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*Cr_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    + Cc_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - Cc_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                    + Cc_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - Cc_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         +    0.2*vth*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                         + qL*0.2*vth*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                         + 3.0/5.0*delossdeps[i][j]*dx*dr //陰的ソース項予測
                         + 3.0/5.0*dx*dr/dt; //時間項
                aE[i][j] =  (Cx_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - Cc_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + Cc_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                            )*dr*bRx
                          + (Cc_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                          - (Cc_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (Cc_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (Cc_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] =  (qR*Cr_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                            )*dx*bRr
                          + (qR*Cc_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                          - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] =  (qL*Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                            )*dx*bLr
                          - (qL*Cc_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                          + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                aEN[i][j] = (Cc_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                          + (Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] =-(Cc_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                           -(Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] =-(Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                           -(Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] = (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                           +(Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;

                double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                double RHS1 =  rhoeps_old[i][j]/dt;
                double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                double RHS3 = Pabs[i][j] - rhoe[i][j]*rate_eloss[i][j] + delossdeps[i][j]*(rhoe[i][j]*(1.5*Boltz*Te[i][j])); //陰的ソース項予測

                b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3)*dx*dr
                + 3.0/5.0*(0.0
                      //Gx_Lx*nbLx //左壁境界1,2
                  )*dr
                - 3.0/5.0*(
                    + 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUex[i+1][j],0.0)*nbRx
                  )*dr
                + 3.0/5.0*qL*(0.0
                    //  Gr_Lr*nbLr //下壁境界　(下中心境界はフラックスゼロのためなし)
                  )*dx
                - 3.0/5.0*qR*(
                    + 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0)*nbRr
                  )*dx;
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,rhoeps);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoeps);
    }

    /********************* 更新 *******************/
    //ゼロ割回避用に電子密度の最大値を計算しておく
    double rhoe_max = 0.0;
    double ratio = 0.001;
    double Te_max = 20.0*e0/Boltz;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }

    //温度を更新
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    ncount ++;
                    rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                }
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100),Te_max);
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative Te count = " << ncount << std::endl;
    }

    //輸送係数用に入れておく (必要かはわからない)
    //左 壁1
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
    }

    //左 壁2
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        Te[i-1][j] = Te[i][j];
    }

    //下 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
    }

    //右 ノイマン
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        Te[i+1][j]  =  Te[i][j];
    }

    //上 ノイマン
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        Te[i][j+1] =  Te[i][j];
    }
    
    //Gxを計算
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;

                double mu_para_Lx  = (mu_para[i][j]  +mu_para[i-1][j]  )/2.0;
                double mu_para_Lr  = (mu_para[i][j]  +mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  +mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te_old[i][j]  +Te_old[i-1][j]  )/2.0;
                double Te_Lr  = (Te_old[i][j]  +Te_old[i][j-1]  )/2.0;
                double Te_LrD = (Te_old[i-1][j]+Te_old[i-1][j-1])/2.0;

                double Te_Rr  = (Te_old[i][j]  + Te_old[i][j+1]  )/2.0;
                double Te_RrD = (Te_old[i-1][j]+ Te_old[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ]) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ]) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ]) + EPS;
                double vd_Rr = mu_para_Rr  *(-Er[i  ][j+1]) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1]) + EPS;

                double z_Lx = vd_Lx*dx/D_Lx;
                double z_Lr = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;

                //フラックス
                double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                double bRr  = double(j!=j_flc_bl[1][1]);
                
                //壁の接線方向の処理
                if(bLrD == 0 || bRr == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }

                //フラックス
                Gx[i][j] 
                    =((-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoeps[i-1][j]
                    - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoeps[i][j+1]
                    + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoeps[i][j-1]
                    - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoeps[i-1][j+1]
                    + (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0;

                if(i == i_flc_bl[0][0]){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                }

                if(i==i_flc_bl[1][0] && j<=j_flc_bl[0][0]-1){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                }

                if(i == i_flc_bl[1][1]+1){
                    Gx[i][j] = 5.0/2.0*Boltz*Te_old[i-1][j]*fmax(rhoUex[i][j],0.0);
                }
            }
        }
    }

    //Grを計算
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1]+mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0*double(j!=j_flc_bl[1][0]); //中心軸境界;;

                double Te_Lx  = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                double Te_LxD = (Te_old[i][j-1]+Te_old[i-1][j-1])/2.0;
                double Te_Rx  = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                double Te_RxD = (Te_old[i][j-1]+Te_old[i+1][j-1])/2.0;
                double Te_Lr  = (Te_old[i][j]+Te_old[i][j-1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ]) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1]) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ]) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1]) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ]) + EPS;
                double z_Lx = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;

                double z_Lr = vd_Lr*dr/D_Lr;
                
                double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                double bRx  = double(i!=i_flc_bl[1][1]);
                
                //壁の接線方向の処理
                if(bLxD == 0 || bRx == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }

                Gr[i][j] 
                    =((- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + Cc_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))
                       - Cc_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp)))
                       - Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoeps[i][j-1]
                    - (Cc_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoeps[i+1][j]
                    + (Cc_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoeps[i-1][j]
                    - (Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoeps[i+1][j-1]
                    + (Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0;

                if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                }

                if(j == j_flc_bl[1][1]+1){
                    Gr[i][j] = 5.0/2.0*Boltz*Te_old[i][j-1]*fmax(rhoUer[i][j],0.0);
                }
            }
        }
    }

    //誤差を計算
    error_rhoeps = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }

    error_Gx = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }

    error_Gr = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_wdTe_direct_old(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_new(ni+2,std::vector<double>(nj+2,0.0));

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    
    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j  ]/mu_para[i-1][j  ])/2.0;
                double Cx_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j  ]/mu_para[i+1][j  ])/2.0;
                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i  ][j-1]/mu_para[i  ][j-1])/2.0;
                double Cr_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i  ][j+1]/mu_para[i  ][j+1])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j  ]/mu_para[i-1][j  ])/2.0;
                double Cc_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j  ]/mu_para[i+1][j  ])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i  ][j-1]/mu_para[i  ][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;
                double Cc_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i  ][j+1]/mu_para[i  ][j+1])/2.0;

                double mu_para_Lx  = (mu_para[i  ][j  ] + mu_para[i-1][j  ])/2.0;
                double mu_para_LxU = (mu_para[i  ][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i  ][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i  ][j  ] + mu_para[i+1][j  ])/2.0;
                double mu_para_RxU = (mu_para[i  ][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i  ][j-1] + mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i  ][j  ] + mu_para[i  ][j-1])/2.0;
                double mu_para_LrU = (mu_para[i+1][j  ] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j  ] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i  ][j  ] + mu_para[i  ][j+1])/2.0;
                double mu_para_RrU = (mu_para[i+1][j  ] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j  ] + mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te[i  ][j  ] + Te[i-1][j  ])/2.0;
                double Te_LxU = (Te[i  ][j+1] + Te[i-1][j+1])/2.0;
                double Te_LxD = (Te[i  ][j-1] + Te[i-1][j-1])/2.0;
                double Te_Rx  = (Te[i  ][j  ] + Te[i+1][j  ])/2.0;
                double Te_RxU = (Te[i  ][j+1] + Te[i+1][j+1])/2.0;
                double Te_RxD = (Te[i  ][j-1] + Te[i+1][j-1])/2.0;
                double Te_Lr  = (Te[i  ][j  ] + Te[i  ][j-1]  )/2.0;
                double Te_LrU = (Te[i+1][j  ] + Te[i+1][j-1])/2.0;
                double Te_LrD = (Te[i-1][j  ] + Te[i-1][j-1])/2.0;
                double Te_Rr  = (Te[i  ][j  ] + Te[i  ][j+1]  )/2.0;
                double Te_RrU = (Te[i+1][j  ] + Te[i+1][j+1])/2.0;
                double Te_RrD = (Te[i-1][j  ] + Te[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                double dTedx_LxU = (Te[i  ][j+1] - Te[i-1][j+1])/dx;
                double dTedx_LxD = (Te[i  ][j-1] - Te[i-1][j-1])/dx;
                double dTedx_Rx  = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                double dTedx_RxU = (Te[i+1][j+1] - Te[i  ][j+1])/dx;
                double dTedx_RxD = (Te[i+1][j-1] - Te[i  ][j-1])/dx;
                double dTedr_Lr  = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                double dTedr_LrU = (Te[i+1][j  ] - Te[i+1][j-1])/dr;
                double dTedr_LrD = (Te[i-1][j  ] - Te[i-1][j-1])/dr;
                double dTedr_Rr  = (Te[i  ][j+1] - Te[i  ][j  ])/dr;
                double dTedr_RrU = (Te[i+1][j+1] - Te[i+1][j  ])/dr;
                double dTedr_RrD = (Te[i-1][j+1] - Te[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;

                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                //double bLxD  = double(i!=i_flc_bl[0][0]); //z0
                //bLxD = bLxD*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                //bLxD = bLxD*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                //bLxD = bLxD*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                
                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                //double bRxD  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                //bRxD = bRxD*double(i!=i_flc_bl[4][1]); //z5

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                //double bLrD  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                //bLrD = bLrD*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2

                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr*bRr1; //全部含む

                double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bRr_Rx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Rx = bRr_Rx*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                bRr_Rx = bRr_Rx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }
                if(bLx_Rr == 0 || bRx_Rr == 0){
                    Cr_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    Cc_Rr = 0.0;
                }
                if(bLr_Lx == 0 || bRr_Lx == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }
                if(bLr_Rx == 0 || bRr_Rx == 0){
                    Cx_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    Cc_Rx = 0.0;
                }

                double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));

                aP[i][j] =      (    Cx_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    + Cc_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - Cc_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                    + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*Cr_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    + Cc_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - Cc_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                    + Cc_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - Cc_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                         +    0.2*vth*exp(fmin(-e0*(-Ex[i  ][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                         +    0.2*vth*exp(fmin(-e0*( Ex[i+1][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx //陰的指定
                         + qL*0.2*vth*exp(fmin(-e0*(-Er[i  ][j  ]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                         + qR*0.2*vth*exp(fmin(-e0*( Er[i  ][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr //陰的指定
                         + 3.0/5.0*delossdeps[i][j]*dx*dr //陰的ソース項予測
                         + 3.0/5.0*dx*dr/dt; //時間項
                aE[i][j] =  (Cx_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - Cc_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + Cc_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                            )*dr*bRx
                          + (Cc_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                          - (Cc_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (Cc_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (Cc_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] =  (qR*Cr_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                            )*dx*bRr
                          + (qR*Cc_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                          - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] =  (qL*Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                            )*dx*bLr
                          - (qL*Cc_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                          + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                aEN[i][j] = (Cc_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                          + (Cc_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] =-(Cc_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                           -(Cc_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] =-(Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                           -(Cc_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] = (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                           +(Cc_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;

                double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                double RHS1 =  rhoeps_old[i][j]/dt;
                double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                double RHS3 = Pabs[i][j] - rhoe[i][j]*rate_eloss[i][j] + delossdeps[i][j]*(rhoe[i][j]*(1.5*Boltz*Te[i][j])); //陰的ソース項予測

                b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3)*dx*dr
                + 3.0/5.0*(0.0
                      //Gx_Lx*nbLx //左壁境界1,2
                  )*dr
                - 3.0/5.0*(0.0
                    //+ 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUex[i+1][j],0.0)*nbRx
                  )*dr
                + 3.0/5.0*qL*(0.0
                    //  Gr_Lr*nbLr //下壁境界　(下中心境界はフラックスゼロのためなし)
                  )*dx
                - 3.0/5.0*qR*(
                    + 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0)*nbRr1
                  )*dx;
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,rhoeps);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoeps);
    }

    /********************* 更新 *******************/
    //ゼロ割回避用に電子密度の最大値を計算しておく
    double rhoe_max = 0.0;
    double ratio = 0.01;
    double Te_max = 200.0*e0/Boltz;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }

    //温度を更新
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    ncount ++;
                    rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                }
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100),Te_max);
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative Te count = " << ncount << std::endl;
    }

    //Gxを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cx_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double Cc_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;

                double mu_para_Lx  = (mu_para[i][j]  +mu_para[i-1][j]  )/2.0;
                double mu_para_Lr  = (mu_para[i][j]  +mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  +mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+mu_para[i-1][j+1])/2.0;

                double Te_Lx  = (Te_old[i][j]  +Te_old[i-1][j]  )/2.0;
                double Te_Lr  = (Te_old[i][j]  +Te_old[i][j-1]  )/2.0;
                double Te_LrD = (Te_old[i-1][j]+Te_old[i-1][j-1])/2.0;

                double Te_Rr  = (Te_old[i][j]  + Te_old[i][j+1]  )/2.0;
                double Te_RrD = (Te_old[i-1][j]+ Te_old[i-1][j+1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;

                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                double dTedr_LrD = (Te_old[i-1][j  ] - Te_old[i-1][j-1])/dr;
                double dTedr_Rr  = (Te_old[i  ][j+1] - Te_old[i  ][j  ])/dr;
                double dTedr_RrD = (Te_old[i-1][j+1] - Te_old[i-1][j  ])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr = mu_para_Rr  *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;

                double z_Lx = vd_Lx*dx/D_Lx;
                double z_Lr = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;

                //フラックス
                //double bLrD  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                //bLrD = bLrD*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                //double bRrD  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                //bRrD = bRrD*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                //bRrD = bRrD*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                
                //壁の接線方向の処理
                if(bLr_Lx == 0 || bRr_Lx == 0){
                    Cx_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    Cc_Lx = 0.0;
                }

                //フラックス
                Gx[i][j] 
                    =((-Cx_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + Cc_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (Cx_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + Cc_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - Cc_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoeps[i-1][j]
                    - (qR*Cc_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoeps[i][j+1]
                    + (qL*Cc_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoeps[i][j-1]
                    - (Cc_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoeps[i-1][j+1]
                    + (Cc_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0;
            }
        }
    }

    //Grを計算
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //double qR = (r[j]+r[j+1])/2.0/r[j];
                double qL = (r[j]+r[j-1])/2.0/r[j];

                double Cr_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double Cc_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0*double(j!=j_flc_bl[3][0]); //中心軸境界;
                
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1]+mu_para[i+1][j-1])/2.0;
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;

                double Te_Lx  = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                double Te_LxD = (Te_old[i][j-1]+Te_old[i-1][j-1])/2.0;
                double Te_Rx  = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                double Te_RxD = (Te_old[i][j-1]+Te_old[i+1][j-1])/2.0;
                double Te_Lr  = (Te_old[i][j]+Te_old[i][j-1])/2.0;

                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;

                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                double dTedx_LxD = (Te_old[i  ][j-1] - Te_old[i-1][j-1])/dx;
                double dTedx_Rx  = (Te_old[i+1][j  ] - Te_old[i  ][j  ])/dx;
                double dTedx_RxD = (Te_old[i+1][j-1] - Te_old[i  ][j-1])/dx;
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;

                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double z_Lx = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr = vd_Lr*dr/D_Lr;
                
                double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                //壁の接線方向の処理
                if(bLx_Lr == 0 || bRx_Lr == 0){
                    Cr_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    Cc_Lr = 0.0;
                }

                Gr[i][j] 
                    =((- Cr_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + Cc_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))
                       - Cc_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (Cr_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp)))
                       - Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoeps[i][j-1]
                    - (Cc_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoeps[i+1][j]
                    + (Cc_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoeps[i-1][j]
                    - (Cc_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoeps[i+1][j-1]
                    + (Cc_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0;
            }
        }
    }

    //電位境界用に入れておく
    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        Te[i-1][j] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        Te[i-1][j] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        Te[i-1][j] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        Te[i+1][j] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gx[i+1][j] = rhoeps[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        Te[i+1][j] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gx[i+1][j] = rhoeps[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }

    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        Te[i][j-1] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        Te[i][j+1] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gr[i][j+1] = rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j+1]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        Te[i][j+1] = Te[i][j];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        Gr[i][j+1] = rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j+1]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        Te[i][j+1] = Te[i][j];
        Gr[i][j+1] = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
    }

    //誤差を計算
    error_rhoeps = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }

    error_Gx = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }

    error_Gr = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_wdTe_direct(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_new(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //limit the arguments of exponential functions not to overflow.
    double EPS = 1.0e-3; //small values to avoid zero division in SG scheme
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    //------------------------------------
    
    //Make coefficient for electron (internal) energy conservation for 9 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xx_hat_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_rr_hat_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xr_hat_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_xr_hat_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;

                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te_old[i][j]   + Te_old[i-1][j]  )/2.0;
                double Te_LxU = (Te_old[i][j+1] + Te_old[i-1][j+1])/2.0;
                double Te_LxD = (Te_old[i][j-1] + Te_old[i-1][j-1])/2.0;
                double Te_Rx  = (Te_old[i][j]   + Te_old[i+1][j]  )/2.0;
                double Te_RxU = (Te_old[i][j+1] + Te_old[i+1][j+1])/2.0;
                double Te_RxD = (Te_old[i][j-1] + Te_old[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te_old[i][j]   + Te_old[i][j-1]  )/2.0;
                double Te_LrU = (Te_old[i+1][j] + Te_old[i+1][j-1])/2.0;
                double Te_LrD = (Te_old[i-1][j] + Te_old[i-1][j-1])/2.0;
                double Te_Rr  = (Te_old[i][j]   + Te_old[i][j+1]  )/2.0;
                double Te_RrU = (Te_old[i+1][j] + Te_old[i+1][j+1])/2.0;
                double Te_RrD = (Te_old[i-1][j] + Te_old[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                double dTedx_LxU = (Te_old[i  ][j+1] - Te_old[i-1][j+1])/dx;
                double dTedx_LxD = (Te_old[i  ][j-1] - Te_old[i-1][j-1])/dx;
                double dTedx_Rx  = (Te_old[i+1][j  ] - Te_old[i  ][j  ])/dx;
                double dTedx_RxU = (Te_old[i+1][j+1] - Te_old[i  ][j+1])/dx;
                double dTedx_RxD = (Te_old[i+1][j-1] - Te_old[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                double dTedr_LrU = (Te_old[i+1][j  ] - Te_old[i+1][j-1])/dr;
                double dTedr_LrD = (Te_old[i-1][j  ] - Te_old[i-1][j-1])/dr;
                double dTedr_Rr  = (Te_old[i  ][j+1] - Te_old[i  ][j  ])/dr;
                double dTedr_RrU = (Te_old[i+1][j+1] - Te_old[i+1][j  ])/dr;
                double dTedr_RrD = (Te_old[i-1][j+1] - Te_old[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;

                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;

                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "cell" to the wall, open, or central axis BC
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;

                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;

                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_open;
                //------------------------------------

                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                double btLxU_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                double btRxU_wall  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                btRxU_wall = btRxU_wall*double(i!=i_flr_bl[4][1]); //z5

                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                double btLrU_wall  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                btLrU_wall = btLrU_wall*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                double btRrU_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrU_wall = btRrU_wall*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                double btRrU_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //------------------------------------
                //*****************************************************

                //BC - normal flux component to the wall or open boundaries
                //*****************************************************
                //wall-flux divide by density (for implicit method)
                //------------------------------------
                double GammaPerNeps_wall_Lx = 0.0;
                double GammaPerNeps_wall_Rx = 0.0;
                double GammaPerNeps_wall_Lr = 0.0;
                double GammaPerNeps_wall_Rr = 0.0;
                if(bLx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                if(bRx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                if(bLr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                if(bRr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                //------------------------------------

                //open-flux (equal to ion)
                //------------------------------------
                double Gamma_open_Rx = 0.0;
                double Gamma_open_Rr = 0.0;
                if(bRr_open == 0){
                    Gamma_open_Rr = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
                }
                //------------------------------------
                //*****************************************************

                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                double Gamma_trans_x_term2_Rx = 0.0;

                double Gamma_trans_r_term2_Lr = 0.0;
                double Gamma_trans_r_term2_Rr = 0.0;
                //------------------------------------
                
                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                if(btLxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    double mu_hat_trans_r_term2_Rr = (mu_xr[i][j]/mu_xx[i][j] + mu_xr[i][j+1]/mu_xx[i][j+1])/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double Gx_out_Rr =  0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*Gx_out_Rr;
                }
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btLrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    double mu_hat_trans_x_term2_Rx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i+1][j]/mu_rr[i+1][j])/2.0;

                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;

                    double Gr_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*Gr_out_Rx;
                }
                //------------------------------------

                //r-directional flux adjacent to right-open boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                if(btRxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]  /mu_xx[i][j]  )/2.0;
                    double mu_hat_trans_r_term2_Rr = (  mu_xr[i][j+1]/mu_xx[i][j+1] +   mu_xr[i][j]  /mu_xx[i][j]  )/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double Gx_out_Rr =  0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*Gx_out_Rr;
                }
                //------------------------------------
                
                //x-directional flux adjacent to upper-open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 5.0/2.0*Boltz*(Te_old[i][j]*fmax(rhoUer[i][j+1],0.0) 
                        + Te_old[i-1][j]*fmax(rhoUer[i-1][j+1],0.0))/2.0;
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btRrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double Gr_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*Gr_out_Rx;
                }
                if(btRrU_open == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double Gr_out_Rx = 5.0/2.0*Boltz*(Te_old[i][j]*fmax(rhoUer[i][j+1],0.0) 
                        + Te_old[i+1][j]*fmax(rhoUer[i+1][j+1],0.0))/2.0;
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*Gr_out_Rx;
                }
                //------------------------------------
                //*****************************************************

                //coefficient for electron energy conservation for 9 point stencil
                //*****************************************************
                //vertical and horizental 5 stencil
                //------------------------------------
                aP[i][j] =      (    mu_xx_hat_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    + mu_xr_hat_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - mu_xr_hat_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                    + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*mu_rr_hat_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    + mu_xr_hat_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - mu_xr_hat_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                    + mu_xr_hat_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - mu_xr_hat_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                        + 3.0/5.0*(
                            -    GammaPerNeps_wall_Lx*dr //wall-flux boundary at left  wall (implicit)
                            +    GammaPerNeps_wall_Rx*dr //wall-flux boundary at right wall (implicit)
                            - qL*GammaPerNeps_wall_Lr*dx //wall-flux boundary at lower wall (implicit)
                            + qR*GammaPerNeps_wall_Rr*dx //wall-flux boundary at upper wall (implicit)
                            + delossdeps[i][j]*dx*dr //part of implicit source term prediction
                            + dx*dr/dt //time term
                                );
                aE[i][j] =  (mu_xx_hat_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + mu_xr_hat_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                            )*dr*bRx
                          + (mu_xr_hat_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                          - (mu_xr_hat_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (mu_xr_hat_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (mu_xr_hat_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] =  (qR*mu_rr_hat_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                            )*dx*bRr
                          + (qR*mu_xr_hat_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                          - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] =  (qL*mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                            )*dx*bLr
                          - (qL*mu_xr_hat_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                          + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                //------------------------------------

                //oblique 4 stencil
                //------------------------------------
                aEN[i][j] = (mu_xr_hat_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                          + (mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] =-(mu_xr_hat_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                           -(mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] =-(mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                           -(mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] = (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                           +(mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;
                //------------------------------------

                //RHS
                //------------------------------------
                double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                double RHS1 =  rhoeps_old[i][j]/dt;
                double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                double RHS3 = Pabs[i][j] - rhoe[i][j]*rate_eloss[i][j]
                    + delossdeps[i][j]*(rhoe[i][j]*(3.0/2.0*Boltz*Te_old[i][j])); //part of implicit source term prediction
                
                b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3)*dx*dr;
                //------------------------------------
                
                //flux boundaries
                //------------------------------------
                b[i][j] = b[i][j]
                    //left-BC
                    + 3.0/5.0*(
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Lx*bLx //at upper and lower (left interface)
                      )*dr
                    //right-BC
                    - 3.0/5.0*(
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Rx*bRx //at upper and lower (right interface)
                      )*dr
                    //lower-BC
                    + 3.0/5.0*qL*(
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Lr*bLr //at left and right (lower interface)
                      )*dx
                    //upper-BC
                    - 3.0/5.0*qR*(
                        //normal (r) boundary flux
                        + Gamma_open_Rr //Open-BC
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Rr*bRr //at left and right (upper interface)
                      )*dx;
                //------------------------------------
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,rhoeps);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoeps);
    }

    //Don’t update unless the value is positive.
    //------------------------------------
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    ncount ++;
                    rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative Te count = " << ncount << std::endl;
    }
    //------------------------------------

    //calculate maximum electron density to avoid zero-division in Te calc.
    //------------------------------------
    double rhoe_max = 0.0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }
    //------------------------------------

    //calculate electron temperature
    //------------------------------------
    double Te_max = 200.0*e0/Boltz;
    double ratio = 0.01;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100),Te_max);
            }
        }
    }
    //------------------------------------

    //set values of ghost cells for transport coefficient
    //=====================================================================================
    
    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        Te[i+1][j] = Te[i][j];
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        Te[i+1][j] = Te[i][j];
    }
    //------------------------------------

    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        Te[i][j-1] = Te[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------
    //=====================================================================================

    //Update flux
    //=====================================================================================
    //for Gx
    //*****************************************************************
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te_old[i][j]+Te_old[i-1][j])/2.0;

                double Te_Lr  = (Te_old[i][j]  + Te_old[i][j-1]  )/2.0;
                double Te_LrD = (Te_old[i-1][j]+ Te_old[i-1][j-1])/2.0;
                double Te_Rr  = (Te_old[i][j]  + Te_old[i][j+1]  )/2.0;
                double Te_RrD = (Te_old[i-1][j]+ Te_old[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                double dTedr_LrD = (Te_old[i-1][j  ] - Te_old[i-1][j-1])/dr;
                double dTedr_Rr  = (Te_old[i  ][j+1] - Te_old[i  ][j  ])/dr;
                double dTedr_RrD = (Te_old[i-1][j+1] - Te_old[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //*****************************************************

                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                //------------------------------------

                //x-directional flux adjacent to upper-open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 5.0/2.0*Boltz*(Te_old[i][j]*fmax(rhoUer[i][j+1],0.0) 
                        + Te_old[i-1][j]*fmax(rhoUer[i-1][j+1],0.0))/2.0;
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                //------------------------------------
                //*****************************************************

                //update Gx
                //------------------------------------
                Gx[i][j] 
                    =((-mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))
                        - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoeps[i-1][j]
                    - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoeps[i][j+1]
                    + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoeps[i][j-1]
                    - (mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoeps[i-1][j+1]
                    + (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0
                    + Gamma_trans_x_term2_Lx;
                //------------------------------------
            }
        }
    }
    
    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx;
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx;
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx;
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx;
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx;
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx;
    }
    //------------------------------------
    //*****************************************************************

    //for Gr
    //*****************************************************************
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //radial position at upper and lower cell interface
                //------------------------------------
                //double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                double Te_LxD = (Te_old[i][j-1]+Te_old[i-1][j-1])/2.0;
                double Te_Rx  = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                double Te_RxD = (Te_old[i][j-1] + Te_old[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te_old[i][j]   + Te_old[i][j-1]  )/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                double dTedx_LxD = (Te_old[i  ][j-1] - Te_old[i-1][j-1])/dx;
                double dTedx_Rx  = (Te_old[i+1][j  ] - Te_old[i  ][j  ])/dx;
                double dTedx_RxD = (Te_old[i+1][j-1] - Te_old[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                //------------------------------------
                //*****************************************************

                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                //------------------------------------
                //*****************************************************
                
                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_r_term2_Lr = 0.0;
                //------------------------------------

                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                //------------------------------------
                
                //r-directional flux adjacent to right-open boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                //------------------------------------
                //*****************************************************

                //update Gr
                //------------------------------------
                Gr[i][j] 
                    =((- mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))
                       - mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp)))
                       - mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoeps[i][j-1]
                    - (mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoeps[i+1][j]
                    + (mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoeps[i-1][j]
                    - (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoeps[i+1][j-1]
                    + (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0
                    + Gamma_trans_r_term2_Lr;
                //------------------------------------
            }
        }
    }

    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr;
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr;
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr;
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr;
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        double Gamma_open_Rr = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
        Gr[i][j+1] = Gamma_open_Rr;
    }
    //------------------------------------
    //*****************************************************************
    //=====================================================================================

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoeps = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_Gx = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_Gr = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_wdTe_wSEE_direct(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aEN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aES(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aWS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_new(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //limit the arguments of exponential functions not to overflow.
    double EPS = 1.0e-3; //small values to avoid zero division in SG scheme
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    //------------------------------------
    
    //Make coefficient for electron (internal) energy conservation for 9 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xx_hat_Rx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_rr_hat_Rr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j+1]/mu_para[i][j+1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                double mu_xr_hat_Rx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i+1][j]/mu_para[i+1][j])/2.0;
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                double mu_xr_hat_Rr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j+1]/mu_para[i][j+1])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]   + mu_para[i-1][j]  )/2.0;
                double mu_para_LxU = (mu_para[i][j+1] + mu_para[i-1][j+1])/2.0;
                double mu_para_LxD = (mu_para[i][j-1] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]   + mu_para[i+1][j]  )/2.0;
                double mu_para_RxU = (mu_para[i][j+1] + mu_para[i+1][j+1])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;

                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                double mu_para_LrU = (mu_para[i+1][j] + mu_para[i+1][j-1])/2.0;
                double mu_para_LrD = (mu_para[i-1][j] + mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]   + mu_para[i][j+1]  )/2.0;
                double mu_para_RrU = (mu_para[i+1][j] + mu_para[i+1][j+1])/2.0;
                double mu_para_RrD = (mu_para[i-1][j] + mu_para[i-1][j+1])/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te_old[i][j]   + Te_old[i-1][j]  )/2.0;
                double Te_LxU = (Te_old[i][j+1] + Te_old[i-1][j+1])/2.0;
                double Te_LxD = (Te_old[i][j-1] + Te_old[i-1][j-1])/2.0;
                double Te_Rx  = (Te_old[i][j]   + Te_old[i+1][j]  )/2.0;
                double Te_RxU = (Te_old[i][j+1] + Te_old[i+1][j+1])/2.0;
                double Te_RxD = (Te_old[i][j-1] + Te_old[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te_old[i][j]   + Te_old[i][j-1]  )/2.0;
                double Te_LrU = (Te_old[i+1][j] + Te_old[i+1][j-1])/2.0;
                double Te_LrD = (Te_old[i-1][j] + Te_old[i-1][j-1])/2.0;
                double Te_Rr  = (Te_old[i][j]   + Te_old[i][j+1]  )/2.0;
                double Te_RrU = (Te_old[i+1][j] + Te_old[i+1][j+1])/2.0;
                double Te_RrD = (Te_old[i-1][j] + Te_old[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxU = Boltz*Te_LxU/e0*mu_para_LxU;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxU = Boltz*Te_RxU/e0*mu_para_RxU;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrU = Boltz*Te_LrU/e0*mu_para_LrU;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrU = Boltz*Te_RrU/e0*mu_para_RrU;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                double dTedx_LxU = (Te_old[i  ][j+1] - Te_old[i-1][j+1])/dx;
                double dTedx_LxD = (Te_old[i  ][j-1] - Te_old[i-1][j-1])/dx;
                double dTedx_Rx  = (Te_old[i+1][j  ] - Te_old[i  ][j  ])/dx;
                double dTedx_RxU = (Te_old[i+1][j+1] - Te_old[i  ][j+1])/dx;
                double dTedx_RxD = (Te_old[i+1][j-1] - Te_old[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                double dTedr_LrU = (Te_old[i+1][j  ] - Te_old[i+1][j-1])/dr;
                double dTedr_LrD = (Te_old[i-1][j  ] - Te_old[i-1][j-1])/dr;
                double dTedr_Rr  = (Te_old[i  ][j+1] - Te_old[i  ][j  ])/dr;
                double dTedr_RrU = (Te_old[i+1][j+1] - Te_old[i+1][j  ])/dr;
                double dTedr_RrD = (Te_old[i-1][j+1] - Te_old[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx* (-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxU = mu_para_LxU*(-Ex[i  ][j+1] - Boltz/e0*dTedx_LxU) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx* (-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxU = mu_para_RxU*(-Ex[i+1][j+1] - Boltz/e0*dTedx_RxU) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;

                double vd_Lr  = mu_para_Lr* (-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrU = mu_para_LrU*(-Er[i+1][j  ] - Boltz/e0*dTedr_LrU) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr* (-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrU = mu_para_RrU*(-Er[i+1][j+1] - Boltz/e0*dTedr_RrU) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxU = vd_LxU*dx/D_LxU;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxU = vd_RxU*dx/D_RxU;
                double z_RxD = vd_RxD*dx/D_RxD;

                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrU = vd_LrU*dr/D_LrU;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrU = vd_RrU*dr/D_RrU;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "cell" to the wall, open, or central axis BC
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;

                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;

                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_open;
                //------------------------------------

                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                double btLxU_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                btLxU_wall = btLxU_wall*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                double btRxU_wall  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                btRxU_wall = btRxU_wall*double(i!=i_flr_bl[4][1]); //z5

                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                double btLrU_wall  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                btLrU_wall = btLrU_wall*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                
                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                double btRrU_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrU_wall = btRrU_wall*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                double btRrU_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //------------------------------------
                //*****************************************************

                //BC - normal flux component to the wall or open boundaries
                //*****************************************************
                //wall-flux divide by density (for implicit method)
                //------------------------------------
                double GammaPerNeps_wall_Lx = 0.0;
                double GammaPerNeps_wall_Rx = 0.0;
                double GammaPerNeps_wall_Lr = 0.0;
                double GammaPerNeps_wall_Rr = 0.0;
                if(bLx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                if(bRx_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                if(bLr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                if(bRr_wall == 0){
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
                    GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
                }
                //------------------------------------

                //open-flux (equal to ion)
                //------------------------------------
                double Gamma_open_Rx = 0.0;
                double Gamma_open_Rr = 0.0;
                if(bRr_open == 0){
                    Gamma_open_Rr = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
                }
                //------------------------------------

                //wallSEE-flux
                //------------------------------------
                double Gamma_wallSEE_Lx = 0.0;
                double Gamma_wallSEE_Rx = 0.0;
                double Gamma_wallSEE_Lr = 0.0;
                double Gamma_wallSEE_Rr = 0.0;
                if(bLx_wall == 0){
                    double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
                    double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));
                    
                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);
                    
                    Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE
                }
                if(bRx_wall == 0){
                    double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
                    double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);
                    
                    Gamma_wallSEE_Rx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rx //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
                }
                if(bLr_wall == 0){
                    double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
                    double GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

                    Gamma_wallSEE_Lr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lr //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j]; //MISEE
                }
                if(bRr_wall == 0){
                    double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                    double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
                    double GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));
                    
                    double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
                    double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
                    double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

                    Gamma_wallSEE_Rr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rr //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
                }
                //*****************************************************

                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                double Gamma_trans_x_term2_Rx = 0.0;

                double Gamma_trans_r_term2_Lr = 0.0;
                double Gamma_trans_r_term2_Rr = 0.0;
                //------------------------------------
                
                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                if(btLxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]/mu_xx[i][j])/2.0;
                    double mu_hat_trans_r_term2_Rr = (mu_xr[i][j]/mu_xx[i][j] + mu_xr[i][j+1]/mu_xx[i][j+1])/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double Gx_out_Rr =  0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*Gx_out_Rr;
                }
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btLrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]/mu_rr[i][j])/2.0;
                    double mu_hat_trans_x_term2_Rx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i+1][j]/mu_rr[i+1][j])/2.0;

                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;

                    double Gr_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*Gr_out_Rx;
                }
                //------------------------------------

                //r-directional flux adjacent to right-open boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                if(btRxU_wall == 0){
                    double mu_hat_trans_r_term1_Rr = (mu_perp[i][j+1]/mu_xx[i][j+1] + mu_perp[i][j]  /mu_xx[i][j]  )/2.0;
                    double mu_hat_trans_r_term2_Rr = (  mu_xr[i][j+1]/mu_xx[i][j+1] +   mu_xr[i][j]  /mu_xx[i][j]  )/2.0;
                    
                    //substitution
                    mu_rr_hat_Rr = mu_hat_trans_r_term1_Rr;
                    mu_xr_hat_Rr = 0.0;

                    double Gx_out_Rr =  0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Rr = mu_hat_trans_r_term2_Rr*Gx_out_Rr;
                }
                //------------------------------------
                
                //x-directional flux adjacent to upper-open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 5.0/2.0*Boltz*(Te_old[i][j]*fmax(rhoUer[i][j+1],0.0) 
                        + Te_old[i-1][j]*fmax(rhoUer[i-1][j+1],0.0))/2.0;
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btRrU_wall == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double Gr_out_Rx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*Gr_out_Rx;
                }
                if(btRrU_open == 0){
                    double mu_hat_trans_x_term1_Rx = (mu_perp[i+1][j]/mu_rr[i+1][j] + mu_perp[i][j]  /mu_rr[i][j]  )/2.0;
                    double mu_hat_trans_x_term2_Rx = (  mu_xr[i+1][j]/mu_rr[i+1][j] +   mu_xr[i][j]  /mu_rr[i][j]  )/2.0;
                    
                    mu_xx_hat_Rx = mu_hat_trans_x_term1_Rx;
                    mu_xr_hat_Rx = 0.0;
  
                    double Gr_out_Rx = 5.0/2.0*Boltz*(Te_old[i][j]*fmax(rhoUer[i][j+1],0.0) 
                        + Te_old[i+1][j]*fmax(rhoUer[i+1][j+1],0.0))/2.0;
                    Gamma_trans_x_term2_Rx = mu_hat_trans_x_term2_Rx*Gr_out_Rx;
                }
                //------------------------------------
                //*****************************************************

                //coefficient for electron energy conservation for 9 point stencil
                //*****************************************************
                //vertical and horizental 5 stencil
                //------------------------------------
                aP[i][j] =      (    mu_xx_hat_Rx*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    + mu_xr_hat_Rx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - mu_xr_hat_Rx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bRx
                         -      (   -mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                                    + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)
                                )*dr*bLx
                         +      ( qR*mu_rr_hat_Rr*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp))) 
                                    + mu_xr_hat_Rr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - mu_xr_hat_Rr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bRr
                         -      (-qL*mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                                    + mu_xr_hat_Lr   /4.0*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp))) 
                                    - mu_xr_hat_Lr   /4.0*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)
                                )*dx*bLr
                        + 3.0/5.0*(
                            -    GammaPerNeps_wall_Lx*dr //wall-flux boundary at left  wall (implicit)
                            +    GammaPerNeps_wall_Rx*dr //wall-flux boundary at right wall (implicit)
                            - qL*GammaPerNeps_wall_Lr*dx //wall-flux boundary at lower wall (implicit)
                            + qR*GammaPerNeps_wall_Rr*dx //wall-flux boundary at upper wall (implicit)
                            + delossdeps[i][j]*dx*dr //part of implicit source term prediction
                            + dx*dr/dt //time term
                                );
                aE[i][j] =  (mu_xx_hat_Rx*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rx*qR/4.0*vd_RrU/(1.0 - exp(fmin(-z_RrU,lim_exp))) 
                                + mu_xr_hat_Rx*qL/4.0*vd_LrU/(exp(fmin( z_LrU,lim_exp)) - 1.0)
                            )*dr*bRx
                          + (mu_xr_hat_Rr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bRr
                          - (mu_xr_hat_Lr/4.0*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*dx*bLr;
                aW[i][j] =  (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                                + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp))) 
                                - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0)
                            )*dr*bLx
                          - (mu_xr_hat_Rr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bRr
                          + (mu_xr_hat_Lr/4.0*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*dx*bLr;
                aN[i][j] =  (qR*mu_rr_hat_Rr*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0) 
                                - mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(1.0 - exp(fmin(-z_RxU,lim_exp))) 
                                + mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(exp(fmin( z_LxU,lim_exp)) - 1.0)
                            )*dx*bRr
                          + (qR*mu_xr_hat_Rx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bRx
                          - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*dr*bLx;
                aS[i][j] =  (qL*mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                                + mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp))) 
                                - mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0)
                            )*dx*bLr
                          - (qL*mu_xr_hat_Rx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bRx
                          + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*dr*bLx;
                //------------------------------------

                //oblique 4 stencil
                //------------------------------------
                aEN[i][j] = (mu_xr_hat_Rx*qR/4.0*vd_RrU/(exp(fmin( z_RrU,lim_exp)) - 1.0))*dr*bRx
                          + (mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_RxU/(exp(fmin( z_RxU,lim_exp)) - 1.0))*dx*bRr;
                aES[i][j] =-(mu_xr_hat_Rx*qL/4.0*vd_LrU/(1.0 - exp(fmin(-z_LrU,lim_exp))))*dr*bRx
                           -(mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*dx*bLr;
                aWN[i][j] =-(mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*dr*bLx
                           -(mu_xr_hat_Rr*r[j+1]/(4.0*r[j])*vd_LxU/(1.0 - exp(fmin(-z_LxU,lim_exp))))*dx*bRr;
                aWS[i][j] = (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*dr*bLx
                           +(mu_xr_hat_Lr*r[j-1]/(4.0*r[j])*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*dx*bLr;
                //------------------------------------

                //RHS
                //------------------------------------
                double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                double RHS1 =  rhoeps_old[i][j]/dt;
                double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                double RHS3 = Pabs[i][j] - rhoe[i][j]*rate_eloss[i][j]
                    + delossdeps[i][j]*(rhoe[i][j]*(3.0/2.0*Boltz*Te_old[i][j])); //part of implicit source term prediction
                
                b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3)*dx*dr;
                //------------------------------------
                
                //flux boundaries
                //------------------------------------
                b[i][j] = b[i][j]
                    //left-BC
                    + 3.0/5.0*(
                        //normal (x) wall-SEE flux
                        + Gamma_wallSEE_Lx //wall-SEE
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Lx*bLx //at upper and lower (left interface)
                      )*dr
                    //right-BC
                    - 3.0/5.0*(
                        //normal (x) wall-SEE flux
                        + Gamma_wallSEE_Rx //wall-SEE
                        //Second term of tangential (x) boundary flux
                        + Gamma_trans_x_term2_Rx*bRx //at upper and lower (right interface)
                      )*dr
                    //lower-BC
                    + 3.0/5.0*qL*(
                        //normal (r) wall-SEE flux
                        + Gamma_wallSEE_Lr //wall-SEE
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Lr*bLr //at left and right (lower interface)
                      )*dx
                    //upper-BC
                    - 3.0/5.0*qR*(
                        //normal (r) boundary flux
                        + Gamma_open_Rr //Open-BC
                        //normal (r) wall-SEE flux
                        + Gamma_wallSEE_Rr //wall-SEE
                        //Second term of tangential (r) boundary flux
                        + Gamma_trans_r_term2_Rr*bRr //at left and right (upper interface)
                      )*dx;
                //------------------------------------
            }
        }
    }

    //solve
    if(icon_iter_rhoe == 0){ //icon_iter_rhoe == 0
        solver_GMRES_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,rhoeps);
    }else{
        solver_LU_9p(aP,aE,aW,aN,aS,aEN,aES,aWN,aWS,b,i_flc_bl,j_flc_bl,0,rhoeps);
    }

    //Don’t update unless the value is positive.
    //------------------------------------
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    ncount ++;
                    rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative Te count = " << ncount << std::endl;
    }
    //------------------------------------

    //calculate maximum electron density to avoid zero-division in Te calc.
    //------------------------------------
    double rhoe_max = 0.0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }
    //------------------------------------

    //calculate electron temperature
    //------------------------------------
    double Te_max = 1000.0*e0/Boltz;
    double ratio = 0.01;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100),Te_max);
            }
        }
    }
    //------------------------------------

    //set values of ghost cells for transport coefficient
    //=====================================================================================
    
    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        Te[i+1][j] = Te[i][j];
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        Te[i+1][j] = Te[i][j];
    }
    //------------------------------------

    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        Te[i][j-1] = Te[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------
    //=====================================================================================

    //Update flux
    //=====================================================================================
    //for Gx
    //*****************************************************************
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_xx_hat_Lx = (mu_xx[i][j]/mu_para[i][j] + mu_xx[i-1][j]/mu_para[i-1][j])/2.0;
                //nondiagonal
                double mu_xr_hat_Lx = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i-1][j]/mu_para[i-1][j])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]  + mu_para[i][j-1]  )/2.0;
                double mu_para_LrD = (mu_para[i-1][j]+ mu_para[i-1][j-1])/2.0;
                double mu_para_Rr  = (mu_para[i][j]  + mu_para[i][j+1]  )/2.0;
                double mu_para_RrD = (mu_para[i-1][j]+ mu_para[i-1][j+1])/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te_old[i][j]+Te_old[i-1][j])/2.0;

                double Te_Lr  = (Te_old[i][j]  + Te_old[i][j-1]  )/2.0;
                double Te_LrD = (Te_old[i-1][j]+ Te_old[i-1][j-1])/2.0;
                double Te_Rr  = (Te_old[i][j]  + Te_old[i][j+1]  )/2.0;
                double Te_RrD = (Te_old[i-1][j]+ Te_old[i-1][j+1])/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                double D_LrD = Boltz*Te_LrD/e0*mu_para_LrD;
                double D_Rr  = Boltz*Te_Rr/e0*mu_para_Rr;
                double D_RrD = Boltz*Te_RrD/e0*mu_para_RrD;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                double dTedr_LrD = (Te_old[i-1][j  ] - Te_old[i-1][j-1])/dr;
                double dTedr_Rr  = (Te_old[i  ][j+1] - Te_old[i  ][j  ])/dr;
                double dTedr_RrD = (Te_old[i-1][j+1] - Te_old[i-1][j  ])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                double vd_LrD = mu_para_LrD*(-Er[i-1][j  ] - Boltz/e0*dTedr_LrD) + EPS;
                double vd_Rr  = mu_para_Rr *(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr ) + EPS;
                double vd_RrD = mu_para_RrD*(-Er[i-1][j+1] - Boltz/e0*dTedr_RrD) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_Lr  = vd_Lr*dr/D_Lr;
                double z_LrD = vd_LrD*dr/D_LrD;
                double z_Rr  = vd_Rr*dr/D_Rr;
                double z_RrD = vd_RrD*dr/D_RrD;
                //------------------------------------
                //*****************************************************

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //*****************************************************
                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //lower
                double btLrD_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                btLrD_wall = btLrD_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                //upper
                double btRrD_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                btRrD_wall = btRrD_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                double btRrD_open = double(j!=j_flx_bl[4][1] || iblock != 4); //x5
                //*****************************************************

                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_x_term2_Lx = 0.0;
                //------------------------------------

                //x-directional flux adjacent to lower-wall
                //------------------------------------
                if(btLrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]/mu_rr[i][j] + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (mu_xr[i][j]/mu_rr[i][j] + mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                //------------------------------------

                //x-directional flux adjacent to upper-open boundary
                //------------------------------------
                if(btRrD_wall == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                if(btRrD_open == 0){
                    double mu_hat_trans_x_term1_Lx = (mu_perp[i][j]  /mu_rr[i][j]   + mu_perp[i-1][j]/mu_rr[i-1][j])/2.0;
                    double mu_hat_trans_x_term2_Lx = (  mu_xr[i][j]  /mu_rr[i][j]   +   mu_xr[i-1][j]/mu_rr[i-1][j])/2.0;

                    mu_xx_hat_Lx = mu_hat_trans_x_term1_Lx;
                    mu_xr_hat_Lx = 0.0;

                    double Gr_out_Lx = 5.0/2.0*Boltz*(Te_old[i][j]*fmax(rhoUer[i][j+1],0.0) 
                        + Te_old[i-1][j]*fmax(rhoUer[i-1][j+1],0.0))/2.0;
                    Gamma_trans_x_term2_Lx = mu_hat_trans_x_term2_Lx*Gr_out_Lx;
                }
                //------------------------------------
                //*****************************************************

                //update Gx
                //------------------------------------
                Gx[i][j] 
                    =((-mu_xx_hat_Lx*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0) 
                        + mu_xr_hat_Lx*qR/4.0*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))
                        - mu_xr_hat_Lx*qL/4.0*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (mu_xx_hat_Lx*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))) 
                        + mu_xr_hat_Lx*qR/4.0*vd_RrD/(1.0 - exp(fmin(-z_RrD,lim_exp)))
                        - mu_xr_hat_Lx*qL/4.0*vd_LrD/(exp(fmin( z_LrD,lim_exp)) - 1.0))*rhoeps[i-1][j]
                    - (qR*mu_xr_hat_Lx/4.0*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0))*rhoeps[i][j+1]
                    + (qL*mu_xr_hat_Lx/4.0*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))))*rhoeps[i][j-1]
                    - (mu_xr_hat_Lx*qR/4.0*vd_RrD/(exp(fmin( z_RrD,lim_exp)) - 1.0))*rhoeps[i-1][j+1]
                    + (mu_xr_hat_Lx*qL/4.0*vd_LrD/(1.0 - exp(fmin(-z_LrD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0
                    + Gamma_trans_x_term2_Lx;
                //------------------------------------
            }
        }
    }
    
    //left-wall-BC (z0)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //left-wall-BC (z1)
    //------------------------------------
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //left-wall-BC (z2)
    //------------------------------------
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //left-wall-BC (z4)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Ex[i][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                        - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                        - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                        - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

        Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
    }
    //------------------------------------

    //right-wall-BC (z3)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Rx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rx //EISEE
            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
            - eps_emitSEE*coefMISEE_ts*rhoUmx[i+1][j]; //MISEE

        Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx + Gamma_wallSEE_Rx;
    }
    //------------------------------------

    //right-wall-BC (z5)
    //------------------------------------
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Ex[i+1][j]*dx/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Rx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rx //EISEE
            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
            - eps_emitSEE*coefMISEE_ts*rhoUmx[i+1][j]; //MISEE
                        
        Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx + Gamma_wallSEE_Rx;
    }
    //------------------------------------
    //*****************************************************************

    //for Gr
    //*****************************************************************
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                //double rR = (r[j]+r[j+1])/2.0;
                double rL = (r[j]+r[j-1])/2.0;
                //------------------------------------

                //radial position at upper and lower cell interface
                //------------------------------------
                //double qR = rR/r[j];
                double qL = rL/r[j];
                //------------------------------------

                //Sharfetter-Gummmel scheme
                //*****************************************************
                //normalized moblity tensor by parallel mobility at cell interface
                //------------------------------------
                //diagonal
                double mu_rr_hat_Lr = (mu_rr[i][j]/mu_para[i][j] + mu_rr[i][j-1]/mu_para[i][j-1])/2.0;
                //nondiagonal
                double mu_xr_hat_Lr = (mu_xr[i][j]/mu_para[i][j] + mu_xr[i][j-1]/mu_para[i][j-1])/2.0;
                //------------------------------------

                //parallel moblity at cell interface
                //------------------------------------
                double mu_para_Lx  = (mu_para[i][j]+mu_para[i-1][j])/2.0;
                double mu_para_LxD = (mu_para[i][j-1]+mu_para[i-1][j-1])/2.0;
                double mu_para_Rx  = (mu_para[i][j]+mu_para[i+1][j])/2.0;
                double mu_para_RxD = (mu_para[i][j-1] + mu_para[i+1][j-1])/2.0;
                
                double mu_para_Lr  = (mu_para[i][j]   + mu_para[i][j-1]  )/2.0;
                //------------------------------------

                //electron temperature at cell interface
                //------------------------------------
                double Te_Lx  = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                double Te_LxD = (Te_old[i][j-1]+Te_old[i-1][j-1])/2.0;
                double Te_Rx  = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                double Te_RxD = (Te_old[i][j-1] + Te_old[i+1][j-1])/2.0;
                
                double Te_Lr  = (Te_old[i][j]   + Te_old[i][j-1]  )/2.0;
                //------------------------------------

                //electron diffusion coefficient at cell interface
                //------------------------------------
                double D_Lx  = Boltz*Te_Lx/e0*mu_para_Lx;
                double D_LxD = Boltz*Te_LxD/e0*mu_para_LxD;
                double D_Rx  = Boltz*Te_Rx/e0*mu_para_Rx;
                double D_RxD = Boltz*Te_RxD/e0*mu_para_RxD;
                
                double D_Lr  = Boltz*Te_Lr/e0*mu_para_Lr;
                //------------------------------------

                //electron temperature gradient at cell interface
                //------------------------------------
                double dTedx_Lx  = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                double dTedx_LxD = (Te_old[i  ][j-1] - Te_old[i-1][j-1])/dx;
                double dTedx_Rx  = (Te_old[i+1][j  ] - Te_old[i  ][j  ])/dx;
                double dTedx_RxD = (Te_old[i+1][j-1] - Te_old[i  ][j-1])/dx;
                
                double dTedr_Lr  = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                //------------------------------------

                //electron drift velocity at cell interface
                //------------------------------------
                double vd_Lx  = mu_para_Lx *(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx ) + EPS;
                double vd_LxD = mu_para_LxD*(-Ex[i  ][j-1] - Boltz/e0*dTedx_LxD) + EPS;
                double vd_Rx  = mu_para_Rx *(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx ) + EPS;
                double vd_RxD = mu_para_RxD*(-Ex[i+1][j-1] - Boltz/e0*dTedx_RxD) + EPS;
                
                double vd_Lr  = mu_para_Lr *(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr ) + EPS;
                //------------------------------------

                //Peclet number at cell interface
                //------------------------------------
                double z_Lx  = vd_Lx*dx/D_Lx;
                double z_LxD = vd_LxD*dx/D_LxD;
                double z_Rx  = vd_Rx*dx/D_Rx;
                double z_RxD = vd_RxD*dx/D_RxD;
                double z_Lr  = vd_Lr*dr/D_Lr;
                //------------------------------------
                //*****************************************************

                //adjacent "tangential flux" to the wall, open BC
                //------------------------------------
                //left
                double btLxD_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                btLxD_wall = btLxD_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                //right
                double btRxD_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                btRxD_wall = btRxD_wall*double(i!=i_flr_bl[4][1]); //z5
                //------------------------------------
                //*****************************************************
                
                //BC - utilize transverse-flux method to set tangential component adjacent to the wall or open boundaries
                //*****************************************************
                //second-term of transverse-flux method
                //------------------------------------
                double Gamma_trans_r_term2_Lr = 0.0;
                //------------------------------------

                //r-directional flux adjacent to left-wall
                //------------------------------------
                if(btLxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]/mu_xx[i][j] + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (mu_xr[i][j]/mu_xx[i][j]   + mu_xr[i][j-1]/mu_xx[i][j-1]  )/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                //------------------------------------
                
                //r-directional flux adjacent to right-open boundary
                //------------------------------------
                if(btRxD_wall == 0){
                    double mu_hat_trans_r_term1_Lr = (mu_perp[i][j]  /mu_xx[i][j]   + mu_perp[i][j-1]/mu_xx[i][j-1])/2.0;
                    double mu_hat_trans_r_term2_Lr = (  mu_xr[i][j]  /mu_xx[i][j]   +   mu_xr[i][j-1]/mu_xx[i][j-1])/2.0;

                    //substitution
                    mu_rr_hat_Lr = mu_hat_trans_r_term1_Lr;
                    mu_xr_hat_Lr = 0.0;

                    double Gx_out_Lr = 0.0; //outflow flux of electron (zero bulk velocity)
                    Gamma_trans_r_term2_Lr = mu_hat_trans_r_term2_Lr*Gx_out_Lr;
                }
                //------------------------------------
                //*****************************************************

                //update Gr
                //------------------------------------
                Gr[i][j] 
                    =((- mu_rr_hat_Lr*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0) 
                       + mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))
                       - mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0))*rhoeps[i][j]
                    + (mu_rr_hat_Lr*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp))) 
                       + mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(1.0 - exp(fmin(-z_RxD,lim_exp)))
                       - mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(exp(fmin( z_LxD,lim_exp)) - 1.0))*rhoeps[i][j-1]
                    - (mu_xr_hat_Lr/(4.0*qL)*vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0))*rhoeps[i+1][j]
                    + (mu_xr_hat_Lr/(4.0*qL)*vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp))))*rhoeps[i-1][j]
                    - (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_RxD/(exp(fmin( z_RxD,lim_exp)) - 1.0))*rhoeps[i+1][j-1]
                    + (mu_xr_hat_Lr*r[j-1]/(4.0*rL)*vd_LxD/(1.0 - exp(fmin(-z_LxD,lim_exp))))*rhoeps[i-1][j-1]
                    )*5.0/3.0
                    + Gamma_trans_r_term2_Lr;
                //------------------------------------
            }
        }
    }

    //lower-wall-BC (x0)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lr //EISEE
            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
            - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j]; //MISEE
         
        Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr + Gamma_wallSEE_Lr;
    }
    //------------------------------------

    //lower-wall-BC (x2)
    //------------------------------------
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi = -Er[i][j]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Lr = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Lr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lr //EISEE
            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
            - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j]; //MISEE

        Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr + Gamma_wallSEE_Lr;
    }
    //------------------------------------

    //upper-wall-BC (x1)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);
        
        double Gamma_wallSEE_Rr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rr //EISEE
            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
            - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j+1]; //MISEE

        Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr + Gamma_wallSEE_Rr;
    }
    //------------------------------------

    //upper-wall-BC (x4)
    //------------------------------------
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
        double delta_phi =  Er[i][j+1]*dr/2.0; //adjacent cell-center potential from wall
        double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
        double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
        double GammaPerN_wall_Rr = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

        double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
        double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
        double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

        double Gamma_wallSEE_Rr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rr //EISEE
            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
            - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j+1]; //MISEE

        Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr + Gamma_wallSEE_Rr;
    }
    //------------------------------------

    //upper-open-BC (x5)
    //------------------------------------
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        double Gamma_open_Rr = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
        Gr[i][j+1] = Gamma_open_Rr;
    }
    //------------------------------------
    //*****************************************************************
    //=====================================================================================

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoeps = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_Gx = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_Gr = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gx_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gr_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoeps(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGx(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGr(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //2.9
    double ratioY = 1.0; //2.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            drhoeps[i][j] = rhoeps[i][j] - rhoeps_old[i][j];

            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    
    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoeps_old_tmp[i][j] = rhoeps[i][j];
                Gx_old_tmp[i][j] = Gx[i][j];
                Gr_old_tmp[i][j] = Gr[i][j];
            }
        }

        //Gx更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //前ステップから
                    double Gr_tmp = (rR*Gr_old_tmp[i][j+1]*bRr + rL*Gr_old_tmp[i][j]*bLr 
                        + rR*Gr_old_tmp[i-1][j+1]*bRr + rL*Gr_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //前ステップから
                    Gx[i][j] = Gx_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*Gx_old_tmp[i][j] + mu_inv_xr_tmp*Gr_tmp)*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;
                    
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                        Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                    }
                    //右は電子フラックス x 5/2kTe
                    if(i == i_flc_bl[1][1]+1){
                        Gx[i][j] = 5.0/2.0*Boltz*Te_old[i-1][j]*rhoUex[i][j];
                    }
                }
            }     
        }

        //Gr更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //前のステップから
                    double Gx_tmp = (r[j]*Gx_old_tmp[i+1][j]*bRx + r[j]*Gx_old_tmp[i][j]*bLx
                        + r[j-1]*Gx_old_tmp[i+1][j-1]*bRx + r[j-1]*Gx_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    Gr[i][j] = Gr_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*Gx_tmp + mu_inv_rr_tmp*Gr_old_tmp[i][j])*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;

                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
                    
                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                        Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                    }    

                    //上はイオンフラックスと同じ
                    if(j == j_flc_bl[1][1]+1){
                        Gr[i][j] = 5.0/2.0*Boltz*Te_old[i][j-1]*rhoUer[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j]*double(j!=j_flc_bl[1][0]);

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                    double Te_Rx = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                    double Te_Lr = (Te_old[i][j]+Te_old[i][j-1])/2.0;
                    double Te_Rr = (Te_old[i][j]+Te_old[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx ;
                    double nbLr  = 1.0 - bLr ;

                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr 
                             +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                             + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                             + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                             +    0.2*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                             + qL*0.2*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                             + 3.0/5.0*delossdeps[i][j]*dx*dr //陰的ソース項予測
                             + 3.0/5.0*(dx*dr/dt + dx*dr/dtau*double(icon_dtau)); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;

                    double nabla_G = (Gx[i+1][j]-Gx[i][j])/dx + (qR*Gr[i][j+1]-qL*Gr[i][j])/dr;
                    double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                    double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                    double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                    double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                    double RHS1 = (-rhoeps[i][j] + rhoeps_old[i][j])/dt;
                    double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                    double RHS3 = Pabs[i][j]
                        - rhoe[i][j]*rate_eloss[i][j] 
                        - delossdeps[i][j]*rhoeps[i][j]
                        + rhoe[i][j]*(1.5*Boltz*Te[i][j])*delossdeps[i][j]; //陰的ソース項予測
                        
                    double RHS4 = -nabla_G;

                    b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3 + RHS4)*dx*dr;
                }
            }
        }

        //solve
        double alpha_SOR = 1.0;
        int icon_iter = 1;

        if(icon_iter_rhoeps==0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }

        /********************* 更新 *******************/
        //dGxを計算
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //フラックス
                    dGx[i][j] = (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }   
        }
        //dGrを計算
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    dGr[i][j] =  (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }
        }
        
        //更新
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //rhoeps[i][j] = fmax(rhoeps[i][j] + drhoeps[i][j],1e-6);
                    double rhoeps_new = rhoeps[i][j] + drhoeps[i][j];
                    if(rhoeps_new > 0.0){
                        rhoeps[i][j] = rhoeps_new;
                    }
                }
            }
        }
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    Gx[i][j] = Gx[i][j] + dGx[i][j];
                }
            }
        }
        for (int iblock=0;iblock<2;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    Gr[i][j] = Gr[i][j] + dGr[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoeps2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoeps_tmp = fabs((rhoeps[i][j]-rhoeps_old_tmp[i][j])/(rhoeps[i][j]+rhoeps_old_tmp[i][j]+1e-100));
                        if(error_rhoeps_tmp > error_rhoeps2){
                            error_rhoeps2 = error_rhoeps_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoeps = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoeps2 += pow(rhoeps[i][j]-rhoeps_old_tmp[i][j],2)/(pow(rhoeps_old_tmp[i][j]+1e10,2));
                        ncount_rhoeps++;
                    }
                }
            }
            error_rhoeps2 = sqrt(error_rhoeps2/double(ncount_rhoeps));
        }

        double error_Gx2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_Gx_tmp = fabs((Gx[i][j]-Gx_old_tmp[i][j])/(Gx[i][j]+Gx_old_tmp[i][j]+1e-100));
                        if(error_Gx_tmp > error_Gx2){
                            error_Gx2 = error_Gx_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gx = 0;
            for (int iblock=0;iblock<2;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_Gx2 += pow(Gx[i][j]-Gx_old_tmp[i][j],2)/(pow(Gx_old_tmp[i][j]+1e16,2));
                        ncount_Gx++;
                    }
                }
            }
            error_Gx2 = sqrt(error_Gx2/double(ncount_Gx));
        }

        double error_Gr2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_Gr_tmp = fabs((Gr[i][j]-Gr_old_tmp[i][j])/(Gr[i][j]+Gr_old_tmp[i][j]+1e-100));
                        if(error_Gr_tmp > error_Gr2){
                            error_Gr2 = error_Gr_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gr = 0;
            for (int iblock=0;iblock<2;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_Gr2 += pow(Gr[i][j]-Gr_old_tmp[i][j],2)/(pow(Gr_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_Gr++;
                    }
                }
            }
            error_Gr2 = sqrt(error_Gr2/double(ncount_Gr));
        }

        double error_global = fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoeps = " << error_rhoeps2
                <<  " error_Gx = " << error_Gx2
                <<  " error_Gr= " << error_Gr2
                <<  " error_max = " << fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2)
                << std::endl;
        }
       
        if(error_global < error_cnv_HES_rhoeps || ncount >= maxITR_HES_rhoeps){
            icon_end = 1;
        }
    
    } while (icon_end == 0);

    //電子密度の最大値を計算しておく
    double rhoe_max = 0.0;
    double ratio = 0.01;
    double Te_max = 20.0*e0/Boltz;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }

    std::cout << "ncount_Te = "<<ncount<<std::endl;
    
    //温度を更新
    //double alpha = 1.0;
    ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    ncount ++;
                    //rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                    rhoeps[i][j] = fmax(rhoeps[i][j],0.0);
                }
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100)*(1.0 + ratio),Te_max);
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative Te count = " << ncount << std::endl;
    }

    //輸送係数用に入れておく
    //左 壁1
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
    }

    //左 壁2
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        Te[i-1][j] = Te[i][j];
    }

    //下 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
    }

    //右 ノイマン
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        Te[i+1][j]  =  Te[i][j];
    }

    //上 ノイマン
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        Te[i][j+1] =  Te[i][j];
    }

    //誤差を計算
    error_rhoeps = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }

    error_Gx = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }

    error_Gr = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_wdTe_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gx_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gr_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoeps(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGx(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGr(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 0.5; //2.9
    double ratioY = 0.5; //2.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            drhoeps[i][j] = rhoeps[i][j] - rhoeps_old[i][j];

            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    
    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoeps_old_tmp[i][j] = rhoeps[i][j];
                Gx_old_tmp[i][j] = Gx[i][j];
                Gr_old_tmp[i][j] = Gr[i][j];
            }
        }

        //Gx更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2


                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    //double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    //double nbRr1  = 1.0 - bRr1; //x5だけ
                    //bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    //bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    //前ステップから
                    double Gr_tmp = (rR*Gr_old_tmp[i][j+1]*bRr + rL*Gr_old_tmp[i][j]*bLr 
                        + rR*Gr_old_tmp[i-1][j+1]*bRr_Lx + rL*Gr_old_tmp[i-1][j]*bLr_Lx)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_min_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_min_tmp);

                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_min_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //前ステップから
                    Gx[i][j] = Gx_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*Gx_old_tmp[i][j] + mu_inv_xr_tmp*Gr_tmp)*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;
                }
            }     
        }

        //Gr更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                    //前のステップから
                    double Gx_tmp = (r[j]*Gx_old_tmp[i+1][j]*bRx + r[j]*Gx_old_tmp[i][j]*bLx
                        + r[j-1]*Gx_old_tmp[i+1][j-1]*bRx_Lr + r[j-1]*Gx_old_tmp[i][j-1]*bLx_Lr)/(4.0*r_tmp);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_min_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_min_tmp);
    
                    double dTedr_tmp = (Te[i][j] - Te[i][j-1])/dr;
                    double vd_tmp = mu_min_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    Gr[i][j] = Gr_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*Gx_tmp + mu_inv_rr_tmp*Gr_old_tmp[i][j])*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;
                }
            }
        }

        //電位境界用に入れておく
        //左 壁 z0
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            Te[i-1][j] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //左 壁 z1
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            Te[i-1][j] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //左 壁 z2
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            Te[i-1][j] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //左 壁 z4
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            Te[i-1][j] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Ex[i][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //右 壁 z3
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            Te[i+1][j] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gx[i+1][j] = rhoeps[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //右 壁 z5
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            Te[i+1][j] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gx[i+1][j] = rhoeps[i][j]*exp(fmin(-e0*( Ex[i+1][j]*dx/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }

        //下 壁 x0
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            Te[i][j-1] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //下 壁 x2
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            Te[i][j-1] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }

        //上 壁 x1
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            Te[i][j+1] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gr[i][j+1] = rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j+1]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //上 壁 x4
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            Te[i][j+1] = Te[i][j];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            Gr[i][j+1] = rhoeps[i][j]*exp(fmin(-e0*(-Er[i][j+1]*dr/2.0)/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
        }
        //上 開放 x5
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            Te[i][j+1] = Te[i][j];
            Gr[i][j+1] = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
        }

        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];

                    double mu_min_Lx = (mu_min[i][j]+mu_min[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_min[i][j]+mu_min[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_min[i][j]+mu_min[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_min[i][j]+mu_min[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                    double Te_Rx = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                    double Te_Lr = (Te_old[i][j]+Te_old[i][j-1])/2.0;
                    double Te_Rr = (Te_old[i][j]+Te_old[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double dTedx_Lx = (Te[i  ][j  ] - Te[i-1][j  ])/dx;
                    double dTedx_Rx = (Te[i+1][j  ] - Te[i  ][j  ])/dx;
                    double dTedr_Lr = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double dTedr_Rr = (Te[i  ][j+1] - Te[i  ][j  ])/dr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0]); //z0
                    bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double nbLx  = 1.0 - bLx;

                    double bLx_Lr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLx_Lr = bLx_Lr*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4

                    double bLx_Rr  = double(i!=i_flr_bl[0][0]); //z0
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[2][0] || j+1>j_flr_bl[0][0]-1); //z1
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[3][0] || j+1>j_flr_bl[2][0]-1); //z2
                    bLx_Rr = bLx_Rr*double(i!=i_flr_bl[4][0] || j+1<j_flr_bl[1][0]); //z4

                    double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                    double nbRx  = 1.0 - bRx;

                    double bRx_Lr  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRx_Lr = bRx_Lr*double(i!=i_flr_bl[4][1]); //z5

                    double bRx_Rr  = double(i!=i_flr_bl[1][1] || j+1<j_flr_bl[1][0]); //z3
                    bRx_Rr = bRx_Rr*double(i!=i_flr_bl[4][1]); //z5

                    double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double nbLr  = 1.0 - bLr;

                    double bLr_Lx  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLr_Lx = bLr_Lx*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2

                    double bLr_Rx  = double(j!=j_flx_bl[0][0] || i+1>i_flx_bl[0][1]); //x0
                    bLr_Rx = bLr_Rx*double(j!=j_flx_bl[2][0] || i+1>i_flx_bl[2][1]); //x2
                    
                    double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double nbRr  = 1.0 - bRr; //x5含まない

                    double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                    double nbRr1  = 1.0 - bRr1; //x5だけ
                    
                    bRr = bRr*bRr1; //全部含む

                    double bRr_Lx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Lx = bRr_Lx*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    bRr_Lx = bRr_Lx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double bRr_Rx  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                    bRr_Rx = bRr_Rx*double(j!=j_flx_bl[3][1] || i+1<i_flx_bl[1][1]+1 || i+1>i_flx_bl[3][1]); //x4
                    bRr_Rx = bRr_Rx*double(j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5

                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr 
                             +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                             + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                             + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                             +    0.2*vth*exp(fmin(-e0*(-Ex[i  ][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                             +    0.2*vth*exp(fmin(-e0*( Ex[i+1][j  ]*dx/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dr*nbRx //陰的指定
                             + qL*0.2*vth*exp(fmin(-e0*(-Er[i  ][j  ]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                             + qR*0.2*vth*exp(fmin(-e0*( Er[i  ][j+1]*dr/2.0)/(Boltz*Te[i][j] + 1e-100),lim_exp))*dx*nbRr //陰的指定
                             + 3.0/5.0*delossdeps[i][j]*dx*dr //陰的ソース項予測
                             + 3.0/5.0*(dx*dr/dt + dx*dr/dtau*double(icon_dtau)); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;

                    double nabla_G = (Gx[i+1][j]-Gx[i][j])/dx + (qR*Gr[i][j+1]-qL*Gr[i][j])/dr;
                    double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                    double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                    double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                    double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                    double RHS1 = (-rhoeps[i][j] + rhoeps_old[i][j])/dt;
                    double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                    double RHS3 = Pabs[i][j] 
                        - rhoe[i][j]*rate_eloss[i][j] 
                        - delossdeps[i][j]*rhoeps[i][j]
                        + rhoe[i][j]*(1.5*Boltz*Te[i][j])*delossdeps[i][j]; //陰的ソース項予測
                        
                    double RHS4 = -nabla_G;

                    b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3 + RHS4)*dx*dr;
                }
            }
        }

        //solve
        double alpha_SOR = 1.0;
        int icon_iter = 1;

        if(icon_iter_rhoeps==0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }

        /********************* 更新 *******************/
        //dGxを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i-1][j])/2.0*ratioX;

                    double dTedx_tmp = (Te[i][j] - Te[i-1][j])/dx;
                    double vd_tmp = mu_min_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //フラックス
                    dGx[i][j] = (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }   
        }
        //dGrを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_min[i][j] + mu_min[i][j-1])/2.0*ratioY;

                    double dTedr_tmp = (Te[i  ][j  ] - Te[i  ][j-1])/dr;
                    double vd_tmp = mu_min_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    dGr[i][j] =  (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }
        }
        
        //更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //rhoeps[i][j] = fmax(rhoeps[i][j] + drhoeps[i][j],1e-6);
                    double rhoeps_new = rhoeps[i][j] + drhoeps[i][j];
                    if(rhoeps_new > 0.0){
                        rhoeps[i][j] = rhoeps_new;
                    }
                }
            }
        }
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    Gx[i][j] = Gx[i][j] + dGx[i][j];
                }
            }
        }
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    Gr[i][j] = Gr[i][j] + dGr[i][j];
                }
            }
        }

        //エラー計算
        double error_rhoeps2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoeps_tmp = fabs((rhoeps[i][j]-rhoeps_old_tmp[i][j])/(rhoeps[i][j]+rhoeps_old_tmp[i][j]+1e-100));
                        if(error_rhoeps_tmp > error_rhoeps2){
                            error_rhoeps2 = error_rhoeps_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoeps = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoeps2 += pow(rhoeps[i][j]-rhoeps_old_tmp[i][j],2)/(pow(rhoeps_old_tmp[i][j]+1e10,2));
                        ncount_rhoeps++;
                    }
                }
            }
            error_rhoeps2 = sqrt(error_rhoeps2/double(ncount_rhoeps));
        }

        double error_Gx2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        double error_Gx_tmp = fabs((Gx[i][j]-Gx_old_tmp[i][j])/(Gx[i][j]+Gx_old_tmp[i][j]+1e-100));
                        if(error_Gx_tmp > error_Gx2){
                            error_Gx2 = error_Gx_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gx = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                    for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                        error_Gx2 += pow(Gx[i][j]-Gx_old_tmp[i][j],2)/(pow(Gx_old_tmp[i][j]+1e16,2));
                        ncount_Gx++;
                    }
                }
            }
            error_Gx2 = sqrt(error_Gx2/double(ncount_Gx));
        }

        double error_Gr2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                        double error_Gr_tmp = fabs((Gr[i][j]-Gr_old_tmp[i][j])/(Gr[i][j]+Gr_old_tmp[i][j]+1e-100));
                        if(error_Gr_tmp > error_Gr2){
                            error_Gr2 = error_Gr_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gr = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                    for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                        error_Gr2 += pow(Gr[i][j]-Gr_old_tmp[i][j],2)/(pow(Gr_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_Gr++;
                    }
                }
            }
            error_Gr2 = sqrt(error_Gr2/double(ncount_Gr));
        }

        double error_global = fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoeps = " << error_rhoeps2
                <<  " error_Gx = " << error_Gx2
                <<  " error_Gr= " << error_Gr2
                <<  " error_max = " << fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2)
                << std::endl;
        }
       
        if(error_global < error_cnv_HES_rhoeps || ncount >= maxITR_HES_rhoeps){
            icon_end = 1;
        }
    
    } while (icon_end == 0);

    //電子密度の最大値を計算しておく
    double rhoe_max = 0.0;
    double ratio = 0.001;
    double Te_max = 20.0*e0/Boltz;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }

    std::cout << "ncount_Te = "<<ncount<<std::endl;
    
    //温度を更新
    //double alpha = 1.0;
    ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    ncount ++;
                    //rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                    rhoeps[i][j] = fmax(rhoeps[i][j],0.0);
                }
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100)*(1.0 + ratio),Te_max);
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative Te count = " << ncount << std::endl;
    }

    //誤差を計算
    error_rhoeps = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }

    error_Gx = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }

    error_Gr = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_wdTe_wSEE_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gx_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gr_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoeps(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------

    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------
    
    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            drhoeps[i][j] = rhoeps[i][j] - rhoeps_old[i][j];
        }
    }
    //------------------------------------
    
    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoeps_old_tmp[i][j] = rhoeps[i][j];
                Gx_old_tmp[i][j] = Gx[i][j];
                Gr_old_tmp[i][j] = Gr[i][j];
            }
        }
        //------------------------------------

        //Predict flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_x_inv_tmp =  mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_c_inv_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double dTedx_tmp = (Te_old[i][j] - Te_old[i-1][j])/dx; //electron temperature
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS; //electron temperature gradient
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dx/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double Gr_tmp = (rR*Gr_old_tmp[i][j+1]*bRr + rL*Gr_old_tmp[i][j]*bLr 
                        + rR*Gr_old_tmp[i-1][j+1]*bRrD + rL*Gr_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    Gx[i][j] =
                        ( vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0 
                        + Gx_old_tmp[i][j] 
                        - mu_star_tmp*(mu_x_inv_tmp*Gx_old_tmp[i][j] + mu_c_inv_tmp*Gr_tmp);
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        
        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
            Gx_wall[i][j] = Gx[i][j];
        }
        //------------------------------------

        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
            Gx_wall[i][j] = Gx[i][j];
        }
        //------------------------------------

        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
            Gx_wall[i][j] = Gx[i][j];
        }
        //------------------------------------

        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
            Gx_wall[i][j] = Gx[i][j];
        }
        //------------------------------------

        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rx //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmx[i+1][j]; //MISEE

            Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx + Gamma_wallSEE_Rx;
            Gx_wall[i+1][j] = Gx[i+1][j];
        }
        //------------------------------------

        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rx //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmx[i+1][j]; //MISEE

            Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx + Gamma_wallSEE_Rx;
            Gx_wall[i+1][j] = Gx[i+1][j];
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;

                    double mu_r_inv_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_c_inv_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double dTedr_tmp = (Te_old[i][j] - Te_old[i][j-1])/dr; //electron temperature
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS; //electron temperature gradient
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dr/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double Gx_tmp = (r[j]*Gx_old_tmp[i+1][j]*bRx + r[j]*Gx_old_tmp[i][j]*bLx
                        + r[j-1]*Gx_old_tmp[i+1][j-1]*bRxD + r[j-1]*Gx_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    Gr[i][j] =  
                        ( vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0
                        + Gr_old_tmp[i][j] 
                        - mu_star_tmp*(mu_c_inv_tmp*Gx_tmp + mu_r_inv_tmp*Gr_old_tmp[i][j]);
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j]; //MISEE
             
            Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr + Gamma_wallSEE_Lr;
            Gr_wall[i][j] = Gr[i][j];
        }
        //------------------------------------
    
        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j]; //MISEE
        
            Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------
    
        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
        
            Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr + Gamma_wallSEE_Rr;
            Gr_wall[i][j+1] = Gr[i][j+1];
        }
        //------------------------------------
    
        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
        
            Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr + Gamma_wallSEE_Rr;
            Gr_wall[i][j+1] = Gr[i][j+1];
        }
        //------------------------------------
    
        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double Gamma_open_Rr = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
            Gr[i][j+1] = Gamma_open_Rr;
            Gr_wall[i][j+1] = 0.0;
        }
        //------------------------------------

        //Make coefficient for electron energy conservation for 5 point stencil
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron temperature at cell interface
                    //------------------------------------
                    double Te_Lx = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                    double Te_Rx = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                    double Te_Lr = (Te_old[i][j]+Te_old[i][j-1])/2.0;
                    double Te_Rr = (Te_old[i][j]+Te_old[i][j+1])/2.0;
                    //------------------------------------

                    //electron diffusion coefficient at cell interface
                    //------------------------------------
                    double D_Lx = Boltz*Te_Lx/e0*mu_star_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_star_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_star_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_star_Rr;
                    //------------------------------------

                    //electron temperature gradient at cell interface
                    //------------------------------------
                    double dTedx_Lx = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                    double dTedx_Rx = (Te_old[i+1][j  ] - Te_old[i  ][j  ])/dx;
                    double dTedr_Lr = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                    double dTedr_Rr = (Te_old[i  ][j+1] - Te_old[i  ][j  ])/dr;
                    //------------------------------------

                    //electron drift velocity at cell interface
                    //------------------------------------
                    double vd_Lx = mu_star_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_star_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_star_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_star_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;
                    //------------------------------------

                    //Peclet number at cell interface
                    //------------------------------------
                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    //coefficient for electron energy conservation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr 
                             +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                             + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                             + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                             + 3.0/5.0*delossdeps[i][j]*dx*dr //part of implicit source term prediction
                             + 3.0/5.0*dx*dr/dt; //time-term
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_G = (Gx[i+1][j]-Gx[i][j])/dx + (qR*Gr[i][j+1]-qL*Gr[i][j])/dr;
                    //double rhoUex_tmp = (rhoUex[i+1][j]*bRx_wall + rhoUex[i][j]*bLx_wall)/2.0;
                    //double rhoUer_tmp = (rR*rhoUer[i][j+1]*bRr_wall + rL*rhoUer[i][j]*bLr_wall)/(2.0*r[j]);
                    //double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                    //double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);
                    double JdotE_x = -e0*(rhoUex[i+1][j]*Ex[i+1][j]*bRx_wall + rhoUex[i][j]*Ex[i][j]*bLx_wall)/2.0;
                    double JdotE_r = -e0*(rR*rhoUer[i][j+1]*Er[i][j+1]*bRr_wall + rL*rhoUer[i][j]*Er[i][j]*bLr_wall)/(2.0*r[j]);

                    double RHS1 = (-rhoeps[i][j] + rhoeps_old[i][j])/dt;
                    //double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                    double RHS2 = JdotE_x + JdotE_r;
                    double RHS3 = Pabs[i][j] 
                        - rhoe[i][j]*rate_eloss[i][j] 
                        - delossdeps[i][j]*rhoeps[i][j]
                        + rhoe[i][j]*(1.5*Boltz*Te[i][j])*delossdeps[i][j]; //part of implicit source term prediction
                        
                    double RHS4 = -nabla_G;

                    b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3 + RHS4)*dx*dr;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //solve
        if(icon_iter_rhoeps==0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
            //------------------------------------
        }else{
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
            //------------------------------------
        }

        //Correction
        //==============================================
        //for Gx
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double dTedx_tmp = (Te_old[i][j] - Te_old[i-1][j])/dx;
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;
                    //------------------------------------
                    
                    //calculate flux correction
                    //------------------------------------
                    double dGx = (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    Gx[i][j] = Gx[i][j] + dGx;
                    //------------------------------------
                }
            }   
        }
        //------------------------------------

        //for Gr
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double dTedr_tmp = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double dGr =  (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    Gr[i][j] = Gr[i][j] + dGr;
                    //------------------------------------
                }
            }
        }
        //------------------------------------
        
        //for rhoeps
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //rhoeps[i][j] = fmax(rhoeps[i][j] + drhoeps[i][j],1e-6);
                    double rhoeps_new = rhoeps[i][j] + drhoeps[i][j];
                    if(rhoeps_new > 0.0){
                        rhoeps[i][j] = rhoeps_new;
                    }
                }
            }
        }
        //------------------------------------
        //==============================================
       
        //Caluculate residuals
        //=====================================================================================
        //rhoeps
        //------------------------------------
        double error_rhoeps2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoeps_tmp = fabs((rhoeps[i][j]-rhoeps_old_tmp[i][j])/(rhoeps[i][j]+rhoeps_old_tmp[i][j]+1e-100));
                        if(error_rhoeps_tmp > error_rhoeps2){
                            error_rhoeps2 = error_rhoeps_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoeps = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoeps2 += pow(rhoeps[i][j]-rhoeps_old_tmp[i][j],2)/(pow(rhoeps_old_tmp[i][j]+1e10,2));
                        ncount_rhoeps++;
                    }
                }
            }
            error_rhoeps2 = sqrt(error_rhoeps2/double(ncount_rhoeps));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_Gx2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_Gx_tmp = fabs((Gx[i][j]-Gx_old_tmp[i][j])/(Gx[i][j]+Gx_old_tmp[i][j]+1e-100));
                        if(error_Gx_tmp > error_Gx2){
                            error_Gx2 = error_Gx_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_Gx = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_Gx2 += pow(Gx[i][j]-Gx_old_tmp[i][j],2)/(pow(Gx_old_tmp[i][j]+1e16,2));
                        ncount_Gx++;
                    }
                }
            }
            error_Gx2 = sqrt(error_Gx2/double(ncount_Gx));
        }
        //------------------------------------
        
        //r-directional flux
        //------------------------------------
        double error_Gr2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_Gr_tmp = fabs((Gr[i][j]-Gr_old_tmp[i][j])/(Gr[i][j]+Gr_old_tmp[i][j]+1e-100));
                        if(error_Gr_tmp > error_Gr2){
                            error_Gr2 = error_Gr_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_Gr = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_Gr2 += pow(Gr[i][j]-Gr_old_tmp[i][j],2)/(pow(Gr_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_Gr++;
                    }
                }
            }
            error_Gr2 = sqrt(error_Gr2/double(ncount_Gr));
        }
        //------------------------------------
        //=====================================================================================

        double error_global = fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoeps = " << error_rhoeps2
                <<  " error_Gx = " << error_Gx2
                <<  " error_Gr= " << error_Gr2
                <<  " error_max = " << fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2)
                << std::endl;
        }
       
        if(error_global < error_cnv_HES_rhoeps || ncount >= maxITR_HES_rhoeps){
            icon_end = 1;
        }
    
    } while (icon_end == 0);

    //std::cout << "ncount_Te = "<<ncount<<std::endl;

    //Don’t update unless the value is positive.
    //------------------------------------
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                }
            }
        }
    }
    //------------------------------------

    //calculate maximum electron density to avoid zero-division in Te calc.
    //------------------------------------
    double rhoe_max = 0.0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }
    //------------------------------------

    //calculate electron temperature
    //------------------------------------
    double Te_max = 1000.0*e0/Boltz; //limit maximum
    double ratio = 0.001; //ratio of additional value to maximum
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100),Te_max);
            }
        }
    }
    //------------------------------------

    //set values of ghost cells for transport coefficient
    //=====================================================================================
    //left-wall-BC (chamber)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (magnet)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //lower-wall-BC (antenna)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
    }
    //------------------------------------

    //right-open-BC
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        Te[i+1][j] = Te[i][j];
    }
    //------------------------------------

    //upper-open-BC
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoeps = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_Gx = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_Gr = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_wdTe_wSEE_wInertia_PC(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gx_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gr_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoeps(ni+2,std::vector<double>(nj+2,0.0));

    //Numerical treatment for exponential overflow and zero-division
    //------------------------------------
    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    //------------------------------------

    //Acceleration factor for PC method
    //------------------------------------
    double c_mu = 1.0;
    //------------------------------------

    //convergence criteria
    //------------------------------------
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS
    //------------------------------------

    //output duration
    //------------------------------------
    int ndiv_out = 100;
    //------------------------------------

    //scaling factor of wall flux
    //------------------------------------
    double alpha_wflux = 1.0;
    //------------------------------------
    
    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }
    //------------------------------------

    //Initial prediction of correction
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            drhoeps[i][j] = rhoeps[i][j] - rhoeps_old[i][j];
        }
    }
    //------------------------------------
    
    //calculate maximum electron density to avoid zero-division in Te calc.
    //------------------------------------
    double rhoe_max = 0.0;
    double ratio_rhoe = 0.001;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }
    //------------------------------------

    //PC method iteration
    //------------------------------------
    int ncount = 0; //number of iteration of PC method
    int icon_end = 0;
    do{
        
        ncount ++;

        //Reserve previous-step values
        //------------------------------------
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoeps_old_tmp[i][j] = rhoeps[i][j];
                Gx_old_tmp[i][j] = Gx[i][j];
                Gr_old_tmp[i][j] = Gr[i][j];
            }
        }
        //------------------------------------

        //Predict flux
        //==============================================
        //for rhoUex
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qL = rL/r[j];
                    double qR = rR/r[j];
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;

                    double mu_x_inv_tmp =  mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_c_inv_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------

                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double dTedx_tmp = (Te_old[i][j] - Te_old[i-1][j])/dx; //electron temperature
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS; //electron temperature gradient
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dx/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;

                    //lower-left
                    double bLrD_wall  = double(j!=j_flc_bl[0][0] || i-1>i_flc_bl[0][1]); //x0
                    bLrD_wall = bLrD_wall*double(j!=j_flc_bl[2][0] || i-1>i_flc_bl[2][1]); //x2
                    double bLrD_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLrD  = bLrD_wall*bLrD_cen;

                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    //double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall;

                    //upper-left
                    double bRrD_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRrD_wall = bRrD_wall*double(j!=j_flc_bl[3][1] || i-1<i_flc_bl[1][1]+1 || i-1>i_flc_bl[3][1]); //x4
                    //double bRrD_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRrD = bRrD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double Gr_tmp = (rR*Gr_old_tmp[i][j+1]*bRr + rL*Gr_old_tmp[i][j]*bLr 
                        + rR*Gr_old_tmp[i-1][j+1]*bRrD + rL*Gr_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);
                    //------------------------------------

                    //effect of electron inertia
                    //==============================================
                    //flux at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = (rhoUex[i][j]   + rhoUex[i-1][j]  )/2.0;
                    double rhoUex_Rx = (rhoUex[i][j]   + rhoUex[i+1][j]  )/2.0;
                    double rhoUer_Lr = (rhoUer[i][j]   + rhoUer[i-1][j]  )/2.0;
                    double rhoUer_Rr = (rhoUer[i][j+1] + rhoUer[i-1][j+1])/2.0;
                    //------------------------------------

                    //density at cell (rhoUex control volume) interface
                    //------------------------------------
                    double rhoe_Lx = rhoe[i-1][j];
                    double rhoe_Rx = rhoe[i][j];
                    double rhoe_Lr = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rr = (rhoe[i][j] + rhoe[i][j+1] + rhoe[i-1][j] + rhoe[i-1][j+1])/4.0;
                    //------------------------------------

                    //velocity at cell (rhoUex control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------

                    //BC - set adjacent flag for inertia (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLxI_wall  = double(i!=i_flx_bl[0][0] || iblock != 0); //z0
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[2][0] || j>j_flx_bl[0][0]-1); //z1
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[3][0] || j>j_flx_bl[2][0]-1); //z2
                    bLxI_wall = bLxI_wall*double(i!=i_flx_bl[4][0] || j<j_flx_bl[1][0]); //z4
                    double bLxI  = bLxI_wall;
                    
                    //right
                    double bRxI_wall  = double(i!=i_flx_bl[1][1] || j<j_flx_bl[1][0]); //z3
                    bRxI_wall = bRxI_wall*double(i!=i_flx_bl[4][1]); //z5
                    double bRxI  = bRxI_wall;

                    //lower
                    double bLrI_wall  = double(j!=j_flx_bl[0][0] || i>i_flx_bl[0][1]); //x0
                    bLrI_wall = bLrI_wall*double(j!=j_flx_bl[2][0] || i>i_flx_bl[2][1]); //x2
                    double bLrI_cen = double(j!=j_flx_bl[3][0]); //x6
                    double bLrI  = bLrI_wall*bLrI_cen;

                    //upper
                    double bRrI_wall  = double(j!=j_flx_bl[0][1] || iblock > 2); //x1
                    bRrI_wall = bRrI_wall*double(j!=j_flx_bl[3][1] || i<i_flx_bl[1][1]+1 || i>i_flx_bl[3][1]); //x4
                    double bRrI_open  = (j!=j_flx_bl[4][1] || iblock != 4); //x5
                    double bRrI = bRrI_wall;
                    //------------------------------------

                    //calculate inertia
                    //------------------------------------
                    double inertia = 
                        -mu_star_tmp*masse/e0*(rhoUex[i][j]-rhoUex_old[i][j])/dt 
                        + ( 
                            mu_star_tmp*masse/e0*(
                            +    (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)
                            -    (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)
                            + qR*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)*bRrI
                            - qL*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)*bLrI
                            )
                        )*rhoUex[i][j]
                        + (
                            -mu_star_tmp*masse/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx)
                        )*rhoUex[i+1][j]*bRxI
                        + (
                             mu_star_tmp*masse/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx)
                        )*rhoUex[i-1][j]*bLxI
                        + (
                             -qR*mu_star_tmp*masse/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr)*bRrI
                        )*rhoUex[i][j+1]
                        + (
                              qL*mu_star_tmp*masse/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr)*bLrI
                        )*rhoUex[i][j-1];
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    Gx[i][j] =
                        ( vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0 
                        + Gx_old_tmp[i][j] 
                        - mu_star_tmp*(mu_x_inv_tmp*Gx_old_tmp[i][j] + mu_c_inv_tmp*Gr_tmp)
                        + 5.0/2.0*Boltz*Te_tmp*inertia*scale_inertia;
                    //------------------------------------
                }
            }     
        }
        //------------------------------------

        
        //left-wall-BC (z0)
        //------------------------------------
        for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
            int i=i_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------

        //left-wall-BC (z1)
        //------------------------------------
        for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
            int i=i_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------

        //left-wall-BC (z2)
        //------------------------------------
        for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
            int i=i_flc_bl[3][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------

        //left-wall-BC (z4)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Ex[i][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lx = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lx = -0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i][j] //IISEE
                            - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lx //EISEE
                            - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lx //EISEE
                            - eps_emitSEE*coefMISEE_ts*rhoUmx[i][j]; //MISEE

            Gx[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lx + Gamma_wallSEE_Lx;
        }
        //------------------------------------

        //right-wall-BC (z3)
        //------------------------------------
        for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
            int i=i_flc_bl[1][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rx = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rx //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmx[i+1][j]; //MISEE

            Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx + Gamma_wallSEE_Rx;
        }
        //------------------------------------

        //right-wall-BC (z5)
        //------------------------------------
        for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
            int i=i_flc_bl[4][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Ex[i+1][j]*dx/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rx = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rx = 0.25*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rx = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uix[i+1][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rx //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rx //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmx[i+1][j]; //MISEE

            Gx[i+1][j] = rhoeps[i][j]*GammaPerNeps_wall_Rx + Gamma_wallSEE_Rx;
        }
        //------------------------------------

        //for rhoUer
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //radial position at cell interface
                    //------------------------------------
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double rL = (r[j-1]+r[j-2])/2.0;
                    double rR = (r[j+1]+r[j])/2.0;
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;

                    double mu_star_tmp = mu_perp_tmp*c_mu;
                    //------------------------------------

                    //calculate inverse moblity tensor at cell interface
                    //------------------------------------
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;

                    double mu_r_inv_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_c_inv_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
                    //------------------------------------
    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double dTedr_tmp = (Te_old[i][j] - Te_old[i][j-1])/dr; //electron temperature
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS; //electron temperature gradient
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0; //electron drift velocity
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp; //electron diffusion coefficient
                    double z_tmp = vd_tmp*dr/D_tmp; //Peclet number
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;

                    //left-lower
                    double bLxD_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[2][0] || j-1>j_flc_bl[0][0]-1); //z1
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[3][0] || j-1>j_flc_bl[2][0]-1); //z2
                    bLxD_wall = bLxD_wall*double(i!=i_flc_bl[4][0] || j-1<j_flc_bl[1][0]); //z4
                    double bLxD  = bLxD_wall;

                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;

                    //right-lower
                    double bRxD_wall  = double(i!=i_flc_bl[1][1] || j-1<j_flc_bl[1][0]); //z3
                    bRxD_wall = bRxD_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRxD  = bRxD_wall;
                    //------------------------------------

                    //interpolation of transverse flux component (should be old value)
                    //------------------------------------
                    double Gx_tmp = (r[j]*Gx_old_tmp[i+1][j]*bRx + r[j]*Gx_old_tmp[i][j]*bLx
                        + r[j-1]*Gx_old_tmp[i+1][j-1]*bRxD + r[j-1]*Gx_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);
                    //------------------------------------

                    //effect of electron inertia
                    //==============================================
                    //flux at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoUex_Lx = ( r[j]*rhoUex[i][j]   + r[j-1]*rhoUex[i][j-1]  )/(2.0*r_tmp);
                    double rhoUex_Rx = ( r[j]*rhoUex[i+1][j] + r[j-1]*rhoUex[i+1][j-1])/(2.0*r_tmp);
                    double rhoUer_Lr = (r_tmp*rhoUer[i][j]   +     rL*rhoUer[i][j-1]  )/(2.0*r[j-1]);
                    double rhoUer_Rr = (r_tmp*rhoUer[i][j]   +     rR*rhoUer[i][j+1]  )/(2.0*r[j]);
                    //------------------------------------

                    //density at cell (rhoUer control volume) interface
                    //------------------------------------
                    double rhoe_Lx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i-1][j] + rhoe[i-1][j-1])/4.0;
                    double rhoe_Rx = (rhoe[i][j] + rhoe[i][j-1] + rhoe[i+1][j] + rhoe[i+1][j-1])/4.0;
                    double rhoe_Lr = rhoe[i][j-1];
                    double rhoe_Rr = rhoe[i][j];
                    //------------------------------------

                    //velocity at cell (rhoUer control volume) interface
                    //------------------------------------
                    double Uex_Lx = rhoUex_Lx/(rhoe_Lx + rhoe_max*ratio_rhoe);
                    double Uex_Rx = rhoUex_Rx/(rhoe_Rx + rhoe_max*ratio_rhoe);
                    double Uer_Lr = rhoUer_Lr/(rhoe_Lr + rhoe_max*ratio_rhoe);
                    double Uer_Rr = rhoUer_Rr/(rhoe_Rr + rhoe_max*ratio_rhoe);
                    //------------------------------------

                    //BC - set adjacent flag for inertia (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLxI_wall  = double(i!=i_flr_bl[0][0] || iblock != 0); //z0
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[2][0] || j>j_flr_bl[0][0]-1); //z1
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[3][0] || j>j_flr_bl[2][0]-1); //z2
                    bLxI_wall = bLxI_wall*double(i!=i_flr_bl[4][0] || j<j_flr_bl[1][0]); //z4
                    double bLxI  = bLxI_wall;
                    
                    //right
                    double bRxI_wall  = double(i!=i_flr_bl[1][1] || j<j_flr_bl[1][0]); //z3
                    bRxI_wall = bRxI_wall*double(i!=i_flr_bl[4][1]); //z5
                    double bRxI  = bRxI_wall;

                    //lower
                    double bLrI_wall  = double(j!=j_flr_bl[0][0] || i>i_flr_bl[0][1]); //x0
                    bLrI_wall = bLrI_wall*double(j!=j_flr_bl[2][0] || i>i_flr_bl[2][1]); //x2
                    double bLrI_cen = double(j!=j_flr_bl[3][0]); //x6
                    double bLrI  = bLrI_wall*bLrI_cen;

                    //upper
                    double bRrI_wall  = double(j!=j_flr_bl[0][1] || iblock > 2); //x1
                    bRrI_wall = bRrI_wall*double(j!=j_flr_bl[3][1] || i<i_flr_bl[1][1]+1 || i>i_flr_bl[3][1]); //x4
                    //double bRrI_open  = (j!=j_flr_bl[4][1] || iblock != 4); //x5
                    double bRrI = bRrI_wall;
                    //------------------------------------

                    //calculate inertia
                    //------------------------------------
                    double inertia = 
                        -mu_star_tmp*masse/e0*(rhoUer[i][j]-rhoUer_old[i][j])/dt 
                        + ( 
                            masse/e0*mu_star_tmp*(
                                + (Uex_Rx + fabs(Uex_Rx))/(2.0*dx)*bRxI
                                - (Uex_Lx - fabs(Uex_Lx))/(2.0*dx)*bLxI
                                + r[j]/r_tmp*(Uer_Rr + fabs(Uer_Rr))/(2.0*dr)
                                - r[j-1]/r_tmp*(Uer_Lr - fabs(Uer_Lr))/(2.0*dr)
                            )
                        )*rhoUer[i][j]
                        + (
                            -mu_star_tmp*masse/e0*(Uex_Rx - fabs(Uex_Rx))/(2.0*dx)*bRxI
                        )*rhoUer[i+1][j]
                        + (
                             mu_star_tmp*masse/e0*(Uex_Lx + fabs(Uex_Lx))/(2.0*dx)*bLxI
                        )*rhoUer[i-1][j]
                        + (
                             -r[j]  /r_tmp*mu_star_tmp*masse/e0*(Uer_Rr - fabs(Uer_Rr))/(2.0*dr)
                        )*rhoUer[i][j+1]*bRrI
                        + (
                              r[j-1]/r_tmp*mu_star_tmp*masse/e0*(Uer_Lr + fabs(Uer_Lr))/(2.0*dr)
                        )*rhoUer[i][j-1]*bLrI;
                    //------------------------------------

                    //update flux
                    //------------------------------------
                    Gr[i][j] =  
                        ( vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0
                        + Gr_old_tmp[i][j] 
                        - mu_star_tmp*(mu_c_inv_tmp*Gx_tmp + mu_r_inv_tmp*Gr_old_tmp[i][j])
                        + 5.0/2.0*Boltz*Te_tmp*inertia*scale_inertia;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //lower-wall-BC (x0)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
            int j=j_flc_bl[0][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j]; //MISEE
             
            Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------
    
        //lower-wall-BC (x2)
        //------------------------------------
        for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
            int j=j_flc_bl[2][0];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi = fmax(-Er[i][j]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Lr = -vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Lr = -0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Lr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Lr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Lr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j]; //MISEE
        
            Gr[i][j] = rhoeps[i][j]*GammaPerNeps_wall_Lr + Gamma_wallSEE_Lr;
        }
        //------------------------------------
    
        //upper-wall-BC (x1)
        //------------------------------------
        for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
            int j=j_flc_bl[0][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
        
            Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------
    
        //upper-wall-BC (x4)
        //------------------------------------
        for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
            int j=j_flc_bl[3][1];
            double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
            double delta_phi =  fmax(Er[i][j+1]*dr/2.0,0.0); //adjacent cell-center potential from wall
            double GammaPerNeps_wall_Rr = vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp))/3.0*alpha_wflux;
            double eps_emitSEE = 2.0*e0*Te_emitSEE_eV;
            double GammaPerN_wall_Rr = 0.25*alpha_wflux*vth*exp(fmin(-e0*delta_phi/(Boltz*Te_old[i][j] + 1e-100),lim_exp));

            double coefEISEE_eb = func_Te(coefEISEE_eb_table,Te[i][j],dTe_SEE);
            double coefEISEE_rd = func_Te(coefEISEE_rd_table,Te[i][j],dTe_SEE);
            double coefEISEE_ts = func_Te(coefEISEE_ts_table,Te[i][j],dTe_SEE);

            double Gamma_wallSEE_Rr = - eps_emitSEE*coefIISEE_ts*rhoi[i][j]*Uir[i][j+1] //IISEE
                - (coefEISEE_eb + ratioEngy_EISEE_rd*coefEISEE_rd)*rhoeps_old[i][j]*GammaPerNeps_wall_Rr //EISEE
                - eps_emitSEE*coefEISEE_ts*rhoe_old[i][j]*GammaPerN_wall_Rr //EISEE
                - eps_emitSEE*coefMISEE_ts*rhoUmr[i][j+1]; //MISEE
        
            Gr[i][j+1] = rhoeps[i][j]*GammaPerNeps_wall_Rr + Gamma_wallSEE_Rr;
        }
        //------------------------------------
    
        //upper-open-BC (x5)
        //------------------------------------
        for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
            int j=j_flc_bl[4][1];
            double Gamma_open_Rr = 5.0/2.0*Boltz*Te_old[i][j]*fmax(rhoUer[i][j+1],0.0);
            Gr[i][j+1] = Gamma_open_Rr;
        }
        //------------------------------------

        //Make coefficient for electron energy conservation for 5 point stencil
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //moblity at cell interface
                    //------------------------------------
                    double mu_star_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*c_mu;
                    double mu_star_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*c_mu;
                    double mu_star_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*c_mu;
                    double mu_star_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*c_mu;
                    //------------------------------------

                    //electron temperature at cell interface
                    //------------------------------------
                    double Te_Lx = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                    double Te_Rx = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                    double Te_Lr = (Te_old[i][j]+Te_old[i][j-1])/2.0;
                    double Te_Rr = (Te_old[i][j]+Te_old[i][j+1])/2.0;
                    //------------------------------------

                    //electron diffusion coefficient at cell interface
                    //------------------------------------
                    double D_Lx = Boltz*Te_Lx/e0*mu_star_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_star_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_star_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_star_Rr;
                    //------------------------------------

                    //electron temperature gradient at cell interface
                    //------------------------------------
                    double dTedx_Lx = (Te_old[i  ][j  ] - Te_old[i-1][j  ])/dx;
                    double dTedx_Rx = (Te_old[i+1][j  ] - Te_old[i  ][j  ])/dx;
                    double dTedr_Lr = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                    double dTedr_Rr = (Te_old[i  ][j+1] - Te_old[i  ][j  ])/dr;
                    //------------------------------------

                    //electron drift velocity at cell interface
                    //------------------------------------
                    double vd_Lx = mu_star_Lx*(-Ex[i  ][j  ] - Boltz/e0*dTedx_Lx) + EPS;
                    double vd_Rx = mu_star_Rx*(-Ex[i+1][j  ] - Boltz/e0*dTedx_Rx) + EPS;
                    double vd_Lr = mu_star_Lr*(-Er[i  ][j  ] - Boltz/e0*dTedr_Lr) + EPS;
                    double vd_Rr = mu_star_Rr*(-Er[i  ][j+1] - Boltz/e0*dTedr_Rr) + EPS;
                    //------------------------------------

                    //Peclet number at cell interface
                    //------------------------------------
                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    //coefficient for electron energy conservation for 5 point stencil
                    //==============================================
                    //vertical and horizental 5 stencil
                    //------------------------------------
                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr 
                             +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                             + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                             + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                             + 3.0/5.0*delossdeps[i][j]*dx*dr //part of implicit source term prediction
                             + 3.0/5.0*dx*dr/dt; //time-term
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;
                    //------------------------------------

                    //RHS
                    //------------------------------------
                    double nabla_G = (Gx[i+1][j]-Gx[i][j])/dx + (qR*Gr[i][j+1]-qL*Gr[i][j])/dr;
                    double rhoUex_tmp = (rhoUex[i+1][j]*bRx_wall + rhoUex[i][j]*bLx_wall)/2.0;
                    double rhoUer_tmp = (rR*rhoUer[i][j+1]*bRr_wall + rL*rhoUer[i][j]*bLr_wall)/(2.0*r[j]);
                    double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                    double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                    double RHS1 = (-rhoeps[i][j] + rhoeps_old[i][j])/dt;
                    double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                    double RHS3 = Pabs[i][j] 
                        - rhoe[i][j]*rate_eloss[i][j] 
                        - delossdeps[i][j]*rhoeps[i][j]
                        + rhoe[i][j]*(1.5*Boltz*Te[i][j])*delossdeps[i][j]; //part of implicit source term prediction
                        
                    double RHS4 = -nabla_G;

                    b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3 + RHS4)*dx*dr;
                    //------------------------------------
                }
            }
        }
        //------------------------------------

        //solve
        if(icon_iter_rhoeps==0){
            //SOR
            //------------------------------------
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
            //------------------------------------
        }else{
            //------------------------------------
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
            //------------------------------------
        }

        //Correction
        //==============================================
        //for Gx
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*c_mu;
                    double dTedx_tmp = (Te_old[i][j] - Te_old[i-1][j])/dx;
                    double vd_tmp = mu_star_tmp*(-Ex[i][j] - Boltz/e0*dTedx_tmp) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;
                    //------------------------------------
                    
                    //calculate flux correction
                    //------------------------------------
                    double dGx = (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    Gx[i][j] = Gx[i][j] + dGx;
                    //------------------------------------
                }
            }   
        }
        //------------------------------------

        //for Gr
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    
                    //values at cell interface for Sharfetter-Gummmel scheme
                    //------------------------------------
                    double mu_star_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*c_mu;
                    double dTedr_tmp = (Te_old[i  ][j  ] - Te_old[i  ][j-1])/dr;
                    double vd_tmp = mu_star_tmp*(-Er[i][j] - Boltz/e0*dTedr_tmp) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_star_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;
                    //------------------------------------

                    //calculate flux correction
                    //------------------------------------
                    double dGr =  (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                    //------------------------------------
                    
                    //Update
                    //------------------------------------
                    Gr[i][j] = Gr[i][j] + dGr;
                    //------------------------------------
                }
            }
        }
        //------------------------------------
        
        //for rhoeps
        //------------------------------------
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //rhoeps[i][j] = fmax(rhoeps[i][j] + drhoeps[i][j],1e-6);
                    double rhoeps_new = rhoeps[i][j] + drhoeps[i][j];
                    if(rhoeps_new > 0.0){
                        rhoeps[i][j] = rhoeps_new;
                    }
                }
            }
        }
        //------------------------------------
        //==============================================
       
        //Caluculate residuals
        //=====================================================================================
        //rhoeps
        //------------------------------------
        double error_rhoeps2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoeps_tmp = fabs((rhoeps[i][j]-rhoeps_old_tmp[i][j])/(rhoeps[i][j]+rhoeps_old_tmp[i][j]+1e-100));
                        if(error_rhoeps_tmp > error_rhoeps2){
                            error_rhoeps2 = error_rhoeps_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_rhoeps = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoeps2 += pow(rhoeps[i][j]-rhoeps_old_tmp[i][j],2)/(pow(rhoeps_old_tmp[i][j]+1e10,2));
                        ncount_rhoeps++;
                    }
                }
            }
            error_rhoeps2 = sqrt(error_rhoeps2/double(ncount_rhoeps));
        }
        //------------------------------------

        //x-directional flux
        //------------------------------------
        double error_Gx2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_Gx_tmp = fabs((Gx[i][j]-Gx_old_tmp[i][j])/(Gx[i][j]+Gx_old_tmp[i][j]+1e-100));
                        if(error_Gx_tmp > error_Gx2){
                            error_Gx2 = error_Gx_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_Gx = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_Gx2 += pow(Gx[i][j]-Gx_old_tmp[i][j],2)/(pow(Gx_old_tmp[i][j]+1e16,2));
                        ncount_Gx++;
                    }
                }
            }
            error_Gx2 = sqrt(error_Gx2/double(ncount_Gx));
        }
        //------------------------------------
        
        //r-directional flux
        //------------------------------------
        double error_Gr2 = 0.0;
        if(icon_error2 == 0){ //normalized maximum
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_Gr_tmp = fabs((Gr[i][j]-Gr_old_tmp[i][j])/(Gr[i][j]+Gr_old_tmp[i][j]+1e-100));
                        if(error_Gr_tmp > error_Gr2){
                            error_Gr2 = error_Gr_tmp;
                        }
                    }
                }
            }
        }else{ //normalized L2 norm
            double ncount_Gr = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_Gr2 += pow(Gr[i][j]-Gr_old_tmp[i][j],2)/(pow(Gr_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_Gr++;
                    }
                }
            }
            error_Gr2 = sqrt(error_Gr2/double(ncount_Gr));
        }
        //------------------------------------
        //=====================================================================================

        double error_global = fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoeps = " << error_rhoeps2
                <<  " error_Gx = " << error_Gx2
                <<  " error_Gr= " << error_Gr2
                <<  " error_max = " << fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2)
                << std::endl;
        }
       
        if(error_global < error_cnv_HES_rhoeps || ncount >= maxITR_HES_rhoeps){
            icon_end = 1;
        }
    
    } while (icon_end == 0);

    //std::cout << "ncount_Te = "<<ncount<<std::endl;

    //Don’t update unless the value is positive.
    //------------------------------------
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoeps[i][j]<0.0){
                    rhoeps[i][j] = fmax(rhoeps_old[i][j],0.0);
                }
            }
        }
    }
    //------------------------------------

    //calculate electron temperature
    //------------------------------------
    double Te_max = 1000.0*e0/Boltz; //limit maximum
    double ratio = 0.001; //ratio of additional value to maximum
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100),Te_max);
            }
        }
    }
    //------------------------------------

    //set values of ghost cells for transport coefficient
    //=====================================================================================
    //left-wall-BC (chamber)
    //------------------------------------
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //left-wall-BC (magnet)
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        Te[i-1][j] = Te[i][j];
    }
    //------------------------------------

    //lower-wall-BC (antenna)
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
    }
    //------------------------------------

    //right-open-BC
    //------------------------------------
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        Te[i+1][j] = Te[i][j];
    }
    //------------------------------------

    //upper-open-BC
    //------------------------------------
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        Te[i][j+1] = Te[i][j];
    }
    //------------------------------------

    //Caluculate residuals
    //=====================================================================================
    //Electron density
    //------------------------------------
    error_rhoeps = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }
    //------------------------------------

    //x-directional flux
    //------------------------------------
    error_Gx = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
                for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }
    //------------------------------------

    //r-directional flux
    //------------------------------------
    error_Gr = 0.0;
    if(icon_error == 0){ //normalized maximum
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{ //normalized L2 norm
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
                for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }
    //------------------------------------
    //=====================================================================================

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void solve_Te_PC_new(){

    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhoeps_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gx_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > Gr_old_tmp(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > drhoeps(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGx(ni+2,std::vector<double>(nj+2,0.0));
    std::vector<std::vector<double> > dGr(ni+2,std::vector<double>(nj+2,0.0));

    int icon_end = 0;
    int ncount = 0;
    int ndiv_out = 100;

    double ratioX = 1.0; //2.9
    double ratioY = 1.0; //2.9
    double icon_dtau = 0.0;

    double lim_exp = 1.0e2; //expの制限
    double EPS = 1.0e-3; //ゼロ割回避用の数字
    double dtau = dt; //擬似時間ステップ
    int icon_error2 = 1; //擬似ステップのエラー収束判定 0:max, 1:RMS

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            //drhoeを予想
            drhoeps[i][j] = rhoeps[i][j] - rhoeps_old[i][j];

            Te_old[i][j] = Te[i][j];
            rhoeps_old[i][j] = rhoeps[i][j];
            Gx_old[i][j] = Gx[i][j];
            Gr_old[i][j] = Gr[i][j];
        }
    }

    //電子密度の最大値を計算しておく
    double rhoe_max = 0.0;
    double ratio = 0.01;
    double Te_max = 20.0*e0/Boltz;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhoe_max < rhoe[i][j]){
                    rhoe_max = rhoe[i][j];
                }
            }
        }
    }

    
    do{
        
        ncount ++;

        //過去の値を保存 (ゴーストセルも含む)
        for (int i=0;i<=ni+1;i++){ 
            for (int j=0;j<=nj+1;j++){ 
                rhoeps_old_tmp[i][j] = rhoeps[i][j];
                Gx_old_tmp[i][j] = Gx[i][j];
                Gr_old_tmp[i][j] = Gr[i][j];
            }
        }

        //Gx更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                
                    double rL = (r[j]+r[j-1])/2.0;
                    double rR = (r[j]+r[j+1])/2.0;

                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);
                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);

                    //前ステップから
                    double Gr_tmp = (rR*Gr_old_tmp[i][j+1]*bRr + rL*Gr_old_tmp[i][j]*bLr 
                        + rR*Gr_old_tmp[i-1][j+1]*bRr + rL*Gr_old_tmp[i-1][j]*bLrD)/(4.0*r[j]);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i-1][j])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioX;
                    double mu_r_tmp = (mu_rr[i][j] + mu_rr[i-1][j])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i-1][j])/2.0;
                    double mu_inv_xx_tmp = mu_r_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //前ステップから
                    Gx[i][j] = Gx_old_tmp[i][j] 
                        - (mu_inv_xx_tmp*Gx_old_tmp[i][j] + mu_inv_xr_tmp*Gr_tmp)*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;
                    
                    if(bLx != 0.0 && bRx != 0.0){
                        if(1.0 - mu_inv_xx_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (x) coef = "<< 1.0 - mu_inv_xx_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }

                    //左壁は電子フラックス指定
                    if((iblock==0 && i==i_flc_bl[0][0]) || (iblock==1 && i==i_flc_bl[1][0] && j<j_flc_bl[0][0])){
                        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                        Gx[i][j] = -rhoeps[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                    }
                    //右は電子フラックス x 5/2kTe
                    if(i == i_flc_bl[1][1]+1){
                        Gx[i][j] = 5.0/2.0*Boltz*Te_old[i-1][j]*rhoUex[i][j];
                    }
                }
            }     
        }

        //Gr更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1]+1;j++){
                    double r_tmp = (r[j] + r[j-1])/2.0;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    //前のステップから
                    double Gx_tmp = (r[j]*Gx_old_tmp[i+1][j]*bRx + r[j]*Gx_old_tmp[i][j]*bLx
                        + r[j-1]*Gx_old_tmp[i+1][j-1]*bRx + r[j-1]*Gx_old_tmp[i][j-1]*bLxD)/(4.0*r_tmp);

                    double mu_para_tmp = (mu_para[i][j] + mu_para[i][j-1])/2.0;
                    double mu_perp_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0;
                    double mu_min_tmp = mu_perp_tmp*ratioY;
                    double mu_x_tmp = (mu_xx[i][j] + mu_xx[i][j-1])/2.0;
                    double mu_c_tmp = (mu_xr[i][j] + mu_xr[i][j-1])/2.0;
                    double mu_inv_rr_tmp = mu_x_tmp/(mu_para_tmp*mu_perp_tmp);
                    double mu_inv_xr_tmp = -mu_c_tmp/(mu_para_tmp*mu_perp_tmp);
    
                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te_old[i][j] + Te_old[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    Gr[i][j] = Gr_old_tmp[i][j] 
                        - (mu_inv_xr_tmp*Gx_tmp + mu_inv_rr_tmp*Gr_old_tmp[i][j])*mu_min_tmp 
                        + (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*rhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*rhoeps[i][j]
                        )*5.0/3.0;

                    //タイムステップが負にならないように確認
                    if(bLr != 0.0 && bRr != 0.0){
                        if(1.0 - mu_inv_rr_tmp*mu_min_tmp < -1e-15){
                            std::cout << "Warning! negative pseudo-timestep (r) coef = "<< 1.0 - mu_inv_rr_tmp*mu_min_tmp << " i = " << i <<", j = "<< j << std::endl;
                        }
                    }
                    
                    //下は電子フラックス指定
                    if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                        double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));
                        Gr[i][j] = -rhoeps[i][j]*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*vth/3.0;
                    }    

                    //上はイオンフラックスと同じ
                    if(j == j_flc_bl[1][1]+1){
                        Gr[i][j] = 5.0/2.0*Boltz*Te_old[i][j-1]*rhoUer[i][j];
                    }
                }
            }
        }

        //係数作成
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j]*double(j!=j_flc_bl[1][0]);

                    double mu_min_Lx = (mu_perp[i][j]+mu_perp[i-1][j])/2.0*ratioX;
                    double mu_min_Rx = (mu_perp[i][j]+mu_perp[i+1][j])/2.0*ratioX;
                    double mu_min_Lr = (mu_perp[i][j]+mu_perp[i][j-1])/2.0*ratioY;
                    double mu_min_Rr = (mu_perp[i][j]+mu_perp[i][j+1])/2.0*ratioY;

                    double Te_Lx = (Te_old[i][j]+Te_old[i-1][j])/2.0;
                    double Te_Rx = (Te_old[i][j]+Te_old[i+1][j])/2.0;
                    double Te_Lr = (Te_old[i][j]+Te_old[i][j-1])/2.0;
                    double Te_Rr = (Te_old[i][j]+Te_old[i][j+1])/2.0;

                    double D_Lx = Boltz*Te_Lx/e0*mu_min_Lx;
                    double D_Rx = Boltz*Te_Rx/e0*mu_min_Rx;
                    double D_Lr = Boltz*Te_Lr/e0*mu_min_Lr;
                    double D_Rr = Boltz*Te_Rr/e0*mu_min_Rr;

                    double vd_Lx = mu_min_Lx*(-Ex[i  ][j  ]) + EPS;
                    double vd_Rx = mu_min_Rx*(-Ex[i+1][j  ]) + EPS;
                    double vd_Lr = mu_min_Lr*(-Er[i  ][j  ]) + EPS;
                    double vd_Rr = mu_min_Rr*(-Er[i  ][j+1]) + EPS;

                    double z_Lx = vd_Lx*dx/D_Lx;
                    double z_Rx = vd_Rx*dx/D_Rx;
                    double z_Lr = vd_Lr*dr/D_Lr;
                    double z_Rr = vd_Rr*dr/D_Rr;

                    double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                    double bLxD = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j-1>=j_flc_bl[0][0]);
                    double bRx  = double(i!=i_flc_bl[1][1]);
                    double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                    double bLrD = double(j!=j_flc_bl[0][0] || i-1>=i_flc_bl[1][0]);
                    double bRr  = double(j!=j_flc_bl[1][1]);

                    double nbLx  = 1.0 - bLx ;
                    double nbLr  = 1.0 - bLr ;

                    double vth = sqrt(8.0*Boltz*Te_old[i][j]/(M_PI*masse));

                    aP[i][j] =    vd_Rx/(1.0 - exp(fmin(-z_Rx,lim_exp)))*bRx*dr 
                             +    vd_Lx/(exp(fmin( z_Lx,lim_exp)) - 1.0)*bLx*dr
                             + qR*vd_Rr/(1.0 - exp(fmin(-z_Rr,lim_exp)))*bRr*dx
                             + qL*vd_Lr/(exp(fmin( z_Lr,lim_exp)) - 1.0)*bLr*dx
                             +    0.2*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dr*nbLx //陰的指定
                             + qL*0.2*vth*exp(fmin(-e0*phi[i][j]/(Boltz*Te_old[i][j] + 1e-100),lim_exp))*dx*nbLr //陰的指定
                             + 3.0/5.0*delossdeps[i][j]*dx*dr //陰的ソース項予測
                             + 3.0/5.0*(dx*dr/dt + dx*dr/dtau*double(icon_dtau)); //時間項 + 擬似時間項
                    aE[i][j] =    vd_Rx/(exp(fmin( z_Rx,lim_exp)) - 1.0)*bRx*dr;
                    aW[i][j] =    vd_Lx/(1.0 - exp(fmin(-z_Lx,lim_exp)))*bLx*dr;
                    aN[i][j] = qR*vd_Rr/(exp(fmin( z_Rr,lim_exp)) - 1.0)*bRr*dx;
                    aS[i][j] = qL*vd_Lr/(1.0 - exp(fmin(-z_Lr,lim_exp)))*bLr*dx;

                    double nabla_G = (Gx[i+1][j]-Gx[i][j])/dx + (qR*Gr[i][j+1]-qL*Gr[i][j])/dr;
                    double rhoUex_tmp = (rhoUex[i+1][j] + rhoUex[i][j])/2.0;
                    double rhoUer_tmp = (rR*rhoUer[i][j+1] + rL*rhoUer[i][j])/(2.0*r[j]);
                    double Ex_tmp = (Ex[i+1][j] + Ex[i][j])/2.0;
                    double Er_tmp = (rR*Er[i][j+1] + rL*Er[i][j])/(2.0*r[j]);

                    double RHS1 = (-rhoeps[i][j] + rhoeps_old[i][j])/dt;
                    double RHS2 = -e0*(Ex_tmp*rhoUex_tmp + Er_tmp*rhoUer_tmp);
                    double RHS3 = Pabs[i][j] 
                        - rhoe[i][j]*rate_eloss[i][j] 
                        - delossdeps[i][j]*rhoeps[i][j]
                        + rhoe[i][j]*(1.5*Boltz*Te[i][j])*delossdeps[i][j]; //陰的ソース項予測
                        
                    double RHS4 = -nabla_G;

                    b[i][j] = 3.0/5.0*(RHS1 + RHS2 + RHS3 + RHS4)*dx*dr;
                }
            }
        }

        //solve
        double alpha_SOR = 1.0;
        int icon_iter = 1;

        if(icon_iter_rhoeps==0){
            double alpha = 1.9;
            solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }else{
            solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_rhoeps,error_cnv_SOR_rhoeps,0,drhoeps);
        }

        /********************* 更新 *******************/
        //dGxを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i-1][j])/2.0*ratioX;

                    double vd_tmp = mu_min_tmp*(-Ex[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i-1][j])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dx/D_tmp;

                    //フラックス
                    dGx[i][j] = (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i-1][j]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }   
        }
        //dGrを計算
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    double r_tmp = (r[j] + r[j-1])/2.0;
                    double mu_min_tmp = (mu_perp[i][j] + mu_perp[i][j-1])/2.0*ratioY;

                    double vd_tmp = mu_min_tmp*(-Er[i][j]) + EPS;
                    double Te_tmp = (Te[i][j] + Te[i][j-1])/2.0;
                    double D_tmp = Boltz*Te_tmp/e0*mu_min_tmp;
                    double z_tmp = vd_tmp*dr/D_tmp;

                    dGr[i][j] =  (vd_tmp/(1.0 - exp(fmin(-z_tmp,lim_exp)))*drhoeps[i][j-1]
                        - vd_tmp/(exp(fmin( z_tmp,lim_exp)) - 1.0)*drhoeps[i][j]
                        )*5.0/3.0;
                }
            }
        }
        
        //更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    //rhoeps[i][j] = fmax(rhoeps[i][j] + drhoeps[i][j],1e-6);
                    double rhoeps_new = rhoeps[i][j] + drhoeps[i][j];
                    if(rhoeps_new > 0.0){
                        rhoeps[i][j] = rhoeps_new;
                    }
                }
            }
        }
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    Gx[i][j] = Gx[i][j] + dGx[i][j];
                }
            }
        }
        for (int iblock=0;iblock<n_bl-1;iblock++){
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){ //一番上下は更新しない
                    Gr[i][j] = Gr[i][j] + dGr[i][j];
                }
            }
        }

        //温度を更新
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    if(rhoeps[i][j]<0.0){
                        rhoeps[i][j] = fmax(rhoeps[i][j],0.0);
                    }
                    Te[i][j] = fmin(rhoeps[i][j]/(3.0/2.0*(rhoe[i][j] + rhoe_max*ratio)*Boltz + 1e-100),Te_max);
                }
            }
        }

        //エラー計算
        double error_rhoeps2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_rhoeps_tmp = fabs((rhoeps[i][j]-rhoeps_old_tmp[i][j])/(rhoeps[i][j]+rhoeps_old_tmp[i][j]+1e-100));
                        if(error_rhoeps_tmp > error_rhoeps2){
                            error_rhoeps2 = error_rhoeps_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_rhoeps = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_rhoeps2 += pow(rhoeps[i][j]-rhoeps_old_tmp[i][j],2)/(pow(rhoeps_old_tmp[i][j]+1e10,2));
                        ncount_rhoeps++;
                    }
                }
            }
            error_rhoeps2 = sqrt(error_rhoeps2/double(ncount_rhoeps));
        }

        double error_Gx2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        double error_Gx_tmp = fabs((Gx[i][j]-Gx_old_tmp[i][j])/(Gx[i][j]+Gx_old_tmp[i][j]+1e-100));
                        if(error_Gx_tmp > error_Gx2){
                            error_Gx2 = error_Gx_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gx = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){ 
                for (int i=i_flc_bl[iblock][0] + 1 - iblock;i<=i_flc_bl[iblock][1];i++){ //一番左右は更新しない
                    for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                        error_Gx2 += pow(Gx[i][j]-Gx_old_tmp[i][j],2)/(pow(Gx_old_tmp[i][j]+1e16,2));
                        ncount_Gx++;
                    }
                }
            }
            error_Gx2 = sqrt(error_Gx2/double(ncount_Gx));
        }

        double error_Gr2 = 0.0;
        if(icon_error2 == 0){
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        double error_Gr_tmp = fabs((Gr[i][j]-Gr_old_tmp[i][j])/(Gr[i][j]+Gr_old_tmp[i][j]+1e-100));
                        if(error_Gr_tmp > error_Gr2){
                            error_Gr2 = error_Gr_tmp;
                        }
                    }
                }
            }
        }else{
            double ncount_Gr = 0;
            for (int iblock=0;iblock<n_bl-1;iblock++){
                for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                    for (int j=j_flc_bl[iblock][0] + 1;j<=j_flc_bl[iblock][1];j++){
                        error_Gr2 += pow(Gr[i][j]-Gr_old_tmp[i][j],2)/(pow(Gr_old_tmp[i][j]+1e16,2))/CFL;
                        ncount_Gr++;
                    }
                }
            }
            error_Gr2 = sqrt(error_Gr2/double(ncount_Gr));
        }

        double error_global = fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2);
        if(ncount % ndiv_out == 0){
            std::cout << "ncount = "<<ncount<<std::endl;
            std::cout << "error_rhoeps = " << error_rhoeps2
                <<  " error_Gx = " << error_Gx2
                <<  " error_Gr= " << error_Gr2
                <<  " error_max = " << fmax(fmax(error_rhoeps2,error_Gx2),error_Gr2)
                << std::endl;
        }
       
        if(error_global < error_cnv_HES_rhoeps || ncount >= maxITR_HES_rhoeps){
            icon_end = 1;
        }
    
    } while (icon_end == 0);

    
    std::cout << "ncount_Te = "<<ncount<<std::endl;
    
    

    //輸送係数用に入れておく
    //左 壁1
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        Te[i-1][j] = Te[i][j];
    }

    //左 壁2
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        Te[i-1][j] = Te[i][j];
    }

    //下 壁
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        Te[i][j-1] = Te[i][j];
    }

    //右 ノイマン
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        Te[i+1][j]  =  Te[i][j];
    }

    //上 ノイマン
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        Te[i][j+1] =  Te[i][j];
    }

    //誤差を計算
    error_rhoeps = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhoeps[i][j] - rhoeps_old[i][j])/(rhoeps[i][j] + rhoeps_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhoeps){
                        error_rhoeps = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhoeps += pow(rhoeps[i][j]-rhoeps_old[i][j],2)/(pow(rhoeps_old[i][j]+1e10,2))/CFL;
                    ncount++;
                }
            }
        }
        error_rhoeps = sqrt(error_rhoeps/double(ncount));
    }

    error_Gx = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gx[i][j] - Gx_old[i][j])/(Gx[i][j] + Gx_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gx){
                        error_Gx = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gx += pow(Gx[i][j]-Gx_old[i][j],2)/(pow(Gx_old[i][j]+1.0,2))/CFL;
                    ncount++;
                }
            }
        }
        error_Gx = sqrt(error_Gx/double(ncount));
    }

    error_Gr = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((Gr[i][j] - Gr_old[i][j])/(Gr[i][j] + Gr_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_Gr){
                        error_Gr = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_Gr += pow(Gr[i][j]-Gr_old[i][j],2)/(pow(Gr_old[i][j]+1.0,2)+1e-100)/CFL;
                    ncount++;
                }
            }
        }
        error_Gr = sqrt(error_Gr/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhom_diff(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > rhom_new (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    double Dn = DmN/(rhon_ini+1e-100);

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhom_old[i][j] = rhom[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                aP[i][j] = 2.0*dr*dr 
                    + (qR + qL)*dx*dx + (nu_ionzStep[i][j] + nu_excStep[i][j])/Dn*dx*dx*dr*dr;
                aE[i][j] = dr*dr;
                aW[i][j] = dr*dr;
                aN[i][j] = qR*dx*dx;
                aS[i][j] = qL*dx*dx;

                double G = rhoe[i][j]*nu_excMeta[i][j]; 
                //損失 (stepwise Ionizationとstepwise Excitation)
                double L = rhom_old[i][j]*(nu_ionzStep[i][j] + nu_excStep[i][j]);

                //b[i][j] = (G - L)/Dn*dx*dx*dr*dr;
                b[i][j] = (G)/Dn*dx*dx*dr*dr;

                //b[i][j] = (e0*rhoi[i][j] - e0*(rhoe[i][j] + drhoe[i][j]))*dx*dx*dr*dr;
                //std::cout << rhoe[i][j] - rhoe_old[i][j] << std::endl;
            }
        }
    }

    //境界条件
    //左 壁1
    //std::cout << " Left1 "<< std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0]   << std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << " ~ "<< j_flc_bl[0][1]<< std::endl;
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        double v_tmp = -0.25*vth;
        aP[i][j] = aP[i][j] - aW[i][j]*(1.0 + 2.0*Dn/(v_tmp*dx))/(1.0 - 2.0*Dn/(v_tmp*dx));
        aW[i][j] = 0.0;
    }

    //左 壁2
    //std::cout << " Left2 "<< std::endl;
    //std::cout << " i = "  << i_flc_bl[1][0]   << std::endl;
    //std::cout << " j = "  << j_flc_bl[1][0] << " ~ "<< j_flc_bl[0][0]-1 << std::endl;
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        double v_tmp = -0.25*vth;
        aP[i][j] = aP[i][j] - aW[i][j]*(1.0 + 2.0*Dn/(v_tmp*dx))/(1.0 - 2.0*Dn/(v_tmp*dx));
        aW[i][j] = 0.0;
    }

    //右 壁
    //std::cout << " Right "<< std::endl;
    //std::cout << " i = "  << i_flc_bl[1][1] << std::endl;
    //std::cout << " j = "  << j_flc_bl[1][0] << " ~ "<< j_flc_bl[1][1] << std::endl;
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        double v_tmp = 0.25*vth;
        aP[i][j] = aP[i][j] - aE[i][j]*(1.0 - 2.0*Dn/(v_tmp*dx))/(1.0 + 2.0*Dn/(v_tmp*dx));
        aE[i][j] = 0.0;
    }

   //下壁
    //std::cout << " Bottom wall "<< std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[0][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];

        double v_tmp = -0.25*vth;
        double r_tmp = (r[j] + r[j-1])/2.0;
        double qL = r[j-1]/r_tmp;
        double qR = r[j]/r_tmp;
        
        aP[i][j] = aP[i][j] - aS[i][j]*(qR + 2.0*Dn/(v_tmp*dx))/(qL - 2.0*Dn/(v_tmp*dx));
        aS[i][j] = 0.0;

    }

    //上 壁
    //std::cout << " Top "<< std::endl;
    //std::cout << " j = "  << j_flc_bl[0][1] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[1][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        double v_tmp = 0.25*vth;
        double r_tmp = (r[j] + r[j+1])/2.0;
        double qL = r[j]/r_tmp;
        double qR = r[j+1]/r_tmp;
        
        aP[i][j] = aP[i][j] - aN[i][j]*(qL - 2.0*Dn/(v_tmp*dx))/(qR + 2.0*Dn/(v_tmp*dx));
        aN[i][j] = 0.0;
    }

    //solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl_tmp,j_flc_bl_tmp,1.0,30,error_cnv_SOR_Ui,0,phi);
    solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,10000,error_cnv_SOR_Ui,1,rhom);

    //境界条件
    //左 壁1
    //std::cout << " Left1 "<< std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0]   << std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << " ~ "<< j_flc_bl[0][1]<< std::endl;
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0];
        double v_tmp = -0.25*vth;
        rhom[i-1][j] = rhom[i][j]*(1.0 + 2.0*Dn/(v_tmp*dx))/(1.0 - 2.0*Dn/(v_tmp*dx));
    }

    //左 壁2
    //std::cout << " Left1 "<< std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0]   << std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << " ~ "<< j_flc_bl[0][1]<< std::endl;
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0];
        double v_tmp = -0.25*vth;
        rhom[i-1][j] = rhom[i][j]*(1.0 + 2.0*Dn/(v_tmp*dx))/(1.0 - 2.0*Dn/(v_tmp*dx));
    }


    //右 壁
    //std::cout << " Right "<< std::endl;
    //std::cout << " i = "  << i_flc_bl[1][1] << std::endl;
    //std::cout << " j = "  << j_flc_bl[1][0] << " ~ "<< j_flc_bl[1][1] << std::endl;
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        double v_tmp = 0.25*vth;
        rhom[i+1][j] = rhom[i][j]*(1.0 - 2.0*Dn/(v_tmp*dx))/(1.0 + 2.0*Dn/(v_tmp*dx));
    }

    //rhoUmx更新
    for (int iblock=0;iblock<2;iblock++){ 
        //std::cout << "Block = "  << iblock  << std::endl;
        //std::cout << " i = "  << i_flc_bl[iblock][0]  << " ~ "<<i_flc_bl[iblock][1] + iblock << std::endl;
        //std::cout << " j = "  << j_flc_bl[iblock][0] << " ~ "<< j_flc_bl[iblock][1] << std::endl;
        //std::cout <<  std::endl;
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                rhoUmx[i][j] = -Dn*(rhom[i][j] - rhom[i-1][j])/dx;
            }
        }
    }

    //下 壁
    //std::cout << " Bottom wall "<< std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[0][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0];
        double v_tmp = -0.25*vth;
        double r_tmp = (r[j] + r[j-1])/2.0;
        double qL = r[j-1]/r_tmp;
        double qR = r[j]/r_tmp;
        rhom[i][j-1] = rhom[i][j]*(qR + 2.0*Dn/(v_tmp*dx))/(qL - 2.0*Dn/(v_tmp*dx));

    }

    //上 壁
    //std::cout << " Top "<< std::endl;
    //std::cout << " j = "  << j_flc_bl[0][1] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[1][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        double v_tmp = 0.25*vth;
        double r_tmp = (r[j] + r[j+1])/2.0;
        double qL = r[j]/r_tmp;
        double qR = r[j+1]/r_tmp;

        rhom[i][j+1] = rhom[i][j]*(qL - 2.0*Dn/(v_tmp*dx))/(qR + 2.0*Dn/(v_tmp*dx));
    }

    

    //rhoUerを計算
    for (int iblock=0;iblock<2;iblock++){
        //std::cout << "Block = "  << iblock  << std::endl;
        //std::cout << " i = "  << i_flc_bl[iblock][0]  << " ~ "<< i_flc_bl[iblock][1] << std::endl;
        //std::cout << " j = "  << j_flc_bl[iblock][0] + iblock << " ~ "<< j_flc_bl[iblock][1]+1 << std::endl;
        //std::cout <<  std::endl;
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0] + iblock;j<=j_flc_bl[iblock][1]+1;j++){
                rhoUmr[i][j] = -Dn*(rhom[i][j] - rhom[i][j-1])/dr;
            }
        }   
    }

    /*
    //左壁境界1 (フラックス指定)
    //std::cout << " Left1 " << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0]+1   << std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << " ~ "<< j_flc_bl[0][1]<< std::endl;
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0]+1;
        rhoUmx[i-1][j] = -0.25*rhom[i-1][j]*vth;
    }

    //右開放境界 (フラックス指定)
    //std::cout << " Right " << std::endl;
    //std::cout << " i = "  << i_flc_bl[1][1] << std::endl;
    //std::cout << " j = "  << j_flc_bl[1][0] << " ~ "<< j_flc_bl[1][1] << std::endl;
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
    }

    //下壁境界 (フラックス指定)
    //std::cout << " Bottom wall "<< std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[0][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][0]+1;
        rhoUmr[i][j-1] = -0.25*rhom[i][j-1]*vth;
    }

    //上開放境界 (ノイマン)
    //std::cout << " Top " << std::endl;
    //std::cout << " j = "  << j_flc_bl[0][1] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[1][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
    }
    */

    //エラー計算
    error_rhom = 0.0;
    for (int i = i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        for (int j= j_flc_bl[0][0];j<=j_flc_bl[1][1];j++){
            double error_rhom_tmp = fabs((rhom[i][j]-rhom_old[i][j])/(rhom[i][j]+rhom_old[i][j]+1e-100));
            if(error_rhom_tmp > error_rhom){
                error_rhom = error_rhom_tmp;
            }
        }
    }
    //std::cout << "error_rhom = " << error_rhom << std::endl;

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhom_explicit(){

    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    double Dn = DmN/rhon_ini;

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhom_old[i][j] = rhom[i][j];
        }
    }

    //Fx更新
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0] + 1;i<=i_flc_bl[iblock][1] + 1 - iblock;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                rhoUmx[i][j] = -Dn*(rhom[i][j] - rhom[i-1][j])/dx;
            }
        }
    }

    //左壁境界1 (フラックス指定)
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i = i_flc_bl[0][0]+1;
        rhoUmx[i-1][j] = -0.25*rhom[i-1][j]*vth;
    }

    //左壁境界2 (フラックス指定)
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[0][0]-1;j++){
        int i = i_flc_bl[1][0]+1;
        rhoUmx[i-1][j] = -0.25*rhom[i-1][j]*vth;
    }

    //右開放境界 (フラックス指定)
    //std::cout << " Right " << std::endl;
    //std::cout << " i = "  << i_flc_bl[1][1] << std::endl;
    //std::cout << " j = "  << j_flc_bl[1][0] << " ~ "<< j_flc_bl[1][1] << std::endl;
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i = i_flc_bl[1][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
    }

    //rhoUmr更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0]+1;j<=j_flc_bl[iblock][1];j++){
                rhoUmr[i][j] = -Dn*(rhom[i][j] - rhom[i][j-1])/dr;
            }

        }   
    }

    //下壁境界 (フラックス指定)
    //std::cout << " Bottom wall "<< std::endl;
    //std::cout << " j = "  << j_flc_bl[0][0] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[0][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){ 
        int j = j_flc_bl[0][0]+1;
        rhoUmr[i][j-1] = -0.25*rhom[i][j-1]*vth;
    }

    //下中心境界 (速度0) 
    //std::cout << " j = "  << j_flc_bl[1][0]+1 << std::endl;
    //std::cout << " i = "  << i_flc_bl[1][0] << " ~ "<< i_flc_bl[1][1] << std::endl;
    //for (int i=i_flc_bl[1][0];i<=i_flc_bl[1][1];i++){ 
    //    int j = j_flc_bl[1][0]+1;
    //    rhoUmr[i][j-1] = 0.0;
    //}

    //上開放境界 (ノイマン)
    //std::cout << " Top " << std::endl;
    //std::cout << " j = "  << j_flc_bl[0][1] << std::endl;
    //std::cout << " i = "  << i_flc_bl[0][0] << " ~ "<< i_flc_bl[1][1] << std::endl;
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){ 
        int j = j_flc_bl[0][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
    }

    //更新
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //生成 (励起)
                double G = rhoe_old[i][j]*nu_excMeta[i][j]; 
                //損失 (stepwise Ionizationとstepwise Excitation)
                double L = rhom_old[i][j]*(nu_ionzStep[i][j] + nu_excStep[i][j]);

                rhom[i][j] = rhom_old[i][j] 
                    + dt*(G - L - (rhoUmx[i+1][j]-rhoUmx[i][j])/dx - (rhoUmr[i][j+1]-rhoUmr[i][j])/dr);
            }
        }
    }

    //エラー計算
    error_rhom = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhom[i][j] - rhom_old[i][j])/(rhom[i][j] + rhom_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhom){
                        error_rhom = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhom += pow(rhom[i][j]-rhom_old[i][j],2)/(pow(rhom_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhom = sqrt(error_rhom/double(ncount));
    }
    //std::cout << "error_rhom = " << error_rhom << std::endl;

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhom_old(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    //common parameter
    //------------------------------------
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi)); //thermal speed
    double Dn = DmN/rhon_ini; //diffusion coefficient
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhom_old[i][j] = rhom[i][j];
            rhoUmx_old[i][j] = rhoUmx[i][j];
            rhoUmr_old[i][j] = rhoUmr[i][j];
        }
    }
    //------------------------------------

    //Make coefficient for continuity equation for 5 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                //------------------------------------
                
                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];
                //------------------------------------

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1]); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr*bRr1; //全部含む


                double um = sqrt(2.0*Boltz*Tn/massi);

                aP[i][j] = (bRx + bLx)*dr*dr 
                    + (qR*bRr + qL*bLr)*dx*dx 
                    +    0.25*vth*dr*dx*dr/Dn*nbLx //陰的指定
                    +    0.25*vth*dr*dx*dr/Dn*nbRx //陰的指定
                    + qL*0.25*vth*dx*dx*dr/Dn*nbLr //陰的指定
                    + qR*0.25*vth*dx*dx*dr/Dn*nbRr //陰的指定
                    + dx*dx*dr*dr/dt/Dn; //時間項;
                aE[i][j] = dr*dr*bRx;
                aW[i][j] = dr*dr*bLx;
                aN[i][j] = qR*dx*dx*bRr;
                aS[i][j] = qL*dx*dx*bLr;

                //ソース項
                double G = rhoe[i][j]*(nu_excMeta[i][j] + 0.5*nu_exc[i][j]); //生成　直接励起と upperの半分がmetaに最終的に落ちてくる
                double L = rhoe[i][j]*(nu_ionzStep[i][j] + nu_excStep[i][j] + nu_super[i][j]); //損失 (stepwise Ionizationとstepwise Excitation)

                double rhoUmx_Rx = rhoUmx_old[i][j];
                double rhoUmx_Rr = rhoUmr_old[i][j]*rL/rR;

                b[i][j] = rhom_old[i][j]/dt/Dn*dx*dx*dr*dr + (G - L)/Dn*dx*dx*dr*dr
                    + (0.0
                          //rhoUmx_Lx*nbLx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr/Dn
                    - (0.0
                         //rhoUmx_Rx*nbRx //右壁境界
                      )*dr*dx*dr/Dn
                    + qL*(0.0
                          //rhoUmr_Lr*nbLr //下壁境界　 //陽的指定
                      )*dx*dx*dr/Dn
                    - qR*(
                        rhoUmx_Rr*nbRr1 //上壁境界
                      )*dx*dx*dr/Dn;
            }
        }
    }
    //=================================================================================

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhom[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhom[i][j]<< std::endl; 
                    ncount ++;
                    rhom[i][j] = fmax(rhom_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhom count = " << ncount << std::endl;
    }

    //rhoUmx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                rhoUmx[i][j] = -Dn*(rhom[i][j] - rhom[i-1][j])/dx;
            }
        }
    }

    //rhoUmr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                rhoUmr[i][j] = -Dn*(rhom[i][j] - rhom[i][j-1])/dr;
            }
        }   
    }

    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoUmr[i][j] = -0.25*rhom[i][j]*vth;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoUmr[i][j] = -0.25*rhom[i][j]*vth;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double rhoUmr_Rr = rhoUmr_old[i][j]*rL/rR;
        rhoUmr[i][j+1] = rhoUmr_Rr;
    }

    //エラー計算
    error_rhom = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhom[i][j] - rhom_old[i][j])/(rhom[i][j] + rhom_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhom){
                        error_rhom = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhom += pow(rhom[i][j]-rhom_old[i][j],2)/(pow(rhom_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhom = sqrt(error_rhom/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhom_old2(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    //time step for metastable neutral
    //------------------------------------
    double dt_m = dt*double(ndt_m);
    //------------------------------------

    //common parameter
    //------------------------------------
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi)); //thermal speed
    double Dm = DmN/rhon_ini; //diffusion coefficient
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhom_old[i][j] = rhom[i][j];
            rhoUmx_old[i][j] = rhoUmx[i][j];
            rhoUmr_old[i][j] = rhoUmr[i][j];
        }
    }
    //------------------------------------

    //Make coefficient for continuity equation for 5 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                //------------------------------------
                
                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];
                //------------------------------------

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //adjacent "cell" to the wall for setting zero-flux on the wall
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;
                
                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;
                
                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1 not inlet
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_open;
                //------------------------------------

                //BC - normal flux component to the wall or open boundaries
                //*****************************************************
                //wall-flux divide by density (for implicit method)
                //------------------------------------
                double GammaPerNeps_wall_Lx = 0.0;
                double GammaPerNeps_wall_Rx = 0.0;
                double GammaPerNeps_wall_Lr = 0.0;
                double GammaPerNeps_wall_Rr = 0.0;
                if(bLx_wall == 0){
                    GammaPerNeps_wall_Lx = -0.25*vth;
                }
                if(bRx_wall == 0){
                    GammaPerNeps_wall_Rx =  0.25*vth;
                }
                if(bLr_wall == 0){
                    GammaPerNeps_wall_Lr = -0.25*vth;
                }
                if(bRr_wall == 0){
                    GammaPerNeps_wall_Rr =  0.25*vth;
                }
                //------------------------------------

                //open-flux (equal to ion)
                //------------------------------------
                double Gamma_open_Rr = 0.0;
                if(bRr_open == 0){
                    Gamma_open_Rr = rL/rR*rhoUmr_old[i][j];
                }
                //*****************************************************


                double um = sqrt(2.0*Boltz*Tn/massi);

                aP[i][j] = (bRx + bLx)*dr*dr 
                    + (qR*bRr + qL*bLr)*dx*dx 
                    -    GammaPerNeps_wall_Lx*dr*dx*dr/Dm //陰的指定
                    +    GammaPerNeps_wall_Rx*dr*dx*dr/Dm //陰的指定
                    - qL*GammaPerNeps_wall_Lr*dx*dx*dr/Dm //陰的指定
                    + qR*GammaPerNeps_wall_Rr*dx*dx*dr/Dm //陰的指定
                    + dx*dx*dr*dr/dt_m/Dm; //時間項;
                aE[i][j] = dr*dr*bRx;
                aW[i][j] = dr*dr*bLx;
                aN[i][j] = qR*dx*dx*bRr;
                aS[i][j] = qL*dx*dx*bLr;

                //ソース項
                double G = rhoe[i][j]*(nu_excMeta[i][j] + 0.5*nu_exc[i][j]); //生成　直接励起と upperの半分がmetaに最終的に落ちてくる
                double L = rhoe[i][j]*(nu_ionzStep[i][j] + nu_excStep[i][j] + nu_super[i][j]); //損失 (stepwise Ionizationとstepwise Excitation)

                b[i][j] = rhom_old[i][j]/dt_m/Dm*dx*dx*dr*dr + (G - L)/Dm*dx*dx*dr*dr
                    + (0.0
                          //rhoUmx_Lx*nbLx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr/Dm
                    - (0.0
                         //rhoUmx_Rx*nbRx //右壁境界
                      )*dr*dx*dr/Dm
                    + qL*(0.0
                          //rhoUmr_Lr*nbLr //下壁境界　 //陽的指定
                      )*dx*dx*dr/Dm
                    - qR*(
                        Gamma_open_Rr //上壁境界
                      )*dx*dx*dr/Dm;
            }
        }
    }
    //=================================================================================

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhom[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhom[i][j]<< std::endl; 
                    ncount ++;
                    rhom[i][j] = fmax(rhom_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhom count = " << ncount << std::endl;
    }

    //rhoUmx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                rhoUmx[i][j] = -Dm*(rhom[i][j] - rhom[i-1][j])/dx;
            }
        }
    }

    //rhoUmr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                rhoUmr[i][j] = -Dm*(rhom[i][j] - rhom[i][j-1])/dr;
            }
        }   
    }

    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoUmr[i][j] = -0.25*rhom[i][j]*vth;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoUmr[i][j] = -0.25*rhom[i][j]*vth;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double rhoUmr_Rr = rhoUmr_old[i][j]*rL/rR;
        rhoUmr[i][j+1] = rhoUmr_Rr;
    }

    //エラー計算
    error_rhom = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhom[i][j] - rhom_old[i][j])/(rhom[i][j] + rhom_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhom){
                        error_rhom = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhom += pow(rhom[i][j]-rhom_old[i][j],2)/(pow(rhom_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhom = sqrt(error_rhom/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhom(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    //time step for metastable neutral
    //------------------------------------
    double dt_m = dt*double(ndt_m);
    //------------------------------------

    //common parameter
    //------------------------------------
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi)); //thermal speed
    //------------------------------------

    //Reserve the past values
    //------------------------------------
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhom_old[i][j] = rhom[i][j];
            rhoUmx_old[i][j] = rhoUmx[i][j];
            rhoUmr_old[i][j] = rhoUmr[i][j];
        }
    }
    //------------------------------------

    //Make coefficient for continuity equation for 5 point stencil
    //=================================================================================
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                //radial position at upper and lower cell interface
                //------------------------------------
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                //------------------------------------
                
                //normalized radial position at upper and lower cell interface
                //------------------------------------
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];
                //------------------------------------

                //diffusion coefficient at cell interface
                //------------------------------------
                double rhon_Lx = (rhon[i][j]+rhon[i-1][j])/2.0;
                double rhon_Rx = (rhon[i][j]+rhon[i+1][j])/2.0;
                double rhon_Lr = (rhon[i][j]+rhon[i][j-1])/2.0;
                double rhon_Rr = (rhon[i][j]+rhon[i][j+1])/2.0;

                double Dm_Lx = DmN/(rhon_Lx + 1e-100);
                double Dm_Rx = DmN/(rhon_Rx + 1e-100);
                double Dm_Lr = DmN/(rhon_Lr + 1e-100);
                double Dm_Rr = DmN/(rhon_Rr + 1e-100);
                //------------------------------------

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //adjacent "cell" to the wall for setting zero-flux on the wall
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;
                
                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;
                
                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1 not inlet
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_open;
                //------------------------------------

                //BC - normal flux component to the wall or open boundaries
                //*****************************************************
                //wall-flux divide by density (for implicit method)
                //------------------------------------
                double GammaPerNeps_wall_Lx = 0.0;
                double GammaPerNeps_wall_Rx = 0.0;
                double GammaPerNeps_wall_Lr = 0.0;
                double GammaPerNeps_wall_Rr = 0.0;
                if(bLx_wall == 0){
                    GammaPerNeps_wall_Lx = -0.25*vth;
                }
                if(bRx_wall == 0){
                    GammaPerNeps_wall_Rx =  0.25*vth;
                }
                if(bLr_wall == 0){
                    GammaPerNeps_wall_Lr = -0.25*vth;
                }
                if(bRr_wall == 0){
                    GammaPerNeps_wall_Rr =  0.25*vth;
                }
                //------------------------------------

                //open-flux (equal to ion)
                //------------------------------------
                double Gamma_open_Rr = 0.0;
                if(bRr_open == 0){
                    Gamma_open_Rr = rL/rR*rhoUmr_old[i][j];
                }
                //*****************************************************


                double um = sqrt(2.0*Boltz*Tn/massi);

                aP[i][j] = (Dm_Rx*bRx + Dm_Lx*bLx)*dr*dr 
                    + (qR*Dm_Rr*bRr + qL*Dm_Lr*bLr)*dx*dx 
                    -    GammaPerNeps_wall_Lx*dr*dx*dr //陰的指定
                    +    GammaPerNeps_wall_Rx*dr*dx*dr //陰的指定
                    - qL*GammaPerNeps_wall_Lr*dx*dx*dr //陰的指定
                    + qR*GammaPerNeps_wall_Rr*dx*dx*dr //陰的指定
                    + dx*dx*dr*dr/dt_m; //時間項;
                aE[i][j] =    Dm_Rx*dr*dr*bRx;
                aW[i][j] =    Dm_Lx*dr*dr*bLx;
                aN[i][j] = qR*Dm_Rr*dx*dx*bRr;
                aS[i][j] = qL*Dm_Lr*dx*dx*bLr;

                //ソース項
                double G = rhoe[i][j]*(nu_excMeta[i][j] + 0.5*nu_exc[i][j]); //生成　直接励起と upperの半分がmetaに最終的に落ちてくる
                double L = rhoe[i][j]*(nu_ionzStep[i][j] + nu_excStep[i][j] + nu_super[i][j]); //損失 (stepwise Ionizationとstepwise Excitation)

                b[i][j] = rhom_old[i][j]/dt_m*dx*dx*dr*dr + (G - L)*dx*dx*dr*dr
                    + (0.0
                          //rhoUmx_Lx*nbLx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr
                    - (0.0
                         //rhoUmx_Rx*nbRx //右壁境界
                      )*dr*dx*dr
                    + qL*(0.0
                          //rhoUmr_Lr*nbLr //下壁境界　 //陽的指定
                      )*dx*dx*dr
                    - qR*(
                        Gamma_open_Rr //上壁境界
                      )*dx*dx*dr;
            }
        }
    }
    //=================================================================================

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhom[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhom[i][j]<< std::endl; 
                    ncount ++;
                    rhom[i][j] = fmax(rhom_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhom count = " << ncount << std::endl;
    }

    //rhoUmx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                double rhon_Lx = (rhon[i][j]+rhon[i-1][j])/2.0;
                double Dm_Lx = DmN/(rhon_Lx + 1e-100);

                rhoUmx[i][j] = -Dm_Lx*(rhom[i][j] - rhom[i-1][j])/dx;
            }
        }
    }

    //rhoUmr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                double rhon_Lr = (rhon[i][j]+rhon[i][j-1])/2.0;
                double Dm_Lr = DmN/(rhon_Lr + 1e-100);
                
                rhoUmr[i][j] = -Dm_Lr*(rhom[i][j] - rhom[i][j-1])/dr;
            }
        }   
    }

    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
        rhoUmx_wall[i][j] = rhoUmx[i][j];
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
        rhoUmx_wall[i][j] = rhoUmx[i][j];
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
        rhoUmx_wall[i][j] = rhoUmx[i][j];
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoUmx[i][j] = -0.25*rhom[i][j]*vth;
        rhoUmx_wall[i][j] = rhoUmx[i][j];
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
        rhoUmx_wall[i+1][j] = rhoUmx[i+1][j];
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoUmx[i+1][j] = 0.25*rhom[i][j]*vth;
        rhoUmx_wall[i+1][j] = rhoUmx[i+1][j];
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoUmr[i][j] = -0.25*rhom[i][j]*vth;
        rhoUmr_wall[i][j] = rhoUmr[i][j];
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoUmr[i][j] = -0.25*rhom[i][j]*vth;
        rhoUmr_wall[i][j] = rhoUmr[i][j];
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
        rhoUmr_wall[i][j+1] = rhoUmr[i][j+1];
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoUmr[i][j+1] = 0.25*rhom[i][j]*vth;
        rhoUmr_wall[i][j+1] = rhoUmr[i][j+1];
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double rhoUmr_Rr = rhoUmr_old[i][j]*rL/rR;
        rhoUmr[i][j+1] = rhoUmr_Rr;
        rhoUmr_wall[i][j+1] = 0.0;
    }

    
    //calculation of particle balance
    //------------------------------------
    if(itime%ndiv_fout == 0 || itime == ntime){
        
        //volume integrated values
        //------------------------------------
        double dNmdt_sum         = 0.0;
        double nabla_rhoUm_sum   = 0.0;
        double rate_exc_to_h_sum = 0.0;
        double rate_super_sum    = 0.0;
        double rate_exc_to_m_sum = 0.0;
        double rate_drop_sum     = 0.0;
        double rate_s_ionz_sum   = 0.0;
        //------------------------------------
    
        //calculate volume integrated of each term
        //------------------------------------
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1 not inlet
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    double nabla_rhoUm = (rhoUmx[i+1][j]*bRx_wall - rhoUmx[i][j]*bLx_wall)/dx 
                                       + (qR*rhoUmr[i][j+1]*bRr_wall - qL*rhoUmr[i][j]*bLr_wall)/dr
                                       + (rhoUmx_wall[i+1][j] -rhoUmx_wall[i][j])/dx 
                                       + (qR*rhoUmr_wall[i][j+1] - qL*rhoUmr_wall[i][j])/dr;

                    double volume = 2.0*M_PI*r[j]*dr*dx;
                    
                    dNmdt_sum         = dNmdt_sum         + volume*(rhom[i][j] - rhom_old[i][j])/dt;
                    nabla_rhoUm_sum   = nabla_rhoUm_sum   + volume*nabla_rhoUm;
                    rate_s_ionz_sum   = rate_s_ionz_sum   + volume*rhoe[i][j]*nu_ionzStep[i][j];
                    rate_exc_to_h_sum = rate_exc_to_h_sum + volume*rhoe[i][j]*nu_excStep[i][j];
                    rate_super_sum    = rate_super_sum    + volume*rhoe[i][j]*nu_super[i][j];
                    rate_exc_to_m_sum = rate_exc_to_m_sum + volume*rhoe[i][j]*nu_excMeta[i][j];
                    rate_drop_sum     = rate_drop_sum     + volume*rhoe[i][j]*0.5*nu_exc[i][j];
                }
            }
        }

        //output particle balance for metastable
        //------------------------------------
        std::string char1="results/particle_balance_meta";
        std::string char2=std::to_string(nOut);
        std::string char_csv=".csv";
        std::ofstream outputfile10(char1+char2+char_csv);
        outputfile10 << std::setprecision(std::numeric_limits<double>::max_digits10) << std::scientific;
        outputfile10<< "dN/dt (pcl/s), loss_to_bnd (pcl/s), sw-iz (pcl/s), sw-ex (pcl/s), super (pcl/s), direct-ex (pcl/s), drop (pcl/s), sum (pcl/s)"<< std::endl;
        outputfile10<< dNmdt_sum << ","<< -nabla_rhoUm_sum <<  ","<< -rate_s_ionz_sum  
            <<"," << -rate_exc_to_h_sum << "," << -rate_super_sum << "," <<  rate_exc_to_m_sum << "," <<  rate_drop_sum
            << "," << -dNmdt_sum + (-nabla_rhoUm_sum - rate_s_ionz_sum - rate_exc_to_h_sum - rate_super_sum + rate_exc_to_m_sum + rate_drop_sum)<< std::endl;
        outputfile10.close();
        //------------------------------------
    }
    //------------------------------------
    
    //エラー計算
    error_rhom = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhom[i][j] - rhom_old[i][j])/(rhom[i][j] + rhom_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhom){
                        error_rhom = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhom += pow(rhom[i][j]-rhom_old[i][j],2)/(pow(rhom_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhom = sqrt(error_rhom/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhon_old(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    double Dn = DmN/rhon_ini;

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhon_old[i][j] = rhon[i][j];
            rhoUnx_old[i][j] = rhoUnx[i][j];
            rhoUnr_old[i][j] = rhoUnr[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bRr_in  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1] || x[i] > width_neutIn); //x1 inlet
                double nbRr_in  = 1.0 - bRr_in;
                //test1[i][j] = nbRr_in;
                
                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1] || x[i] <= width_neutIn); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr_in*bRr*bRr1; //全部含む

                double um = sqrt(2.0*Boltz*Tn/massi);

                aP[i][j] = (bRx + bLx)*dr*dr 
                    + (qR*bRr + qL*bLr)*dx*dx 
                    +    0.25*vth*dr*dx*dr/Dn*nbLx //陰的指定
                    +    0.25*vth*dr*dx*dr/Dn*nbRx //陰的指定
                    + qL*0.25*vth*dx*dx*dr/Dn*nbLr //陰的指定
                    + qR*0.25*vth*dx*dx*dr/Dn*nbRr //陰的指定
                    + dx*dx*dr*dr/dt/Dn; //時間項;
                aE[i][j] = dr*dr*bRx;
                aW[i][j] = dr*dr*bLx;
                aN[i][j] = qR*dx*dx*bRr;
                aS[i][j] = qL*dx*dx*bLr;

                //double rhoUnx_Rx = rhoUnx_old[i][j];
                double rhoUnx_Rr = rhoUnr_old[i][j]*rL/rR;
                double rhoUnx_Rr_in = -fn_In;

                b[i][j] = rhon_old[i][j]/dt/Dn*dx*dx*dr*dr// + (rate_ionize[i][j])/Dn*dx*dx*dr*dr
                    + (0.0
                          //rhoUnx_Lx*nbLx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr/Dn
                    - (0.0
                         //rhoUnx_Rx*nbRx //右壁境界
                      )*dr*dx*dr/Dn
                    + qL*(0.0
                          //rhoUnr_Lr*nbLr //下壁境界　 //陽的指定
                      )*dx*dx*dr/Dn
                    - qR*(
                        + rhoUnx_Rr*nbRr1 //上壁境界
                        + rhoUnx_Rr_in*nbRr_in
                      )*dx*dx*dr/Dn;
            }
        }
    }

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhon[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhon[i][j]<< std::endl; 
                    ncount ++;
                    rhon[i][j] = fmax(rhon_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhon count = " << ncount << std::endl;
    }

    //rhoUnx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                rhoUnx[i][j] = -Dn*(rhon[i][j] - rhon[i-1][j])/dx;
            }
        }
    }

    //rhoUnr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                rhoUnr[i][j] = -Dn*(rhon[i][j] - rhon[i][j-1])/dr;
            }
        }   
    }

    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
    }
    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        if(x[i] < width_neutIn){ //流入部
            rhoUnr[i][j+1] = -fn_In;
        }else{ //ただの壁
            rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
        }
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double rhoUnr_Rr = rhoUnr_old[i][j]*rL/rR;
        rhoUnr[i][j+1] = rhoUnr_Rr;
    }

    //エラー計算
    error_rhon = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhon[i][j] - rhon_old[i][j])/(rhon[i][j] + rhon_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhon){
                        error_rhon = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhon += pow(rhon[i][j]-rhon_old[i][j],2)/(pow(rhon_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhon = sqrt(error_rhon/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhon_old2(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    //double sigma = M_PI*ri*ri;
    //double nu_tmp = sqrt(2.0)*rhon*sigma*vth;
    //double Dn = Boltz*Tn/(massi*nu_tmp);
    
    double Dn = DmN/rhon_ini;

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhon_old[i][j] = rhon[i][j];
            rhoUnx_old[i][j] = rhoUnx[i][j];
            rhoUnr_old[i][j] = rhoUnr[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bRr_in  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1] || x[i] > width_neutIn); //x1 inlet
                double nbRr_in  = 1.0 - bRr_in;
                //test1[i][j] = nbRr_in;
                
                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1] || x[i] <= width_neutIn); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr_in*bRr*bRr1; //全部含む
                
                bRr = bRr_in*bRr; //全部含む


                double um = sqrt(2.0*Boltz*Tn/massi);

                aP[i][j] = (bRx + bLx)*dr*dr 
                    + (qR*bRr + qL*bLr)*dx*dx 
                    //+    0.25*vth*dr*dx*dr/Dn*nbLx //陰的指定
                    //+    0.25*vth*dr*dx*dr/Dn*nbRx //陰的指定
                    //+ qL*0.25*vth*dx*dx*dr/Dn*nbLr //陰的指定
                    + qR*0.25*vth*dx*dx*dr/Dn*nbRr1 //陰的指定
                    + dx*dx*dr*dr/dt/Dn; //時間項;
                aE[i][j] = dr*dr*bRx;
                aW[i][j] = dr*dr*bLx;
                aN[i][j] = qR*dx*dx*bRr;
                aS[i][j] = qL*dx*dx*bLr;

                //double rhoUnx_Rx = rhoUnx_old[i][j];
                //double rhoUnx_Rr = rhoUnr_old[i][j]*rL/rR;

                //recombination
                double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]; 
                double rhoUnx_Rx_RC = -rhoi[i][j]*Uix[i+1][j];
                double rhoUnr_Lr_RC = -rhoi[i][j]*Uir[i][j]; 
                double rhoUnr_Rr_RC = -rhoi[i][j]*Uir[i][j+1]; 

                double rhoUnx_Rr_in = -fn_In;

                b[i][j] = rhon_old[i][j]/dt/Dn*dx*dx*dr*dr + (-nu_ionz[i][j]*rhoe[i][j])/Dn*dx*dx*dr*dr
                    + (
                        rhoUnx_Lx_RC*nbLx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr/Dn
                    - (
                         rhoUnx_Rx_RC*nbRx //右壁境界
                      )*dr*dx*dr/Dn
                    + qL*(
                          rhoUnr_Lr_RC*nbLr //下壁境界
                      )*dx*dx*dr/Dn
                    - qR*(
                          rhoUnr_Rr_RC*nbRr //上壁境界
                        + rhoUnx_Rr_in*nbRr_in
                      )*dx*dx*dr/Dn;
            }
        }
    }

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhon[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhon[i][j]<< std::endl; 
                    ncount ++;
                    rhon[i][j] = fmax(rhon_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhon count = " << ncount << std::endl;
    }

    //rhoUnx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                rhoUnx[i][j] = -Dn*(rhon[i][j] - rhon[i-1][j])/dx;
            }
        }
    }

    //rhoUnr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                rhoUnr[i][j] = -Dn*(rhon[i][j] - rhon[i][j-1])/dr;
            }
        }   
    }

    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        //rhoUnx[i+1][j] = -rhoi[i][j]*Uix[i+1][j]; //Recombination
        double rhoUnx_Rx_RC = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = rhoUnx_Rx_RC;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        //rhoUnx[i+1][j] = -rhoi[i][j]*Uix[i+1][j]; //Recombination
        double rhoUnx_Rx_RC = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = rhoUnx_Rx_RC;
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double rhoUnr_Lr_RC = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = rhoUnr_Lr_RC;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double rhoUnr_Lr_RC = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = rhoUnr_Lr_RC;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        if(x[i] < width_neutIn){ //流入部
            
            //rhoUnr[i][j+1] = -fn_In;
            double rhoUnx_Rr_in = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1] - fn_In;
            rhoUnr[i][j+1] = rhoUnx_Rr_in;
            //std::cout << i << "," <<j <<","<< rhoUnr[i][j+1] << std::endl;
        }else{ //ただの壁
            //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
            //rhoUnr[i][j+1] = -rhoi[i][j]*Uir[i][j+1]; //Recombination
            double rhoUnr_Rr_RC = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
            rhoUnr[i][j+1] = rhoUnr_Rr_RC;
        }
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
        //rhoUnr[i][j+1] = -rhoi[i][j]*Uir[i][j+1]; //Recombination
        double rhoUnr_Rr_RC = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
        rhoUnr[i][j+1] = rhoUnr_Rr_RC;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        //double rL = (r[j]+r[j-1])/2.0;
        //double rR = (r[j]+r[j+1])/2.0;
        //double rhoUnr_Rr = rhoUnr_old[i][j]*rL/rR;
        //rhoUnr[i][j+1] = rhoUnr_Rr;

        rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
    }

    //エラー計算
    error_rhon = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhon[i][j] - rhon_old[i][j])/(rhon[i][j] + rhon_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhon){
                        error_rhon = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhon += pow(rhon[i][j]-rhon_old[i][j],2)/(pow(rhon_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhon = sqrt(error_rhon/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhon_old3(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    double sigma = M_PI*(2.0*ri)*(2.0*ri); //Attention：有効半径なので\sigma = \pi*d^2
    //double nu_tmp = sqrt(2.0)*rhon*sigma*vth;
    //double Dn = Boltz*Tn/(massi*nu_tmp);
    double DnN = 2.0/(3.0*sigma)*sqrt(Boltz*Tn/(M_PI*massi));

    //double di_tmp = 2.0*ri;
    //double DnN2 = 3.0/(8.0*di_tmp*di_tmp)*sqrt(Boltz*Tn/(M_PI*massi));
    //std::cout << "DnN = " <<DnN << " DnN2 = " << DnN2 << std::endl;

    //std::cout << "DnN = " << DnN <<std::endl;

    //double Dn = DmN/rhon_ini;

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhon_old[i][j] = rhon[i][j];
            rhoUnx_old[i][j] = rhoUnx[i][j];
            rhoUnr_old[i][j] = rhoUnr[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                double rhon_Lx = (rhon_old[i][j]+rhon_old[i-1][j])/2.0;
                double rhon_Rx = (rhon_old[i][j]+rhon_old[i+1][j])/2.0;
                double rhon_Lr = (rhon_old[i][j]+rhon_old[i][j-1])/2.0;
                double rhon_Rr = (rhon_old[i][j]+rhon_old[i][j+1])/2.0;

                double Dn_Lx = DnN/(rhon_Lx + 1e-100);
                double Dn_Rx = DnN/(rhon_Rx + 1e-100);
                double Dn_Lr = DnN/(rhon_Lr + 1e-100);
                double Dn_Rr = DnN/(rhon_Rr + 1e-100);

                double bLx  = double(i!=i_flc_bl[0][0]); //z0
                bLx = bLx*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx = bLx*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx = bLx*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double nbLx  = 1.0 - bLx;

                double bRx  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx = bRx*double(i!=i_flc_bl[4][1]); //z5
                double nbRx  = 1.0 - bRx;

                double bLr  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr = bLr*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double nbLr  = 1.0 - bLr;

                double bRr_in  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1] || x[i] > width_neutIn); //x1 inlet
                double nbRr_in  = 1.0 - bRr_in;
                //test1[i][j] = nbRr_in;
                
                double bRr  = double(j!=j_flc_bl[0][1] || i>i_flc_bl[1][1] || x[i] <= width_neutIn); //x1
                bRr = bRr*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double nbRr  = 1.0 - bRr; //x5含まない

                double bRr1  = (j!=j_flc_bl[4][1] || i<i_flc_bl[4][0]); //x5
                double nbRr1  = 1.0 - bRr1; //x5だけ
                
                bRr = bRr_in*bRr*bRr1; //全部含む

                //open-flux (equal to ion)
                //------------------------------------
                double Gamma_open_Rr = rL/rR*rhoUnr_old[i][j];
                //------------------------------------

                aP[i][j] = (Dn_Rx*bRx + Dn_Lx*bLx)*dr*dr 
                    + (qR*Dn_Rr*bRr + qL*Dn_Lr*bLr)*dx*dx 
                    //+    0.25*vth*dr*dx*dr/Dn*nbLx //陰的指定
                    //+    0.25*vth*dr*dx*dr/Dn*nbRx //陰的指定
                    //+ qL*0.25*vth*dx*dx*dr/Dn*nbLr //陰的指定
                    //+ qR*0.25*vth*dx*dx*dr*nbRr1 //陰的指定
                    + dx*dx*dr*dr/dt; //時間項;
                aE[i][j] = Dn_Rx*dr*dr*bRx;
                aW[i][j] = Dn_Lx*dr*dr*bLx;
                aN[i][j] = qR*Dn_Rr*dx*dx*bRr;
                aS[i][j] = qL*Dn_Lr*dx*dx*bLr;

                //double rhoUnx_Rx = rhoUnx_old[i][j];
                //double rhoUnx_Rr = rhoUnr_old[i][j]*rL/rR;

                //recombination
                double rhoUnx_Lx_RC = -0.0*rhoi[i][j]*Uix[i][j]   - 0.0*rhoUmx[i][j];
                double rhoUnx_Rx_RC = -0.0*rhoi[i][j]*Uix[i+1][j] - 0.0*rhoUmx[i+1][j];
                double rhoUnr_Lr_RC = -0.0*rhoi[i][j]*Uir[i][j]   - 0.0*rhoUmr[i][j];
                double rhoUnr_Rr_RC = -0.0*rhoi[i][j]*Uir[i][j+1] - 0.0*rhoUmr[i][j+1];
                double rhoUnx_Rr_in = -0.0*rhoi[i][j]*Uir[i][j+1] - 0.0*rhoUmr[i][j+1] - fn_In;
                //metaからのstepwise-excitationとsuper-elasticのde-excitationによる生成
                double G = (nu_excStep[i][j] + nu_super[i][j])*rhoe[i][j]; 
                //metaに行ってしまう分と「direct」-ionizationによる分
                double L = (nu_excMeta[i][j] + 0.5*nu_exc[i][j] + nu_ionz[i][j])*rhoe[i][j];

                b[i][j] = rhon_old[i][j]/dt*dx*dx*dr*dr + 0.0*(G - L)*dx*dx*dr*dr
                    + (
                        rhoUnx_Lx_RC*nbLx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr
                    - (
                         rhoUnx_Rx_RC*nbRx //右壁境界
                      )*dr*dx*dr
                    + qL*(
                          rhoUnr_Lr_RC*nbLr //下壁境界
                      )*dx*dx*dr
                    - qR*(
                          rhoUnr_Rr_RC*nbRr //上壁境界
                        + Gamma_open_Rr*nbRr1 //上壁境界
                        + rhoUnx_Rr_in*nbRr_in
                      )*dx*dx*dr;
            }
        }
    }

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhon[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhon[i][j]<< std::endl; 
                    ncount ++;
                    rhon[i][j] = fmax(rhon_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhon count = " << ncount << std::endl;
    }

    //rhoUnx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                double rhon_Lx = (rhon_old[i][j]+rhon_old[i-1][j])/2.0;
                double Dn_Lx = DnN/(rhon_Lx + 1e-100);

                rhoUnx[i][j] = -Dn_Lx*(rhon[i][j] - rhon[i-1][j])/dx;
            }
        }
    }

    //rhoUnr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                double rhon_Lr = (rhon_old[i][j]+rhon_old[i][j-1])/2.0;
                double Dn_Lr = DnN/(rhon_Lr + 1e-100);

                rhoUnr[i][j] = -Dn_Lr*(rhon[i][j] - rhon[i][j-1])/dr;
            }
        }   
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        if(x[i] < width_neutIn){ //流入部
            //rhoUnr[i][j+1] = -fn_In;
            double rhoUnx_Rr_in = - fn_In;
            rhoUnr[i][j+1] = rhoUnx_Rr_in;
            //std::cout << i << "," <<j <<","<< rhoUnr[i][j+1] << std::endl;
        }
    }

    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double rhoUnr_Rr = rhoUnr_old[i][j]*rL/rR;
        rhoUnr[i][j+1] = rhoUnr_Rr;

        //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
    }

    /*
    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double rhoUnx_Lx_RC = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = rhoUnx_Lx_RC;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        double rhoUnx_Rx_RC = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = rhoUnx_Rx_RC;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        double rhoUnx_Rx_RC = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = rhoUnx_Rx_RC;
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double rhoUnr_Lr_RC = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = rhoUnr_Lr_RC;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double rhoUnr_Lr_RC = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = rhoUnr_Lr_RC;
    }

    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        if(x[i] < width_neutIn){ //流入部
            //rhoUnr[i][j+1] = -fn_In;
            double rhoUnx_Rr_in = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1] - fn_In;
            rhoUnr[i][j+1] = rhoUnx_Rr_in;
            //std::cout << i << "," <<j <<","<< rhoUnr[i][j+1] << std::endl;
        }else{ //ただの壁
            //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
            double rhoUnr_Rr_RC = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
            rhoUnr[i][j+1] = rhoUnr_Rr_RC;
        }
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
        //rhoUnr[i][j+1] = -rhoi[i][j]*Uir[i][j+1]; //Recombination
        double rhoUnr_Rr_RC = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
        rhoUnr[i][j+1] = rhoUnr_Rr_RC;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double rhoUnr_Rr = rhoUnr_old[i][j]*rL/rR;
        rhoUnr[i][j+1] = rhoUnr_Rr;

        //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
    }
    */
    

    //エラー計算
    error_rhon = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhon[i][j] - rhon_old[i][j])/(rhon[i][j] + rhon_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhon){
                        error_rhon = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhon += pow(rhon[i][j]-rhon_old[i][j],2)/(pow(rhon_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhon = sqrt(error_rhon/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhon(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    //time step for metastable neutral
    //------------------------------------
    double dt_n = dt*double(ndt_n);
    //------------------------------------
    
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    double sigma = M_PI*(2.0*ri)*(2.0*ri); //Attention：有効半径なので\sigma = \pi*d^2
    //double nu_tmp = sqrt(2.0)*rhon*sigma*vth;
    //double Dn = Boltz*Tn/(massi*nu_tmp);
    double DnN = 2.0/(3.0*sigma)*sqrt(Boltz*Tn/(M_PI*massi));

    //double di_tmp = 2.0*ri;
    //double DnN2 = 3.0/(8.0*di_tmp*di_tmp)*sqrt(Boltz*Tn/(M_PI*massi));
    //std::cout << "DnN = " <<DnN << " DnN2 = " << DnN2 << std::endl;

    //std::cout << "DnN = " << DnN <<std::endl;

    //double Dn = DmN/rhon_ini;

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhon_old[i][j] = rhon[i][j];
            rhoUnx_old[i][j] = rhoUnx[i][j];
            rhoUnr_old[i][j] = rhoUnr[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                double rhon_Lx = (rhon_old[i][j]+rhon_old[i-1][j])/2.0;
                double rhon_Rx = (rhon_old[i][j]+rhon_old[i+1][j])/2.0;
                double rhon_Lr = (rhon_old[i][j]+rhon_old[i][j-1])/2.0;
                double rhon_Rr = (rhon_old[i][j]+rhon_old[i][j+1])/2.0;

                double Dn_Lx = DnN/(rhon_Lx + 1e-100);
                double Dn_Rx = DnN/(rhon_Rx + 1e-100);
                double Dn_Lr = DnN/(rhon_Lr + 1e-100);
                double Dn_Rr = DnN/(rhon_Rr + 1e-100);

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //adjacent "cell" to the wall for setting zero-flux on the wall
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;
                
                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;
                
                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2 || x[i] <= width_neutIn+x6); //x1 not inlet
                double bRr_in  = double(j!=j_flc_bl[0][1] || iblock > 2 || x[i] > width_neutIn+x6); //x1 inlet
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_in*bRr_open;
                //------------------------------------

                //wall-flux divide by density (for implicit method)
                //------------------------------------
                //double GammaPerN_open_Rr = 0.0;
                //if(bRr_open == 0){
                //    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                //    GammaPerN_open_Rr = 0.25*vth;
                //}
                //------------------------------------

                //boundary-flux
                //------------------------------------
                double Gamma_wall_Lx = 0.0;
                if(bLx_wall == 0){
                    Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
                }
                double Gamma_wall_Rx = 0.0;
                if(bRx_wall == 0){
                    Gamma_wall_Rx = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
                }
                double Gamma_wall_Lr = 0.0;
                if(bLr_wall == 0){
                    Gamma_wall_Lr = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
                }
                double Gamma_wall_Rr = 0.0;
                if(bRr_wall == 0){
                    Gamma_wall_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
                }
                double Gamma_in_Rr = 0.0;
                if(bRr_in== 0){
                    Gamma_in_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1] - fn_In;
                    //std::cout << Gamma_in_Rr << ","<<fn_In << std::endl;
                }
                double Gamma_open_Rr = 0.0;
                if(bRr_open== 0){
                    Gamma_open_Rr = fmax(rL/rR*rhoUnr_old[i][j],0.0);
                }
                //------------------------------------

   
                aP[i][j] = (Dn_Rx*bRx + Dn_Lx*bLx)*dr*dr 
                    + (qR*Dn_Rr*bRr + qL*Dn_Lr*bLr)*dx*dx 
                    //+    0.25*vth*dr*dx*dr/Dn*nbLx //陰的指定
                    //+    0.25*vth*dr*dx*dr/Dn*nbRx //陰的指定
                    //+ qL*0.25*vth*dx*dx*dr/Dn*nbLr //陰的指定
                    //+ qR*GammaPerN_open_Rr*dx*dx*dr //陰的指定
                    + dx*dx*dr*dr/dt_n; //時間項;
                aE[i][j] = Dn_Rx*dr*dr*bRx;
                aW[i][j] = Dn_Lx*dr*dr*bLx;
                aN[i][j] = qR*Dn_Rr*dx*dx*bRr;
                aS[i][j] = qL*Dn_Lr*dx*dx*bLr;

                //double rhoUnx_Rx = rhoUnx_old[i][j];
                //double rhoUnx_Rr = rhoUnr_old[i][j]*rL/rR;


                

                //metaからのstepwise-excitationとsuper-elasticのde-excitationによる生成
                double G = (nu_excStep[i][j] + nu_super[i][j])*rhoe[i][j]; 
                
                //metaに行ってしまう分と「direct」-ionizationによる分
                double L = (nu_excMeta[i][j] + 0.5*nu_exc[i][j] + nu_ionz[i][j])*rhoe[i][j];

                b[i][j] = rhon_old[i][j]/dt_n*dx*dx*dr*dr + (G - L)*dx*dx*dr*dr
                    + (
                        Gamma_wall_Lx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr
                    - (
                        Gamma_wall_Rx //右壁境界
                      )*dr*dx*dr
                    + qL*(
                        Gamma_wall_Lr //下壁境界
                      )*dx*dx*dr
                    - qR*(
                        Gamma_wall_Rr //上壁境界
                        + Gamma_open_Rr //上壁境界
                        + Gamma_in_Rr
                      )*dx*dx*dr;
            }
        }
    }

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhon);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhon[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhon[i][j]<< std::endl; 
                    ncount ++;
                    rhon[i][j] = fmax(rhon_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhon count = " << ncount << std::endl;
    }

    //rhoUnx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                double rhon_Lx = (rhon_old[i][j]+rhon_old[i-1][j])/2.0;
                double Dn_Lx = DnN/(rhon_Lx + 1e-100);

                rhoUnx[i][j] = -Dn_Lx*(rhon[i][j] - rhon[i-1][j])/dx;
            }
        }
    }

    //rhoUnr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                double rhon_Lr = (rhon_old[i][j]+rhon_old[i][j-1])/2.0;
                double Dn_Lr = DnN/(rhon_Lr + 1e-100);

                rhoUnr[i][j] = -Dn_Lr*(rhon[i][j] - rhon[i][j-1])/dr;
            }
        }   
    }


    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
        rhoUnx_wall[i][j] = rhoUnx[i][j];
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
        rhoUnx_wall[i][j] = rhoUnx[i][j];
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
        rhoUnx_wall[i][j] = rhoUnx[i][j];
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
        rhoUnx_wall[i][j] = rhoUnx[i][j];
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        double Gamma_wall_Rx = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = Gamma_wall_Rx;
        rhoUnx_wall[i+1][j] = rhoUnx[i+1][j];
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        double Gamma_wall_Rx = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = Gamma_wall_Rx;
        rhoUnx_wall[i+1][j] = rhoUnx[i+1][j];
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double Gamma_wall_Lr = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = Gamma_wall_Lr;
        rhoUnr_wall[i][j] = rhoUnr[i][j];
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double Gamma_wall_Lr = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = Gamma_wall_Lr;
        rhoUnr_wall[i][j] = rhoUnr[i][j];
    }
    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        if(x[i] < width_neutIn + x6){ //流入部
            //rhoUnr[i][j+1] = -fn_In;
            double Gamma_in_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1] - fn_In;
            rhoUnr[i][j+1] = Gamma_in_Rr;
        }else{ //ただの壁
            //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
            double Gamma_wall_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
            rhoUnr[i][j+1] = Gamma_wall_Rr;
            rhoUnr_wall[i][j+1] = rhoUnr[i][j+1];
        }
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
        //rhoUnr[i][j+1] = -rhoi[i][j]*Uir[i][j+1]; //Recombination
        double Gamma_wall_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
        rhoUnr[i][j+1] = Gamma_wall_Rr;
        rhoUnr_wall[i][j+1] = rhoUnr[i][j+1];
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double Gamma_open_Rr = fmax(rL/rR*rhoUnr_old[i][j],0.0);
        rhoUnr[i][j+1] = Gamma_open_Rr;
        rhoUnr_wall[i][j+1] = 0.0;

        //double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //double GammaPerN_open_Rr = 0.25*vth;
        //rhoUnr[i][j+1] = rhon[i][j]*GammaPerN_open_Rr ;
        
        //std::cout << Gamma_open_Rr << std::endl;
    }

    //calculation of particle balance
    //------------------------------------
    if(itime%ndiv_fout == 0 || itime == ntime){
        
        //volume integrated values
        //------------------------------------
        double dNndt_sum         = 0.0;
        double nabla_rhoUn_sum   = 0.0;
        double rate_exc_m_to_h_sum = 0.0;
        double rate_super_sum    = 0.0;
        double rate_exc_g_to_m_sum = 0.0;
        double rate_exc_g_to_h_sum     = 0.0;
        double rate_d_ionz_sum   = 0.0;
        //------------------------------------
    
        //calculate volume integrated of each term
        //------------------------------------
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    
                    //radial position at upper and lower cell interface
                    //------------------------------------
                    double rR = (r[j]+r[j+1])/2.0;
                    double rL = (r[j]+r[j-1])/2.0;
                    //------------------------------------

                    //normalized radial position at upper and lower cell interface
                    //------------------------------------
                    double qR = (r[j]+r[j+1])/2.0/r[j];
                    double qL = (r[j]+r[j-1])/2.0/r[j];
                    //------------------------------------

                    //BC - set adjacent flag (adjacent = 0, others = 1)
                    //adjacent "cell" to the wall for setting zero-flux on the wall
                    //------------------------------------
                    //left
                    double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                    bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                    double bLx  = bLx_wall;
                    
                    //right
                    double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                    bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                    double bRx  = bRx_wall;
                    
                    //lower
                    double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                    bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                    double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                    double bLr  = bLr_wall*bLr_cen;
                    
                    //upper
                    double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2); //x1 not inlet
                    bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                    double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                    double bRr = bRr_wall*bRr_open;
                    //------------------------------------

                    double nabla_rhoUn = (rhoUnx[i+1][j]*bRx_wall - rhoUnx[i][j]*bLx_wall)/dx 
                                       + (qR*rhoUnr[i][j+1]*bRr_wall - qL*rhoUnr[i][j]*bLr_wall)/dr
                                       + (rhoUnx_wall[i+1][j] -rhoUnx_wall[i][j])/dx 
                                       + (qR*rhoUnr_wall[i][j+1] - qL*rhoUnr_wall[i][j])/dr;

                    double volume = 2.0*M_PI*r[j]*dr*dx;
                    
                    dNndt_sum         = dNndt_sum         + volume*(rhon[i][j] - rhon_old[i][j])/dt;
                    nabla_rhoUn_sum   = nabla_rhoUn_sum   + volume*nabla_rhoUn;

                    //generation
                    rate_exc_m_to_h_sum = rate_exc_m_to_h_sum  + volume*rhoe[i][j]*nu_excStep[i][j];
                    rate_super_sum      = rate_super_sum       + volume*rhoe[i][j]*nu_super[i][j];
                    rate_exc_g_to_m_sum = rate_exc_g_to_m_sum  - volume*rhoe[i][j]*nu_excMeta[i][j];
                    rate_exc_g_to_h_sum = rate_exc_g_to_h_sum  - volume*rhoe[i][j]*0.5*nu_exc[i][j];
                    rate_d_ionz_sum     = rate_d_ionz_sum      - volume*rhoe[i][j]*nu_ionz[i][j];
                }
            }
        }

        //output particle balance for metastable
        //------------------------------------
        std::string char1="results/particle_balance_ground";
        std::string char2=std::to_string(nOut);
        std::string char_csv=".csv";
        std::ofstream outputfile10(char1+char2+char_csv);
        outputfile10 << std::setprecision(std::numeric_limits<double>::max_digits10) << std::scientific;
        outputfile10<< "dN/dt (pcl/s), loss_to_bnd (pcl/s), sw-ex (pcl/s), super (pcl/s), ex-to-m (pcl/s), ex-to-h (pcl/s), iz (pcl/s), sum (pcl/s)"<< std::endl;
        outputfile10 << dNndt_sum 
            << "," << -nabla_rhoUn_sum 
            << "," << rate_exc_m_to_h_sum  
            << "," << rate_super_sum 
            << "," << rate_exc_g_to_m_sum 
            << "," << rate_exc_g_to_h_sum
            << "," << rate_d_ionz_sum
            << "," << -dNndt_sum 
                + (
                    + rate_exc_m_to_h_sum 
                    + rate_super_sum 
                    + rate_exc_g_to_m_sum 
                    + rate_exc_g_to_h_sum 
                    + rate_d_ionz_sum
                )
            << std::endl;
        outputfile10.close();
        //------------------------------------
    }
    //------------------------------------

    //エラー計算
    error_rhon = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhon[i][j] - rhon_old[i][j])/(rhon[i][j] + rhon_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhon){
                        error_rhon = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhon += pow(rhon[i][j]-rhon_old[i][j],2)/(pow(rhon_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhon = sqrt(error_rhon/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhon_log(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース
    std::vector<std::vector<double> > logN_old(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > logN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    double sigma = M_PI*(2.0*ri)*(2.0*ri); //Attention：有効半径なので\sigma = \pi*d^2
    //double nu_tmp = sqrt(2.0)*rhon*sigma*vth;
    //double Dn = Boltz*Tn/(massi*nu_tmp);
    double DnN = 2.0/(3.0*sigma)*sqrt(Boltz*Tn/(M_PI*massi));

    //double di_tmp = 2.0*ri;
    //double DnN2 = 3.0/(8.0*di_tmp*di_tmp)*sqrt(Boltz*Tn/(M_PI*massi));
    //std::cout << "DnN = " <<DnN << " DnN2 = " << DnN2 << std::endl;

    //std::cout << "DnN = " << DnN <<std::endl;

    //double Dn = DmN/rhon_ini;

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhon_old[i][j] = rhon[i][j];
            rhoUnx_old[i][j] = rhoUnx[i][j];
            rhoUnr_old[i][j] = rhoUnr[i][j];
        }
    }

    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            logN[i][j] = log(rhon[i][j]+1e-100);
            logN_old[i][j] = log(rhon_old[i][j]+1e-100);
        }
    }

    //係数作成
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                //BC - set adjacent flag (adjacent = 0, others = 1)
                //adjacent "cell" to the wall for setting zero-flux on the wall
                //------------------------------------
                //left
                double bLx_wall  = double(i!=i_flc_bl[0][0] || iblock != 0); //z0
                bLx_wall = bLx_wall*double(i!=i_flc_bl[2][0] || j>j_flc_bl[0][0]-1); //z1
                bLx_wall = bLx_wall*double(i!=i_flc_bl[3][0] || j>j_flc_bl[2][0]-1); //z2
                bLx_wall = bLx_wall*double(i!=i_flc_bl[4][0] || j<j_flc_bl[1][0]); //z4
                double bLx  = bLx_wall;
                
                //right
                double bRx_wall  = double(i!=i_flc_bl[1][1] || j<j_flc_bl[1][0]); //z3
                bRx_wall = bRx_wall*double(i!=i_flc_bl[4][1]); //z5
                double bRx  = bRx_wall;
                
                //lower
                double bLr_wall  = double(j!=j_flc_bl[0][0] || i>i_flc_bl[0][1]); //x0
                bLr_wall = bLr_wall*double(j!=j_flc_bl[2][0] || i>i_flc_bl[2][1]); //x2
                double bLr_cen = double(j!=j_flc_bl[3][0]); //x6
                double bLr  = bLr_wall*bLr_cen;
                
                //upper
                double bRr_wall  = double(j!=j_flc_bl[0][1] || iblock > 2 || x[i] <= width_neutIn+x6); //x1 not inlet
                double bRr_in  = double(j!=j_flc_bl[0][1] || iblock > 2 || x[i] > width_neutIn+x6); //x1 inlet
                bRr_wall = bRr_wall*double(j!=j_flc_bl[3][1] || i<i_flc_bl[1][1]+1 || i>i_flc_bl[3][1]); //x4
                double bRr_open  = (j!=j_flc_bl[4][1] || iblock != 4); //x5
                double bRr = bRr_wall*bRr_in*bRr_open;
                //------------------------------------

                //wall-flux divide by density (for implicit method)
                //------------------------------------
                //double GammaPerN_open_Rr = 0.0;
                //if(bRr_open == 0){
                //    double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
                //    GammaPerN_open_Rr = 0.25*vth;
                //}
                //------------------------------------

                //boundary-flux
                //------------------------------------
                double Gamma_wall_Lx = 0.0;
                if(bLx_wall == 0){
                    Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
                }
                double Gamma_wall_Rx = 0.0;
                if(bRx_wall == 0){
                    Gamma_wall_Rx = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
                }
                double Gamma_wall_Lr = 0.0;
                if(bLr_wall == 0){
                    Gamma_wall_Lr = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
                }
                double Gamma_wall_Rr = 0.0;
                if(bRr_wall == 0){
                    Gamma_wall_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
                }
                double Gamma_in_Rr = 0.0;
                if(bRr_in== 0){
                    Gamma_in_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1] - fn_In;
                    //std::cout << Gamma_in_Rr << ","<<fn_In << std::endl;
                }
                double Gamma_open_Rr = 0.0;
                if(bRr_open== 0){
                    Gamma_open_Rr = fmax(rL/rR*rhoUnr_old[i][j],0.0);
                }
                //------------------------------------

   
                aP[i][j] = (DnN*bRx + DnN*bLx)*dr*dr 
                    + (qR*DnN*bRr + qL*DnN*bLr)*dx*dx;
                    //+    0.25*vth*dr*dx*dr/Dn*nbLx //陰的指定
                    //+    0.25*vth*dr*dx*dr/Dn*nbRx //陰的指定
                    //+ qL*0.25*vth*dx*dx*dr/Dn*nbLr //陰的指定
                    //+ qR*GammaPerN_open_Rr*dx*dx*dr //陰的指定
                aE[i][j] = DnN*dr*dr*bRx;
                aW[i][j] = DnN*dr*dr*bLx;
                aN[i][j] = qR*DnN*dx*dx*bRr;
                aS[i][j] = qL*DnN*dx*dx*bLr;

                //double rhoUnx_Rx = rhoUnx_old[i][j];
                //double rhoUnx_Rr = rhoUnr_old[i][j]*rL/rR;


                

                //metaからのstepwise-excitationとsuper-elasticのde-excitationによる生成
                double G = (nu_excStep[i][j] + nu_super[i][j])*rhoe[i][j]; 
                //metaに行ってしまう分と「direct」-ionizationによる分
                double L = (nu_excMeta[i][j] + 0.5*nu_exc[i][j] + nu_ionz[i][j])*rhoe[i][j];

                b[i][j] = (G - L)*dx*dx*dr*dr
                    + (
                        Gamma_wall_Lx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr
                    - (
                        Gamma_wall_Rx //右壁境界
                      )*dr*dx*dr
                    + qL*(
                        Gamma_wall_Lr //下壁境界
                      )*dx*dx*dr
                    - qR*(
                        Gamma_wall_Rr //上壁境界
                        + Gamma_open_Rr //上壁境界
                        + Gamma_in_Rr
                      )*dx*dx*dr;
            }
        }
    }

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,logN);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,logN);
    }

    //nnにもどす
    double lim_exp = 1.0e2; //expの制限
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                rhon[i][j] = exp(fmin(logN[i][j],lim_exp));
            }
        }
    }

    //rhoUnx更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flx_bl[iblock][0];i<=i_flx_bl[iblock][1];i++){ 
            for (int j=j_flx_bl[iblock][0];j<=j_flx_bl[iblock][1];j++){
                rhoUnx[i][j] = -DnN*(logN[i][j] - logN[i-1][j])/dx;
            }
        }
    }

    //rhoUnr更新
    for (int iblock=0;iblock<n_bl-1;iblock++){ 
        for (int i=i_flr_bl[iblock][0];i<=i_flr_bl[iblock][1];i++){ 
            for (int j=j_flr_bl[iblock][0];j<=j_flr_bl[iblock][1];j++){
                rhoUnr[i][j] = -DnN*(logN[i][j] - logN[i][j-1])/dr;
            }
        }   
    }


    //左 壁 z0
    for (int j=j_flc_bl[0][0];j<=j_flc_bl[0][1];j++){
        int i=i_flc_bl[0][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
    }
    //左 壁 z1
    for (int j=j_flc_bl[2][0];j<=j_flc_bl[0][0]-1;j++){
        int i=i_flc_bl[2][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
    }
    //左 壁 z2
    for (int j=j_flc_bl[3][0];j<=j_flc_bl[2][0]-1;j++){
        int i=i_flc_bl[3][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
    }
    //左 壁 z4
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][0];
        //rhoUnx[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnx[i][j] = -rhoi[i][j]*Uix[i][j]; //Recombination
        double Gamma_wall_Lx = -rhoi[i][j]*Uix[i][j]   - rhoUmx[i][j];
        rhoUnx[i][j] = Gamma_wall_Lx;
    }
    //右 壁 z3
    for (int j=j_flc_bl[1][0];j<=j_flc_bl[1][1];j++){
        int i=i_flc_bl[1][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        double Gamma_wall_Rx = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = Gamma_wall_Rx;
    }
    //右 壁 z5
    for (int j=j_flc_bl[4][0];j<=j_flc_bl[4][1];j++){
        int i=i_flc_bl[4][1];
        //rhoUnx[i+1][j] = 0.25*rhon[i][j]*vth;
        double Gamma_wall_Rx = -rhoi[i][j]*Uix[i+1][j] - rhoUmx[i+1][j];
        rhoUnx[i+1][j] = Gamma_wall_Rx;
    }
    //下 壁 x0
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[0][1];i++){
        int j=j_flc_bl[0][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double Gamma_wall_Lr = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = Gamma_wall_Lr;
    }
    //下 壁 x2
    for (int i=i_flc_bl[2][0];i<=i_flc_bl[2][1];i++){
        int j=j_flc_bl[2][0];
        //rhoUnr[i][j] = -0.25*rhon[i][j]*vth;
        //rhoUnr[i][j] = -rhoi[i][j]*Uir[i][j]; //Recombination
        double Gamma_wall_Lr = -rhoi[i][j]*Uir[i][j]   - rhoUmr[i][j];
        rhoUnr[i][j] = Gamma_wall_Lr;
    }
    //上 壁 x1
    for (int i=i_flc_bl[0][0];i<=i_flc_bl[1][1];i++){
        int j=j_flc_bl[0][1];
        if(x[i] < width_neutIn + x6){ //流入部
            //rhoUnr[i][j+1] = -fn_In;
            double Gamma_in_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1] - fn_In;
            rhoUnr[i][j+1] = Gamma_in_Rr;
        }else{ //ただの壁
            //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
            double Gamma_wall_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
            rhoUnr[i][j+1] = Gamma_wall_Rr;
        }
    }
    //上 壁 x4
    for (int i=i_flc_bl[1][1]+1;i<=i_flc_bl[3][1];i++){
        int j=j_flc_bl[3][1];
        //rhoUnr[i][j+1] = 0.25*rhon[i][j]*vth;
        //rhoUnr[i][j+1] = -rhoi[i][j]*Uir[i][j+1]; //Recombination
        double Gamma_wall_Rr = -rhoi[i][j]*Uir[i][j+1] - rhoUmr[i][j+1];
        rhoUnr[i][j+1] = Gamma_wall_Rr;
    }
    //上 開放 x5
    for (int i=i_flc_bl[4][0];i<=i_flc_bl[4][1];i++){
        int j=j_flc_bl[4][1];
        //continuous
        double rL = (r[j]+r[j-1])/2.0;
        double rR = (r[j]+r[j+1])/2.0;
        double Gamma_open_Rr = fmax(rL/rR*rhoUnr_old[i][j],0.0);
        rhoUnr[i][j+1] = Gamma_open_Rr;

        //double vth = sqrt(8.0*Boltz*Te[i][j]/(M_PI*masse));
        //double GammaPerN_open_Rr = 0.25*vth;
        //rhoUnr[i][j+1] = rhon[i][j]*GammaPerN_open_Rr ;
        
        //std::cout << Gamma_open_Rr << std::endl;
    }

    //エラー計算
    error_rhon = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhon[i][j] - rhon_old[i][j])/(rhon[i][j] + rhon_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhon){
                        error_rhon = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<n_bl-1;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhon += pow(rhon[i][j]-rhon_old[i][j],2)/(pow(rhon_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhon = sqrt(error_rhon/double(ncount));
    }

}

//*****************************************************************
//**                                                             **
//**           void solve_rhoe_simple                         **
//**                                                             **
//*****************************************************************
void update_rhom_kinetic(){


    std::vector<std::vector<double> > aW(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aE(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aS(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aN(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > aP(ni+2,std::vector<double>(nj+2,0.0)); //係数
    std::vector<std::vector<double> > b (ni+2,std::vector<double>(nj+2,0.0)); //ソース

    
    double vth = sqrt(8.0*Boltz*Tn/(M_PI*massi));
    double Dn = DmN/rhon_ini;

    //過去の値を保存 (ゴーストセルも含む)
    for (int i=0;i<=ni+1;i++){ 
        for (int j=0;j<=nj+1;j++){ 
            rhom_old[i][j] = rhom[i][j];
            rhoUmx_old[i][j] = rhoUmx[i][j];
            rhoUmr_old[i][j] = rhoUmr[i][j];
        }
    }

    //係数作成
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                double rL = (r[j]+r[j-1])/2.0;
                double rR = (r[j]+r[j+1])/2.0;
                double qL = (r[j]+r[j-1])/2.0/r[j];
                double qR = (r[j]+r[j+1])/2.0/r[j];

                double bLx  = double(i!=i_flc_bl[0][0])*double(i!=i_flc_bl[1][0] || j   >=j_flc_bl[0][0]);
                double bRx  = double(i!=i_flc_bl[1][1]);
                double bLr  = double(j!=j_flc_bl[0][0] || i  >=i_flc_bl[1][0]);
                double bRr  = double(j!=j_flc_bl[1][1]);

                double nbLx  = 1.0 - bLx;
                double nbLr  = 1.0 - bLr;
                double nbRx  = 1.0 - bRx;
                double nbRr  = 1.0 - bRr;

                double um = sqrt(2.0*Boltz*Tn/massi);
                double utx = rhoUmx_old[i+1][j]/(rhom_old[i][j]*um + 1e-100)*0.0; //無次元化速度 (上流速度をとる)
                double utx_Rx = rhoUmx_old[i][j]/(rhom_old[i][j]*um + 1e-100)*0.0; //無次元化速度 (上流速度をとる)
                double utr = rhoUmr_old[i][j+1]/(rhom_old[i][j]*um+1e-100)*0.0; //無次元化速度
                double utr_Rr = rhoUmr_old[i][j]/(rhom_old[i][j]*um+1e-100)*0.0; //無次元化速度

                aP[i][j] = (bRx + bLx)*dr*dr 
                    + (qR*bRr + qL*bLr)*dx*dx 
                    +    0.25*vth*(exp(-utx*utx) + utx*sqrt(M_PI)*(erf(utx) - 1.0))*dr*dx*dr/Dn*nbLx //陰的指定
                    + qL*0.25*vth*(exp(-utr*utr) + utr*sqrt(M_PI)*(erf(utr) - 1.0))*dx*dx*dr/Dn*nbLr //陰的指定
                    + dx*dx*dr*dr/dt/Dn; //時間項;
                aE[i][j] = dr*dr*bRx;
                aW[i][j] = dr*dr*bLx;
                aN[i][j] = qR*dx*dx*bRr;
                aS[i][j] = qL*dx*dx*bLr;

                //ソース項
                double G = rhoe_old[i][j]*(nu_excMeta[i][j] + 0.5*nu_exc[i][j]); //生成　直接励起と resoの半分がmetaに最終的に落ちてくる
                double L = rhoe_old[i][j]*(nu_ionzStep[i][j] + nu_excStep[i][j]); //損失 (stepwise Ionizationとstepwise Excitation)

                double rhoUmx_Rx = rhoUmx_old[i][j];
                double rhoUmx_Rr = rhoUmr_old[i][j]*rL/rR;

                b[i][j] = rhom_old[i][j]/dt/Dn*dx*dx*dr*dr + (G - L)/Dn*dx*dx*dr*dr
                    + (0.0
                          //rhoUmx_Lx*nbLx //左壁境界1,2 //陽的指定
                      )*dr*dx*dr/Dn
                    - (
                        rhoUmx_Rx*nbRx //右壁境界
                      )*dr*dx*dr/Dn
                    + qL*(0.0
                          //rhoUmr_Lr*nbLr //下壁境界　 //陽的指定
                      )*dx*dx*dr/Dn
                    - qR*(
                        rhoUmx_Rr*nbRr //上壁境界
                      )*dx*dx*dr/Dn;
            }
        }
    }

    if(icon_iter_phi==0){
        double alpha = 1.9;
        solver_SOR(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,alpha,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }else{
        solver_SMG(aP,aE,aW,aN,aS,b,i_flc_bl,j_flc_bl,maxITR_SOR_phi,error_cnv_SOR_phi,0,rhom);
    }

    //ゴーストセル以外で負になっているところがあれば戻す
    int ncount = 0;
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                if(rhom[i][j]<0.0){
                    //std::cout << "Warning negative density at (" << i <<","<<j<<") ne = " << rhom[i][j]<< std::endl; 
                    ncount ++;
                    rhom[i][j] = fmax(rhom_old[i][j],0.0);
                }
            }
        }
    }
    if(ncount!=0){
        std::cout << "negative rhom count = " << ncount << std::endl;
    }

    //rhoUmx更新
    for (int iblock=0;iblock<2;iblock++){ 
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1] + 1;i++){ //第2ブロックの時はもう1つ向こうまで
            for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                rhoUmx[i][j] = -Dn*(rhom[i][j] - rhom[i-1][j])/dx;

                if(i==i_flc_bl[0][0]){
                    double um = sqrt(2.0*Boltz*Tn/massi);
                    double utx = rhoUmx_old[i+1][j]/(rhom_old[i][j]*um + 1e-100)*0.0; //無次元化速度 (上流速度をとる)
                    double rhoUmx_Lx = -0.25*rhom[i][j]*vth
                        *(exp(-utx*utx) + utx*sqrt(M_PI)*(erf(utx) - 1.0));
                    rhoUmx[i][j] = rhoUmx_Lx;
                }

                if(i==i_flc_bl[1][0] && j<=j_flc_bl[0][0]-1){
                    double um = sqrt(2.0*Boltz*Tn/massi);
                    double utx = rhoUmx_old[i+1][j]/(rhom_old[i][j]*um + 1e-100)*0.0; //無次元化速度 (上流速度をとる)
                    double rhoUmx_Lx = -0.25*rhom[i][j]*vth
                        *(exp(-utx*utx) + utx*sqrt(M_PI)*(erf(utx) - 1.0));
                    rhoUmx[i][j] = rhoUmx_Lx;
                }

                if(i==i_flc_bl[1][1]+1){
                    double rhoUmx_Rx = rhoUmx_old[i-1][j];
                    rhoUmx[i][j] = rhoUmx_Rx;
                }
            }
        }
    }

    //rhoUmr更新
    for (int iblock=0;iblock<2;iblock++){
        for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
            for (int j=j_flc_bl[iblock][0]+iblock;j<=j_flc_bl[iblock][1]+1;j++){
                rhoUmr[i][j] = -Dn*(rhom[i][j] - rhom[i][j-1])/dr;

                if(j==j_flc_bl[0][0] && i<=i_flc_bl[0][1]){
                    double um = sqrt(2.0*Boltz*Tn/massi);
                    double utr = rhoUmr_old[i][j+1]/(rhom_old[i][j]*um+1e-100)*0.0; //無次元化速度
                    double rhoUmr_Lr = -0.25*rhom[i][j]*vth
                        *(exp(-utr*utr) + utr*sqrt(M_PI)*(erf(utr) - 1.0));
                    rhoUmr[i][j] = rhoUmr_Lr;
                }

                if(j==j_flc_bl[1][1]+1){
                    //continuous
                    double rL = (r[j-1]+r[j-2])/2.0;
                    double rR = (r[j-1]+r[j])/2.0;
                    double rhoUmr_Rr = rhoUmr_old[i][j-1]*rL/rR;
                    rhoUmr[i][j] = rhoUmr_Rr;
                }
            }
        }   
    }

    //エラー計算
    error_rhom = 0.0;
    if(icon_error == 0){
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    double error_tmp = fabs((rhom[i][j] - rhom_old[i][j])/(rhom[i][j] + rhom_old[i][j]+1e-100)*2.0/CFL);
                    if(error_tmp > error_rhom){
                        error_rhom = error_tmp;
                    }
                }
            }
        }
    }else{
        double ncount = 0;
        for (int iblock=0;iblock<2;iblock++){ 
            for (int i=i_flc_bl[iblock][0];i<=i_flc_bl[iblock][1];i++){ 
                for (int j=j_flc_bl[iblock][0];j<=j_flc_bl[iblock][1];j++){
                    error_rhom += pow(rhom[i][j]-rhom_old[i][j],2)/(pow(rhom_old[i][j],2)+1e9)/CFL;
                    ncount++;
                }
            }
        }
        error_rhom = sqrt(error_rhom/double(ncount));
    }

}


